#  v19.0: keywords.txt 关键词加载器
# ================================================================
def load_keywords_file(filepath="keywords.txt"):
    """
    从 keywords.txt 加载搜索关键词
    格式: 每行一个关键词, #开头为注释, 空行跳过
    返回: 关键词列表
    """
    keywords = []
    if not os.path.exists(filepath):
        return keywords
    with open(filepath, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            keywords.append(line)
    return keywords


def generate_default_keywords_file(filepath="keywords.txt"):
    """如果 keywords.txt 不存在, 生成默认模板"""
    if os.path.exists(filepath):
        return
    template = """# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
# Amazon 选品关键词 — 每行一个, #开头为注释
# 编辑此文件添加你的关键词, 脚本自动读取
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

# 示例关键词 (取消注释即可使用)
# massage gun deep tissue
# red light therapy panel
# laser engraver wood metal
# galaxy projector star light
# standing desk electric adjustable
"""
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(template)

