# ================================================================
#  v56.0: 产品验证系统 (Product Validation System)
# ================================================================
class ValidationStats:
    """v56.0: 全局验证统计"""
    total = 0
    passed = 0
    failed = 0
    rejected_products = []
    
    @classmethod
    def reset(cls):
        cls.total = 0
        cls.passed = 0
        cls.failed = 0
        cls.rejected_products = []
    
    @classmethod
    def record_pass(cls):
        cls.total += 1
        cls.passed += 1
    
    @classmethod
    def record_fail(cls, product, reason):
        cls.total += 1
        cls.failed += 1
        cls.rejected_products.append({'product': product, 'reason': reason})
    
    @classmethod
    def get_report(cls):
        pass_rate = (cls.passed / cls.total * 100) if cls.total > 0 else 0
        return {
            'total': cls.total,
            'passed': cls.passed,
            'failed': cls.failed,
            'pass_rate': pass_rate,
            'rejected_count': len(cls.rejected_products)
        }

def validate_product(product):
    """
    v56.0: 产品数据验证
    验证规则:
    - name: 非空字符串
    - price: > 0
    - rating: 0-5
    - reviews_count: >= 0
    - asin: 10字符字母数字
    - url: 包含 amazon.com
    """
    errors = []
    
    # 验证 name
    name = product.get('name', '')
    if not name or not isinstance(name, str) or not name.strip():
        errors.append('name为空或无效')
    
    # 验证 price
    price = product.get('price', 0)
    try:
        price_val = float(price)
        if price_val <= 0:
            errors.append(f'price无效: {price}')
    except (ValueError, TypeError):
        errors.append(f'price格式错误: {price}')
    
    # 验证 rating
    rating = product.get('rating', 0)
    try:
        rating_val = float(rating)
        if not (0 <= rating_val <= 5):
            errors.append(f'rating超出范围: {rating}')
    except (ValueError, TypeError):
        errors.append(f'rating格式错误: {rating}')
    
    # 验证 reviews_count
    reviews = product.get('reviews_count', 0)
    try:
        reviews_val = int(reviews)
        if reviews_val < 0:
            errors.append(f'reviews_count为负: {reviews}')
    except (ValueError, TypeError):
        errors.append(f'reviews_count格式错误: {reviews}')
    
    # 验证 asin
    asin = product.get('asin', '')
    if asin:
        if not isinstance(asin, str) or len(asin) != 10 or not asin.isalnum():
            errors.append(f'asin格式错误: {asin}')
    
    # 验证 url
    url = product.get('url', '')
    if url:
        if not isinstance(url, str) or 'amazon.com' not in url.lower():
            errors.append(f'url无效: {url}')
    
    if errors:
        ValidationStats.record_fail(product, '; '.join(errors))
        return False, errors
    else:
        ValidationStats.record_pass()
        return True, []


