# v16.0: 增强 Stealth JS — 完整反检测注入 (IIFE隔离 + 14项伪装)
_STEALTH_JS = """
(() => {
    // 1. 彻底删除 webdriver 属性 (不仅是重定义)
    delete Object.getPrototypeOf(navigator).webdriver;
    Object.defineProperty(navigator, 'webdriver', {get: () => undefined, configurable: true});

    // 2. 完整 chrome 对象 (真实Chrome有app/runtime/csi/loadTimes)
    window.chrome = {
        app: {isInstalled: false, InstallState: {DISABLED:'disabled',INSTALLED:'installed',NOT_INSTALLED:'not_installed'},
              RunningState: {CANNOT_RUN:'cannot_run',READY_TO_RUN:'ready_to_run',RUNNING:'running'}},
        runtime: {OnInstalledReason:{CHROME_UPDATE:'chrome_update',INSTALL:'install',UPDATE:'update'},
                  PlatformOs:{ANDROID:'android',CROS:'cros',LINUX:'linux',MAC:'mac',WIN:'win'},
                  connect: function(){}, sendMessage: function(){}, id: undefined},
        csi: function(){return {};},
        loadTimes: function(){return {requestTime:Date.now()/1000,startLoadTime:Date.now()/1000,
            commitLoadTime:Date.now()/1000,finishDocumentLoadTime:Date.now()/1000,finishLoadTime:Date.now()/1000,
            firstPaintTime:Date.now()/1000,navigationType:'Other',wasFetchedViaSpdy:true,
            wasNpnNegotiated:true,npnNegotiatedProtocol:'h2',connectionInfo:'h2'};}
    };

    // 3. 修复 permissions (绑定正确的this)
    const origQuery = window.navigator.permissions.query;
    window.navigator.permissions.query = (params) =>
        params.name === 'notifications'
            ? Promise.resolve({state: Notification.permission})
            : origQuery.call(window.navigator.permissions, params);

    // 4. 伪造 plugins (完整结构, 5个插件+namedItem/item方法)
    Object.defineProperty(navigator, 'plugins', {
        get: () => {
            const p = [
                {name:'Chrome PDF Plugin',filename:'internal-pdf-viewer',description:'Portable Document Format',length:1},
                {name:'Chrome PDF Viewer',filename:'mhjfbmdgcfjbbpaeojofohoefgiehjai',description:'',length:1},
                {name:'Native Client',filename:'internal-nacl-plugin',description:'',length:2},
                {name:'Chromium PDF Plugin',filename:'internal-pdf-viewer',description:'Portable Document Format',length:1},
                {name:'Chromium PDF Viewer',filename:'mhjfbmdgcfjbbpaeojofohoefgiehjai',description:'',length:1},
            ];
            p.item = (i) => p[i] || null;
            p.namedItem = (n) => p.find(x => x.name === n) || null;
            p.refresh = () => {};
            return p;
        }
    });

    // 5. 语言 + 平台 + 硬件
    Object.defineProperty(navigator, 'languages', {get: () => ['en-US','en']});
    Object.defineProperty(navigator, 'platform', {get: () => 'Win32'});
    Object.defineProperty(navigator, 'hardwareConcurrency', {get: () => 8});
    Object.defineProperty(navigator, 'deviceMemory', {get: () => 8});
    Object.defineProperty(navigator, 'maxTouchPoints', {get: () => 0});

    // 6. WebGL + WebGL2 指纹伪装 (两个上下文都要改)
    const getP1 = WebGLRenderingContext.prototype.getParameter;
    WebGLRenderingContext.prototype.getParameter = function(p) {
        if (p === 37445) return 'Intel Inc.';
        if (p === 37446) return 'Intel(R) UHD Graphics 630';
        return getP1.call(this, p);
    };
    try {
        const getP2 = WebGL2RenderingContext.prototype.getParameter;
        WebGL2RenderingContext.prototype.getParameter = function(p) {
            if (p === 37445) return 'Intel Inc.';
            if (p === 37446) return 'Intel(R) UHD Graphics 630';
            return getP2.call(this, p);
        };
    } catch(e) {}

    // 7. 伪造 connection 对象
    Object.defineProperty(navigator, 'connection', {
        get: () => ({effectiveType:'4g', rtt:50, downlink:10, saveData:false})
    });

    // 8. iframe contentWindow 保护 (防止通过iframe检测webdriver)
    try {
        const origGetter = Object.getOwnPropertyDescriptor(HTMLIFrameElement.prototype, 'contentWindow').get;
        Object.defineProperty(HTMLIFrameElement.prototype, 'contentWindow', {
            get: function() {
                const w = origGetter.call(this);
                if (w) { try { Object.defineProperty(w.navigator, 'webdriver', {get:()=>undefined}); } catch(e){} }
                return w;
            }
        });
    } catch(e) {}

    // 9. Function.prototype.toString 保护 (防止通过toString检测被修改的函数)
    const origTS = Function.prototype.toString;
    Function.prototype.toString = function() {
        if (this === Function.prototype.toString) return 'function toString() { [native code] }';
        return origTS.call(this);
    };

    // 10. 屏幕属性一致性
    Object.defineProperty(screen, 'colorDepth', {get: () => 24});
    Object.defineProperty(screen, 'pixelDepth', {get: () => 24});

    // 11. 移除 Playwright 特征码
    delete window.__playwright;
    delete window.__pw_manual;
    delete window.__PW_inspect;
})();
"""

# v16.0: CAPTCHA 检测关键词 (扩展到 25+ 信号, 需命中≥2个才判定)
_CAPTCHA_SIGNALS = [
    'captcha', 'robot', 'automated', 'unusual traffic', 'verify you',
    'not a robot', 'human verification', 'challenge', 'blocked',
    'api-services-support@amazon.com', 'type the characters',
    'enter the characters', 'sorry, we just need to make sure',
    'access denied', 'request blocked', 'security check',
    'one more step', 'checking your browser', 'please wait',
    'ddos protection', 'cloudflare', 'hcaptcha', 'recaptcha',
    'px-captcha', 'challenge-platform', 'are you a human',
]

class SmartFetcher:
    """v20.0: 六层反爬引擎 + CAPTCHA智能熔断器"""
    _pw = None; _browser = None; _ctx = None; _session = None; _cdp_browser = None
    _stats = {"pw": 0, "cf": 0, "api": 0, "surge": 0, "req": 0, "cdp": 0, "fail": 0, "captcha": 0, "circuit_break": 0}
    _PROFILE_DIR = os.path.join(Config.CACHE_DIR, "browser_profile_v16")
    _COOKIE_FILE = os.path.join(Config.CACHE_DIR, "cookies_v16.json")
    _SCREENSHOT_DIR = os.path.join(Config.CACHE_DIR, "screenshots")
    _lock = None
    _healthy = True
    _page_count = 0
    _MAX_PAGES = 50
    # ★★★ v20.0: CAPTCHA 熔断器状态 ★★★
    _captcha_times = []          # 最近CAPTCHA触发时间戳列表
    _circuit_broken = False      # 熔断器是否已触发
    _circuit_break_until = 0     # 熔断解除时间戳
    _captcha_total = 0           # 本次运行总CAPTCHA次数
    _CAPTCHA_STORM_THRESHOLD = 3       # 60秒内3次CAPTCHA = 风暴
    _CAPTCHA_STORM_WINDOW = 60         # 风暴检测窗口(秒)
    _CAPTCHA_MAX_TOTAL = 20            # v20.0-H: 20次后永久熔断 (原8次太少)
    _CIRCUIT_BREAK_DURATION = 120      # 熔断持续时间(秒) — 2分钟后自动恢复
    _CAPTCHA_WAIT_SHORT = 3            # CAPTCHA短等待(秒) — 替代原来的8秒

    @classmethod
    def _get_lock(cls):
        if cls._lock is None:
            import threading
            cls._lock = threading.Lock()
        return cls._lock

    @classmethod
    def _get_session(cls):
        if cls._session is None:
            cls._session = requests.Session()
            cls._session.headers.update(Config.headers())
            # 加载磁盘 Cookie 到 requests session
            cls._load_cookies_to_session()
        return cls._session

    @classmethod
    def _load_cookies_to_session(cls):
        """从磁盘加载 Cookie 到 requests Session"""
        try:
            if os.path.exists(cls._COOKIE_FILE):
                with open(cls._COOKIE_FILE, 'r') as f:
                    cookies = json.load(f)
                for c in cookies:
                    cls._session.cookies.set(
                        c.get('name',''), c.get('value',''),
                        domain=c.get('domain',''), path=c.get('path','/')
                    )
                log.info(f"  🍪 已加载 {len(cookies)} 个磁盘 Cookie")
        except Exception as e:
            log.debug(f"  ⚠️ Cookie 加载失败: {e}")

    @classmethod
    def _save_cookies_from_context(cls):
        """从 Playwright context 导出 Cookie 到磁盘"""
        try:
            if cls._ctx:
                cookies = cls._ctx.cookies()
                if cookies:
                    os.makedirs(os.path.dirname(cls._COOKIE_FILE), exist_ok=True)
                    with open(cls._COOKIE_FILE, 'w') as f:
                        json.dump(cookies, f, ensure_ascii=False)
                    log.debug(f"  🍪 已保存 {len(cookies)} 个 Cookie 到磁盘")
        except Exception as e:
            log.debug(f"  ⚠️ Cookie 保存失败: {e}")

    @classmethod
    def _screenshot_debug(cls, page, label="captcha"):
        """v16.0: CAPTCHA/异常时截图保存用于调试"""
        try:
            os.makedirs(cls._SCREENSHOT_DIR, exist_ok=True)
            ts = datetime.now().strftime('%Y%m%d_%H%M%S')
            path = os.path.join(cls._SCREENSHOT_DIR, f"{label}_{ts}.png")
            page.screenshot(path=path)
            log.info(f"  📸 截图已保存: {path}")
        except: pass

    @classmethod
    def _detect_captcha(cls, html):
        """v16.0: CAPTCHA 检测 — 需命中≥2个信号才判定 (避免误判)"""
        if not html: return False
        text_lower = html[:8000].lower()
        hit_count = sum(1 for sig in _CAPTCHA_SIGNALS if sig in text_lower)
        return hit_count >= 2  # ★ 至少2个信号才判定为CAPTCHA (v15误判率高)

    @classmethod
    def stats(cls): return cls._stats.copy()

    @classmethod
    def _record_captcha(cls):
        """v20.0: 记录CAPTCHA并检测风暴"""
        now = time.time()
        cls._captcha_total += 1
        cls._captcha_times.append(now)
        cls._stats["captcha"] = cls._captcha_total
        # 清理过期记录
        cls._captcha_times = [t for t in cls._captcha_times if now - t < cls._CAPTCHA_STORM_WINDOW]
        # 检测风暴: N秒内M次CAPTCHA
        if len(cls._captcha_times) >= cls._CAPTCHA_STORM_THRESHOLD:
            cls._circuit_broken = True
            cls._circuit_break_until = now + cls._CIRCUIT_BREAK_DURATION
            cls._stats["circuit_break"] += 1
            log.warning(f"  ⚡ CAPTCHA风暴! {len(cls._captcha_times)}次/{cls._CAPTCHA_STORM_WINDOW}s → 熔断{cls._CIRCUIT_BREAK_DURATION}s (Playwright暂停)")
            # 重启浏览器 (清理被标记的session)
            try: cls._force_restart()
            except: pass
            return True
        # 检测总量上限
        if cls._captcha_total >= cls._CAPTCHA_MAX_TOTAL:
            cls._circuit_broken = True
            cls._circuit_break_until = now + 999999  # 永久熔断
            log.warning(f"  🔴 CAPTCHA累计{cls._captcha_total}次 → 永久熔断Playwright (本次运行)")
            return True
        return False

    @classmethod
    def _is_circuit_broken(cls):
        """v20.0: 检查熔断器状态"""
        if not cls._circuit_broken:
            return False
        now = time.time()
        if now >= cls._circuit_break_until:
            cls._circuit_broken = False
            cls._captcha_times = []  # 重置风暴计数
            log.info("  ✅ CAPTCHA熔断器已恢复 — 尝试恢复Playwright")
            return False
        return True

    @classmethod
    def fetch(cls, url, need_js=False, retries=2, allow_pw=True):
        """v20.0-H: 智能多层抓取 + CAPTCHA熔断器 + allow_pw控制
        allow_pw=False: 禁止Playwright (采集阶段用, 保留配额给验证阶段)
        allow_pw=True:  允许Playwright (验证阶段用, 默认)
        """
        for attempt in range(retries):
            # ★★★ Playwright控制: allow_pw=False时完全跳过 ★★★
            pw_available = HAS_PW and allow_pw and not cls._is_circuit_broken()

            # Layer 1: Playwright (仅验证阶段+未熔断)
            if (need_js or attempt >= 1) and pw_available:
                html = cls._pw_fetch(url)
                if html and not cls._detect_captcha(html):
                    cls._stats["pw"] += 1; return html
                elif html and cls._detect_captcha(html):
                    storm = cls._record_captcha()
                    if storm:
                        # 风暴触发 — 立即跳到非Playwright层
                        pass
                    else:
                        log.debug(f"  🤖 CAPTCHA [{url[:40]}] (累计{cls._captcha_total}次)")

            # Layer 2: curl_cffi (不受熔断影响)
            if HAS_CF:
                html = cls._cf_fetch(url)
                if html and not cls._detect_captcha(html):
                    cls._stats["cf"] += 1; return html

            # Layer 3: ScraperAPI (不受熔断影响)
            if Config.SCRAPER_KEY:
                html = cls._api_fetch(url)
                if html and not cls._detect_captcha(html):
                    cls._stats["api"] += 1; return html

            # Layer 4: Surge 代理 (轮换出口IP, 不受熔断影响)
            html = cls._surge_fetch(url)
            if html and not cls._detect_captcha(html):
                cls._stats["surge"] = cls._stats.get("surge", 0) + 1; return html

            # Layer 5: requests 直连 (不受熔断影响)
            html = cls._req_fetch(url)
            if html and not cls._detect_captcha(html):
                cls._stats["req"] += 1; return html

            # 快速退避 (熔断期间不等太久)
            if attempt < retries - 1:
                wait = 1.5 if cls._circuit_broken else 2 ** (attempt + 1) + random.uniform(1, 3)
                time.sleep(wait)

        cls._stats["fail"] += 1
        return None

    @classmethod
    def _force_restart(cls):
        """v16.0: 强制重启浏览器 (崩溃/不健康时)"""
        try:
            cls._save_cookies_from_context()
            if cls._ctx: cls._ctx.close()
        except: pass
        try:
            if cls._pw: cls._pw.stop()
        except: pass
        cls._ctx = None; cls._pw = None; cls._healthy = True
        log.info("  🔄 浏览器已强制重启")

    @classmethod
    def _ensure_browser(cls):
        """v16.0: 初始化 Playwright — --headless=new + CDP Stealth + 持久化 + 健康检查"""
        if cls._ctx is not None and cls._healthy:
            # 定期重启防内存泄漏
            if cls._page_count >= cls._MAX_PAGES:
                log.info(f"  🔄 已处理 {cls._page_count} 页, 重启浏览器防内存泄漏")
                cls._force_restart()
            else:
                return
        with cls._get_lock():
            if cls._ctx is not None and cls._healthy:
                return
            if cls._ctx is not None:
                cls._force_restart()
            os.makedirs(cls._PROFILE_DIR, exist_ok=True)
            cls._pw = sync_playwright().start()
            # 随机化浏览器指纹
            ua = random.choice(Config.UAS)
            width = random.choice([1366, 1440, 1536, 1920])
            height = random.choice([768, 900, 864, 1080])
            cls._ctx = cls._pw.chromium.launch_persistent_context(
                user_data_dir=cls._PROFILE_DIR,
                headless=False,  # ★★★ 不用 headless=True (会被反爬检测!)
                args=[
                    '--headless=new',                    # ★★★ Chrome 新无头模式 (核心修复! 完全不可被检测)
                    '--disable-blink-features=AutomationControlled',
                    '--disable-features=IsolateOrigins,site-per-process',
                    '--disable-dev-shm-usage',
                    '--disable-infobars',
                    '--disable-background-timer-throttling',
                    '--disable-backgrounding-occluded-windows',
                    '--disable-renderer-backgrounding',
                    '--disable-field-trial-config',
                    '--disable-back-forward-cache',
                    '--disable-component-update',
                    '--no-first-run',
                    '--no-default-browser-check',
                    '--no-service-autorun',
                    '--password-store=basic',
                    '--window-size={},{}'.format(width, height),
                    '--lang=en-US,en',
                    '--accept-lang=en-US,en;q=0.9',
                    '--disable-ipc-flooding-protection',
                    '--enable-features=NetworkService,NetworkServiceInProcess',
                    '--force-color-profile=srgb',
                    '--metrics-recording-only',
                    '--use-mock-keychain',
                    '--export-tagged-pdf',
                ],
                user_agent=ua,
                viewport={'width': width, 'height': height},
                screen={'width': width, 'height': height},  # ★ 屏幕尺寸必须匹配viewport (否则被检测)
                locale='en-US',
                timezone_id='America/New_York',
                geolocation={'latitude': 40.7128, 'longitude': -74.0060},
                permissions=['geolocation'],
                color_scheme='light',
                java_script_enabled=True,
                ignore_https_errors=True,
                bypass_csp=True,
                extra_http_headers={                      # ★ 预设安全请求头 (避免缺失被检测)
                    'Accept-Language': 'en-US,en;q=0.9',
                    'sec-ch-ua': '"Chromium";v="124", "Google Chrome";v="124", "Not-A.Brand";v="99"',
                    'sec-ch-ua-mobile': '?0',
                    'sec-ch-ua-platform': '"Windows"',
                },
            )
            cls._page_count = 0; cls._healthy = True
            log.info(f"  🚀 v16.0 新无头模式已启动 ({width}x{height}) --headless=new")
            log.info(f"  📁 浏览器数据目录: {cls._PROFILE_DIR}")
            log.info(f"  ✅ headless=new: 使用真实Chrome渲染引擎, 不可被 webdriver/chrome对象 检测")

    # ★★★ v20.0-I: Playwright禁止访问的域名 (100%触发CAPTCHA) ★★★
    _PW_BLOCKED_DOMAINS = ['amazon.com', 'amazon.co', 'amzn.to', 'amzn.com']

    @classmethod
    def _pw_fetch(cls, url):
        """v20.0-I: Playwright抓取 — 禁止Amazon域名 + 快速CAPTCHA检测"""
        if cls._is_circuit_broken():
            return None
        # ★★★ 核心修复: Amazon域名100%触发CAPTCHA, 永远不用Playwright访问 ★★★
        url_lower = url.lower()
        for blocked in cls._PW_BLOCKED_DOMAINS:
            if blocked in url_lower:
                return None  # 直接返回None, 让上层用requests/curl-cffi
        try:
            cls._ensure_browser()
            page = cls._ctx.new_page()
            if HAS_STEALTH:
                stealth_sync(page)
            page.add_init_script(_STEALTH_JS)
            # 拦截不必要资源 (加速)
            def _block_resources(route):
                rt = route.request.resource_type
                if rt in ('image', 'media', 'font', 'stylesheet'):
                    route.abort()
                else:
                    route.continue_()
            page.route('**/*', _block_resources)
            # 导航
            try:
                page.goto(url, wait_until='domcontentloaded', timeout=30000)
            except Exception:
                try: page.goto(url, wait_until='commit', timeout=20000)
                except: pass
            # 人类行为模拟 (简化版 — 验证阶段速度优先)
            try:
                page.wait_for_timeout(random.randint(1000, 2500))
                page.mouse.wheel(0, random.randint(100, 300))
                page.wait_for_timeout(random.randint(300, 800))
            except: pass
            # CAPTCHA 检测 — v20.0: 快速检测, 不长等
            content = page.content()
            if cls._detect_captcha(content):
                # ★ 只等3秒, 不等8秒 (CAPTCHA基本不会自动解决)
                page.wait_for_timeout(cls._CAPTCHA_WAIT_SHORT * 1000)
                content = page.content()
                if cls._detect_captcha(content):
                    # 仍然是CAPTCHA → 快速放弃, 交给上层处理
                    page.close()
                    return content  # 返回CAPTCHA页面, 让fetch()的_detect_captcha判定
            # 保存 Cookie
            cls._save_cookies_from_context()
            cls._page_count += 1
            page.close()
            return content if len(content) > 1000 else None
        except Exception as e:
            log.debug(f"  PW fetch: {e}")
            try: page.close()
            except: pass
            return None

    @classmethod
    def _human_behavior(cls, page):
        """v15.0: 人类行为模拟 — 随机鼠标移动 + 平滑滚动 + 随机停顿"""
        try:
            page.wait_for_timeout(random.randint(1500, 3000))
            # 随机鼠标移动 (2-4次)
            for _ in range(random.randint(2, 4)):
                x = random.randint(100, 800)
                y = random.randint(100, 600)
                page.mouse.move(x, y, steps=random.randint(5, 15))
                page.wait_for_timeout(random.randint(100, 400))
            # 平滑滚动 (分段)
            scroll_total = random.randint(300, 800)
            scroll_steps = random.randint(3, 6)
            for i in range(scroll_steps):
                delta = scroll_total // scroll_steps
                page.mouse.wheel(0, delta)
                page.wait_for_timeout(random.randint(200, 600))
            # 随机停顿
            page.wait_for_timeout(random.randint(500, 1500))
            # 偶尔往回滚一点
            if random.random() < 0.3:
                page.mouse.wheel(0, -random.randint(50, 150))
                page.wait_for_timeout(random.randint(200, 500))
        except: pass

    @classmethod
    def _cdp_fetch(cls, url):
        """v16.0: CDP 连接外部浏览器 — 用户手动启动 Chrome --remote-debugging-port=9222"""
        if not HAS_PW: return None
        try:
            if cls._cdp_browser is None:
                pw = cls._pw or sync_playwright().start()
                cls._cdp_browser = pw.chromium.connect_over_cdp("http://127.0.0.1:9222")
            ctx = cls._cdp_browser.contexts[0] if cls._cdp_browser.contexts else cls._cdp_browser.new_context()
            page = ctx.new_page()
            page.goto(url, wait_until='domcontentloaded', timeout=30000)
            page.wait_for_timeout(2000)
            content = page.content()
            page.close()
            return content if len(content) > 1000 else None
        except:
            cls._cdp_browser = None
            return None

    @classmethod
    def _cf_fetch(cls, url):
        """v16.0: curl_cffi — Chrome TLS 指纹 + 完整安全请求头"""
        try:
            versions = ["chrome110", "chrome116", "chrome119", "chrome120", "chrome124", "chrome"]
            imp = random.choice(versions)
            h = Config.headers()
            h.update({
                "Sec-Ch-Ua": '"Chromium";v="124", "Google Chrome";v="124", "Not-A.Brand";v="99"',
                "Sec-Ch-Ua-Mobile": "?0",
                "Sec-Ch-Ua-Platform": '"Windows"',
                "Sec-Fetch-Dest": "document",
                "Sec-Fetch-Mode": "navigate",
                "Sec-Fetch-Site": "none",
                "Sec-Fetch-User": "?1",
                "Upgrade-Insecure-Requests": "1",
                "DNT": "1",
            })
            r = cf_req.get(url, impersonate=imp, headers=h, timeout=Config.TIMEOUT, allow_redirects=True)
            return r.text if r.status_code == 200 and len(r.text) > 500 else None
        except: return None

    @classmethod
    def _api_fetch(cls, url):
        try:
            r = requests.get("http://api.scraperapi.com",
                params={"api_key": Config.SCRAPER_KEY, "url": url,
                        "render": "true", "country_code": "us"}, timeout=60)
            return r.text if r.status_code == 200 and len(r.text) > 500 else None
        except: return None

    # ★★★ v55.2: Surge 代理支持 ★★★
    SURGE_PROXY = {"http": "http://127.0.0.1:6152", "https": "http://127.0.0.1:6152"}
    _surge_available = None  # None=未检测, True/False

    @classmethod
    def _check_surge(cls):
        """检测 Surge 代理是否可用"""
        if cls._surge_available is not None:
            return cls._surge_available
        try:
            import urllib.request
            proxy = urllib.request.ProxyHandler(cls.SURGE_PROXY)
            opener = urllib.request.build_opener(proxy)
            resp = opener.open(urllib.request.Request("https://httpbin.org/ip", headers={"User-Agent": "Mozilla/5.0"}), timeout=5)
            cls._surge_available = resp.status == 200
        except:
            cls._surge_available = False
        log.info(f"  🌐 Surge 代理: {'✅ 可用' if cls._surge_available else '❌ 不可用'}")
        return cls._surge_available

    @classmethod
    def _surge_fetch(cls, url):
        """Layer 4.5: Surge 代理抓取 — 轮换出口 IP"""
        if not cls._check_surge():
            return None
        try:
            r = cls._get_session().get(url, timeout=Config.TIMEOUT, proxies=cls.SURGE_PROXY)
            return r.text if r.status_code == 200 and len(r.text) > 500 else None
        except: return None

    @classmethod
    def _req_fetch(cls, url):
        try:
            r = cls._get_session().get(url, timeout=Config.TIMEOUT)
            return r.text if r.status_code == 200 and len(r.text) > 500 else None
        except: return None

    @classmethod
    def warmup(cls, target="amazon"):
        """v15.0: 浏览器预热 — 先访问首页建立合法 session + Cookie"""
        if not HAS_PW: return
        warmup_urls = {
            "amazon": ["https://www.amazon.com", "https://www.amazon.com/gp/bestsellers/"],
            "google": ["https://www.google.com", "https://www.google.com/search?q=best+products"],
            "facebook": ["https://www.facebook.com"],
        }
        urls = warmup_urls.get(target, warmup_urls["amazon"])
        log.info(f"  🔥 浏览器预热 [{target}]...")
        for wurl in urls:
            try:
                html = cls._pw_fetch(wurl)
                if html and not cls._detect_captcha(html):
                    log.info(f"  ✅ 预热成功: {wurl[:50]}")
                else:
                    log.warning(f"  ⚠️ 预热遇到 CAPTCHA: {wurl[:50]}")
                time.sleep(random.uniform(2, 4))
            except: pass
        cls._save_cookies_from_context()
        log.info(f"  🍪 预热完成, Cookie 已保存")

    @classmethod
    def cleanup(cls):
        """v16.0: 清理所有资源 — 保存Cookie + 关闭浏览器 + 输出统计"""
        try:
            cls._save_cookies_from_context()
            if cls._session: cls._session.close()
            if cls._cdp_browser:
                try: cls._cdp_browser.close()
                except: pass
            if cls._ctx: cls._ctx.close()
            if cls._pw: cls._pw.stop()
            log.info(f"  🧹 SmartFetcher v16.0 已清理 | 统计: {cls._stats}")
        except: pass
        cls._ctx = None; cls._browser = None; cls._pw = None
        cls._session = None; cls._cdp_browser = None
        cls._healthy = True; cls._page_count = 0


# ================================================================
#  缓存
# ================================================================
class Cache:
    @staticmethod
    def _path(key): return Path(Config.CACHE_DIR)/f"{hashlib.md5(key.encode()).hexdigest()}.json"
    @staticmethod
    def get(key):
        p = Cache._path(key)
        if p.exists():
            try:
                data = json.loads(p.read_text(encoding='utf-8'))
                age_h = (datetime.now()-datetime.fromisoformat(data.get("_t","2000-01-01"))).total_seconds()/3600
                if age_h < Config.CACHE_TTL: return data
            except: pass
        return None
    @staticmethod
    def put(key, val):
        val["_t"] = datetime.now().isoformat()
        Cache._path(key).write_text(json.dumps(val, ensure_ascii=False), encoding='utf-8')


# ================================================================
#  v20.0 并发工具 (Playwright安全模式)
# ================================================================
def _pmap_inplace(fn, items, max_workers=None, desc=""):
    """
    v20.0: 并发处理列表 — Playwright安全模式
    ★ 关键修复: Playwright sync API 用 greenlet 实现, 不能多线程调用
    当 Playwright 激活时, 强制 max_workers=1 (顺序执行)
    """
    if not items: return items
    # ★★★ Playwright安全: 只要Playwright已安装就强制顺序 ★★★
    # 因为fetch()会在第一次调用时初始化_ctx, 之后多线程都会用它
    if HAS_PW:
        log.info(f"  🔒 顺序模式 {desc}: {len(items)} 项 (Playwright已安装, 禁止多线程)")
        for item in items:
            try: fn(item)
            except Exception as e: log.debug(f"  ⚠️ {desc} 异常: {e}")
        return items
    w = max_workers or Config.MAX_WORKERS
    log.info(f"  ⚡ 并发 {desc}: {len(items)} 项, {w} 线程")
    with ThreadPoolExecutor(max_workers=w) as ex:
        futs = {ex.submit(fn, item): i for i, item in enumerate(items)}
        for fut in as_completed(futs):
            try: fut.result()
            except Exception as e: log.debug(f"  ⚠️ {desc} 异常: {e}")
    return items

def _pmap_collect(fn, items, max_workers=None, desc=""):
    """
    v20.0: 并发采集 — Playwright安全模式
    ★ Playwright激活时强制顺序执行, 避免greenlet线程冲突
    """
    if not items: return []
    # ★★★ Playwright安全 ★★★
    if HAS_PW:
        log.info(f"  🔒 顺序模式 {desc}: {len(items)} 项 (Playwright已安装)")
        results = []
        for item in items:
            try:
                r = fn(item)
                if isinstance(r, list): results.extend(r)
                elif r is not None: results.append(r)
            except Exception as e: log.debug(f"  ⚠️ {desc} 异常: {e}")
        return results
    w = max_workers or Config.FETCH_WORKERS
    log.info(f"  ⚡ 并发 {desc}: {len(items)} 项, {w} 线程")
    results = []
    with ThreadPoolExecutor(max_workers=w) as ex:
        futs = {ex.submit(fn, item): item for item in items}
        for fut in as_completed(futs):
            try:
                r = fut.result()
                if isinstance(r, list): results.extend(r)
                elif r is not None: results.append(r)
            except Exception as e: log.debug(f"  ⚠️ {desc} 异常: {e}")
    return results


# ================================================================
#  v14.0 智能抓取引擎 (反反爬增强) + Guard防封控
# ================================================================
@api_guard("google_trends", cooldown=3, use_cache=True)
def _smart_google_fetch(url, retries=2):
    """v20.0-I: Google专用抓取 — Playwright仅用于trends.google.com + Guard防封控"""
    for attempt in range(retries):
        if SmartFetcher._is_circuit_broken():
            return None
        if Config.SCRAPER_KEY:
            try:
                r = requests.get("http://api.scraperapi.com",
                    params={"api_key":Config.SCRAPER_KEY,"url":url,"country_code":"us","render":"true"},timeout=60)
                if r.status_code==200 and len(r.text)>300: return r.text
            except: pass
        if HAS_CF:
            try:
                h=Config.headers(); h["Referer"]="https://www.google.com/"
                r=cf_req.get(url,impersonate="chrome",headers=h,timeout=20)
                if r.status_code==200 and len(r.text)>300: return r.text
            except: pass
        # ★★★ Playwright: 仅用于trends.google.com (需要JS渲染) ★★★
        # 普通Google搜索不用PW (也会触发CAPTCHA)
        if HAS_PW and not SmartFetcher._is_circuit_broken() and 'trends.google.com' in url:
            try:
                html=SmartFetcher._pw_fetch(url)
                if html and len(html)>300:
                    if SmartFetcher._detect_captcha(html):
                        SmartFetcher._record_captcha()
                    else:
                        return html
            except: pass
        try:
            time.sleep(random.uniform(1.0, 2.0))
            h=Config.headers(); h["Referer"]="https://www.google.com/"
            r=requests.get(url,headers=h,timeout=20)
            if r.status_code==200 and len(r.text)>300: return r.text
        except: pass
        if attempt<retries-1: time.sleep(random.uniform(1, 2))
    return None

@api_guard("amazon_scraper", cooldown=4, use_cache=True)
def _smart_amz_fetch(url, retries=2):
    """v20.1: Amazon专用抓取 — 完全禁止Playwright + 饕餮注入分层重试 + Guard防封控"""
    last_err = None
    for attempt in range(retries):
        if Config.SCRAPER_KEY:
            try:
                r = requests.get("http://api.scraperapi.com",
                    params={"api_key":Config.SCRAPER_KEY,"url":url,"country_code":"us"},timeout=60)
                if r.status_code==200 and len(r.text)>500: return r.text
                elif r.status_code in (429, 403):
                    logging.warning(f"ScraperAPI rate limit: {r.status_code}")
                    time.sleep(5 * (attempt + 1))
                    continue
            except requests.exceptions.Timeout:
                last_err = "scraperapi_timeout"
                logging.warning(f"ScraperAPI timeout (attempt {attempt+1})")
            except requests.exceptions.ConnectionError as e:
                last_err = f"scraperapi_conn: {e}"
                logging.warning(f"ScraperAPI connection error: {e}")
            except Exception as e:
                last_err = f"scraperapi_unknown: {e}"
                logging.warning(f"ScraperAPI unexpected error: {e}")
        # ★★★ 不用Playwright — Amazon 100%触发CAPTCHA ★★★
        if HAS_CF:
            try:
                r=cf_req.get(url,impersonate="chrome",headers=Config.headers(),timeout=20)
                if r.status_code==200 and len(r.text)>500: return r.text
                elif r.status_code in (429, 403):
                    logging.warning(f"curl_cffi rate limit: {r.status_code}")
                    time.sleep(3 * (attempt + 1))
            except Exception as e:
                last_err = f"curl_cffi: {e}"
                logging.debug(f"curl_cffi error: {e}")
        try:
            time.sleep(random.uniform(0.8, 1.5))
            r=requests.get(url,headers=Config.headers(),timeout=20)
            if r.status_code==200 and len(r.text)>500: return r.text
            elif r.status_code in (429, 403, 503):
                logging.warning(f"Direct request blocked: {r.status_code}")
                time.sleep(5 * (attempt + 1))
        except requests.exceptions.Timeout:
            last_err = "direct_timeout"
        except requests.exceptions.ConnectionError as e:
            last_err = f"direct_conn: {e}"
        except Exception as e:
            last_err = f"direct_unknown: {e}"
        if attempt<retries-1: time.sleep(random.uniform(1, 2))
    if last_err:
        logging.debug(f"_smart_amz_fetch failed after {retries} attempts: {last_err}")
    return None


def _ddg_search(query, max_results=20):
    """v14.0: DuckDuckGo+Bing 备用搜索 — Google被封时的可靠替代 (无需API KEY)"""
    # DuckDuckGo HTML版 (反爬最宽松)
    try:
        encoded = urllib.parse.quote_plus(query)
        url = "https://html.duckduckgo.com/html/?q=" + encoded
        h = Config.headers(); h["Referer"] = "https://duckduckgo.com/"
        r = requests.get(url, headers=h, timeout=15)
        if r.status_code == 200 and len(r.text) > 500: return r.text
    except: pass
    # Bing 备用
    try:
        url = "https://www.bing.com/search?q=" + urllib.parse.quote_plus(query) + "&count=" + str(max_results)
        r = requests.get(url, headers=Config.headers(), timeout=15)
        if r.status_code == 200 and len(r.text) > 500: return r.text
    except: pass
    return None


def _dedupe_related_queries(keyword, candidates, limit=5):
    seed = re.sub(r'\s+', ' ', str(keyword or '').strip())
    seed_lower = seed.lower()
    seen = {seed_lower} if seed_lower else set()
    out = []
    for raw in candidates or []:
        text = re.sub(r'\s+', ' ', str(raw or '').replace('\u00a0', ' ').strip(' |,-'))
        if not text:
            continue
        low = text.lower()
        if low in seen:
            continue
        seen.add(low)
        out.append(text)
        if len(out) >= limit:
            break
    return out


def _fetch_google_related_queries(keyword, geo="US", limit=5):
    query = str(keyword or '').strip()
    if not query:
        return []
    headers = Config.headers()
    headers["Referer"] = "https://www.google.com/"
    gl = str(geo or 'US').lower()
    encoded = urllib.parse.quote_plus(query)
    urls = [
        f"https://suggestqueries.google.com/complete/search?client=firefox&hl=en&gl={gl}&q={encoded}",
        f"https://suggestqueries.google.com/complete/search?client=chrome&hl=en&gl={gl}&q={encoded}",
    ]
    for url in urls:
        try:
            r = requests.get(url, headers=headers, timeout=10)
            if r.status_code != 200 or not r.text:
                continue
            payload = r.json() if r.text.lstrip().startswith('[') else json.loads(r.text)
            if isinstance(payload, list) and len(payload) > 1:
                related = _dedupe_related_queries(query, payload[1], limit)
                if related:
                    return related
        except: pass
    return []


def _ddg_shopping(query):
    """v14.0: DuckDuckGo Shopping 搜索 — Google Shopping 被封时的替代"""
    try:
        url = "https://html.duckduckgo.com/html/?q=" + urllib.parse.quote_plus(query + " buy price USD")
        h = Config.headers(); h["Referer"] = "https://duckduckgo.com/"
        r = requests.get(url, headers=h, timeout=15)
        if r.status_code == 200 and len(r.text) > 500: return r.text
    except: pass
    # Bing Shopping
    try:
        url = "https://www.bing.com/shop?q=" + urllib.parse.quote_plus(query)
        r = requests.get(url, headers=Config.headers(), timeout=15)
        if r.status_code == 200 and len(r.text) > 500: return r.text
    except: pass
    return None


def _estimate_from_name(name, price):
    """v14.0: 基于产品名+价格的启发式验证 — 当所有爬虫失败时的智能兜底"""
    text = name.lower()
    # 美国市场: 英文产品名+合理价格 = 大概率有需求
    has_en = bool(re.search(r'[a-zA-Z]{3,}', name))
    us_ok = has_en and price > 5
    # Google Shopping: 有明确品类词的产品通常有卖家
    shop_kw = ['toy','plush','stuffed','outdoor','camping','hiking','bike','fishing',
        'sport','chair','light','bag','boot','glove','helmet','tent','pad','mat',
        'bottle','tool','kit','set','case','holder','mount','rod','reel','kayak',
        'backpack','sleeping','stove','lantern','jacket','socks','goggles']
    has_shop = any(w in text for w in shop_kw)
    est_sellers = random.randint(3, 12) if has_shop else random.randint(1, 5) if has_en else 0
    # Shopify: 常见DTC品类有独立站卖家
    shopify_kw = ['cute','kawaii','gift','unique','custom','personalized','viral',
        'trending','premium','luxury','portable','compact','lightweight','waterproof',
        'heated','weighted','sensory','reversible','giant','rechargeable','solar',
        'tactical','survival','inflatable','foldable','ergonomic']
    has_shopify = any(w in text for w in shopify_kw) or has_shop
    est_shopify = random.randint(2, 8) if has_shopify else random.randint(0, 3) if has_en else 0
    return {"us_ok": us_ok, "est_sellers": est_sellers, "has_shop": has_shop,
            "est_shopify": est_shopify, "has_shopify": has_shopify}


def _empty_trends_result(keyword=""):
    return {
        "keyword": str(keyword or "").strip(),
        "interest": 0,
        "direction": "",
        "related": [],
        "source": "",
        "quality": "missing",
        "sufficient": False,
    }



def _clean_trend_related(values, limit=5):
    out = []
    seen = set()
    for raw in (values or []):
        text = str(raw or '').strip()
        if not text:
            continue
        key = text.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(text)
        if len(out) >= limit:
            break
    return out



def _finalize_trends_result(keyword, result):
    base = _empty_trends_result(keyword)
    if isinstance(result, dict):
        base.update(result)
    base["keyword"] = str(base.get("keyword") or keyword or "").strip()
    try:
        interest = int(float(base.get("interest", 0) or 0))
    except Exception:
        interest = 0
    base["interest"] = max(0, min(100, interest))
    direction = str(base.get("direction", "") or "").strip()
    base["direction"] = direction if direction in {"↑↑", "↑", "→", "↓", "↓↓"} else ""
    base["related"] = _clean_trend_related(base.get("related"), limit=5)
    source = str(base.get("source", "") or "").strip()
    strong_sources = {"pytrends", "google_trends_page", "google_trends_widgets"}
    medium_sources = {"search_signal", "google_search_signal", "daily_trends", "realtime_trends", "related_topics"}
    if source in strong_sources:
        if base["interest"] >= 12 and (base["direction"] or len(base["related"]) >= 2):
            quality = "strong"
            sufficient = True
        elif base["interest"] > 0 or base["direction"]:
            quality = "medium"
            sufficient = True
        else:
            quality = "weak"
            sufficient = False
    elif source in medium_sources:
        if base["interest"] >= 45 or (base["direction"] in {"↑↑", "↑"} and len(base["related"]) >= 1):
            quality = "medium"
        elif base["interest"] > 0 or base["direction"]:
            quality = "weak"
        else:
            quality = "missing"
        sufficient = False
    elif source == "heuristic":
        quality = "weak" if (base["interest"] > 0 or base["direction"]) else "missing"
        sufficient = False
    else:
        quality = "missing" if not (base["interest"] or base["direction"] or base["related"]) else str(base.get("quality", "") or "weak")
        sufficient = False
    base["quality"] = quality
    base["sufficient"] = bool(sufficient)
    return base



def scrape_google_trends_robust(keyword, geo="US", force_refresh=False):
    """v22.5: 统一 Google Trends 信号 — 返回热度/方向/相关词/来源/证据强度"""
    keyword = str(keyword or '').strip()
    if not keyword:
        return _empty_trends_result("")
    ck = f"trends_v3_{keyword[:25]}"
    cached = _finalize_trends_result(keyword, Cache.get(ck))
    if not force_refresh and (cached.get("source") or cached.get("interest") > 0 or cached.get("direction") or cached.get("related")):
        return cached

    result = _empty_trends_result(keyword)

    # Method 1: pytrends (最优先, 可直接拿到真实时间序列)
    if HAS_TRENDS:
        try:
            # 使用Surge代理绕过IP限流
            proxies = {
                'https': 'http://127.0.0.1:6152',
                'http': 'http://127.0.0.1:6152'
            }
            pt = TrendReq(hl='en-US', tz=360, proxies=proxies, retries=2, backoff_factor=0.5)
            pt.build_payload([keyword], cat=0, timeframe='today 3-m', geo=geo)
            df = pt.interest_over_time()
            if df is not None and not df.empty and keyword in df.columns:
                vals = df[keyword].tolist()
                result["interest"] = int(vals[-1]) if vals else 0
                if len(vals) >= 4:
                    recent = sum(vals[-4:]) / 4
                    older = sum(vals[:4]) / 4
                    if older > 0:
                        ratio = recent / older
                        if ratio >= 1.3:
                            result["direction"] = "↑↑"
                        elif ratio >= 1.1:
                            result["direction"] = "↑"
                        elif ratio >= 0.9:
                            result["direction"] = "→"
                        elif ratio >= 0.7:
                            result["direction"] = "↓"
                        else:
                            result["direction"] = "↓↓"
                try:
                    related = pt.related_queries().get(keyword, {}).get('top', pd.DataFrame())
                    if related is not None and not related.empty:
                        result["related"] = _dedupe_related_queries(keyword, related['query'].tolist(), limit=5)
                except Exception:
                    pass
            if result["interest"] > 0 or result["direction"]:
                result["source"] = "pytrends"
                if not result.get("related"):
                    result["related"] = _fetch_google_related_queries(keyword, geo=geo, limit=5)
                final = _finalize_trends_result(keyword, result)
                Cache.put(ck, final)
                time.sleep(random.uniform(1.0, 2.5))  # 防止连续请求被封
                return final
        except Exception as e:
            log.debug(f"  ⚠️ pytrends失败 [{keyword[:20]}]: {e}")
            pass

    # Method 2: Google Trends 页面抓取
    encoded = urllib.parse.quote_plus(keyword)
    try:
        url = "https://trends.google.com/trends/explore?q=" + encoded + "&geo=" + geo + "&date=today%203-m"
        html = _smart_google_fetch(url)
        if html and len(html) > 1000:
            for pattern in [r'"value"\s*:\s*(\d+)', r'interest.*?(\d+)']:
                vals = [int(m) for m in re.findall(pattern, html) if 0 < int(m) <= 100]
                if vals:
                    result["interest"] = vals[-1]
                    if len(vals) >= 4:
                        recent = sum(vals[-4:]) / 4
                        older = sum(vals[:4]) / 4
                        if older > 0:
                            ratio = recent / older
                            if ratio >= 1.3:
                                result["direction"] = "↑↑"
                            elif ratio >= 1.1:
                                result["direction"] = "↑"
                            elif ratio >= 0.9:
                                result["direction"] = "→"
                            elif ratio >= 0.7:
                                result["direction"] = "↓"
                            else:
                                result["direction"] = "↓↓"
                    break
            if result["interest"] > 0 or result["direction"]:
                result["source"] = "google_trends_page"
                if not result.get("related"):
                    result["related"] = _fetch_google_related_queries(keyword, geo=geo, limit=5)
                final = _finalize_trends_result(keyword, result)
                Cache.put(ck, final)
                return final
    except Exception:
        pass

    # Method 3: 搜索趋势信号降级
    try:
        ddg_html = _ddg_search(f"{keyword} trend 2024 2025 growing popular")
        if ddg_html:
            text = BeautifulSoup(ddg_html, 'html.parser').get_text().lower()
            up_signals = ['growing', 'trending', 'popular', 'surge', 'boom', 'rising', 'viral', 'hot']
            down_signals = ['declining', 'dying', 'falling', 'dead', 'decreasing']
            up_count = sum(1 for s in up_signals if s in text)
            down_count = sum(1 for s in down_signals if s in text)
            result["source"] = "search_signal"
            if up_count >= 3:
                result["direction"] = "↑↑"
                result["interest"] = 75
            elif up_count >= 2:
                result["direction"] = "↑"
                result["interest"] = 60
            elif down_count >= 2:
                result["direction"] = "↓"
                result["interest"] = 25
            elif up_count >= 1:
                result["direction"] = "→"
                result["interest"] = 50
            else:
                result["direction"] = "→"
                result["interest"] = 40
    except Exception:
        pass

    # Method 4: 启发式 — 仅作最后兜底, 不算充分证据
    if result["interest"] == 0:
        text = keyword.lower()
        result["source"] = "heuristic"
        hot_kw = ['plush', 'kawaii', 'viral', 'trending', 'heated', 'weighted', 'sensory',
            'camping', 'hiking', 'survival', 'portable', 'rechargeable', 'solar', 'inflatable']
        if any(h in text for h in hot_kw):
            result["interest"] = random.randint(45, 70)
            result["direction"] = "↑"
        else:
            result["interest"] = random.randint(25, 50)
            result["direction"] = "→"

    final = _finalize_trends_result(keyword, result)
    if final.get("interest") > 0 or final.get("direction") or final.get("source"):
        Cache.put(ck, final)
    return final



def apply_google_trends_result(p, keyword="", geo="US", force_refresh=False):
    if not isinstance(p, dict):
        return _empty_trends_result(keyword)
    kw = str(keyword or _product_query_keyword(p) or '').strip()
    if not kw:
        p['google_trends_keyword'] = ''
        p['google_trends_interest'] = 0
        p['google_trends_related'] = []
        p['google_trends_source'] = ''
        p['google_trends_quality'] = 'missing'
        p['google_trends_sufficient'] = False
        if not p.get('trend_direction'):
            p['trend_direction'] = ''
        return _empty_trends_result("")
    result = scrape_google_trends_robust(kw, geo=geo, force_refresh=force_refresh) or _empty_trends_result(kw)
    p['google_trends_keyword'] = str(result.get('keyword') or kw).strip()
    p['google_trends_interest'] = int(result.get('interest', 0) or 0)
    p['google_trends_related'] = _clean_trend_related(result.get('related'), limit=5)
    p['google_trends_source'] = str(result.get('source', '') or '').strip()
    p['google_trends_quality'] = str(result.get('quality', '') or 'missing').strip()
    p['google_trends_sufficient'] = bool(result.get('sufficient'))
    p['trend_direction'] = str(result.get('direction', '') or '').strip()
    return result





def gen_verification_links(product_name):
    """v14.0: 生成产品验证链接 — Google Trends / FB Ad Library / Shopify竞品 / Google Shopping"""
    words = re.findall(r'[a-zA-Z0-9]+', product_name)
    kw = " ".join(words[:5]).strip()
    encoded = urllib.parse.quote_plus(kw)
    t_url = "https://trends.google.com/trends/explore?q=" + encoded + "&geo=US"
    fb_url = "https://www.facebook.com/ads/library/?active_status=active&ad_type=all&country=US&q=" + encoded + "&media_type=all"
    sh_url = "https://www.google.com/search?q=site:myshopify.com+" + encoded
    gs_url = "https://www.google.com/search?q=" + encoded + "&tbm=shop&hl=en&gl=us"
    az_url = "https://www.amazon.com/s?k=" + encoded
    return {
        "google_trends": t_url,
        "fb_ad_library": fb_url,
        "shopify_site": sh_url,
        "google_shopping": gs_url,
        "amazon_search": az_url,
        "keywords": kw,
    }

