# ================================================================
#  工具函数
# ================================================================
def extract_num(text):
    m = re.search(r'[\d.]+', str(text).replace(',',''))
    return float(m.group()) if m else 0.0

def parse_orders(text):
    t = str(text).lower().replace(",","").replace("+","")
    return int(extract_num(t.replace("k",""))*1000) if "k" in t else int(extract_num(t))

def dedup_key(name, price):
    return hashlib.md5(f"{name[:30].lower().strip()}_{price}".encode()).hexdigest()

def extract_asin_from_url(url):
    """从 Amazon URL 中提取 ASIN"""
    m = re.search(r'/dp/([A-Z0-9]{10})', url)
    return m.group(1) if m else ""

def build_amazon_url(asin):
    """从 ASIN 构建标准产品 URL (保证有效)"""
    if asin and len(asin) == 10:
        return f"https://www.amazon.com/dp/{asin}"
    return ""


def _product_query_keyword(p):
    """商用版验证查询词: 优先短 verify_keyword, 其次 seed/category, 最后回退产品名"""
    if not isinstance(p, dict):
        return ""
    for key in ("verify_keyword", "seed_keyword", "category", "name"):
        val = str(p.get(key, "") or "").strip()
        if val:
            return val
    return ""


