def estimate_1688_cost(ali_price_usd):
    """v11.0: 基于 Amazon 售价估算 1688 采购成本 (实战经验: Amazon 售价的 15-25%)"""
    cost_1688_usd = round(ali_price_usd * Config.AMZ_TO_1688_PCT, 2)
    cost_1688_rmb = round(cost_1688_usd * Config.RMB_USD, 2)
    return cost_1688_usd, cost_1688_rmb

def estimate_source_costs(amz_price):
    """v11.0: 同时估算 1688 和 AliExpress 成本 → 返回 (1688_usd, 1688_rmb, ae_usd)"""
    if amz_price <= 0: return 0.0, 0.0, 0.0
    c1688 = round(amz_price * Config.AMZ_TO_1688_PCT, 2)
    c1688_rmb = round(c1688 * Config.RMB_USD, 2)
    cae = round(amz_price * Config.AMZ_TO_AE_PCT, 2)
    return c1688, c1688_rmb, cae

def gen_1688_link(product_name):
    """v11.0: 生成 1688 搜索链接 — 智能中英文翻译"""
    name_lower = product_name.lower().strip()
    cn_kw = ""
    # 精确匹配 EN_TO_CN_MAP
    for en, cn in Config.EN_TO_CN_MAP.items():
        if en in name_lower:
            cn_kw = cn; break
    # 提取英文核心词做 fallback
    en_words = re.findall(r'[a-zA-Z]+', product_name)
    en_kw = " ".join(en_words[:4]).strip()
    if not cn_kw:
        # 用英文搜 1688 (1688 也支持英文搜索)
        cn_kw = en_kw
    # v11.1 fix: 1688 搜索用 GBK 编码，不是 UTF-8
    try:
        url_1688 = Config.URL_1688 + urllib.parse.quote(cn_kw.encode('gbk'))
    except UnicodeEncodeError:
        url_1688 = Config.URL_1688 + urllib.parse.quote(cn_kw)
    return url_1688, cn_kw

def gen_aliexpress_link(product_name):
    """v11.0: 生成 AliExpress 搜索链接"""
    words = re.findall(r'[a-zA-Z0-9]+', product_name)
    kw = " ".join(words[:5]).strip()
    url_ae = Config.URL_ALIEXPRESS + urllib.parse.quote_plus(kw)
    return url_ae, kw

def estimate_shopify_profit(amz_price, cost_1688_usd):
    """v11.0: Shopify 真实利润计算 — 采购+国际运费+美国运费+广告+支付网关+退货"""
    if amz_price <= 0 or cost_1688_usd <= 0: return 0.0, 0.0, 0.0, {}
    # Shopify 售价 = 1688成本 × 理想加价倍率, 但不低于 Amazon 价格的 80%
    sell_price = max(
        round(cost_1688_usd * Config.SHOPIFY_MARKUP_IDEAL, 2),
        round(amz_price * 0.80, 2)  # 不低于 Amazon 的 80% (价值锚定)
    )
    # 成本拆解
    cogs = cost_1688_usd                                    # 货物成本
    ship_intl = Config.SHOPIFY_SHIP_INTL                    # 国际运费
    ship_us = Config.SHOPIFY_SHIP_US                        # 美国境内运费
    ad_cost = sell_price * Config.SHOPIFY_AD_COST_PCT       # 广告费
    gateway = sell_price * Config.SHOPIFY_GATEWAY_PCT + Config.SHOPIFY_GATEWAY_FIXED  # 支付网关
    return_loss = sell_price * Config.SHOPIFY_RETURN_RATE * 0.5  # 退货损失
    total_cost = cogs + ship_intl + ship_us + ad_cost + gateway + return_loss
    net_profit = sell_price - total_cost
    roi = (net_profit / total_cost * 100) if total_cost > 0 else 0
    breakdown = {
        "sell_price": round(sell_price, 2),
        "cogs": round(cogs, 2), "ship_intl": round(ship_intl, 2),
        "ship_us": round(ship_us, 2), "ad_cost": round(ad_cost, 2),
        "gateway": round(gateway, 2), "return_loss": round(return_loss, 2),
        "total_cost": round(total_cost, 2),
    }
    return round(sell_price, 2), round(net_profit, 2), round(roi, 1), breakdown

def enrich_source_links(products):
    """v11.0: 为所有产品添加 1688/AliExpress 链接 + Shopify 利润估算"""
    log.info("[v11.0] 生成 1688/AliExpress 货源链接 + Shopify 利润估算...")
    for p in products:
        name = p.get("name","")
        price = p.get("price",0)
        if not name: continue
        # 1688 链接 + 中文关键词
        link_1688, cn_kw = gen_1688_link(name)
        p["link_1688"] = link_1688
        p["cn_keywords"] = cn_kw
        # AliExpress 链接
        link_ae, _ = gen_aliexpress_link(name)
        p["link_aliexpress"] = link_ae
        # 成本估算 (1688 + AE)
        c1688, c1688_rmb, cae = estimate_source_costs(price)
        p["cost_1688_usd"] = c1688
        p["cost_1688_rmb"] = c1688_rmb
        p["cost_ae_usd"] = cae
        p["cost"] = c1688  # 覆盖旧成本
        p["cost_rmb"] = c1688_rmb
        # Shopify 利润
        sell, net, roi, bd = estimate_shopify_profit(price, c1688)
        p["shopify_sell_price"] = sell
        p["shopify_net_profit"] = net
        p["shopify_roi_pct"] = roi
        p["shopify_profit_breakdown"] = bd
        p["est_sell_price"] = sell
        # 更新定价策略
        p["pricing_strategy"] = classify_pricing_strategy(c1688_rmb)
    log.info(f"  ✅ 已为 {len(products)} 个产品生成货源链接 + Shopify 利润")
    return products

# ================================================================
#  v13.0 FB Ad Library 深度验证 + CPM预估 + 盈亏平衡 + 可持续性评分
# ================================================================
def query_fb_ad_library_deep(product_name, category=""):
    """v13.0: FB Ad Library 深度查询 — 广告存活天数 + 竞品数 + 素材类型 + 投放强度"""
    if not product_name: return {}
    words = re.findall(r'[a-zA-Z]+', product_name)
    kw = " ".join(words[:3]).strip()
    if len(kw) < 3: return {}
    ck = f"fbdeep_{kw[:25]}"
    cached = Cache.get(ck)
    if cached: return cached
    result = {"keyword":kw,"total_ads":0,"oldest_days":0,"avg_survival_days":0,
              "creative_types":[],"competitors":0,"ad_spend_signal":"","verdict":""}
    # Step 1: FB Ad Library 页面抓取 (JS渲染优先)
    try:
        encoded = urllib.parse.quote_plus(kw)
        url = (f"https://www.facebook.com/ads/library/?active_status=active"
               f"&ad_type=all&country=US&q={encoded}&media_type=all")
        html = SmartFetcher.fetch(url, need_js=True)
        if html:
            for pattern in [r'_7jyr|_8nhe|ad-card|AdLibraryPageAdCard',
                            r'data-testid="ad_[^"]*"', r'"adArchiveID"']:
                cards = len(re.findall(pattern, html))
                result["total_ads"] = max(result["total_ads"], cards)
            # 解析广告开始日期 → 计算存活天数
            ad_dates = []
            for dp in [r'Started running on\s*(\w+\s+\d+,?\s*\d{4})',
                       r'"startDate"\s*:\s*"?(\d{4}-\d{2}-\d{2})']:
                for m in re.finditer(dp, html):
                    try:
                        ds = m.group(1)
                        for fmt in ['%B %d, %Y','%B %d %Y','%Y-%m-%d']:
                            try: ad_dates.append(datetime.strptime(ds, fmt)); break
                            except: continue
                    except: pass
            if ad_dates:
                now = datetime.now()
                survival = [(now - d).days for d in ad_dates if (now - d).days > 0]
                if survival:
                    result["oldest_days"] = max(survival)
                    result["avg_survival_days"] = int(sum(survival)/len(survival))
            # 素材类型检测
            creative_types = set()
            if re.search(r'video|mp4|play button', html, re.I): creative_types.add("video")
            if re.search(r'carousel|multiple images', html, re.I): creative_types.add("carousel")
            creative_types.add("image")
            result["creative_types"] = list(creative_types)
            # 统计不同广告主 (竞品数)
            advertisers = set()
            for ap in [r'"pageName"\s*:\s*"([^"]+)"']:
                for am in re.finditer(ap, html): advertisers.add(am.group(1).strip().lower())
            result["competitors"] = max(len(advertisers), 1) if result["total_ads"] > 0 else 0
    except Exception as e: log.debug(f"  FB Deep [{kw}]: {e}")
    # Step 2: Google 辅助验证
    if result["total_ads"] == 0:
        try:
            query = urllib.parse.quote_plus(f'site:facebook.com/ads/library "{kw}"')
            gurl = "https://www.google.com/search?q=" + query + "&num=20&hl=en"
            html2 = _smart_google_fetch(gurl)
            if html2:
                soup = BeautifulSoup(html2, 'html.parser')
                ad_links = soup.select('a[href*="facebook.com/ads/library"]')
                result["total_ads"] = len(ad_links)
                result["competitors"] = min(len(ad_links), 10)
        except: pass
    # Step 3: v52 广告格式分布分析
    if result.get("creative_types"):
        fmt_breakdown = {}
        for ct in result["creative_types"]:
            fmt_breakdown[ct] = fmt_breakdown.get(ct, 0) + 1
        result["format_breakdown"] = fmt_breakdown
        if "video" in fmt_breakdown:
            result["video_ratio"] = round(fmt_breakdown["video"] / max(ta, 1) * 100, 1)
            result["creative_insight"] = "🎬 视频主导 — 适合短视频素材" if fmt_breakdown.get("video", 0) > ta * 0.4 else "📸 图片为主"
        else:
            result["video_ratio"] = 0
            result["creative_insight"] = "📸 纯图片 — 视频切入有差异化机会"
    # Step 4: v52 广告花费估算 (基于广告数*存活天数*CPM)
    est_monthly_spend = 0
    if ta > 0 and od > 0:
        # 粗略估算: 每个广告日均$5-20 impression spend
        avg_daily_per_ad = 12 if od >= 30 else 8
        active_ratio = min(1.0, od / 90)  # 长期广告更可能持续活跃
        est_monthly_spend = int(ta * avg_daily_per_ad * 30 * active_ratio)
    result["est_monthly_ad_spend"] = est_monthly_spend
    if est_monthly_spend >= 10000: result["spend_tier"] = "💰💰 重度投放 ($10K+/月)"
    elif est_monthly_spend >= 3000: result["spend_tier"] = "💰 中度投放 ($3K-10K/月)"
    elif est_monthly_spend >= 500: result["spend_tier"] = "💵 轻度投放 ($500-3K/月)"
    elif est_monthly_spend > 0: result["spend_tier"] = "💲 微投放 (<$500/月)"
    else: result["spend_tier"] = "❓ 无数据"
    # Step 5: v52 竞争热度综合评分 (0-100)
    fb_heat = 0
    fb_heat += min(25, ta * 3)         # 广告数贡献
    fb_heat += min(25, od // 3)        # 存活天数贡献
    fb_heat += min(25, comp * 4)       # 竞品数贡献
    fb_heat += min(25, est_monthly_spend // 400)  # 花费贡献
    result["fb_competition_heat"] = min(100, fb_heat)
    if fb_heat >= 75: result["heat_grade"] = "🔴 红海"
    elif fb_heat >= 50: result["heat_grade"] = "🟡 中竞争"
    elif fb_heat >= 25: result["heat_grade"] = "🟢 低竞争"
    else: result["heat_grade"] = "⚪ 空白市场"
    # Step 6: 综合判定 (升级v52)
    ta = result["total_ads"]; od = result["oldest_days"]; comp = result["competitors"]
    if ta == 0: result["verdict"] = "⚠️ 无FB广告 — 需手动验证"
    elif comp <= 2 and od < 14: result["verdict"] = "🆕 新兴 — 低竞争未验证"
    elif 3 <= comp <= 8 and od >= 30: result["verdict"] = "✅ 甜区 — 已验证+低竞争"
    elif 3 <= comp <= 15 and od >= 14: result["verdict"] = "🟢 可进入 — 有利润空间"
    elif comp > 15 and od >= 30: result["verdict"] = "🟡 中竞争 — 需差异化"
    elif comp > 30: result["verdict"] = "🔴 红海 — 不建议"
    else: result["verdict"] = "🟡 待观察"
    if od >= 60 and comp >= 5: result["ad_spend_signal"] = "💰 高投放"
    elif od >= 30: result["ad_spend_signal"] = "💵 中投放"
    elif od >= 14: result["ad_spend_signal"] = "💲 初期验证"
    else: result["ad_spend_signal"] = "❓ 未知"
    Cache.put(ck, result)
    return result

def estimate_cpm(category, price=0):
    """v13.0: FB CPM 预估 — 基于品类+客单价+季节"""
    cat_lower = category.lower() if category else ""
    base_cpm = 20
    for cat_key, cpm_val in Config.FB_CPM_BASE.items():
        if cat_key in cat_lower: base_cpm = cpm_val; break
    if price >= 300: base_cpm *= 1.3
    elif price >= 200: base_cpm *= 1.15
    elif price >= 100: base_cpm *= 1.05
    month = datetime.now().month
    if month in (11, 12): base_cpm *= 1.5   # Q4 黑五/圣诞
    elif month in (1, 2): base_cpm *= 0.85  # Q1 低谷
    elif month in (6, 7): base_cpm *= 0.9
    return round(base_cpm, 2)

def calc_breakeven(sell_price, cost_1688, cpm, cvr=None):
    """v13.0: FB广告盈亏平衡 — 售价/成本/CPM → CPA + ROAS + 日预算"""
    if sell_price <= 0 or cost_1688 <= 0: return {}
    cvr = cvr or Config.FB_CVR_COLD
    cogs = cost_1688
    ship = Config.SHOPIFY_SHIP_INTL + Config.SHOPIFY_SHIP_US
    gateway = sell_price * Config.SHOPIFY_GATEWAY_PCT + Config.SHOPIFY_GATEWAY_FIXED
    returns = sell_price * Config.SHOPIFY_RETURN_RATE * 0.5
    fixed_cost = cogs + ship + gateway + returns
    ctr_est = 0.02  # 预估 CTR 2%
    cpc = cpm / 1000 / max(ctr_est, 0.001)
    cpa_cold = cpc / max(cvr, 0.001)
    roas_cold = sell_price / max(cpa_cold, 0.01)
    profit_cold = sell_price - fixed_cost - cpa_cold
    cpa_retarget = cpc / max(Config.FB_CVR_RETARGET, 0.001)
    profit_retarget = sell_price - fixed_cost - cpa_retarget
    roas_retarget = sell_price / max(cpa_retarget, 0.01)
    daily_min = cpa_cold * 3   # 至少获3单/天
    daily_ideal = cpa_cold * 5  # 理想5单/天
    return {
        "sell_price":round(sell_price,2),"fixed_cost":round(fixed_cost,2),
        "max_ad_spend":round(sell_price-fixed_cost,2),
        "est_cpm":round(cpm,2),"est_cpc":round(cpc,2),
        "est_cpa_cold":round(cpa_cold,2),"est_cpa_retarget":round(cpa_retarget,2),
        "roas_cold":round(roas_cold,2),"roas_retarget":round(roas_retarget,2),
        "profit_cold":round(profit_cold,2),"profit_retarget":round(profit_retarget,2),
        "daily_budget_min":round(daily_min,2),"daily_budget_ideal":round(daily_ideal,2),
        "verdict": "✅ 可投" if profit_cold > 0 and roas_cold >= Config.FB_ROAS_MIN else
                   "🟡 需优化" if roas_cold >= 1.5 else "🔴 不建议投"
    }

def score_sustainability(p):
    """v13.0: 可持续出单评分 — Trends + FB存活 + 评论增速 + 季节 + 竞争"""
    w = Config.SUSTAIN_W; total = 0; detail = {}
    # 1. 趋势斜率 (0-100)
    td = p.get("trend_direction","")
    trend_sc = {"↑↑":100,"↑":80,"→":50,"↓":20,"↓↓":0}.get(td, 40)
    detail["trend"] = trend_sc; total += trend_sc * w["trend_slope"]
    # 2. FB广告存活 (0-100)
    fb_days = p.get("fb_oldest_ad_days",0)
    fb_sc = 100 if fb_days>=90 else 85 if fb_days>=60 else 70 if fb_days>=30 else 50 if fb_days>=14 else 30 if fb_days>0 else 20
    detail["fb_survival"] = fb_sc; total += fb_sc * w["fb_survival"]
    # 3. 评论增速 (0-100)
    rv = p.get("review_velocity",0)
    rv_sc = 100 if rv>=50 else 80 if rv>=20 else 60 if rv>=10 else 40 if rv>=5 else 20
    detail["review_vel"] = rv_sc; total += rv_sc * w["review_velocity"]
    # 4. 季节稳定性 (0-100)
    text = (p.get("name","")+" "+p.get("category","")).lower()
    evergreen = ['daily','everyday','essential','office','sleep','pain','health','beauty','clean','pet']
    if p.get("seasonal_match"):
        season_sc = 90 if any(s in text for s in evergreen) else 60
    else:
        season_sc = 50
    detail["seasonal"] = season_sc; total += season_sc * w["seasonal_stability"]
    # 5. 竞争窗口 (0-100)
    fb_comp = p.get("fb_competitors_count",0); sh_comp = p.get("shopify_competitors",0)
    if fb_comp<=3 and sh_comp<=3: comp_sc=100
    elif fb_comp<=8 and sh_comp<=8: comp_sc=75
    elif fb_comp<=15 and sh_comp<=15: comp_sc=50
    elif fb_comp<=30: comp_sc=25
    else: comp_sc=10
    detail["competition"] = comp_sc; total += comp_sc * w["competition_window"]
    score = int(total)
    if score>=80: grade="🔥 A+ (强烈推荐投放)"
    elif score>=65: grade="✅ A (可投放)"
    elif score>=50: grade="🟢 B (谨慎投放)"
    elif score>=35: grade="🟡 C (需优化后投放)"
    else: grade="🔴 D (不建议投放)"
    return score, grade, detail


def classify_pricing_strategy(cost_rmb):
    if 0 < cost_rmb <= Config.STRATEGY_A["cost_rmb_max"]: return "A"
    if Config.STRATEGY_B["cost_rmb_min"] <= cost_rmb <= Config.STRATEGY_B["cost_rmb_max"]: return "B"
    if Config.STRATEGY_C["cost_rmb_min"] <= cost_rmb <= Config.STRATEGY_C["cost_rmb_max"]: return "C"
    return ""

def estimate_fba_profit(price, cost_rmb, is_large=False):
    """v10.0: 真实 FBA 净利润计算 — 佣金+配送+仓储+PPC+头程+退货"""
    if price <= 0 or cost_rmb <= 0: return 0.0, 0.0, {}
    cost_usd = cost_rmb / Config.RMB_USD
    referral = price * Config.FBA_REFERRAL_PCT
    fba_fee = Config.FBA_FULFILL_LARGE if is_large else Config.FBA_FULFILL_STD
    inbound = Config.FBA_INBOUND + Config.FBA_SHIP_TO_AMZ
    storage = Config.FBA_STORAGE_STD * 0.5  # 假设 0.5 立方英尺
    ppc_per_sale = Config.PPC_CPC_HIGH / max(Config.PPC_CVR_EST, 0.01)
    ret_rate = Config.RETURN_RATE_HIGH if price >= Config.HIGH_TICKET_MIN else Config.RETURN_RATE_LOW
    return_loss = price * ret_rate * 0.5  # 退货损50%货值
    total_cost = cost_usd + referral + fba_fee + inbound + storage + ppc_per_sale + return_loss
    net_profit = price - total_cost
    roi = (net_profit / total_cost * 100) if total_cost > 0 else 0
    breakdown = {
        "cost_usd": round(cost_usd, 2), "referral": round(referral, 2),
        "fba_fee": round(fba_fee, 2), "inbound": round(inbound, 2),
        "storage": round(storage, 2), "ppc": round(ppc_per_sale, 2),
        "return_loss": round(return_loss, 2), "total_cost": round(total_cost, 2),
    }
    return round(net_profit, 2), round(roi, 1), breakdown


