def scrape_amazon_movers(niche):
    log.info("📦 [采集] Amazon Movers & Shakers (v12.0 并发)...")
    def _f(path):
        try: r=_scrape_amz_page(path); Config.delay(0.5); return r
        except Exception as e: log.error(f"  ❌ Amazon [{path}]: {e}"); return []
    products = _pmap_collect(_f, niche.get("amz_paths",[]), desc="Movers")
    log.info(f"  ✅ Amazon Movers: {len(products)} 个")
    return products

def _scrape_amz_page(path):
    """v19.0: Movers & Shakers 抓取 — 提取 ASIN/评分/评论/图片/变体"""
    products = []; base = "https://www.amazon.com"
    cat_name = path.strip('/').split('/')[-1].replace('-',' ').title()
    html = SmartFetcher.fetch(base + path, allow_pw=False)  # v20.0-H: 采集禁PW
    if not html: return products
    soup = BeautifulSoup(html, 'html.parser')
    for item in soup.select('div[id^="gridItemRoot"], div.zg-grid-general-faceout, div[data-asin]')[:30]:
        try:
            # v19.0: 标题
            t_el = item.select_one('[class*="line-clamp"]') or item.select_one('[class*="title"]') or item.select_one('h2 a span, h2 span')
            title = t_el.get_text(strip=True) if t_el else ""
            if not title or len(title) < 3: continue
            # v19.0: 价格
            pr_el = item.select_one('.a-price .a-offscreen') or item.select_one('[class*="price"]') or item.select_one('.a-color-price')
            price = extract_num(pr_el.get_text() if pr_el else "0")
            # v19.0: ASIN (多策略提取 — 这是核心修复!)
            asin = item.get('data-asin', '').strip()
            if not asin or len(asin) != 10:
                # 从链接中提取ASIN
                link_el = item.select_one('a[href*="/dp/"]')
                if link_el:
                    m = re.search(r'/dp/([A-Z0-9]{10})', link_el.get('href', ''))
                    if m: asin = m.group(1)
            # v19.0: URL (从ASIN构建, 保证有效!)
            purl = build_amazon_url(asin) if asin else ""
            if not purl:
                link_el = item.select_one('a[href*="/dp/"]') or item.select_one('a[href]')
                if link_el:
                    href = link_el.get('href', '')
                    purl = (base + href) if href.startswith('/') else href
            # v20.0-F: 评分 (6层CSS选择器)
            rating = 0.0
            for r_sel in ['[aria-label*="out of 5"]', '[aria-label*="stars"]',
                          'i[class*="a-icon-star"] span.a-icon-alt', 'span.a-icon-alt',
                          '.a-icon-star-small .a-icon-alt', 'span[class*="a-icon-alt"]']:
                r_el = item.select_one(r_sel)
                if r_el:
                    r_text = r_el.get('aria-label', '') or r_el.get_text()
                    r_m = re.search(r'(\d\.\d)', r_text)
                    if r_m:
                        rating = float(r_m.group(1))
                        if 0 < rating <= 5: break
                        rating = 0.0
            if rating == 0:
                star_el = item.select_one('[class*="a-star-"]')
                if star_el:
                    cls_str = ' '.join(star_el.get('class', []))
                    sm = re.search(r'a-star-(\d)-(\d)', cls_str)
                    if sm: rating = float(sm.group(1) + '.' + sm.group(2))
            # v20.0-F: 评论数 (多层)
            rev_count = 0
            for rev_sel in ['span.a-size-small[aria-label]', 'a span.a-size-base',
                            'span.s-underline-text', 'a[href*="customerReviews"] span']:
                rev_el = item.select_one(rev_sel)
                if rev_el:
                    rev_text = rev_el.get('aria-label', '') or rev_el.get_text()
                    rv_m = re.search(r'([\d,]+)', rev_text.replace(',',''))
                    if rv_m:
                        rev_count = int(rv_m.group(1))
                        if rev_count > 0: break
            # v19.0: 图片URL
            img_url = ""
            img_el = item.select_one('img.s-image, img[src*="images-amazon"], img')
            if img_el:
                img_url = img_el.get('src', '') or img_el.get('data-src', '')
            # v19.0: Badge
            badge = ""
            badge_el = item.select_one('.a-badge-text, span[class*="badge"]')
            if badge_el: badge = badge_el.get_text(strip=True)
            # v19.0: 排名
            rank = 0
            rank_el = item.select_one('.zg-bdg-text, span[class*="rank"]')
            if rank_el: rank = int(extract_num(rank_el.get_text()))
            # 创建产品 (所有字段都有值!)
            p = _make_product(title, "amazon_movers", price, cat_name,
                              asin=asin, url=purl, image_url=img_url,
                              rating=rating, reviews_count=rev_count, badge=badge)
            p["bsr_rank"] = rank
            cost_usd, cost_rmb = estimate_1688_cost(price)
            p["cost"] = cost_usd; p["cost_rmb"] = cost_rmb
            p["pricing_strategy"] = classify_pricing_strategy(cost_rmb)
            products.append(p)
        except Exception as e:
            log.debug(f"  ⚠️ Movers解析异常: {e}")
    return products

def scrape_amazon_pain(niche):
    log.info("🔴 [采集] Amazon 差评痛点挖掘 (v12.0 并发)...")
    def _f(term):
        try: r=_search_amz_pain(term); Config.delay(0.5); return r
        except Exception as e: log.error(f"  ❌ Amazon 差评 [{term}]: {e}"); return []
    products = _pmap_collect(_f, niche.get("pain_terms",[]), desc="差评痛点")
    log.info(f"  ✅ Amazon 差评: {len(products)} 个")
    return products

def _search_amz_pain(term):
    products = []
    search_url = "https://www.amazon.com/s?k=" + urllib.parse.quote_plus(term) + "&s=review-rank"
    html = SmartFetcher.fetch(search_url, allow_pw=False)
    if not html: return products
    soup = BeautifulSoup(html, 'html.parser')
    asins = []
    for link in soup.select('a[href*="/dp/"]'):
        m = re.search(r'/dp/([A-Z0-9]{10})', link.get('href',''))
        if m and m.group(1) not in asins: asins.append(m.group(1))
        if len(asins) >= 3: break
    for asin in asins:
        try:
            data = _extract_reviews(asin)
            if data:
                price = data.get("price",0)
                p = _make_product(data["product_name"], "amazon_reviews", price, term,
                                  asin=asin, url="https://www.amazon.com/dp/" + asin,
                                  rating=data.get("rating",0), reviews_count=data.get("total_reviews",0))
                p["amazon_complaints"] = data.get("top_complaints",[])
                p["pain_keywords_found"] = data.get("pain_keywords",[])
                p["scene_keywords_found"] = data.get("scene_keywords",[])
                cost_usd, cost_rmb = estimate_1688_cost(price)
                p["cost"]=cost_usd; p["cost_rmb"]=cost_rmb
                p["pricing_strategy"] = classify_pricing_strategy(cost_rmb)
                products.append(p)
            Config.delay()
        except: pass
    return products

def _looks_english_review_text(text):
    raw = re.sub(r'\s+', ' ', str(text or '').strip())
    if not raw:
        return False
    if re.search(r'[À-ÿ]', raw):
        return False
    tokens = re.findall(r"[a-z']+", raw.lower())
    if len(tokens) < 4:
        return True
    english_markers = {
        'i', 'my', 'me', 'it', 'this', 'that', 'the', 'and', 'for', 'with', 'to', 'is', 'was', 'are', 'but',
        'on', 'in', 'of', 'you', 'your', 'we', 'our', 'they', 'their', 'works', 'worked', 'helps', 'helped'
    }
    foreign_markers = {
        'molto', 'rilassante', 'massaggiatore', 'achete', 'acheté', 'soulager', 'douleurs', 'jai', 'cest',
        'ce', 'que', 'pour', 'avec', 'muy', 'pero', 'para', 'con', 'und', 'der', 'die', 'das'
    }
    english_hits = sum(1 for t in tokens if t in english_markers)
    foreign_hits = sum(1 for t in tokens if t in foreign_markers)
    if foreign_hits >= 2 and english_hits <= 1:
        return False
    if english_hits == 0:
        return False
    return True



def _normalize_review_point(text, min_len=10, max_len=90):
    raw = re.sub(r'\s+', ' ', str(text or '').replace('\u00a0', ' ').strip())
    raw = re.sub(r'^[\-•·\)\(\s]+', '', raw)
    if not raw:
        return ''
    rating_only = bool(re.fullmatch(r'\d(?:\.\d)?\s*out of 5 stars?', raw, re.I))
    parts = re.split(r'(?<=[.!?])\s+', raw)
    best = parts[0].strip() if parts else raw
    best = re.sub(r'^["“”\'\s]+|["“”\'\s]+$', '', best)
    best = re.sub(r'^\d(?:\.\d)?\s*out of 5 stars?\s*', '', best, flags=re.I)
    best = re.sub(r'^(?:and|but|so|also)\s+', '', best, flags=re.I)
    best = re.sub(r'\*\s*do i recommend.*$', '', best, flags=re.I)
    best = re.sub(r'\bdo i recommend.*$', '', best, flags=re.I)
    best = re.sub(r'\bRead more\b.*$', '', best, flags=re.I).strip()
    if len(best) > max_len:
        clipped = best[:max_len].rstrip(' ,;:-')
        if ' ' in clipped:
            clipped = clipped.rsplit(' ', 1)[0]
        best = clipped
    if len(best) < min_len:
        if rating_only:
            return ''
        fallback = re.sub(r'\bRead more\b.*$', '', raw, flags=re.I).strip()
        fallback = re.sub(r'^(?:and|but|so|also)\s+', '', fallback, flags=re.I)
        best = fallback[:max_len].rstrip(' ,;:-')
        if len(best) == max_len and ' ' in best:
            best = best.rsplit(' ', 1)[0]
    best = best.strip(' ,;:-')
    if len(best) < min_len:
        return ''
    if not _looks_english_review_text(best):
        return ''
    return best


def _review_star_value(review):
    for sel in ['i[data-hook="review-star-rating"] span', '[data-hook="review-star-rating"]',
                'i[data-hook="cmps-review-star-rating"] span', '[data-hook="cmps-review-star-rating"]']:
        el = review.select_one(sel)
        if not el:
            continue
        text = el.get_text(' ', strip=True)
        m = re.search(r'(\d(?:\.\d)?)\s*out of 5', text, re.I)
        if m:
            try:
                return float(m.group(1))
            except Exception:
                return 0.0
    return 0.0


def _is_amazon_signin_page(html):
    text = str(html or '')
    if not text:
        return False
    low = text[:300000].lower()
    title_match = re.search(r'<title[^>]*>(.*?)</title>', low, re.I | re.S)
    title = re.sub(r'\s+', ' ', title_match.group(1)).strip() if title_match else ''
    if 'amazon sign-in' in title or 'amazon sign in' in title:
        return True
    if 'sign in to your amazon account' in low[:120000]:
        return True
    strong_markers = sum(1 for token in (
        'authportal-main-section',
        'ap_email',
        'ap_password',
        'signinsubmit',
        'createaccountsubmit',
        'auth-fpp-link-bottom',
    ) if token in low)
    return strong_markers >= 2


def _review_point_key(text):
    raw = re.sub(r'[^a-z0-9]+', ' ', str(text or '').lower()).strip()
    raw = re.sub(r'\b(?:i|me|my|mine|we|our|ours|you|your|yours|it|this|that|because|had|have|has|was|were|been|only|just|really|very|some|more|most|also|wish|wanted|allow|allowed|using|started|month|nightly|routine)\b', ' ', raw)
    raw = re.sub(r'\s+', ' ', raw).strip()
    return raw


def _merge_review_points(existing, incoming, limit=10):
    out = [str(x).strip() for x in (existing or []) if str(x).strip()]
    seen = {_review_point_key(x) for x in out}
    for raw in incoming or []:
        point = str(raw).strip()
        if not point:
            continue
        key = _review_point_key(point)
        if not key or key in seen:
            continue
        seen.add(key)
        out.append(point)
        if len(out) >= limit:
            break
    return out[:limit]


def _review_positive_score(text, rating=0.0):
    raw = str(text or '').strip()
    low = re.sub(r'\s+', ' ', raw.lower()).strip()
    if not low:
        return -99

    weak_patterns = [
        r'^a little background\b',
        r'^roughly\s+\d+\s+years?\s+now\b',
        r'^received this item promptly\b',
        r'^i finally got to use this\b',
        r'^i originally bought\b',
        r'^it was my first\b',
        r'^i accidentally\b',
        r'^at first i didn\'t realize\b',
        r'^my\s+.+\s+got rained on and died\b',
        r'^summary[,\s]',
        r'^i am unsure\b',
        r'^i\s+(?:cook|used|have used|was worried)\b.*\b(?:week|month|year|years)\b',
    ]
    if any(re.search(pat, low, re.I) for pat in weak_patterns):
        return -99

    score = 0
    strong_patterns = [
        r'\b(?:sharp|accurate|comfortable|easy to use|easy to read|easy to clean|well made|solid build|reliable|beautiful|worth it|great value|battery life|locks on|clear optics|cuts amazing|fits great in the hand)\b',
        r'\b(?:fast|precise|premium|sturdy|durable|lightweight|effective|works great|works well|excellent|impressed|love the look|great in the hand)\b',
    ]
    feature_patterns = [
        r'\b(?:feature|quality|design|handle|edge|blade|display|screen|slope|magnification|optics|battery|charge|fit|finish|build)\b',
        r'\b(?:comfortable|accurate|sharp|clear|easy|reliable|solid|beautiful|clean|quiet)\b',
    ]
    score += sum(2 for pat in strong_patterns if re.search(pat, low, re.I))
    score += sum(1 for pat in feature_patterns if re.search(pat, low, re.I))

    if rating >= 4.0:
        score += 2
    if rating >= 4.5:
        score += 1

    if re.search(r'\b(?:issue|problem|complaint|return|refund|wish|downside|too\s+|not\s+enough|doesn\'t|didn\'t|can\'t|won\'t|couldn\'t)\b', low, re.I):
        score -= 3
    if re.search(r'\b(?:but|however|except)\b', low, re.I):
        score -= 1

    return score


def _collect_review_points(review_html, limit=10, min_rating=None, max_rating=None):
    if not review_html:
        return []
    soup = BeautifulSoup(review_html, 'html.parser')
    ranked = []
    seen = set()
    for review in soup.select('[data-hook="review"]'):
        rating = _review_star_value(review)
        if min_rating is not None and rating and rating < min_rating:
            continue
        if max_rating is not None and rating and rating > max_rating:
            continue
        title_el = review.select_one('[data-hook="review-title"]')
        body_el = review.select_one('[data-hook="review-body"]')
        candidates = []
        if title_el:
            candidates.append(title_el.get_text(' ', strip=True))
        if body_el:
            body_text = body_el.get_text(' ', strip=True)
            body_parts = [part.strip() for part in re.split(r'(?<=[.!?])\s+|\s+but\s+|\s+however\s+', body_text) if part.strip()]
            candidates.extend(body_parts[:6])
        for cand in candidates:
            point = _normalize_review_point(cand, min_len=12, max_len=100)
            if not point:
                continue
            low = point.lower()
            if low in seen:
                continue
            score = _review_positive_score(point, rating)
            if score < 2:
                continue
            seen.add(low)
            ranked.append((score, rating, point))
    ranked.sort(key=lambda x: (x[0], x[1]), reverse=True)
    return [point for _, _, point in ranked[:limit]]



def _review_negative_score(text, rating=0.0):
    raw = str(text or '').strip()
    low = re.sub(r'\s+', ' ', raw.lower()).strip()
    if not low:
        return -99

    if re.search(r'[À-ÿ]', raw):
        return -99

    no_issue_patterns = [
        r'\b(?:not|isn\'t|wasn\'t|aren\'t|weren\'t|hasn\'t|haven\'t|hadn\'t|never|without|no)\s+(?:really\s+)?(?:an?\s+)?issue\b',
        r'\b(?:not|isn\'t|wasn\'t|aren\'t|weren\'t|hasn\'t|haven\'t|hadn\'t|never|without|no)\s+(?:really\s+)?(?:a\s+)?problem\b',
        r'\bno\s+issues?\b',
        r'\bno\s+problems?\b',
        r'\bexpected\b',
        r'\bnot a deal breaker\b',
        r'\bfighting chance that you won\'t leave it behind\b',
    ]
    if any(re.search(pat, low, re.I) for pat in no_issue_patterns):
        return -99

    negative_patterns = [
        r'\btoo\s+(?:strong|loud|noisy|cold|big|large|bulky|heavy|sharp)\b',
        r'\ba bit\s+(?:strong|louder|noisy|cold|bulky|heavy)\b',
        r'\b(?:loud|louder|noisy|noise)\b',
        r'\bwish(?:ed)?\s+(?:it|the|they)\s+(?:were|was|had|came|included|fit|felt|lasted|worked)\b',
        r'\b(?:doesn\'t|didn\'t|can\'t|couldn\'t|won\'t)\s+(?:work|hold|last|fit|focus|lock|charge|connect|stay|cut|read|close|open|pair|track|slice|detect|reach)\b',
        r'\bnot\s+(?:as\s+)?(?:accurate|sharp|clear|bright|durable|comfortable|strong|powerful|effective|working|worth it|heavy duty)\b',
        r'\bcould be better\b',
        r'\bwould be better\b',
        r'\bdifficult\b',
        r'\bhard to\b',
        r'\bheavy\b',
        r'\bbulky\b',
        r'\bexpensive\b',
        r'\bpricey\b',
        r'\bcostly\b',
        r'\bslow\b',
        r'\bweak\b',
        r'\bcheap\b',
        r'\bflimsy\b',
        r'\bplastic\b',
        r'\bfragile\b',
        r'\bblurry\b',
        r'\bunclear\b',
        r'\bdim\b',
        r'\binaccurate\b',
        r'\boff\s+by\b',
        r'\bbattery(?:\s+life)?\b.*\b(?:short|poor|weak|drain|dies|died|lasts?)\b',
        r'\b(?:broke|broken|stopped working|quit working|failed)\b',
        r'\bdull\b',
        r'\blost\s+(?:its\s+)?edge\b',
        r'\bneeds?\s+sharpening\b',
        r'\bslippery\b',
        r'\bawkward\b',
        r'\buncomfortable\b',
        r'\bcase\b.*\b(?:cheap|weak|flimsy|plastic|poor)\b',
        r'\b(?:instructions?|manual)\b.*\b(?:unclear|poor|bad|missing)\b',
        r'\b(?:small|smaller|large|larger)\b.*\bthan expected\b',
        r'\breplacement\s+(?:parts|filters?|battery)\b',
        r'\b(?:odor|smell)\b.*\b(?:still|again|bad|strong|unpleasant|lingers?)\b',
        r'\b(?:main|biggest|real)\s+(?:issue|problem)\b',
        r'\bhad\s+(?:an?\s+)?(?:issue|problem)\b',
        r'\btakes? up\s+(?:too much\s+)?space\b',
        r'\bfootprint\b',
        r'\breturn(?:ing|ed)?\b',
        r'\brefund\b',
        r'\brust\b',
        r'\bscratch(?:ed)?\b',
    ]
    soft_negative_patterns = [
        r'\ba bit\s+(?:strong|louder|noisy|cold|bulky|heavy)\b',
        r'\b(?:loud|louder|noisy|noise)\b',
        r'\bcold\b',
        r'\bheavy\b',
        r'\bbulky\b',
        r'\bplastic\b',
        r'\bcheap\b',
        r'\bblurry\b',
        r'\breplacement\s+(?:parts|filters?|battery)\b',
    ]
    mitigation_patterns = [
        r'\bexpected\b',
        r'\bnot\s+(?:really\s+)?(?:an?\s+)?issue\b',
        r'\bno\s+issues?\b',
        r'\bno\s+problems?\b',
        r'\bsolution\b',
        r'\bmoved?\b',
        r'\bworks?\s+(?:great|well|incredibly well|perfectly)\b',
        r'\bvery\s+quiet\b',
        r"\bcan\'t even tell\b",
        r'\bdoes a great job\b',
        r'\bsmells?\s+(?:clean|fresh)\b',
        r'\bbreath(?:able|ing better)\b',
    ]

    neg_hits = sum(1 for pat in negative_patterns if re.search(pat, low, re.I))
    if neg_hits == 0:
        return -99
    score = neg_hits * 2
    if any(re.search(pat, low, re.I) for pat in soft_negative_patterns):
        score -= 1
    if any(re.search(pat, low, re.I) for pat in mitigation_patterns):
        score -= 2

    if rating:
        if rating <= 3.0:
            score += 2
        elif rating <= 4.0:
            score += 1
        elif rating >= 5.0:
            score -= 2
    return score


def _review_negative_fallbacks(review_html, limit=10):
    if not review_html:
        return []
    soup = BeautifulSoup(review_html, 'html.parser')
    out = []
    seen = set()
    fallback_patterns = [
        (r'\b(?:loud|louder|noisy|noise)\b', 'Higher settings can get noticeably louder'),
        (r'\b(?:cold|cooler airflow|strong airflow|too strong)\b', 'The airflow can feel too strong at close range'),
        (r'\breplacement\s+(?:filters?|parts|battery)\b', 'Replacement parts add an ongoing ownership cost'),
        (r'\b(?:odor|smell)\b', 'Odor removal can feel inconsistent in tougher use cases'),
        (r'\b(?:big|large|bulky|footprint|takes? up space)\b', 'The product takes up more space than compact alternatives'),
        (r'\b(?:app|alexa|connect|wifi|pair)\b', 'Setup and pairing can take extra effort on the first use'),
        (r'\b(?:line of fire|move it away|behind my desk|placement)\b', 'Placement matters more than buyers may expect'),
        (r'\b(?:sensitive to air quality|detects? it almost immediately|ramps up the fan|auto mode)\b', 'Auto mode can react aggressively when conditions change'),
        (r'\b(?:clean the unit weekly|washable filter|clean the prefilter|change the air filter)\b', 'Routine maintenance matters more than some buyers expect'),
        (r'\b(?:plastic|cheap|flimsy|fragile)\b', 'Some parts feel less premium than the headline promise'),
        (r'\b(?:blurry|unclear|dim)\b', 'Display clarity can disappoint in some conditions'),
        (r'\b(?:battery|charge)\b.*\b(?:short|poor|drain|dies|died|lasts?)\b', 'Battery life may not feel strong enough for heavier use'),
        (r'\b(?:dull|sharpening|lost its edge)\b', 'Edge retention may need more upkeep than expected'),
        (r'\b(?:heavy|weight)\b', 'The weight can feel tiring over longer sessions'),
        (r'\b(?:case|instructions?|manual)\b.*\b(?:cheap|poor|bad|unclear|missing)\b', 'The included accessories or instructions feel underwhelming'),
    ]
    for review in soup.select('[data-hook="review"]'):
        rating = _review_star_value(review)
        title_el = review.select_one('[data-hook="review-title"]')
        body_el = review.select_one('[data-hook="review-body"]')
        clauses = []
        if title_el:
            clauses.append(title_el.get_text(' ', strip=True))
        if body_el:
            body_text = body_el.get_text(' ', strip=True)
            clauses.extend([c.strip() for c in re.split(r'(?<=[.!?])\s+|\s+but\s+|\s+however\s+|\s+except\s+', body_text) if c.strip()])
        for clause in clauses:
            score = _review_negative_score(clause, rating)
            if score < 1:
                continue
            low = clause.lower()
            mapped = ''
            for pat, label in fallback_patterns:
                if re.search(pat, low, re.I):
                    mapped = label
                    break
            if not mapped:
                continue
            key = _review_point_key(mapped)
            if key in seen:
                continue
            seen.add(key)
            out.append(mapped)
            if len(out) >= limit:
                return out
    return out


def _collect_review_objection_points(review_html, limit=10):
    if not review_html:
        return []
    soup = BeautifulSoup(review_html, 'html.parser')
    ranked = []
    seen = set()
    for review in soup.select('[data-hook="review"]'):
        rating = _review_star_value(review)
        title_el = review.select_one('[data-hook="review-title"]')
        body_el = review.select_one('[data-hook="review-body"]')
        clauses = []
        if title_el:
            clauses.append(title_el.get_text(' ', strip=True))
        if body_el:
            body_text = body_el.get_text(' ', strip=True)
            clauses.extend(re.split(r'(?<=[.!?])\s+|\s+but\s+|\s+however\s+|\s+except\s+', body_text))
        for clause in clauses:
            raw_clause = re.sub(r'\s+', ' ', clause).strip()
            if len(raw_clause) < 14:
                continue
            score = _review_negative_score(raw_clause, rating)
            if score < 2:
                continue
            point = _normalize_review_point(raw_clause, min_len=12, max_len=100)
            if not point:
                continue
            key = _review_point_key(point)
            if not key or key in seen:
                continue
            seen.add(key)
            ranked.append((score, (5.0 - rating) if rating else 0.0, point))
    ranked.sort(key=lambda x: (x[0], x[1]), reverse=True)
    return [point for _, _, point in ranked[:limit]]


def _normalize_amazon_asset_url(url, size=1500):
    raw = str(url or '').strip().replace('\\u0026', '&').replace('\\/', '/')
    if not raw:
        return ''
    if not any(host in raw for host in ('media-amazon.com', 'ssl-images-amazon.com', '/images/I/')):
        return raw
    ext_match = re.search(r'(\.(?:jpg|jpeg|png|webp))(?:\?.*)?$', raw, re.I)
    if not ext_match:
        return raw
    ext = ext_match.group(1)
    suffix = raw[ext_match.end(1):]
    prefix = raw[:ext_match.start(1)]
    prefix = re.sub(r'\._[^/]*$', '', prefix)
    target = max(600, int(size or 1500))
    return f'{prefix}._AC_SL{target}_.{ext.lstrip(".")}{suffix}'



def _normalize_review_media_item(item):
    if not isinstance(item, dict):
        return None
    kind = 'video' if str(item.get('type') or '').strip().lower() == 'video' else 'image'
    media_url = str(item.get('media_url') or item.get('video_url') or item.get('thumb_url') or '').strip()
    thumb_url = str(item.get('thumb_url') or item.get('poster_url') or media_url).strip()
    if not media_url and not thumb_url:
        return None
    video_like = bool(re.search(r'\.(?:mp4|webm|mov|m3u8)(?:\?|$)', media_url, re.I))
    image_like = bool(re.search(r'\.(?:jpg|jpeg|png|webp)(?:\?|$)', media_url, re.I))
    if kind == 'video' and not video_like and image_like:
        media_url = ''
    if kind == 'image' or image_like:
        media_url = _normalize_amazon_asset_url(media_url, 1500)
    thumb_url = _normalize_amazon_asset_url(thumb_url or media_url, 900)
    caption = _normalize_review_point(item.get('caption', ''), min_len=8, max_len=90) or ''
    source = str(item.get('source') or '').strip().lower()
    return {
        'type': kind,
        'thumb_url': thumb_url or media_url,
        'media_url': media_url,
        'caption': caption,
        'source': source,
    }



def _extract_review_media(review_html, limit=8):
    if not review_html:
        return []
    soup = BeautifulSoup(review_html, 'html.parser')
    out = []
    seen = set()

    def add_media(kind, thumb_url='', media_url='', caption=''):
        normalized = _normalize_review_media_item({
            'type': kind,
            'thumb_url': thumb_url,
            'media_url': media_url,
            'caption': caption,
        })
        if not normalized:
            return
        key = f"{normalized['type']}|{normalized['media_url'] or normalized['thumb_url'] or normalized['caption']}"
        if key in seen:
            return
        seen.add(key)
        out.append(normalized)

    for review in soup.select('[data-hook="review"]'):
        title_el = review.select_one('[data-hook="review-title"] span:last-child') or review.select_one('[data-hook="review-title"]')
        body_el = review.select_one('[data-hook="review-body"]')
        caption = ''
        if title_el:
            caption = title_el.get_text(' ', strip=True)
        if not caption and body_el:
            body_text = body_el.get_text(' ', strip=True)
            caption = re.split(r'(?<=[.!?])\s+', body_text)[0]

        for img in review.select('img.review-image-tile, [data-hook="review-image-tile"] img, img[data-hook="review-image-tile"], .review-image-tile-section img'):
            src = str(img.get('src', '') or img.get('data-src', '') or '').strip()
            if src and 'grey-pixel' not in src:
                add_media('image', thumb_url=src, media_url=src, caption=caption)
                if len(out) >= limit:
                    return out

        for video in review.select('[class*="video"], [data-hook*="video"]'):
            thumb = ''
            img = video.select_one('img')
            if img:
                thumb = str(img.get('src', '') or img.get('data-src', '') or '').strip()
            data_blob = ' '.join([
                str(video.get('data-thumb-action', '') or ''),
                str(video.get('data-a-modal', '') or ''),
                str(video.get('data-action', '') or ''),
                str(video),
            ])
            video_match = re.search(r'https://[^\s"\']+\.(?:mp4|webm|mov|m3u8)(?:\?[^\s"\']*)?', data_blob, re.I)
            media_match = re.search(r'https://[^\s"\']+\.(?:mp4|webm|mov|m3u8|jpg|jpeg|png)(?:\?[^\s"\']*)?', data_blob, re.I)
            media_url = video_match.group(0) if video_match else (media_match.group(0) if media_match else '')
            if thumb or media_url:
                add_media('video', thumb_url=thumb, media_url=media_url, caption=caption)
                if len(out) >= limit:
                    return out

    gallery = soup.select_one('.review-image-tile-section')
    if gallery:
        for img in gallery.select('img.review-image-tile, img'):
            src = str(img.get('src', '') or img.get('data-src', '') or '').strip()
            if src and 'grey-pixel' not in src:
                add_media('image', thumb_url=src, media_url=src, caption='Customer review media')
                if len(out) >= limit:
                    return out

    for video in soup.select('[class*="videoThumbnail"]'):
        img = video.select_one('img')
        thumb = str(img.get('src', '') or img.get('data-src', '') or '').strip() if img else ''
        data_blob = ' '.join([
            str(video.get('data-thumb-action', '') or ''),
            str(video.get('data-a-modal', '') or ''),
            str(video.get('data-action', '') or ''),
            str(video),
        ])
        video_match = re.search(r'https://[^\s"\']+\.(?:mp4|webm|mov|m3u8)(?:\?[^\s"\']*)?', data_blob, re.I)
        media_url = video_match.group(0) if video_match else ''
        add_media('video', thumb_url=thumb, media_url=media_url, caption='Customer review video')
        if len(out) >= limit:
            return out

    return out


def _extract_pdp_media_assets(product_html, limit=8):
    if not product_html:
        return []
    soup = BeautifulSoup(product_html, 'html.parser')
    assets = []
    seen = set()

    def add_asset(kind, thumb_url='', media_url='', caption='', source='pdp_video'):
        normalized = _normalize_review_media_item({
            'type': kind,
            'thumb_url': thumb_url,
            'media_url': media_url,
            'caption': caption,
            'source': source,
        })
        if not normalized:
            return
        key = f"{normalized.get('source','')}|{normalized['type']}|{normalized['media_url'] or normalized['thumb_url'] or normalized['caption']}"
        if key in seen:
            return
        seen.add(key)
        assets.append(normalized)

    for img in soup.select('#altImages img, #imageBlock img, #main-image-container img, img[data-old-hires], img[data-a-dynamic-image]'):
        thumb = str(img.get('src') or img.get('data-src') or '').strip()
        media_url = str(img.get('data-old-hires') or '').strip()
        if not media_url:
            dyn = str(img.get('data-a-dynamic-image') or '').strip()
            for match in re.finditer(r'https://[^"\s]+\.(?:jpg|jpeg|png|webp)(?:\?[^"\s]*)?', dyn, re.I):
                media_url = match.group(0)
                break
        if thumb or media_url:
            add_asset('image', thumb_url=thumb or media_url, media_url=media_url or thumb, caption='Amazon PDP image', source='pdp_image')
            if len(assets) >= limit:
                return assets[:limit]

    blobs = [
        product_html,
        ' '.join(str(x.get('data-a-modal') or '') for x in soup.select('[data-a-modal]')),
        ' '.join(str(x.get('data-action') or '') for x in soup.select('[data-action]')),
        ' '.join(str(x.get('data-thumb-action') or '') for x in soup.select('[data-thumb-action]')),
        ' '.join(script.get_text(' ', strip=True) for script in soup.select('script')),
    ]
    full_blob = ' '.join(blobs)

    video_urls = []
    for match in re.finditer(r'https://[^\s"\']+\.(?:mp4|webm|mov|m3u8)(?:\?[^\s"\']*)?', full_blob, re.I):
        url = match.group(0)
        if url not in video_urls:
            video_urls.append(url)
        if len(video_urls) >= limit:
            break

    poster_candidates = []
    for match in re.finditer(r'https://[^\s"\']+\.(?:jpg|jpeg|png|webp)(?:\?[^\s"\']*)?', full_blob, re.I):
        url = match.group(0)
        if 'images-amazon.com' not in url and 'media-amazon.com' not in url and '/images/I/' not in url:
            continue
        if url not in poster_candidates:
            poster_candidates.append(url)
        if len(poster_candidates) >= max(limit * 2, 8):
            break

    for idx, video_url in enumerate(video_urls, 1):
        poster = poster_candidates[idx - 1] if idx - 1 < len(poster_candidates) else ''
        add_asset('video', thumb_url=poster, media_url=video_url, caption=f'Amazon PDP video #{idx}', source='pdp_video')
        if len(assets) >= limit:
            return assets[:limit]

    return assets[:limit]



def _estimate_amazon_monthly_sales(bsr_rank, reviews_count, review_velocity):
    try:
        bsr = int(float(bsr_rank or 0))
    except Exception:
        bsr = 0
    try:
        reviews = int(float(reviews_count or 0))
    except Exception:
        reviews = 0
    try:
        velocity = float(review_velocity or 0)
    except Exception:
        velocity = 0.0

    if bsr > 0:
        if bsr <= 1000:
            base = 1800
        elif bsr <= 3000:
            base = 1200
        elif bsr <= 10000:
            base = 700
        elif bsr <= 30000:
            base = 350
        elif bsr <= 80000:
            base = 140
        elif bsr <= 150000:
            base = 60
        else:
            base = 25
        est = max(base, velocity * 45, reviews * 0.08)
        confidence = 'high' if bsr <= 10000 and velocity > 0 else ('medium' if bsr <= 80000 else 'low')
        return int(round(est)), 'BSR+review_velocity', confidence

    if velocity > 0:
        est = max(12, velocity * 35)
        confidence = 'medium' if velocity >= 8 else 'low'
        return int(round(est)), 'review_velocity_proxy', confidence

    if reviews > 0:
        est = max(8, reviews * 0.06)
        confidence = 'low'
        return int(round(est)), 'review_count_proxy', confidence

    return 0, '', ''



def _bucket_bsr_rank(bsr_rank):
    try:
        bsr = int(float(bsr_rank or 0))
    except Exception:
        bsr = 0
    if bsr <= 0:
        return ''
    if bsr <= 1000:
        return 'Top 1k'
    if bsr <= 5000:
        return 'Top 5k'
    if bsr <= 10000:
        return 'Top 10k'
    if bsr <= 50000:
        return 'Top 50k'
    if bsr <= 100000:
        return 'Top 100k'
    return '100k+'



def _apply_amazon_fact_enrichment(p, source=''):
    if not isinstance(p, dict):
        return p
    src = str(source or '').strip()
    p['amazon_badge_text'] = str(p.get('amazon_badge_text') or p.get('badge') or '').strip()
    if p.get('variant_count', 0) > 0 and not p.get('amazon_sku_count'):
        p['amazon_sku_count'] = int(p.get('variant_count', 0) or 0)
    if p.get('has_variants') and not p.get('amazon_variant_source'):
        p['amazon_variant_source'] = src or 'search_snippet'
    if p.get('bsr_rank', 0) > 0:
        p['amazon_bsr_hit'] = True
        if not p.get('amazon_bsr_source'):
            p['amazon_bsr_source'] = src or 'search_proxy'
        p['amazon_bsr_bucket'] = _bucket_bsr_rank(p.get('bsr_rank', 0))
    est_sales, sales_source, sales_conf = _estimate_amazon_monthly_sales(
        p.get('bsr_rank', 0),
        p.get('reviews_count', 0),
        p.get('review_velocity', 0),
    )
    if est_sales > 0:
        p['amazon_sales_est_monthly'] = est_sales
        if sales_source:
            p['amazon_sales_source'] = sales_source
        if sales_conf:
            p['amazon_sales_confidence'] = sales_conf
    if not p.get('amazon_fact_confidence'):
        fact_points = 0
        if p.get('amazon_brand'):
            fact_points += 1
        if p.get('amazon_sold_by') or p.get('amazon_ships_from'):
            fact_points += 1
        if p.get('amazon_offer_count', 0) > 0:
            fact_points += 1
        if p.get('amazon_main_image_count', 0) > 0:
            fact_points += 1
        if p.get('amazon_bullet_count', 0) > 0:
            fact_points += 1
        if p.get('amazon_bsr_hit'):
            fact_points += 1
        if fact_points >= 5:
            p['amazon_fact_confidence'] = '高'
        elif fact_points >= 3:
            p['amazon_fact_confidence'] = '中'
        elif fact_points >= 1:
            p['amazon_fact_confidence'] = '低'
    return p


def normalize_operator_product(p, source='output_normalize'):
    if not isinstance(p, dict):
        return p
    _apply_amazon_fact_enrichment(p, source=source)

    offer_count = int(float(p.get('amazon_offer_count', 0) or 0))
    seller_count = int(float(p.get('amz_seller_count', 0) or 0))
    if offer_count <= 0 and seller_count > 0:
        p['amazon_offer_count'] = seller_count
    elif seller_count <= 0 and offer_count > 0:
        p['amz_seller_count'] = offer_count

    variant_count = int(float(p.get('variant_count', 0) or 0))
    sku_count = int(float(p.get('amazon_sku_count', 0) or 0))
    if sku_count <= 0 and variant_count > 0:
        p['amazon_sku_count'] = variant_count
        sku_count = variant_count
    if sku_count > 1:
        p['has_variants'] = True
        if not p.get('amazon_variant_source'):
            p['amazon_variant_source'] = 'variant_count_proxy'

    if p.get('image_url') and int(float(p.get('amazon_main_image_count', 0) or 0)) <= 0:
        p['amazon_main_image_count'] = 1

    if p.get('bsr_rank', 0) and not p.get('amazon_bsr_source'):
        p['amazon_bsr_source'] = source or 'existing_data'
    if p.get('bsr_rank', 0) and not p.get('amazon_bsr_bucket'):
        p['amazon_bsr_bucket'] = _bucket_bsr_rank(p.get('bsr_rank', 0))
    if p.get('bsr_rank', 0):
        p['amazon_bsr_hit'] = True

    if not p.get('amazon_badge_text') and p.get('badge'):
        p['amazon_badge_text'] = p.get('badge')
    if not p.get('google_trends_quality'):
        p['google_trends_quality'] = 'missing'
    if p.get('google_trends_sufficient') is None:
        p['google_trends_sufficient'] = False

    _apply_amazon_fact_enrichment(p, source=source)

    # ━━━ v55修复: 缺失字段桥接 ━━━
    # trend_related_breakout (list) → trend_related_breakout_str (Excel string)
    breakout = p.get('trend_related_breakout') or []
    if breakout and not p.get('trend_related_breakout_str'):
        p['trend_related_breakout_str'] = ', '.join(str(x).strip() for x in breakout if str(x).strip())[:200]

    # closed_loop_score: 由 _closed_loop_frame 设置但key可能不同
    if not p.get('closed_loop_score') and p.get('loop_score'):
        p['closed_loop_score'] = p['loop_score']

    # star percentages: 从 star_distribution dict 提取
    star_dist = p.get('star_distribution') or p.get('rating_distribution') or {}
    if isinstance(star_dist, dict):
        for star in (5, 4, 3, 2, 1):
            key = f'amazon_star_{star}_pct'
            if not p.get(key):
                val = star_dist.get(str(star)) or star_dist.get(star) or star_dist.get(f'{star}_star') or 0
                if val:
                    p[key] = val

    # fb_review fields: map from review_copy_* if available
    if not p.get('fb_review_primary_text') and p.get('fb_primary_text'):
        p['fb_review_primary_text'] = p['fb_primary_text']
    if not p.get('fb_review_creative_angle') and p.get('fb_creative_angle'):
        p['fb_review_creative_angle'] = p['fb_creative_angle']

    return p


