def _operator_to_float(val):
    try:
        return float(val or 0)
    except Exception:
        return 0.0



def _stringify_operator_export(val):
    if isinstance(val, (list, tuple)):
        return " | ".join(str(x).strip() for x in val if str(x).strip())
    if isinstance(val, dict):
        return json.dumps(val, ensure_ascii=False)
    if val is None:
        return ""
    return str(val).strip()



def _operator_verdict_bucket(text):
    raw = str(text or '').strip()
    if not raw:
        return 'watch'
    low = raw.lower()
    if 'launch now' in low or '立即投放' in raw:
        return 'launch'
    if 'test first' in low or '测试观察' in raw:
        return 'test'
    return 'watch'


def display_operator_value(field, p):
    raw = p.get(field, "") if isinstance(p, dict) else ""
    if field in OPERATOR_BOOLEAN_LABELS:
        yes_label, no_label = OPERATOR_BOOLEAN_LABELS[field]
        return yes_label if bool(raw) else no_label
    if field in OPERATOR_MONEY_FIELDS:
        num = _operator_to_float(raw)
        if num > 0:
            return round(num, 2)
        if raw not in ("", None):
            return 0.0  # 0 is valid data
        return OPERATOR_EXPLICIT_STATUS.get(field, "0")
    if field == "rating":
        num = _operator_to_float(raw)
        return round(num, 1) if num > 0 else OPERATOR_EXPLICIT_STATUS.get(field, "未检出")
    if field == "bsr_rank":
        num = int(_operator_to_float(raw))
        return f'#{num:,}' if num > 0 else OPERATOR_EXPLICIT_STATUS.get(field, "未检出")
    if field == "amazon_search_rank":
        num = int(_operator_to_float(raw))
        return f'第{num}位' if num > 0 else OPERATOR_EXPLICIT_STATUS.get(field, "未检出")
    if field == "amazon_sales_est_monthly":
        num = int(_operator_to_float(raw))
        return f'{num}/月' if num > 0 else OPERATOR_EXPLICIT_STATUS.get(field, "未形成估算")
    if field == "google_trends_interest":
        num = int(_operator_to_float(raw))
        return f'{num}/100' if num > 0 else OPERATOR_EXPLICIT_STATUS.get(field, "未形成热度")
    if field in OPERATOR_COUNT_FIELDS:
        num = int(_operator_to_float(raw))
        if num > 0:
            return num
        if raw not in ("", None):
            return 0  # 0 is valid data (e.g. 0 ads found)
        return OPERATOR_EXPLICIT_STATUS.get(field, "0")
    if field == "review_velocity":
        num = _operator_to_float(raw)
        if num > 0:
            return round(num, 1)
        if raw not in ("", None):
            return 0.0
        return OPERATOR_EXPLICIT_STATUS.get(field, "0")
    if field in OPERATOR_ROUNDED_1_FIELDS:
        num = _operator_to_float(raw)
        if num > 0:
            return round(num, 1)
        if raw not in ("", None):
            return 0.0
        return OPERATOR_EXPLICIT_STATUS.get(field, "0")
    if field in OPERATOR_ROUNDED_0_FIELDS:
        num = _operator_to_float(raw)
        if num > 0:
            return round(num, 0)
        if raw not in ("", None):
            return 0  # 0 is valid data
        return OPERATOR_EXPLICIT_STATUS.get(field, "0")
    if field == "google_trends_quality":
        label = _stringify_operator_export(raw).lower()
        return {"strong": "强", "medium": "中", "weak": "弱", "missing": "缺失"}.get(label, label or OPERATOR_EXPLICIT_STATUS.get(field, "缺失"))
    if field == "amazon_review_media":
        if isinstance(raw, (list, tuple)):
            parts = []
            for item in raw:
                if not isinstance(item, dict):
                    continue
                kind = str(item.get('type') or 'image').strip()
                source = str(item.get('source') or '').strip()
                media_url = str(item.get('media_url') or item.get('thumb_url') or '').strip()
                caption = str(item.get('caption') or '').strip()
                prefix = f"{source}:{kind}" if source else kind
                if media_url:
                    parts.append(f"{prefix}:{caption}:{media_url}" if caption else f"{prefix}:{media_url}")
            return " | ".join(parts) if parts else OPERATOR_EXPLICIT_STATUS.get(field, "未收集到媒体资产")
        text = _stringify_operator_export(raw)
        return text or OPERATOR_EXPLICIT_STATUS.get(field, "未收集到媒体资产")
    if field in OPERATOR_LIST_LIKE_FIELDS:
        text = _stringify_operator_export(raw)
        return text or OPERATOR_EXPLICIT_STATUS.get(field, "待补")
    text = _stringify_operator_export(raw)
    if text not in ("",):
        return text  # "0" and "0.0" are valid values
    return OPERATOR_EXPLICIT_STATUS.get(field, "—")



def has_usable_operator_value(field, p):
    val = display_operator_value(field, p)
    return val not in (None, "", "—")



def _column_has_meaningful_raw_value(field, raw):
    if raw is None:
        return False
    if isinstance(raw, bool):
        return bool(raw)
    if isinstance(raw, (int, float)):
        return raw > 0
    if isinstance(raw, (list, tuple, set)):
        if field == "amazon_review_media":
            return any(isinstance(item, dict) and str(item.get('media_url') or item.get('thumb_url') or '').strip() for item in raw)
        return any(_stringify_operator_export(item).strip() for item in raw)
    if isinstance(raw, dict):
        return any(_stringify_operator_export(v).strip() for v in raw.values())
    text = str(raw).strip()
    return text not in ("", "0", "0.0", "False", "None")



