        "fb_creative_feasibility", "fb_policy_risk",
        "ad_library_count", "fb_oldest_ad_days",
        "fb_touchpoints_needed", "est_cpm", "est_roas_cold", "profit_cold", "daily_budget_min",
        "shopify_competitors", "shopify_launch_readiness", "fb_launch_readiness", "launch_readiness_summary",
        # ━━━ 评论情报 (_review_intelligence_frame, 需评论数据) ━━━
        "review_intelligence_summary", "review_top_demands", "review_top_hates",
        "review_most_valuable_feature", "review_real_pain_story", "review_real_proof_story",
        "review_best_fb_angle", "review_best_hook_seed",
        "review_competitor_weaknesses", "review_competitor_opportunity",
        "review_bundle_extensions", "review_bundle_logic", "review_bundle_score",
        "review_demand_clarity_score", "review_pain_intensity_score",
        "review_feature_focus_score", "review_objection_severity_score", "review_creative_angle_score",
