def _normalize_review_segment_map(raw_map, limit=14):
    out = {}
    if not isinstance(raw_map, dict):
        return out
    for key, values in raw_map.items():
        items = []
        seen = set()
        for raw in (values or []):
            point = _normalize_review_point(raw, min_len=10, max_len=100)
            if not point:
                point = re.sub(r'\s+', ' ', str(raw or '')).strip(' .;:-')
            if not point:
                continue
            norm_key = _review_point_key(point)
            if not norm_key or norm_key in seen:
                continue
            seen.add(norm_key)
            items.append(point)
            if len(items) >= limit:
                break
        if items:
            out[str(key).strip()] = items
    return out



def _dedupe_review_media_items(items, limit=8):
    merged = []
    seen = set()
    for item in list(items or []):
        if not isinstance(item, dict):
            continue
        normalized = _normalize_review_media_item(item)
        if not normalized:
            continue
        key = f"{normalized.get('source','')}|{normalized.get('type','')}|{normalized.get('media_url') or normalized.get('thumb_url') or normalized.get('caption','')}"
        if key in seen:
            continue
        seen.add(key)
        merged.append(normalized)
        if len(merged) >= limit:
            break
    return merged[:limit]



def _review_segment_summary(pos_segments, neg_segments):
    labels = {
        'positive_recent': 'Positive recent',
        'positive_helpful': 'Positive helpful',
        'five_star_helpful': '5★ helpful',
        'pdp_positive': 'PDP positive',
        'critical_recent': 'Critical recent',
        'critical_helpful': 'Critical helpful',
        'one_star_helpful': '1★ helpful',
        'two_star_helpful': '2★ helpful',
        'three_star_helpful': '3★ helpful',
        'pdp_negative': 'PDP negative',
        'fallback_negative': 'Fallback complaints',
    }
    summary = []
    for key in (
        'positive_recent', 'positive_helpful', 'five_star_helpful', 'pdp_positive',
        'critical_recent', 'critical_helpful', 'one_star_helpful', 'two_star_helpful', 'three_star_helpful', 'pdp_negative', 'fallback_negative',
    ):
        bucket = (pos_segments if key.startswith('positive') or key == 'five_star_helpful' or key == 'pdp_positive' else neg_segments).get(key) or []
        if bucket:
            summary.append(f"{labels.get(key, key)} {len(bucket)}")
    return summary[:8]



def extract_amazon_review_insights(asin):
    ck = f"revins_v15_{asin}"
    cached = Cache.get(ck)
    if isinstance(cached, dict):
        cached_pos = [str(x).strip() for x in (cached.get('positive_points') or []) if str(x).strip()][:10]
        cached_neg = [str(x).strip() for x in (cached.get('negative_points') or []) if str(x).strip()][:10]
        cached_media = _dedupe_review_media_items(cached.get('media') or [], limit=8)
        cached_pos_segments = _normalize_review_segment_map(cached.get('positive_segments') or {}, limit=14)
        cached_neg_segments = _normalize_review_segment_map(cached.get('negative_segments') or {}, limit=14)
        cached_segment_summary = [str(x).strip() for x in (cached.get('segment_summary') or []) if str(x).strip()][:8]
        if cached_pos or cached_neg or cached_media or cached_pos_segments or cached_neg_segments:
            return {
                "positive_points": cached_pos,
                "negative_points": cached_neg,
                "media": cached_media,
                "positive_segments": cached_pos_segments,
                "negative_segments": cached_neg_segments,
                "segment_summary": cached_segment_summary or _review_segment_summary(cached_pos_segments, cached_neg_segments),
            }
    if not asin:
        return {"positive_points": [], "negative_points": [], "media": [], "positive_segments": {}, "negative_segments": {}, "segment_summary": []}

    def add_points(seg_map, key, points, limit=14):
        if not points:
            return
        existing = seg_map.get(key, [])
        seg_map[key] = _merge_review_points(existing, points, limit=limit)

    positive_segments = {}
    negative_segments = {}
    positive_points = []
    negative_points = []
    media = []
    product_html = ''

    positive_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=positive&sortBy=recent"
    critical_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=critical&sortBy=recent"
    positive_helpful_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=positive&sortBy=helpful"
    five_star_helpful_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=five_star&sortBy=helpful"
    critical_helpful_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=critical&sortBy=helpful"
    one_star_helpful_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=one_star&sortBy=helpful"
    two_star_helpful_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=two_star&sortBy=helpful"
    three_star_helpful_url = f"https://www.amazon.com/product-reviews/{asin}/?filterByStar=three_star&sortBy=helpful"

    positive_html = SmartFetcher.fetch(positive_url, allow_pw=False)
    Config.delay()
    negative_html = SmartFetcher.fetch(critical_url, allow_pw=False)

    if positive_html and not _is_amazon_signin_page(positive_html):
        add_points(positive_segments, 'positive_recent', _collect_review_points(positive_html, limit=16), limit=14)
        positive_points = _merge_review_points(positive_points, positive_segments.get('positive_recent', []), limit=10)
        media = _dedupe_review_media_items(list(media) + _extract_review_media(positive_html, limit=8), limit=8)
    if negative_html and not _is_amazon_signin_page(negative_html):
        recent_neg = _collect_review_objection_points(negative_html, limit=16)
        add_points(negative_segments, 'critical_recent', recent_neg, limit=14)
        if len(recent_neg) < 14:
            add_points(negative_segments, 'critical_recent', _review_negative_fallbacks(negative_html, limit=16), limit=14)
        negative_points = _merge_review_points(negative_points, negative_segments.get('critical_recent', []), limit=10)
        media = _dedupe_review_media_items(list(media) + _extract_review_media(negative_html, limit=8), limit=8)

    for key, url, mode in [
        ('positive_helpful', positive_helpful_url, 'positive'),
        ('five_star_helpful', five_star_helpful_url, 'positive'),
        ('critical_helpful', critical_helpful_url, 'negative'),
        ('one_star_helpful', one_star_helpful_url, 'negative'),
        ('two_star_helpful', two_star_helpful_url, 'negative'),
        ('three_star_helpful', three_star_helpful_url, 'negative'),
    ]:
        need_more = len(positive_points) < 10 if mode == 'positive' else len(negative_points) < 10
        if not need_more:
            continue
        Config.delay()
        html = SmartFetcher.fetch(url, allow_pw=False)
        if not html or _is_amazon_signin_page(html):
            continue
        if mode == 'positive':
            add_points(positive_segments, key, _collect_review_points(html, limit=18, min_rating=4.0), limit=14)
            positive_points = _merge_review_points(positive_points, positive_segments.get(key, []), limit=10)
        else:
            points = _collect_review_objection_points(html, limit=18)
            add_points(negative_segments, key, points, limit=14)
            if len(negative_segments.get(key, [])) < 10:
                add_points(negative_segments, key, _review_negative_fallbacks(html, limit=16), limit=14)
            negative_points = _merge_review_points(negative_points, negative_segments.get(key, []), limit=10)
        media = _dedupe_review_media_items(list(media) + _extract_review_media(html, limit=8), limit=8)

    needs_fallback = len(positive_points) < 10 or len(negative_points) < 10 or len(media) < 4
    if needs_fallback:
        product_html = SmartFetcher.fetch(build_amazon_url(asin), allow_pw=False)
        if product_html and not _is_amazon_signin_page(product_html):
            add_points(positive_segments, 'pdp_positive', _collect_review_points(product_html, limit=18, min_rating=4.0), limit=14)
            add_points(negative_segments, 'pdp_negative', _collect_review_objection_points(product_html, limit=18), limit=14)
            if len(negative_segments.get('pdp_negative', [])) < 10:
                add_points(negative_segments, 'pdp_negative', _review_negative_fallbacks(product_html, limit=16), limit=14)
            positive_points = _merge_review_points(positive_points, positive_segments.get('pdp_positive', []), limit=10)
            negative_points = _merge_review_points(negative_points, negative_segments.get('pdp_negative', []), limit=10)
            media = _dedupe_review_media_items(list(media) + _extract_review_media(product_html, limit=8), limit=8)

    if len(negative_points) < 10:
        try:
            review_info = _extract_reviews(asin) or {}
            fallback_neg = [
                _normalize_review_point(x)
                for x in (review_info.get('top_complaints') or [])
                if _review_negative_score(x) >= 2
            ]
            add_points(negative_segments, 'fallback_negative', fallback_neg, limit=14)
            negative_points = _merge_review_points(negative_points, negative_segments.get('fallback_negative', []), limit=10)
        except Exception:
            pass

    if len(media) < 8:
        if not product_html:
            product_html = SmartFetcher.fetch(build_amazon_url(asin), allow_pw=False)
        if product_html and not _is_amazon_signin_page(product_html):
            media = _dedupe_review_media_items(list(media) + _extract_pdp_media_assets(product_html, limit=8), limit=8)

    result = {
        "positive_points": positive_points[:10],
        "negative_points": negative_points[:10],
        "media": media[:8],
        "positive_segments": _normalize_review_segment_map(positive_segments, limit=14),
        "negative_segments": _normalize_review_segment_map(negative_segments, limit=14),
        "segment_summary": _review_segment_summary(positive_segments, negative_segments),
    }
    if result["positive_points"] or result["negative_points"] or result["media"] or result["positive_segments"] or result["negative_segments"]:
        Cache.put(ck, result)
    return result



def _extract_reviews(asin):
    ck = f"rev_v2_{asin}"
    cached = Cache.get(ck)
    if cached: return cached
    html = SmartFetcher.fetch("https://www.amazon.com/dp/" + asin, allow_pw=False)
    if not html: return None
    soup = BeautifulSoup(html, 'html.parser')
    t_el = soup.select_one('#productTitle')
    name = t_el.get_text(strip=True)[:100] if t_el else asin
    pr_el = soup.select_one('.a-price .a-offscreen')
    price = extract_num(pr_el.get_text() if pr_el else "0")
    rating = 0.0
    r_el = soup.select_one('#acrPopover')
    if r_el:
        try: rating = float(r_el.get('title','0').split()[0])
        except: pass
    rev_el = soup.select_one('#acrCustomerReviewText')
    total = int(extract_num(rev_el.get_text() if rev_el else "0"))
    Config.delay()
    rev_url = "https://www.amazon.com/product-reviews/" + asin + "/?filterByStar=critical&sortBy=recent"
    html2 = SmartFetcher.fetch(rev_url, allow_pw=False)
    complaints, pain_kws, scene_kws = [], [], []
    review_html = html2 if html2 and not _is_amazon_signin_page(html2) else html
    if review_html and not _is_amazon_signin_page(review_html):
        complaints = _collect_review_objection_points(review_html, limit=8)
        all_pain = Config.PAIN_S + Config.PAIN_A + Config.PAIN_B
        for text in complaints[:5]:
            low = str(text).lower()
            for kw in all_pain:
                if kw in low and kw not in pain_kws: pain_kws.append(kw)
            for kw in Config.SCENE_MAP:
                if kw in low and kw not in scene_kws: scene_kws.append(kw)
    result = {"product_name":name,"price":price,"rating":rating,"total_reviews":total,
              "top_complaints":complaints[:10],"pain_keywords":pain_kws,"scene_keywords":scene_kws}
    Cache.put(ck, result)
    return result


# ================================================================
#  Amazon 深度采集 v9.0 (Best Sellers + New Releases + 搜索 + Q&A)
# ================================================================
def _scrape_amz_list_page(path, tag):
    """v19.0: 通用 Amazon 列表页抓取 — 全字段提取"""
    products=[]; base="https://www.amazon.com"
    cat=path.strip('/').split('/')[-1].replace('-',' ').title()
    html=SmartFetcher.fetch(base+path, allow_pw=False)  # v20.0-H: 采集禁PW
    if not html: return products
    soup=BeautifulSoup(html,'html.parser')
    for item in soup.select('div[id^="gridItemRoot"], div.zg-grid-general-faceout, div[data-asin]')[:30]:
        try:
            t_el=item.select_one('[class*="line-clamp"]') or item.select_one('[class*="title"]') or item.select_one('h2 a span')
            title=t_el.get_text(strip=True) if t_el else ""
            if not title or len(title)<3: continue
            pr_el=item.select_one('.a-price .a-offscreen') or item.select_one('[class*="price"], .a-color-price')
            price=extract_num(pr_el.get_text() if pr_el else "0")
            # v19.0: ASIN提取 (核心!)
            asin = item.get('data-asin', '').strip()
            if not asin or len(asin) != 10:
                for a_tag in item.select('a[href*="/dp/"]'):
                    m = re.search(r'/dp/([A-Z0-9]{10})', a_tag.get('href',''))
                    if m: asin = m.group(1); break
            # v19.0: URL从ASIN构建
            purl = build_amazon_url(asin) if asin else ""
            if not purl:
                link_el=item.select_one('a[href*="/dp/"]')
                if link_el:
                    href=link_el.get('href','')
                    purl=(base+href) if href.startswith('/') else href
            # v20.0-F: 评分 (6层)
            rating = 0.0
            for r_sel in ['[aria-label*="out of 5"]', '[aria-label*="stars"]',
                          'i[class*="a-icon-star"] span.a-icon-alt', 'span.a-icon-alt',
                          '.a-icon-star-small .a-icon-alt', 'span[class*="a-icon-alt"]']:
                r_el = item.select_one(r_sel)
                if r_el:
                    r_text = r_el.get('aria-label', '') or r_el.get_text()
                    r_m = re.search(r'(\d\.\d)', r_text)
                    if r_m:
                        rating = float(r_m.group(1))
                        if 0 < rating <= 5: break
                        rating = 0.0
            if rating == 0:
                star_el = item.select_one('[class*="a-star-"]')
                if star_el:
                    cls_str = ' '.join(star_el.get('class', []))
                    sm = re.search(r'a-star-(\d)-(\d)', cls_str)
                    if sm: rating = float(sm.group(1) + '.' + sm.group(2))
            # v20.0-F: 评论数 (多层)
            rev_count = 0
            for rev_sel in ['span.a-size-small[aria-label]', 'span.s-underline-text',
                            'a span.a-size-base', 'a[href*="customerReviews"] span']:
                rev_el = item.select_one(rev_sel)
                if rev_el:
                    rev_text = rev_el.get('aria-label', '') or rev_el.get_text()
                    rv_m = re.search(r'([\d,]+)', rev_text.replace(',',''))
                    if rv_m:
                        rev_count = int(rv_m.group(1))
                        if rev_count > 0: break
            # v19.0: 图片
            img_url = ""
            img_el = item.select_one('img[src*="images-amazon"], img.s-image, img')
            if img_el: img_url = img_el.get('src','') or img_el.get('data-src','')
            # v19.0: Badge
            badge = ""
            badge_el = item.select_one('.a-badge-text')
            if badge_el: badge = badge_el.get_text(strip=True)
            # 排名
            rank_el=item.select_one('.zg-bdg-text, span[class*="rank"]')
            rank=int(extract_num(rank_el.get_text())) if rank_el else 0
            p=_make_product(title, tag, price, cat,
                            asin=asin, url=purl, image_url=img_url,
                            rating=rating, reviews_count=rev_count, badge=badge)
            p["bsr_rank"]=rank
            cost_usd, cost_rmb=estimate_1688_cost(price)
            p["cost"]=cost_usd; p["cost_rmb"]=cost_rmb
            p["pricing_strategy"]=classify_pricing_strategy(cost_rmb)
            products.append(p)
        except Exception as e:
            log.debug(f"  ⚠️ 列表页解析: {e}")
    return products

