    def clean(val):
        return str(val or "").strip()

    def esc(val, fallback="—"):
        text = clean(val)
        return html_lib.escape(text if text else fallback)

    def split_parts(val):
        return [part.strip() for part in clean(val).split("|") if part.strip()]

    def chip(text, tone=""):
        text = clean(text)
        if not text:
            return ""
        cls = f"chip {tone}".strip()
        return f'<span class="{cls}">{html_lib.escape(text)}</span>'

    def chips(items, tone=""):
        tags = [chip(x, tone) for x in items if clean(x)]
        return f'<div class="chips">{"".join(tags)}</div>' if tags else ""

    def tag_row(items, tone=""):
        parts = [clean(x) for x in items if clean(x)]
        if not parts:
            return ""
        cls = f'tag {tone}'.strip()
        return '<div class="tag-row">' + ''.join(f'<span class="{cls}">{html_lib.escape(x)}</span>' for x in parts) + '</div>'

    def metric(label, value, note="", tone=""):
        cls = f'metric {tone}'.strip()
        note_html = f'<div class="metric-note">{html_lib.escape(clean(note))}</div>' if clean(note) else ''
        return f'<div class="{cls}"><div class="metric-label">{html_lib.escape(label)}</div><div class="metric-value">{html_lib.escape(str(value))}</div>{note_html}</div>'

    def field_text(field, p):
        return clean(display_operator_value(field, p))

    def field_row(label, field, p):
        return row(label, field_text(field, p))

    def field_chip(field, p, prefix='', suffix='', tone='muted', fallback=''):
        text = field_text(field, p)
        if not text:
            text = fallback
        if not text:
            return ''
        body = f'{prefix}{text}{suffix}' if prefix or suffix else text
        return chip(body, tone)

    def proof_stat(label, value):
        text = clean(value)
        if not text:
            return ''
        return (f'<div class="proof-mini">'
                f'<div class="proof-mini-title">{html_lib.escape(label)}</div>'
                f'<div class="proof-mini-copy">{html_lib.escape(text)}</div>'
                f'</div>')

    def row(label, value):
        value = clean(value)
        if not value:
            return ""
        return f'<div class="row"><div class="row-label">{html_lib.escape(label)}</div><div class="row-value">{html_lib.escape(value)}</div></div>'

    def section(title, body, cls_name=''):
        if not body:
            return ""
        cls = ' '.join(x for x in ('section', cls_name) if x).strip()
        return f'<div class="{html_lib.escape(cls)}"><div class="section-title">{html_lib.escape(title)}</div>{body}</div>'

    def bullet_list(items, cls_name):
        vals = [clean(x) for x in items if clean(x)]
        if not vals:
            return ""
        return f'<ul class="{cls_name}">' + ''.join(f'<li>{html_lib.escape(x)}</li>' for x in vals) + '</ul>'

    def proof_group(title, items, cls_name='hook-list'):
        vals = [clean(x) for x in items if clean(x)]
        if not vals:
            return ''
        return (f'<div class="proof-group"><div class="proof-title">{html_lib.escape(title)}</div>'
                f'{bullet_list(vals, cls_name)}</div>')

    def _short_phrase(text, limit=24):
        raw = re.sub(r'\s+', ' ', str(text or '')).strip(' ,;:-')
        if not raw:
            return ''
        return raw if len(raw) <= limit else raw[:limit].rstrip(' ,;:-') + '…'

    def render_review_media(media_items):
        items = [x for x in (media_items or []) if isinstance(x, dict)][:8]
        if not items:
            return ''
        image_count = sum(1 for x in items if clean(x.get('type', '')).lower() != 'video')
        video_count = sum(1 for x in items if clean(x.get('type', '')).lower() == 'video')
        source_labels = {
            'review_media': 'Review media',
            'pdp_video': 'PDP video',
            'pdp_image': 'PDP image',
        }
        source_counts = {}
        for item in items:
            source = clean(item.get('source', 'review_media')).lower() or 'review_media'
            source_counts[source] = source_counts.get(source, 0) + 1
        stat_bits = []
        if image_count:
            stat_bits.append(f'{image_count} image asset{"s" if image_count != 1 else ""}')
        if video_count:
            stat_bits.append(f'{video_count} video asset{"s" if video_count != 1 else ""}')
        for source, count in source_counts.items():
            label = source_labels.get(source, source.replace('_', ' ').title())
            stat_bits.append(f'{label} {count}')
        if not stat_bits:
            return ''
        return ('<div class="review-media-shell">'
                '<div class="review-media-label">Asset coverage</div>'
                '<div class="review-media-stats">' + ' • '.join(html_lib.escape(x) for x in stat_bits) + '</div></div>')


    def bar(label, val, mx=20):
        try:
            num = float(val or 0)
        except Exception:
            num = 0
        pct = max(0, min(100, int(num / mx * 100))) if mx else 0
        return (f'<div class="bar-wrap"><span class="bar-label">{html_lib.escape(label)}</span>'
                f'<div class="bar-track"><div class="bar-fill" style="width:{pct}%"></div></div>'
                f'<span class="bar-label">{num:.0f}</span></div>')

    def verdict_tone(text):
        bucket = _operator_verdict_bucket(clean(text))
        if bucket == 'launch':
            return "good"
        if bucket == 'test':
            return "warn"
        return "muted"

    def grade_tone(text):
        text = clean(text)
        if text.startswith("S"):
            return "good"
        if text.startswith("A"):
            return "primary"
        if text.startswith("B"):
            return "warn"
        return "muted"

    def priority_tone(text):
        text = clean(text)
        low = text.lower()
        if "launch now" in low or "立即" in text:
            return "good"
        if "close one key proof gap" in low or "优先" in text:
            return "primary"
        if "test first" in low or "测试" in text:
            return "warn"
        return "muted"

    def to_float(val):
        try:
            return float(val or 0)
        except Exception:
            return 0.0

    def signal(label, value, note="", tone="muted"):
        note_html = f'<div class="signal-note">{html_lib.escape(clean(note))}</div>' if clean(note) else ''
        return (f'<div class="signal {tone}"><div class="signal-label">{html_lib.escape(label)}</div>'
                f'<div class="signal-value">{html_lib.escape(value)}</div>{note_html}</div>')

    def roi_tone(val, has_data=True):
        if not has_data:
            return "muted"
        if val >= 45:
            return "good"
        if val >= 20:
            return "warn"
        return "danger"

    def roas_tone(val, has_data=True):
        if not has_data:
            return "muted"
        if val >= 2.0:
            return "good"
        if val >= 1.2:
            return "warn"
        return "danger"

    def profit_tone(val, has_data=True):
        if not has_data:
            return "muted"
        if val >= 20:
            return "good"
        if val > 0:
            return "warn"
        return "danger"

    def trend_tone(direction, interest=0):
        direction = clean(direction)
        if interest >= 60 or direction in ('↑↑', '↗'):
            return 'good'
        if direction in ('↓', '↓↓'):
            return 'danger'
        if interest >= 25 or direction in ('↑', '→'):
            return 'warn'
        return 'muted'

    def creative_method_lines(p, media_items, pos_points, neg_points, shopify_headline='', shopify_bullets_en=None, fb_hooks_en=None):
        product_images = int(to_float(p.get('amazon_main_image_count', 0)))
        if product_images <= 0 and clean(p.get('image_url')):
            product_images = 1
        review_images = sum(1 for x in (media_items or []) if str(x.get('type') or '').lower() != 'video')
        review_videos = sum(1 for x in (media_items or []) if str(x.get('type') or '').lower() == 'video')
        total_image_pool = max(product_images, 0) + review_images
        lines = []
        if shopify_headline:
            lines.append(f'Hero section — lead with "{shopify_headline}" and the strongest product image as the main visual.')
        elif pos_points:
            lines.append(f'Hero section — turn "{_short_phrase(pos_points[0], 68)}" into the opening promise and pair it with the strongest product image.')
        else:
            lines.append('Hero section — open with the clearest buyer payoff and the strongest product image.')
        lines.append(f'Image workflow — use the full product image set ({max(product_images, 1)} core image{"s" if max(product_images, 1) != 1 else ""}) across hero, feature stack, comparison block, and final CTA.')
        if shopify_bullets_en:
            lines.append('Benefit stack — map the first 3-4 Shopify bullets to image-backed sections so every claim has its own visual proof.')
        if pos_points:
            lines.append(f'Proof section — place buyer language like "{_short_phrase(pos_points[0], 64)}" beside testimonials, star ratings, and close-up product shots.')
        if neg_points:
            lines.append(f'FAQ / objection block — answer concerns like "{_short_phrase(neg_points[0], 64)}" before the final CTA.')
        if review_images > 0:
            lines.append(f'UGC stills — use the {review_images} buyer image asset{"s" if review_images != 1 else ""} in testimonial cards, review strips, and comparison modules.')
        else:
            lines.append('UGC stills — when buyer photos are missing, reuse the full Amazon image set and overlay short review proof instead of leaving the proof section thin.')
        if review_videos > 0 or p.get('amazon_has_video'):
            lines.append('Video workflow — cut available review/PDP videos into Hook → Demo → Proof → Objection handling → CTA for a 15-30s Meta ad.')
        else:
            lines.append('Video workflow — animate the full image pool into Hook → Demo → Proof → Objection handling → CTA when direct video files are limited.')
        if fb_hooks_en:
            lines.append(f'Ad opening — test hook lines starting with "{_short_phrase(fb_hooks_en[0], 72)}" so the ad promise matches the Shopify hero.')
        lines.append(f'Page build order — Hero → benefit stack → proof strip → FAQ / objection handling → CTA, using the full available asset pool ({max(total_image_pool, 1)} image-led proof slot{"s" if max(total_image_pool, 1) != 1 else ""}).')
        out = []
        seen = set()
        for line in lines:
            key = re.sub(r'[^a-z0-9]+', ' ', line.lower()).strip()
            if not key or key in seen:
                continue
            seen.add(key)
            out.append(line)
            if len(out) >= 8:
                break
        return out

    def render_thumb(url, cls_name, alt_text):
        image_url = clean(_normalize_amazon_asset_url(url, 1400) if url else '')
        safe_url = html_lib.escape(image_url, quote=True)
        safe_alt = html_lib.escape(clean(alt_text) or 'product image', quote=True)
        if safe_url:
            return f'<div class="thumb {cls_name}"><img src="{safe_url}" alt="{safe_alt}" loading="lazy" referrerpolicy="no-referrer"></div>'
        return f'<div class="thumb {cls_name} thumb-placeholder">No Image</div>'

    def trends_body(p):
        keyword = clean(p.get('google_trends_keyword') or p.get('verify_keyword') or p.get('seed_keyword'))
        interest = int(to_float(p.get('google_trends_interest', 0)))
        direction = clean(p.get('trend_direction', ''))
        related = [clean(x) for x in (p.get('google_trends_related') or []) if clean(x)][:3]
        source = clean(p.get('google_trends_source', ''))
        quality = clean(p.get('google_trends_quality', 'missing'))
        sufficient = bool(p.get('google_trends_sufficient', False))

        quality_label = {
            'strong': '证据 强',
            'medium': '证据 中',
            'weak': '证据 弱',
            'missing': '证据 缺失',
        }.get(quality, '证据 待补')
        quality_tone = 'good' if sufficient else ('warn' if quality in ('medium', 'weak') else 'muted')

        trend_bits = []
        if keyword:
            trend_bits.append(chip(f'词 {keyword}', 'primary'))
        trend_bits.append(field_chip('google_trends_interest', p, prefix='热度 ', tone=trend_tone(direction, interest)))
        if direction:
            trend_bits.append(chip(f'趋势 {direction}', trend_tone(direction, interest)))
        else:
            trend_bits.append(field_chip('trend_direction', p, prefix='趋势 ', tone='muted'))
        trend_bits.append(chip(quality_label, quality_tone))

        body = f'<div class="trend-stack">{"".join(x for x in trend_bits if x)}</div>' if trend_bits else ''
        if related:
            body += '<div class="trend-related">' + ''.join(chip(f'相关 {rel}', 'muted') for rel in related[:3]) + '</div>'
        if source:
            src_label = {
                'pytrends': 'pytrends',
                'google_trends_page': 'Google Trends页面',
                'search_signal': '搜索信号',
                'heuristic': '启发式估算',
            }.get(source, source)
            body += row('数据来源', src_label)
        if sufficient:
            body += row('趋势说明', '当前趋势证据已足够进入验证判断')
        elif direction and not interest:
            body += row('趋势说明', f'当前仅拿到方向信号 {direction}，仍需补热度/相关词')
        elif quality == 'weak':
            body += row('趋势说明', '当前趋势信号偏弱，更多像参考，不应视作硬验证')
        elif not keyword and not interest and not direction:
            body += row('趋势说明', '当前未拿到Google Trends细分数据')
        return body

    def product_key(p):
        return clean(p.get('asin')) or f'{clean(p.get("name"))}|{to_float(p.get("price", 0)):.2f}'

    def product_bucket(p):
        shortlist_bucket = clean(p.get('shortlist_bucket', ''))
        if shortlist_bucket in ('launch', 'test', 'watch'):
            return shortlist_bucket
        verdict = clean(p.get('sell_verdict', ''))
        if p.get('verification_passed'):
            bucket = _operator_verdict_bucket(verdict)
            if bucket == 'launch':
                return 'launch'
            if bucket == 'test':
                return 'test'
        return 'watch'

