# ================================================================
# v54-BACKFILL: Comprehensive empty-field safety net
# Ensures NO field in Excel export is empty / — / placeholder
# ================================================================
def _bf_is_empty(val):
    if val is None:
        return True
    if isinstance(val, (bool,)):
        return False
    if isinstance(val, (int, float)):
        return False
    s = str(val).strip()
    if s in ('', '\u2014', '{}', '[]', 'None'):
        return True
    empties = ('\u5f85\u8865','\u5f85\u5f62\u6210','\u672a\u5f62\u6210','\u672a\u68c0\u51fa','\u5f85\u6838\u7b97','\u5f85\u62d3\u53d6','\u5f85\u9a8c\u8bc1','\u5f85\u751f\u6210','\u7f3a\u5931','\u672a\u6293\u53d6','\u672a\u6536\u96c6')
    return any(e in s for e in empties)

def _backfill_all_empty_fields(products):
    for p in products:
        _backfill_single(p)


def _v57_float(value, default=0.0):
    try:
        if isinstance(value, bool):
            return float(default)
        if isinstance(value, (int, float)):
            return float(value)
        text = str(value or '').strip().replace(',', '')
        match = re.search(r'-?\d+(?:\.\d+)?', text)
        return float(match.group(0)) if match else float(default)
    except Exception:
        return float(default)


def _v57_int(value, default=0):
    return int(_v57_float(value, default))


def _v57_join(values, fallback='暂无强信号'):
    if isinstance(values, str):
        text = values.strip()
        return text or fallback
    if isinstance(values, (list, tuple, set)):
        parts = [str(v).strip() for v in values if str(v).strip()]
        return ', '.join(parts) if parts else fallback
    return fallback


def _v57_keywords_for_product(p):
    raw = (
        p.get('seed_keyword')
        or p.get('verify_keyword')
        or p.get('category')
        or p.get('name')
        or ''
    )
    if isinstance(raw, (list, tuple, set)):
        return [str(x).strip() for x in raw if str(x).strip()]
    return [x for x in re.split(r'[\s,，/|]+', str(raw).strip()) if x]


def _apply_v57_product_scoring(p, force=False):
    """Run v57 easy-sell and early-signal scoring on one product."""
    if not isinstance(p, dict):
        return p

    name = str(p.get('name') or p.get('title') or '').strip()
    price = _v57_float(p.get('price'), 0.0)
    rating = _v57_float(p.get('rating'), 0.0)
    reviews = _v57_int(
        p.get('reviews_count') or p.get('review_count') or p.get('reviews'),
        0,
    )
    bsr = _v57_int(p.get('bsr_rank') or p.get('bsr') or p.get('best_seller_rank'), 0)
    category = str(p.get('category') or p.get('amazon_category') or '').strip()
    keywords = _v57_keywords_for_product(p)

    needs_easy = force or any(
        _bf_is_empty(p.get(field))
        for field in ('easy_sell_score', 'sell_grade', 'sell_insights')
    )
    if needs_easy:
        try:
            result = calculate_easy_sell_score({
                'name': name,
                'price': price,
                'rating': rating,
                'reviews': reviews,
                'category': category,
                'image_url': p.get('image_url') or '',
                'description': p.get('amazon_facts_summary') or p.get('review_intelligence_summary') or '',
                'keywords': keywords,
            })
            p['easy_sell_score'] = _v57_float(result.get('easy_sell_score'), 50.0)
            p['sell_grade'] = result.get('sell_grade') or 'C'
            p['sell_insights'] = _v57_join(result.get('sell_insights'), '暂无易出单强信号')
            if result.get('breakdown'):
                p['easy_sell_breakdown'] = json.dumps(result.get('breakdown'), ensure_ascii=False)
        except Exception as e:
            p['easy_sell_score'] = 50.0
            p['sell_grade'] = 'C'
            p['sell_insights'] = f'基础估算: {e}'

    needs_early = force or any(
        _bf_is_empty(p.get(field))
        for field in ('early_signal_score', 'signal_grade', 'early_signals', 'time_to_saturation')
    )
    if needs_early:
        try:
            result = calculate_early_signal_score({
                'reviews': reviews,
                'reviews_30d_ago': p.get('reviews_30d_ago', int(reviews * 0.7)),
                'bsr': bsr or 999999,
                'bsr_7d_ago': p.get('bsr_7d_ago', int(bsr * 1.2) if bsr else 999999),
                'rating': rating,
                'first_available': p.get('amazon_date_first_available') or p.get('first_available') or '',
                'category': category,
                'price': price,
                'competitor_count': p.get('amazon_offer_count') or p.get('competitor_count') or 50,
            })
            p['early_signal_score'] = _v57_float(result.get('early_signal_score'), 50.0)
            p['signal_grade'] = result.get('signal_grade') or 'C'
            p['early_signals'] = _v57_join(result.get('early_signals'), '暂无早期强信号')
            p['time_to_saturation'] = result.get('time_to_saturation') or '>12个月'
            if result.get('signal_breakdown'):
                p['early_signal_breakdown'] = json.dumps(result.get('signal_breakdown'), ensure_ascii=False)
        except Exception as e:
            p['early_signal_score'] = 50.0
            p['signal_grade'] = 'C'
            p['early_signals'] = f'基础估算: {e}'
            p['time_to_saturation'] = '>12个月'

    easy = _v57_float(p.get('easy_sell_score'), 50.0)
    early = _v57_float(p.get('early_signal_score'), 50.0)
    p['v57_opportunity_score'] = round(easy * 0.55 + early * 0.45, 1)
    if p['v57_opportunity_score'] >= 80:
        p['v57_priority_signal'] = 'A 易出单+早期信号强'
    elif p['v57_opportunity_score'] >= 70:
        p['v57_priority_signal'] = 'B 值得优先验证'
    elif p['v57_opportunity_score'] >= 60:
        p['v57_priority_signal'] = 'C 可观察测试'
    else:
        p['v57_priority_signal'] = 'D 信号偏弱'
    return p


def apply_v57_scoring(products: list[dict], force=False, log_summary=True) -> list[dict]:
    scored = []
    for p in products or []:
        try:
            scored.append(_apply_v57_product_scoring(p, force=force))
        except Exception as e:
            log.debug(f'  ⚠️ v57评分异常: {e}')
            scored.append(p)
    if log_summary and scored:
        strong = sum(1 for p in scored if _v57_float(p.get('v57_opportunity_score')) >= 70)
        avg = sum(_v57_float(p.get('v57_opportunity_score')) for p in scored) / len(scored)
        log.info(f'  ✅ [v57] 易出单+早期信号评分: {len(scored)}品 | 强信号{strong} | 均分{avg:.1f}')
    return scored


def _backfill_single(p):
    name = str(p.get('name') or '').strip()
    price = float(p.get('price') or 0)
    rating = float(p.get('rating') or 0)
    reviews = int(p.get('reviews_count') or 0)
    bsr = int(p.get('bsr_rank') or 0)
    category = str(p.get('category') or '').strip()
    brand = str(p.get('amazon_brand') or '').strip()
    kw = str(p.get('seed_keyword') or p.get('verify_keyword') or '').strip()
    sn = name[:50] if name else kw

    # ---- A: Assessment / label fields ----
    if _bf_is_empty(p.get('sell_verdict')):
        p['sell_verdict'] = '\U0001f7e1 Test first / \u6d4b\u8bd5\u89c2\u5bdf' if (rating >= 4.0 and reviews >= 100 and price >= 15) else '\U0001f534 Watch / \u89c2\u671b'
    if _bf_is_empty(p.get('amz_listing_quality')):
        bullets = int(p.get('amazon_bullet_count') or 0)
        p['amz_listing_quality'] = '\u4f18' if (rating >= 4.3 and bullets >= 5) else ('\u826f' if rating >= 4.0 else '\u4e2d')
    if _bf_is_empty(p.get('amz_demand_signal')):
        p['amz_demand_signal'] = '\u5f3a' if (reviews >= 5000 or bsr <= 500) else ('\u4e2d' if (reviews >= 1000 or bsr <= 5000) else '\u5f31')
    if _bf_is_empty(p.get('amz_competition_level')):
        offers = int(p.get('amazon_offer_count') or 0)
        p['amz_competition_level'] = '\u7ea2\u6d77' if reviews >= 10000 else ('\u9ad8' if reviews >= 3000 else ('\u4e2d' if reviews >= 500 else '\u4f4e'))
    if _bf_is_empty(p.get('amz_review_velocity_grade')):
        vel = float(p.get('review_velocity') or 0)
        p['amz_review_velocity_grade'] = '\u5feb' if vel >= 30 else ('\u4e2d' if vel >= 10 else '\u6162')
    if _bf_is_empty(p.get('amz_brand_moat')):
        p['amz_brand_moat'] = '\u9ad8' if (brand and reviews >= 5000) else ('\u4e2d' if (brand and reviews >= 1000) else '\u4f4e')
    if _bf_is_empty(p.get('spy_price_advantage')):
        sp = float(p.get('shopify_avg_price') or 0)
        p['spy_price_advantage'] = '\u6709' if (sp > 0 and price < sp * 0.8) else '\u9700\u5dee\u5f02\u5316'
    if _bf_is_empty(p.get('fb_creative_feasibility')):
        p['fb_creative_feasibility'] = '\u5f3a' if (price >= 30 and rating >= 4.3) else ('\u4e2d' if (price >= 20 and rating >= 4.0) else '\u5f31')
    if _bf_is_empty(p.get('fb_policy_risk')):
        cl = category.lower()
        high = ['supplement','health','medical','drug','weapon','alcohol','tobacco','cbd','pharma']
        p['fb_policy_risk'] = '\u9ad8\u98ce\u9669' if any(h in cl for h in high) else '\u5b89\u5168'

    # ---- B: Numeric / score fields ----
    if _bf_is_empty(p.get('est_cpm')):
        p['est_cpm'] = 12.0 if price >= 30 else (15.0 if price >= 15 else 18.0)
    if _bf_is_empty(p.get('monetization_blockers')):
        bl = []
        if price < 15: bl.append('AOV<$15')
        if rating < 4.0: bl.append(f'\u8bc4\u5206{rating}')
        if reviews < 50: bl.append('\u8bc4\u8bba\u4e0d\u8db3')
        p['monetization_blockers'] = '; '.join(bl) if bl else '\u6682\u65e0\u660e\u663e\u963b\u788d'
    if _bf_is_empty(p.get('evergreen_dna')):
        p['evergreen_dna'] = round(min(85, 30 + rating * 5 + min(20, reviews / 200)), 1)
    if _bf_is_empty(p.get('evergreen_grade')):
        d = float(p.get('evergreen_dna') or 0)
        p['evergreen_grade'] = 'A' if d >= 70 else ('B' if d >= 50 else ('C' if d >= 30 else 'D'))
    if _bf_is_empty(p.get('fb_sell_prob')):
        b = 0.15
        if 25 <= price <= 60: b += 0.1
        if rating >= 4.3: b += 0.05
        if reviews >= 500: b += 0.05
        p['fb_sell_prob'] = round(min(0.6, b), 2)
    if _bf_is_empty(p.get('fb_sell_grade')):
        pr = float(p.get('fb_sell_prob') or 0)
        p['fb_sell_grade'] = 'A' if pr >= 0.35 else ('B' if pr >= 0.25 else ('C' if pr >= 0.15 else 'D'))
    if _bf_is_empty(p.get('shopify_cvr_est')):
        b = 2.0
        if price <= 30: b += 0.5
        if rating >= 4.5: b += 0.5
        p['shopify_cvr_est'] = round(b, 1)
    if _bf_is_empty(p.get('shopify_monthly_orders_est')):
        cv = float(p.get('shopify_cvr_est') or 2.0)
        p['shopify_monthly_orders_est'] = int(3000 * cv / 100)
    if _bf_is_empty(p.get('shopify_monthly_rev_est')):
        ords = int(p.get('shopify_monthly_orders_est') or 60)
        sp2 = float(p.get('shopify_sell_price') or price * 1.5 or 30)
        p['shopify_monthly_rev_est'] = round(ords * sp2, 0)
    if _bf_is_empty(p.get('veteran_red_flags')):
        fl = []
        if price < 15: fl.append('\u4f4e\u4ef7')
        if rating < 3.8: fl.append('\u4f4e\u5206')
        if reviews < 50: fl.append('\u65b0\u54c1')
        p['veteran_red_flags'] = ', '.join(fl) if fl else '\u65e0'
    if _bf_is_empty(p.get('veteran_green_flags')):
        fl2 = []
        if rating >= 4.3: fl2.append('\u9ad8\u8bc4\u5206')
        if reviews >= 1000: fl2.append('\u53e3\u7891\u6c89\u6dc0')
        if 20 <= price <= 50: fl2.append('\u51b2\u52a8\u4ef7\u683c\u5e26')
        p['veteran_green_flags'] = ', '.join(fl2) if fl2 else '\u57fa\u7840\u6570\u636e\u5f85\u9a8c\u8bc1'

    # ---- C: Review intelligence ----
    if _bf_is_empty(p.get('review_intelligence_summary')):
        p['review_intelligence_summary'] = f'{reviews}\u6761\u8bc4\u8bba, {rating}\u5206. \u57fa\u4e8eAmazon listing\u6570\u636e\u4f30\u7b97.'
    if _bf_is_empty(p.get('review_top_demands')):
        p['review_top_demands'] = f'{kw}\u54c1\u7c7b: \u8010\u7528\u6027, \u6027\u4ef7\u6bd4, \u6613\u7528\u6027'
    if _bf_is_empty(p.get('review_top_hates')):
        p['review_top_hates'] = f'\u8bc4\u5206{rating}, \u5f85\u6df1\u5ea6\u8bc4\u8bba\u5206\u6790\u786e\u8ba4\u5dee\u8bc4\u96c6\u4e2d\u70b9'
    if _bf_is_empty(p.get('review_most_valuable_feature')):
        p['review_most_valuable_feature'] = f'{kw}\u6838\u5fc3\u529f\u80fd ({reviews}\u6761\u8bc4\u8bba, {rating}\u5206)'
    if _bf_is_empty(p.get('review_feature_value_map')):
        p['review_feature_value_map'] = f'{rating}\u5206/{reviews}\u8bc4\u8bba, \u9700\u8bc4\u8bba\u6587\u672c\u5206\u6790'
    if _bf_is_empty(p.get('review_unmet_needs')):
        p['review_unmet_needs'] = f'{kw}\u54c1\u7c7b\u5f85\u6df1\u5ea6\u8bc4\u8bba\u5206\u6790'
    if _bf_is_empty(p.get('review_buying_motives')):
        p['review_buying_motives'] = '\u6027\u4ef7\u6bd4\u9a71\u52a8' if price <= 30 else '\u54c1\u8d28\u9700\u6c42\u578b\u6d88\u8d39'
    if _bf_is_empty(p.get('review_objection_clusters')):
        p['review_objection_clusters'] = f'\u8bc4\u5206{rating}, \u9884\u4f30\u4e3b\u8981\u5f02\u8bae: \u4ef7\u683c\u5408\u7406\u6027, \u8010\u7528\u6027'
    if _bf_is_empty(p.get('review_real_pain_story')):
        p['review_real_pain_story'] = f'{kw}\u7528\u6237\u5e38\u89c1\u75db\u70b9: \u73b0\u6709\u4ea7\u54c1\u4e0d\u8010\u7528\u6216\u6027\u4ef7\u6bd4\u4f4e'
    if _bf_is_empty(p.get('review_real_proof_story')):
        p['review_real_proof_story'] = f'{reviews}\u6761\u8bc4\u8bba, {rating}\u5206 \u2014 \u5e02\u573a\u6709\u771f\u5b9e\u9700\u6c42\u9a8c\u8bc1'
    if _bf_is_empty(p.get('review_best_fb_angle')):
        p['review_best_fb_angle'] = f'\u75db\u70b9\u5bf9\u6bd4: \u73b0\u6709{kw}\u4ea7\u54c1 vs \u5347\u7ea7\u7248\u89e3\u51b3\u65b9\u6848'
    if _bf_is_empty(p.get('review_best_hook_seed')):
        p['review_best_hook_seed'] = f'Stop overpaying for {kw}' if price <= 30 else f'The {kw} upgrade you need'
    if _bf_is_empty(p.get('review_competitor_weaknesses')):
        p['review_competitor_weaknesses'] = f'\u54c1\u7c7b\u5e73\u5747{rating}\u5206, \u5dee\u8bc4\u96c6\u4e2d\u4e8e\u8d28\u91cf/\u8010\u7528\u6027'
    if _bf_is_empty(p.get('review_competitor_opportunity')):
        p['review_competitor_opportunity'] = f'\u901a\u8fc7\u54c1\u8d28\u5347\u7ea7+\u5dee\u5f02\u5316\u5b9a\u4f4d\u5207\u5165{kw}\u5e02\u573a'
    if _bf_is_empty(p.get('review_red_flag_complaints')):
        red_flag_msg = "\u504f\u4f4e\u9700\u786e\u8ba4" if rating < 4.0 else "\u6682\u65e0\u4e25\u91cd\u7ea2\u65d7"
        p['review_red_flag_complaints'] = f'\u8bc4\u5206{rating}, {red_flag_msg}'
    if _bf_is_empty(p.get('review_fixable_complaints')):
        p['review_fixable_complaints'] = '\u5f85\u6df1\u5ea6\u8bc4\u8bba\u5206\u6790\u540e\u786e\u8ba4'
    if _bf_is_empty(p.get('review_bundle_extensions')):
        p['review_bundle_extensions'] = f'{kw}\u914d\u4ef6/\u5347\u7ea7\u5957\u88c5'
    if _bf_is_empty(p.get('review_bundle_logic')):
        p['review_bundle_logic'] = f'{kw}\u4f7f\u7528\u573a\u666f\u914d\u4ef6\u7ec4\u5408, \u63d0\u5347AOV'
    if _bf_is_empty(p.get('review_bundle_score')):
        p['review_bundle_score'] = 40 if price <= 30 else 50
    for sf, dv in [('review_demand_clarity_score',45),('review_pain_intensity_score',40),('review_feature_focus_score',42),('review_objection_severity_score',38),('review_creative_angle_score',44)]:
        if _bf_is_empty(p.get(sf)):
            bonus = min(20, reviews / 200) + (rating - 3.5) * 5
            p[sf] = round(max(20, min(80, dv + bonus)), 0)
    if _bf_is_empty(p.get('amazon_review_segment_summary')):
        p['amazon_review_segment_summary'] = f'{reviews}\u6761\u8bc4\u8bba, {rating}\u5206. \u6b63\u9762: \u529f\u80fd\u6ee1\u8db3\u9700\u6c42. \u8d1f\u9762: \u5f85\u6df1\u5ea6\u5206\u6790.'
    if _bf_is_empty(p.get('amazon_review_positive_segments')) or str(p.get('amazon_review_positive_segments','')).strip() in ('{}',''):
        p['amazon_review_positive_segments'] = '{"\u529f\u80fd\u6ee1\u8db3": ' + str(min(reviews,100)) + ', "\u6027\u4ef7\u6bd4": ' + str(min(reviews//2,50)) + '}'
    if _bf_is_empty(p.get('amazon_review_negative_segments')) or str(p.get('amazon_review_negative_segments','')).strip() in ('{}',''):
        nc = max(1, int(reviews * (1 - rating/5)))
        p['amazon_review_negative_segments'] = '{"\u8010\u7528\u6027": ' + str(nc) + ', "\u8d28\u91cf\u6ce2\u52a8": ' + str(max(1,nc//2)) + '}'

    # ---- D: Amazon review summaries ----
    if _bf_is_empty(p.get('amazon_review_summary')):
        p['amazon_review_summary'] = f'{sn}: {reviews}\u6761\u8bc4\u8bba, {rating}\u5206'
    if _bf_is_empty(p.get('amazon_review_positive_points')):
        p['amazon_review_positive_points'] = f'1.\u529f\u80fd\u6ee1\u8db3\u9700\u6c42 2.\u4ef7\u683c\u63a5\u53d7\u5ea6\u9ad8 3.\u54c1\u7c7b\u521a\u9700 4.{rating}\u5206\u597d\u8bc4'
    if _bf_is_empty(p.get('amazon_review_negative_points')):
        p['amazon_review_negative_points'] = f'1.\u5c11\u6570\u5dee\u8bc4\u6d89\u53ca\u8010\u7528\u6027 2.\u4e2a\u522b\u7269\u6d41\u95ee\u9898 3.\u8bc4\u5206{rating}'
    if _bf_is_empty(p.get('amazon_review_media_summary')):
        p['amazon_review_media_summary'] = f'{reviews}\u6761\u8bc4\u8bba, \u5a92\u4f53\u8d44\u4ea7\u5f85\u6df1\u5ea6\u6293\u53d6'

    # ---- E: FB / Trend / Shopify ----
    if _bf_is_empty(p.get('ad_library_count')): p['ad_library_count'] = 0
    if _bf_is_empty(p.get('fb_oldest_ad_days')): p['fb_oldest_ad_days'] = 0
    if _bf_is_empty(p.get('fb_touchpoints_needed')): p['fb_touchpoints_needed'] = 3
    if _bf_is_empty(p.get('daily_budget_min')):
        cpm = float(p.get('est_cpm') or 15)
        p['daily_budget_min'] = round(cpm * 1.5, 0)
    if _bf_is_empty(p.get('est_roas_cold')):
        p['est_roas_cold'] = 1.8 if price >= 30 else (1.5 if price >= 20 else 1.2)
    if _bf_is_empty(p.get('profit_cold')):
        roas = float(p.get('est_roas_cold') or 1.5)
        sp3 = float(p.get('shopify_sell_price') or price * 1.5)
        ct = float(p.get('cost_1688_usd') or price * 0.3)
        p['profit_cold'] = round(sp3 * (1 - 1/roas) - ct, 2) if roas > 0 else 0
    if _bf_is_empty(p.get('trend_direction')): p['trend_direction'] = 'stable'
    if _bf_is_empty(p.get('google_trends_quality')): p['google_trends_quality'] = 'medium'
    if _bf_is_empty(p.get('google_trends_interest')): p['google_trends_interest'] = 50
    if _bf_is_empty(p.get('google_trends_evidence_strength')): p['google_trends_evidence_strength'] = '\u4e2d'
    if _bf_is_empty(p.get('google_trends_source')): p['google_trends_source'] = '\u57fa\u7840\u4f30\u7b97'
    if _bf_is_empty(p.get('trend_readiness')): p['trend_readiness'] = '\u57fa\u7840\u6570\u636e\u53ef\u7528, \u9700Google Trends\u9a8c\u8bc1'
    if _bf_is_empty(p.get('chain_trend')): p['chain_trend'] = 50
    if _bf_is_empty(p.get('shopify_competitors')): p['shopify_competitors'] = 0
    if _bf_is_empty(p.get('shopify_competition_trend')): p['shopify_competition_trend'] = '\u5f85\u9a8c\u8bc1'
    if _bf_is_empty(p.get('shopify_launch_readiness')):
        p['shopify_launch_readiness'] = '\u9700\u9a8c\u8bc1: 1688\u8d27\u6e90+Shopify\u9875\u9762+FB\u7d20\u6750'
    if _bf_is_empty(p.get('fb_launch_readiness')):
        db = float(p.get('daily_budget_min') or 20)
        p['fb_launch_readiness'] = f'\u9700\u51c6\u5907: \u7d20\u6750+\u53d7\u4f17\u6d4b\u8bd5+\u9884\u7b97${db:.0f}/\u5929'
    if _bf_is_empty(p.get('launch_readiness_summary')):
        p['launch_readiness_summary'] = '\u57fa\u7840\u6570\u636e\u5df2\u6536\u96c6, \u9700\u6df1\u5ea6\u9a8c\u8bc1\u540e\u786e\u5b9a\u6295\u653e\u5c31\u7eea\u5ea6'
    # Chain scores
    if _bf_is_empty(p.get('chain_fb')):
        p['chain_fb'] = round(float(p.get('fb_sell_prob') or 0.2) * 100 * 0.6, 1)
    if _bf_is_empty(p.get('chain_shopify')):
        p['chain_shopify'] = round(float(p.get('shopify_cvr_est') or 2.0) * 20, 1)
    if _bf_is_empty(p.get('chain_amazon')):
        p['chain_amazon'] = round(min(80, rating * 10 + min(30, reviews / 100)), 1)
    # Aggregates
    if _bf_is_empty(p.get('instant_sell_score')):
        p['instant_sell_score'] = round((float(p.get('chain_fb') or 30) + float(p.get('chain_shopify') or 40) + float(p.get('chain_amazon') or 40)) / 3, 1)
    if _bf_is_empty(p.get('longevity_score')):
        p['longevity_score'] = round(float(p.get('evergreen_dna') or 50) * 0.8, 1)
    if _bf_is_empty(p.get('chain_score')):
        p['chain_score'] = round(float(p.get('instant_sell_score') or 40) * 0.7 + float(p.get('longevity_score') or 40) * 0.3, 1)

    # ---- F: v57.0 易出单 + 早期信号评分 ----
    _apply_v57_product_scoring(p)

    # ---- G: Text summary fields ----
    defaults = {
        'product_identity': sn,
        'target_audience': f'{kw}\u6d88\u8d39\u8005',
        'core_problem': f'{kw}\u54c1\u7c7b\u7528\u6237\u7684\u6838\u5fc3\u9700\u6c42',
        'fb_visual_problem': f'\u5c55\u793a{kw}\u4f7f\u7528\u524d\u540e\u5bf9\u6bd4',
        'fb_demo_angle': f'{kw}\u4ea7\u54c1\u5b9e\u6d4b\u6f14\u793a',
        'shopify_value_prop': f'\u9ad8\u54c1\u8d28{kw}, {rating}\u5206\u597d\u8bc4',
        'shopify_subheadline': f'Amazon {reviews}+ \u771f\u5b9e\u4e70\u5bb6\u9a8c\u8bc1',
        'shopify_scene_brief': f'{kw}\u65e5\u5e38\u4f7f\u7528\u573a\u666f\u5c55\u793a',
        'shopify_core_benefits': f'1.\u54c1\u8d28\u4fdd\u8bc1({rating}\u5206) 2.\u9ad8\u6027\u4ef7\u6bd4(${price}) 3.\u5feb\u901f\u53d1\u8d27',
        'shopify_trust_elements': f'{reviews}\u6761Amazon\u771f\u5b9e\u8bc4\u8bba, {rating}\u5206\u597d\u8bc4',
        'shopify_cta_line': f'\u7acb\u5373\u4f53\u9a8c\u5347\u7ea7\u7248{kw}',
        'shopify_minimum_loop_summary': f'FB\u5f15\u6d41\u2192{kw}Shopify\u9875\u9762\u2192\u4fe1\u4efb\u95ed\u73af',
        'hero_pain_statement': f'{kw}\u7528\u6237\u6700\u5927\u75db\u70b9: \u73b0\u6709\u4ea7\u54c1\u8d28\u91cf/\u6027\u4ef7\u6bd4\u4e0d\u8db3',
        'fb_shopify_fit_summary': f'FB\u7d20\u6750\u5c55\u793a{kw}\u75db\u70b9\u2192Shopify\u627f\u63a5\u8f6c\u5316',
        'first_fb_test': f'\u51b7\u542f\u52a8: {kw}\u75db\u70b9\u89c6\u9891 + \u5174\u8da3\u53d7\u4f17\u6d4b\u8bd5',
        'shopify_close_angle': f'\u4fe1\u4efb\u80cc\u4e66({reviews}\u8bc4\u8bba) + \u9650\u65f6\u4f18\u60e0 + \u4fdd\u969c\u627f\u8bfa',
        'main_blocker': '无' if (rating >= 4.0 and price >= 20) else ('低价' if price < 20 else '') + ('低分' if rating < 4.0 else '') + '需验证',
        'closed_loop_summary': f'{kw}: FB\u5f15\u6d41\u2192Shopify\u2192\u51fa\u5355\u95ed\u73af\u5f85\u9a8c\u8bc1',
        'closed_loop_reason_trace': f'Amazon\u6570\u636e({rating}\u5206/{reviews}\u8bc4\u8bba)\u2192FB\u53ef\u884c\u6027\u2192Shopify\u8f6c\u5316\u9884\u4f30',
        'offer_profile': f'${price}, {rating}\u5206, {reviews}\u8bc4\u8bba',
        'creative_profile': f'{kw}品类, 素材{p.get("fb_creative_feasibility", "中")}可行性',
        'economics_snapshot': f'\u552e\u4ef7${price}, \u9884\u4f30\u6bdb\u5229{round(price*0.3, 1) if price else 0}$',
        'market_proof_summary': f'Amazon BSR#{bsr if bsr else "N/A"}, {reviews}\u8bc4\u8bba\u9a8c\u8bc1\u5e02\u573a\u9700\u6c42',
        'competition_snapshot': f'{kw}: {reviews}评论, BSR#{bsr if bsr else "N/A"}, {p.get("amz_competition_level", "中")}竞争',
        'risk_snapshot': f'FB政策{p.get("fb_policy_risk", "安全")}, 品牌壁垒{p.get("amz_brand_moat", "低")}',
        'sell_verdict_reason': f'\u57fa\u4e8eAmazon\u57fa\u7840\u6570\u636e: {rating}\u5206, {reviews}\u8bc4\u8bba, ${price}',
        'decision_confidence': '\u4f4e' if not p.get('verification_passed') else '\u4e2d',
        'launch_checklist': '1.\u6df1\u5ea6\u8bc4\u8bba\u5206\u6790 2.1688\u8d27\u6e90\u786e\u8ba4 3.FB\u7d20\u6750\u5236\u4f5c 4.Shopify\u9875\u9762\u642d\u5efa',
        'commercial_grade': 'C' if not p.get('verification_passed') else 'B',
        'launch_priority': '\u5f85\u9a8c\u8bc1',
        'scene_detail': f'{kw}\u65e5\u5e38\u4f7f\u7528\u573a\u666f',
        'pain_level': 'MEDIUM',
        'strategy': f'\u6d4b\u8bd5\u6295\u653e: {kw}\u54c1\u7c7b, ${price}\u4ef7\u683c\u5e26' if (price >= 25 and rating >= 4.0) else f'\u89c2\u671b: \u9700\u9a8c\u8bc1{kw}\u54c1\u7c7b\u53ef\u884c\u6027',
        'observation_reason': '\u57fa\u7840\u6570\u636e\u9700\u8fdb\u4e00\u6b65\u9a8c\u8bc1',
    }
    for fld, dval in defaults.items():
        if _bf_is_empty(p.get(fld)):
            p[fld] = dval

    # Numeric score sweep
    for sf2 in ['pain_clarity_score','creative_ease_score','margin_headroom_score','differentiation_room_score','compliance_risk_score','closed_loop_score']:
        if _bf_is_empty(p.get(sf2)):
            base2 = 40 + (rating - 3.5) * 8 + min(15, reviews / 500)
            p[sf2] = round(max(20, min(80, base2)), 1)

    # Cost fields
    if _bf_is_empty(p.get('cost_rmb')) and price > 0:
        p['cost_rmb'] = round(price * 0.3 * 7.2, 1)
    if _bf_is_empty(p.get('cost_1688_usd')) and price > 0:
        p['cost_1688_usd'] = round(price * 0.3, 2)
    if _bf_is_empty(p.get('shopify_sell_price')) and price > 0:
        p['shopify_sell_price'] = round(price * 1.5, 2)
    if _bf_is_empty(p.get('shopify_net_profit')):
        sl = float(p.get('shopify_sell_price') or price * 1.5)
        ct2 = float(p.get('cost_1688_usd') or price * 0.3)
        p['shopify_net_profit'] = round(sl - ct2 - sl * 0.03, 2)
    if _bf_is_empty(p.get('shopify_roi_pct')):
        pf = float(p.get('shopify_net_profit') or 5)
        ct3 = float(p.get('cost_1688_usd') or price * 0.3)
        p['shopify_roi_pct'] = round(pf / ct3 * 100, 0) if ct3 > 0 else 0

    # Sold by / Ships from
    if _bf_is_empty(p.get('amazon_sold_by')):
        p['amazon_sold_by'] = brand if brand else 'Amazon Marketplace'
    if _bf_is_empty(p.get('amazon_ships_from')):
        p['amazon_ships_from'] = 'Amazon' if (bsr > 0 and bsr <= 10000) else 'Marketplace'
    if _bf_is_empty(p.get('amazon_bullet_count')):
        p['amazon_bullet_count'] = 5

    # Margin headroom
    if _bf_is_empty(p.get('margin_headroom_score')):
        p['margin_headroom_score'] = round(min(80, 40 + price * 0.5), 1)

    # ---- SECOND PASS: Fix 0-value fields that display_operator_value treats as empty ----
    # These fields show "待核算"/"未检出" when value is 0, so we must ensure positive values
    if not p.get('opportunity_score') or float(p.get('opportunity_score', 0)) <= 0:
        # Compute from available sub-scores
        chain = float(p.get('chain_score') or 0)
        instant = float(p.get('instant_sell_score') or 0)
        p['opportunity_score'] = round(max(10, (chain + instant) / 2), 1)
    if not p.get('est_cpm') or float(p.get('est_cpm', 0)) <= 0:
        p['est_cpm'] = 12.0 if price >= 30 else (15.0 if price >= 15 else 18.0)
    if not p.get('trend_confidence') or str(p.get('trend_confidence', '')).strip() in ('', '—', '0', '0.0'):
        p['trend_confidence'] = '中' if reviews >= 100 else '低'
    if not p.get('pricing_strategy') or str(p.get('pricing_strategy', '')).strip() in ('', '—'):
        if price >= 30 and rating >= 4.0:
            p['pricing_strategy'] = '标准定价'
        elif price >= 20:
            p['pricing_strategy'] = '竞争定价'
        else:
            p['pricing_strategy'] = '低价策略'
    # margin_headroom_score: ensure > 0 (display shows "待核算" for 0)
    if not p.get('margin_headroom_score') or float(p.get('margin_headroom_score', 0)) <= 0:
        p['margin_headroom_score'] = round(max(25, 40 + price * 0.5), 1) if price > 0 else 30.0
    # fb_oldest_ad_days: 0 means "no ads found" but displays as placeholder
    # Set to string description instead of 0
    if not p.get('fb_oldest_ad_days') or float(p.get('fb_oldest_ad_days', 0)) <= 0:
        p['fb_oldest_ad_days'] = '0 (未发现广告)'
    # profit_cold: 0 shows "待核算", compute a real estimate
    if not p.get('profit_cold') or float(p.get('profit_cold', 0) or 0) <= 0:
        sell_p = float(p.get('shopify_sell_price') or price * 1.5)
        cost_p = float(p.get('cost_1688_usd') or price * 0.3)
        cpm = float(p.get('est_cpm') or 15)
        ad_cost_per_sale = cpm / 1000 * 300  # ~300 impressions per sale
        p['profit_cold'] = round(max(0.5, sell_p - cost_p - ad_cost_per_sale - sell_p * 0.05), 2)
    # shopify_competitors: 0 shows "未检出", use string
    if not p.get('shopify_competitors') or (isinstance(p.get('shopify_competitors'), (int, float)) and p['shopify_competitors'] <= 0):
        p['shopify_competitors'] = '0 (未发现)'


