    columns = _export_columns_with_data(columns, products)

    # 样式
    fill_green = PatternFill(start_color="C6EFCE", end_color="C6EFCE", fill_type="solid")
    fill_yellow = PatternFill(start_color="FFEB9C", end_color="FFEB9C", fill_type="solid")
    fill_red = PatternFill(start_color="FFC7CE", end_color="FFC7CE", fill_type="solid")
    fill_header = PatternFill(start_color="4472C4", end_color="4472C4", fill_type="solid")
    font_header = Font(name="Calibri", size=11, bold=True, color="FFFFFF")
    font_normal = Font(name="Calibri", size=10)
    font_link = Font(name="Calibri", size=10, color="2563EB", underline="single")
    border_thin = Border(
        left=Side(style="thin"), right=Side(style="thin"),
        top=Side(style="thin"), bottom=Side(style="thin"),
    )
    align_center = Alignment(horizontal="center", vertical="center", wrap_text=False)
    align_left = Alignment(horizontal="left", vertical="center", wrap_text=True)
    for col_idx, (_, header, width) in enumerate(columns, 1):
        cell = ws.cell(row=1, column=col_idx, value=header)
        cell.font = font_header; cell.fill = fill_header
        cell.alignment = align_center; cell.border = border_thin
        ws.column_dimensions[get_column_letter(col_idx)].width = width
    # 排序: 总分降序 → 价格降序
    sorted_products = sorted(products, key=lambda x: (
        1 if str(x.get("sell_verdict", "")).startswith("🟢") else 0,
        1 if x.get("verification_passed") else 0,
        x.get("instant_sell_score", 0),
        x.get("chain_score", 0),
        x.get("v57_opportunity_score", 0),
        x.get("easy_sell_score", 0),
        x.get("early_signal_score", 0),
        x.get("validation_priority_score", 0),
        x.get("total_score", 0),
        x.get("price", 0),
    ), reverse=True)
    # 写数据行
    for row_idx, p in enumerate(sorted_products, 2):
        for col_idx, (field, _, _) in enumerate(columns, 1):
            val = display_operator_value(field, p)
            cell = ws.cell(row=row_idx, column=col_idx, value=val)
            cell.font = font_normal
