# ===== v34.0 安全取值工具函数 =====
# 替代 390+ 处散乱的 _safe_float(p.get('x')) 模式

def _safe_float(val, default=0.0):
    """安全提取 float，None/空字符串/异常 → default"""
    if val is None or val == '':
        return default
    try:
        # 先转字符串，提取开头的数字部分（处理 "0 (未发现广告)" 这种格式）
        s = str(val).strip()
        # 提取开头的数字（包括负号和小数点）
        import re
        match = re.match(r'^-?\d+\.?\d*', s)
        if match:
            return float(match.group())
        return float(val)
    except (ValueError, TypeError):
        return default


def _safe_int(val, default=0):
    """安全提取 int，None/空字符串/异常 → default"""
    if val is None or val == '':
        return default
    try:
        # 先转字符串，提取开头的数字部分（处理 "0 (未发现广告)" 这种格式）
        s = str(val).strip()
        # 提取开头的数字（包括负号和小数点）
        import re
        match = re.match(r'^-?\d+\.?\d*', s)
        if match:
            return int(float(match.group()))
        return int(float(val))
    except (ValueError, TypeError):
        return default


def _safe_str(val, default=''):
    """安全提取 str，None → default，并 strip"""
    if val is None:
        return default
    return str(val).strip()


