class SmartFilterRules:
    """
    v33.0: 智能筛选规则
    基于数据驱动洞见: 低价产品验证ROI低, 高价产品竞争大, 中间价格带最优
    """

    # ===== 价格带筛选 =====
    @staticmethod
    def is_price_ideal(price: float) -> bool:
        """判断价格是否在理想区间 (35-120)"""
        return CommercialConfig.PRICE_IDEAL_MIN <= price <= CommercialConfig.PRICE_IDEAL_MAX

    @staticmethod
    def is_price_impulse(price: float) -> bool:
        """判断是否冲动消费价格"""
        return 20 <= price <= 80

    @staticmethod
    def is_price_premium(price: float) -> bool:
        """判断是否为高端价格"""
        return price > 150

    # ===== BSR 排名筛选 =====
    @staticmethod
    def is_bsr_top(bsr_rank: int) -> bool:
        """判断BSR是否在前500"""
        return 0 < bsr_rank <= CommercialConfig.BSR_RANK_TOP_THRESHOLD

    @staticmethod
    def is_bsr_mid(bsr_rank: int) -> bool:
        """判断BSR是否在中等区间"""
        return CommercialConfig.BSR_RANK_TOP_THRESHOLD < bsr_rank <= CommercialConfig.BSR_RANK_MID_THRESHOLD

    # ===== 评论速度筛选 =====
    @staticmethod
    def is_review_velocity_high(rev_vel: float) -> bool:
        """判断评论增长速度是否高"""
        return rev_vel >= CommercialConfig.REVIEW_VELOCITY_HIGH

    @staticmethod
    def is_review_velocity_mid(rev_vel: float) -> bool:
        """判断评论增长速度是否中等"""
        return CommercialConfig.REVIEW_VELOCITY_MID <= rev_vel < CommercialConfig.REVIEW_VELOCITY_HIGH

    # ===== 评分筛选 =====
    @staticmethod
    def is_rating_good(rating: float) -> bool:
        """判断评分是否良好"""
        return rating >= CommercialConfig.RATING_GOOD

    # ===== 竞争筛选 =====
    @staticmethod
    def is_competition_ideal(offer_count: int) -> bool:
        """判断竞争是否在理想区间"""
        return CommercialConfig.OFFER_COUNT_IDEAL_MIN <= offer_count <= CommercialConfig.OFFER_COUNT_IDEAL_MAX

    @staticmethod
    def is_competition_low(offer_count: int) -> bool:
        """判断竞争是否低 (蓝海信号)"""
        return 0 < offer_count < CommercialConfig.OFFER_COUNT_IDEAL_MIN

    @staticmethod
    def is_competition_high(offer_count: int) -> bool:
        """判断竞争是否过高"""
        return offer_count > CommercialConfig.OFFER_COUNT_IDEAL_MAX

    # ===== 综合筛选 =====
    @staticmethod
    def get_product_quality_score(p: dict) -> float:
        """
        计算产品质量分数 (0-100)
        基于多个维度的加权评估
        """
        score = 0.0

        # 价格得分 (25%)
        price = _safe_float(p.get('price'))
        if SmartFilterRules.is_price_ideal(price):
            score += 25
        elif SmartFilterRules.is_price_impulse(price):
            score += 15
        elif price > 0:
            score += 5

        # BSR得分 (25%)
        bsr = _safe_int(p.get('bsr_rank'))
        if SmartFilterRules.is_bsr_top(bsr):
            score += 25
        elif SmartFilterRules.is_bsr_mid(bsr):
            score += 15
        elif bsr > 0:
            score += 5

        # 评分得分 (15%)
        rating = _safe_float(p.get('rating'))
        if SmartFilterRules.is_rating_good(rating):
            score += 15
        elif rating >= 4.0:
            score += 10
        elif rating > 0:
            score += 5

        # 评论速度得分 (15%)
        rev_vel = _safe_float(p.get('review_velocity'))
        if SmartFilterRules.is_review_velocity_high(rev_vel):
            score += 15
        elif SmartFilterRules.is_review_velocity_mid(rev_vel):
            score += 10
        elif rev_vel > 0:
            score += 5

        # 竞争得分 (10%)
        offers = _safe_int(p.get('amazon_offer_count'))
        if SmartFilterRules.is_competition_ideal(offers):
            score += 10
        elif SmartFilterRules.is_competition_low(offers):
            score += 8
        elif offers > 0:
            score += 3

        # 评论数量加分 (10%)
        reviews = _safe_int(p.get('reviews_count'))
        if reviews >= 500:
            score += 10
        elif reviews >= 100:
            score += 7
        elif reviews >= 30:
            score += 4
        elif reviews > 0:
            score += 2

        return score

    @staticmethod
    def should_verify_product(p: dict) -> tuple[bool, str]:
        """
        判断产品是否值得验证
        返回: (是否验证, 原因)
        """
        # 缺失关键字段
        if not p.get('asin'):
            return False, 'Missing ASIN'
        if not p.get('name'):
            return False, 'Missing name'

        # 价格异常
        price = _safe_float(p.get('price'))
        if price <= 0:
            return False, 'No price'
        if price < 15:
            return False, 'Price too low (<$15)'

        # BSR过差
        bsr = _safe_int(p.get('bsr_rank'))
        if bsr > 100000:
            return False, 'BSR too low (>100k)'

        # 产品质量分数过低
        quality_score = SmartFilterRules.get_product_quality_score(p)
        if quality_score < 35:
            return False, f'Low quality score ({quality_score:.0f})'

        return True, 'OK'


SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))


class ExpertSelectionEngine:
    """
    v33.0: 深度数据分析引擎
    将资深选品专家的直觉判断转化为可量化的决策模型
    """

    # ===== 30年经验核心洞察 =====

    # 1. 品类生命周期判断
    CATEGORY_LIFECYCLE_BONUS = {
        'emerging': 15,   # 新兴品类: 增长快, 竞争少
        'growth': 12,     # 成长品类: 需求上升, 利润好
        'mature': 5,     # 成熟品类: 稳定但竞争激烈
        'declining': -20,# 衰退品类: 趋势向下, 避开
    }

    # 2. 价格带利润分析
    PRICE_MARGIN_MAP = {
        (0, 25): {'margin_score': 8, 'note': '低价走量'},
        (25, 50): {'margin_score': 15, 'note': '最佳利润区间'},
        (50, 80): {'margin_score': 20, 'note': '高利润区间'},
        (80, 120): {'margin_score': 18, 'note': '中高利润'},
        (120, 200): {'margin_score': 12, 'note': '高单价低周转'},
        (200, 9999): {'margin_score': 5, 'note': '高端市场窄'},
    }

    # 3. 风险矩阵权重
    RISK_WEIGHTS = {
        'policy': 1.5,      # 政策风险权重最高
        'competition': 1.2, # 竞争风险
        'supply': 1.1,      # 供应链风险
        'trend': 1.0,       # 趋势风险
        'copy': 1.0,        # 抄袭风险
    }

    # 4. 选品漏斗阈值
    FUNNEL_THRESHOLDS = {
        'stage1_bsr': 2000,    # 第一关: BSR前2000
        'stage2_rating': 4.2,   # 第二关: 评分>4.2
        'stage3_velocity': 15, # 第三关: 月增速>15
        'stage4_offers': 35,   # 第四关: offer<35
        'stage5_price': (30, 150), # 第五关: 价格区间
        'stage6_reviews': 50,   # 第六关: 基础评论数
    }

    @staticmethod
    def get_category_lifecycle(p: dict) -> str:
        """
        30年经验: 判断品类所处生命周期
        依据: 趋势方向 + BSR变化 + 评论增速
        """
        trend = _safe_str(p.get('trend_direction'))
        rev_vel = _safe_float(p.get('review_velocity'))
        bsr = _safe_int(p.get('bsr_rank'))

        # 新兴品类: 趋势向上 + 高增速 + BSR不太高(说明还在增长)
        if trend in ('↑', '↗', '↑↑') and rev_vel > 25 and bsr > 5000:
            return 'emerging'
        # 成长品类: 稳定增长
        elif trend in ('↑', '↗') and rev_vel > 10:
            return 'growth'
        # 衰退品类: 趋势向下
        elif trend in ('↓', '↓↓', '↘'):
            return 'declining'
        # 成熟品类: 默认
        else:
            return 'mature'

    @staticmethod
    def get_margin_profile(price: float) -> dict:
        """30年经验: 根据价格获取利润画像"""
        for (low, high), profile in ExpertSelectionEngine.PRICE_MARGIN_MAP.items():
            if low <= price < high:
                return profile
        return {'margin_score': 5, 'note': '价格异常'}

    @staticmethod
    def compute_expert_score(p: dict) -> tuple[float, list[str]]:
        """
        30年经验: 综合专家评分
        返回: (分数, 原因列表)
        """
        score = 0.0
        reasons = []

        # ===== 品类生命周期 (20%) =====
        lifecycle = ExpertSelectionEngine.get_category_lifecycle(p)
        lifecycle_bonus = ExpertSelectionEngine.CATEGORY_LIFECYCLE_BONUS.get(lifecycle, 0)
        score += lifecycle_bonus * 0.20
        if lifecycle_bonus != 0:
            reasons.append(f'品类周期:{lifecycle}({lifecycle_bonus:+.0f})')

        # ===== 漏斗筛选 (30%) =====
        funnel_passed = ExpertSelectionEngine.count_funnel_stages(p)
        funnel_score = funnel_passed * 6  # 每关6分, 满分30
        score += funnel_score
        if funnel_passed >= 4:
            reasons.append(f'漏斗通过{funnel_passed}/6关(+{funnel_score:.0f})')

        # ===== 利润潜力 (20%) =====
        price = _safe_float(p.get('price'))
        margin_profile = ExpertSelectionEngine.get_margin_profile(price)
        margin_score = margin_profile['margin_score']
        score += margin_score
        reasons.append(f"价格带:{margin_profile['note']}(+{margin_score})")

        # ===== 风险调整 (15%) =====
        risk_penalty = ExpertSelectionEngine.compute_risk_penalty(p)
        score -= risk_penalty
        if risk_penalty > 0:
            reasons.append(f'风险扣分(-{risk_penalty:.0f})')

        # ===== 专家直觉加分 (15%) =====
        intuition_bonus = ExpertSelectionEngine.compute_intuition_bonus(p)
        score += intuition_bonus
        if intuition_bonus > 0:
            reasons.append(f'专家直觉(+{intuition_bonus:.0f})')

        return max(0, min(100, score)), reasons

    @staticmethod
    def count_funnel_stages(p: dict) -> int:
        """30年经验: 计算漏斗通过关卡数"""
        t = ExpertSelectionEngine.FUNNEL_THRESHOLDS
        passed = 0

        # Stage 1: BSR
        bsr = _safe_int(p.get('bsr_rank'))
        if 0 < bsr <= t['stage1_bsr']:
            passed += 1

        # Stage 2: Rating
        rating = _safe_float(p.get('rating'))
        if rating >= t['stage2_rating']:
            passed += 1

        # Stage 3: Review Velocity
        rev_vel = _safe_float(p.get('review_velocity'))
        if rev_vel >= t['stage3_velocity']:
            passed += 1

        # Stage 4: Offer Count
        offers = _safe_int(p.get('amazon_offer_count'))
        if 0 < offers < t['stage4_offers']:
            passed += 1

        # Stage 5: Price Range
        price = _safe_float(p.get('price'))
        if t['stage5_price'][0] <= price <= t['stage5_price'][1]:
            passed += 1

        # Stage 6: Reviews
        reviews = _safe_int(p.get('reviews_count'))
        if reviews >= t['stage6_reviews']:
            passed += 1

        return passed

    @staticmethod
    def compute_risk_penalty(p: dict) -> float:
        """30年经验: 计算综合风险扣分"""
        penalty = 0.0

        # 政策风险
        policy = _safe_str(p.get('fb_policy_risk')).lower()
        if 'high' in policy:
            penalty += 12 * ExpertSelectionEngine.RISK_WEIGHTS['policy']
        elif 'medium' in policy:
            penalty += 6 * ExpertSelectionEngine.RISK_WEIGHTS['policy']

        # 竞争风险
        competition = _safe_str(p.get('amz_competition_level')).lower()
        if 'high' in competition or 'crowded' in competition:
            penalty += 8 * ExpertSelectionEngine.RISK_WEIGHTS['competition']
        elif 'medium' in competition:
            penalty += 4 * ExpertSelectionEngine.RISK_WEIGHTS['competition']

        # 趋势风险
        trend = _safe_str(p.get('trend_direction'))
        if trend in ('↓', '↓↓'):
            penalty += 10 * ExpertSelectionEngine.RISK_WEIGHTS['trend']

        # 供应链风险 (通过offer数量异常判断)
        offers = _safe_int(p.get('amazon_offer_count'))
        if offers > 100:
            penalty += 5 * ExpertSelectionEngine.RISK_WEIGHTS['supply']

        return penalty

    @staticmethod
    def compute_intuition_bonus(p: dict) -> float:
        """
        30年经验: 专家直觉加分项
        这些是基于大量案例总结的"第六感"信号
        """
        bonus = 0.0

        # 信号1: 有Before/After素材 (转化率保障)
        if p.get('has_before_after'):
            bonus += 8

        # 信号2: 有视频 (内容营销基础)
        if p.get('amazon_has_video') or p.get('visual_demo'):
            bonus += 6

        # 信号3: 评论带图/视频 (用户认可)
        media_count = len(p.get('amazon_review_media') or [])
        if media_count >= 3:
            bonus += 5

        # 信号4: BSR在涨 (动态需求)
        bsr_change = _safe_str(p.get('bsr_change_30d'))
        if 'up' in bsr_change.lower() or '↑' in bsr_change:
            bonus += 7

        # 信号5: 差评集中在物流/包装 (产品本身OK)
        negative_rate = _safe_float(p.get('negative_review_rate'))
        if negative_rate < 0.15:
            bonus += 4

        # 信号6: 有差异化描述
        differentiation = _safe_str(p.get('spy_differentiation'))
        if differentiation and len(differentiation) > 10:
            bonus += 4

        # 信号7: 品牌护城河
        brand_moat = _safe_str(p.get('amz_brand_moat')).lower()
        if brand_moat in ('strong', '强', 'high'):
            bonus += 6

        return bonus

    @staticmethod
    def make_selection_decision(p: dict) -> dict:
        """
        30年经验: 最终选品决策
        返回决策框架
        """
        expert_score, reasons = ExpertSelectionEngine.compute_expert_score(p)
        funnel_passed = ExpertSelectionEngine.count_funnel_stages(p)

        # 决策逻辑
        if expert_score >= 70 and funnel_passed >= 5:
            decision = '立即测试'
            priority = 'S'
        elif expert_score >= 55 and funnel_passed >= 4:
            decision = '值得验证'
            priority = 'A'
        elif expert_score >= 40 and funnel_passed >= 3:
            decision = '观察等待'
            priority = 'B'
        else:
            decision = '建议放弃'
            priority = 'C'

        return {
            'expert_selection_score': round(expert_score, 1),
            'expert_decision': decision,
            'expert_priority': priority,
            'funnel_stages_passed': funnel_passed,
            'expert_reasons': ' | '.join(reasons[:5]),
        }


class RiskAssessmentModel:
    """
    v26.0: 专业风险评估模型
    30年经验: 选品失败80%是因为风险评估不足
    """

    @staticmethod
    def assess_market_risk(p: dict) -> dict:
        """市场风险评估"""
        risk_score = 0
        factors = []

        # 竞争激烈度
        offers = _safe_int(p.get('amazon_offer_count'))
        if offers > 50:
            risk_score += 25
            factors.append(f'竞争激烈({offers}offer)')
        elif offers > 30:
            risk_score += 15
            factors.append(f'中度竞争({offers}offer)')

        # 趋势向下
        trend = _safe_str(p.get('trend_direction'))
        if trend in ('↓', '↓↓'):
            risk_score += 30
            factors.append('趋势下行')

        # 价格战风险
        price = _safe_float(p.get('price'))
        if price < 25:
            risk_score += 15
            factors.append('低价易价格战')

        # 头部集中度 (通过评论分布判断)
        reviews = _safe_int(p.get('reviews_count'))
        if reviews > 1000:
            risk_score += 10
            factors.append('头部固化')

        return {
            'market_risk_score': min(100, risk_score),
            'market_risk_factors': factors,
        }

    @staticmethod
    def assess_execution_risk(p: dict) -> dict:
        """执行风险评估"""
        risk_score = 0
        factors = []

        # 素材难度
        if not p.get('has_before_after'):
            risk_score += 15
            factors.append('缺对比素材')

        if not p.get('amazon_has_video'):
            risk_score += 10
            factors.append('缺视频素材')

        # 内容创作难度
        creative_ease = _safe_float(p.get('creative_ease_score'))
        if creative_ease < 40:
            risk_score += 20
            factors.append(f'创意难度高({creative_ease:.0f})')

        # 落地页难度
        landing_score = _safe_float(p.get('pdp_build_score'))
        if landing_score < 40:
            risk_score += 15
            factors.append(f'落地页难做({landing_score:.0f})')

        return {
            'execution_risk_score': min(100, risk_score),
            'execution_risk_factors': factors,
        }

    @staticmethod
    def assess_policy_risk(p: dict) -> dict:
        """政策合规风险"""
        risk_score = 0
        factors = []

        # FB政策风险
        policy = _safe_str(p.get('fb_policy_risk')).lower()
        if 'high' in policy:
            risk_score += 40
            factors.append('FB高风险')
        elif 'medium' in policy:
            risk_score += 20
            factors.append('FB中风险')

        # 品类敏感度
        category = _safe_str(p.get('category')).lower()
        sensitive_cats = ['health', 'beauty', 'supplement', 'food', 'toy']
        if any(c in category for c in sensitive_cats):
            risk_score += 15
            factors.append('敏感品类')

        return {
            'policy_risk_score': min(100, risk_score),
            'policy_risk_factors': factors,
        }

    @staticmethod
    def assess_all_risks(p: dict) -> dict:
        """综合风险评估"""
        market = RiskAssessmentModel.assess_market_risk(p)
        execution = RiskAssessmentModel.assess_execution_risk(p)
        policy = RiskAssessmentModel.assess_policy_risk(p)

        # 权重计算总分
        total_risk = (
            market['market_risk_score'] * 0.4 +
            execution['execution_risk_score'] * 0.35 +
            policy['policy_risk_score'] * 0.25
        )

        return {
            'total_risk_score': round(total_risk, 1),
            'risk_level': '高' if total_risk > 60 else '中' if total_risk > 35 else '低',
            **market,
            **execution,
            **policy,
        }


class TrendPredictionEngine:
    """
    v33.0: 趋势预测引擎
    30年经验: 趋势预测不是算命,而是基于历史数据的科学推断
    """

    # 趋势加速度阈值
    TREND_ACCELERATION = {
        'exploding': {'velocity_min': 50, 'days': 30, 'bonus': 20},
        'growing': {'velocity_min': 25, 'days': 60, 'bonus': 12},
        'stable': {'velocity_min': 10, 'days': 90, 'bonus': 5},
        'declining': {'velocity_min': 0, 'days': 0, 'penalty': -15},
    }

    @staticmethod
    def predict_momentum(p: dict) -> dict:
        """
        预测产品动量趋势
        基于: 评论增速 + BSR变化 + Google Trends斜率
        """
        rev_vel = _safe_float(p.get('review_velocity'))
        bsr = _safe_int(p.get('bsr_rank'))
        trend_dir = _safe_str(p.get('trend_direction'))
        trend_interest = _safe_float(p.get('google_trends_interest'))

        # 动量评分
        momentum_score = 0

        # 评论增速贡献
        if rev_vel > 50:
            momentum_score += 30
        elif rev_vel > 25:
            momentum_score += 20
        elif rev_vel > 10:
            momentum_score += 10
        elif rev_vel > 0:
            momentum_score += 5
        else:
            momentum_score -= 10

        # 趋势方向贡献
        if trend_dir in ('↑↑', '↑'):
            momentum_score += 25
        elif trend_dir == '↗':
            momentum_score += 15
        elif trend_dir in ('↘', '↓'):
            momentum_score -= 20
        elif trend_dir == '↓↓':
            momentum_score -= 30

        # Google Trends热度贡献
        if trend_interest > 70:
            momentum_score += 15
        elif trend_interest > 50:
            momentum_score += 10
        elif trend_interest > 30:
            momentum_score += 5
        elif trend_interest > 0:
            momentum_score += 2

        # BSR贡献 (BSR越低越好)
        if bsr > 0 and bsr < 1000:
            momentum_score += 20
        elif bsr > 0 and bsr < 5000:
            momentum_score += 10
        elif bsr > 0 and bsr < 20000:
            momentum_score += 5

        # 预测结论
        if momentum_score >= 70:
            prediction = '爆品潜力'
            action = '立即测试'
        elif momentum_score >= 45:
            prediction = '增长趋势'
            action = '值得验证'
        elif momentum_score >= 20:
            prediction = '稳定需求'
            action = '观察等待'
        else:
            prediction = '趋势不明'
            action = '建议放弃'

        return {
            'momentum_score': round(momentum_score, 1),
            'trend_prediction': prediction,
            'recommended_action': action,
        }

    @staticmethod
    def calculate_trend_confidence(p: dict) -> float:
        """
        计算趋势预测置信度
        数据点越多,置信度越高
        """
        confidence = 0.0

        # 有Google Trends数据
        if p.get('google_trends_sufficient'):
            confidence += 30

        # 有BSR数据
        if p.get('bsr_rank', 0) > 0:
            confidence += 20

        # 有评论增速
        if p.get('review_velocity', 0) > 0:
            confidence += 25

        # 有历史销售数据
        if p.get('amazon_sales_est_monthly', 0) > 0:
            confidence += 15

        # 有趋势方向
        if p.get('trend_direction'):
            confidence += 10

        return min(100, confidence)


class CompetitorAnalysisEngine:
    """
    v33.0: 竞品分析引擎
    30年经验: 了解竞争对手是为了避开红海,找到差异化空间
    """

    @staticmethod
    def analyze_market_position(p: dict) -> dict:
        """
        分析市场定位
        返回: 竞争优势/劣势/机会
        """
        offers = _safe_int(p.get('amazon_offer_count'))
        reviews = _safe_int(p.get('reviews_count'))
        rating = _safe_float(p.get('rating'))
        price = _safe_float(p.get('price'))
        brand_moat = _safe_str(p.get('amz_brand_moat')).lower()

        analysis = {
            'strengths': [],
            'weaknesses': [],
            'opportunities': [],
        }

        # 竞争优势
        if rating >= 4.5:
            analysis['strengths'].append('高评分口碑好')
        if reviews >= 500:
            analysis['strengths'].append('市场验证充分')
        if brand_moat in ('strong', '强'):
            analysis['strengths'].append('品牌护城河强')
        if offers < 15:
            analysis['strengths'].append('竞争者少')

        # 竞争劣势
        if offers > 50:
            analysis['weaknesses'].append('红海市场')
        if reviews < 50:
            analysis['weaknesses'].append('缺乏市场验证')
        if rating < 4.0:
            analysis['weaknesses'].append('口碑风险')
        if price < 20:
            analysis['weaknesses'].append('价格战风险')

        # 机会点
        if 0 < offers < 20 and reviews > 100:
            analysis['opportunities'].append('蓝海窗口期')
        if rating >= 4.3 and offers < 30:
            analysis['opportunities'].append('品质溢价空间')
        if price > 80 and offers < 25:
            analysis['opportunities'].append('高端差异化')

        return analysis

    @staticmethod
    def calculate_win_probability(p: dict) -> float:
        """
        计算胜出概率 (0-100%)
        基于: 差异化 + 质量 + 价格竞争力
        """
        score = 50  # 基础分

        # 差异化加分
        diff = _safe_str(p.get('spy_differentiation'))
        if len(diff) > 20:
            score += 15
        elif len(diff) > 10:
            score += 10

        # 质量加分
        rating = _safe_float(p.get('rating'))
        if rating >= 4.5:
            score += 15
        elif rating >= 4.2:
            score += 10

        # 价格竞争力
        price = _safe_float(p.get('price'))
        if 30 <= price <= 80:
            score += 10

        # 竞争强度扣分
        offers = _safe_int(p.get('amazon_offer_count'))
        if offers > 50:
            score -= 20
        elif offers > 30:
            score -= 10
        elif offers < 10:
            score += 10

        # 评论规模扣分 (头部已固化)
        reviews = _safe_int(p.get('reviews_count'))
        if reviews > 2000:
            score -= 15
        elif reviews > 500:
            score -= 5

        return max(0, min(100, score))


class HistoricalDataAnalyzer:
    """
    v33.0: 历史数据分析器
    30年经验: 历史不会重复,但会押韵
    """

    @staticmethod
    def analyze_product_maturity(p: dict) -> dict:
        """
        分析产品成熟度
        判断: 新品/成长期/成熟期/衰退期
        """
        reviews = _safe_int(p.get('reviews_count'))
        rev_vel = _safe_float(p.get('review_velocity'))
        rating = _safe_float(p.get('rating'))
        trend = _safe_str(p.get('trend_direction'))

        # 计算成熟度分数
        maturity_score = 0

        # 评论数量维度
        if reviews >= 1000:
            maturity_score += 30
        elif reviews >= 500:
            maturity_score += 20
        elif reviews >= 100:
            maturity_score += 10
        elif reviews > 0:
            maturity_score += 5

        # 增长性维度
        if rev_vel > 30:
            maturity_score += 25
        elif rev_vel > 10:
            maturity_score += 15
        elif rev_vel > 0:
            maturity_score += 10

        # 稳定性维度
        if rating >= 4.3:
            maturity_score += 20
        elif rating >= 4.0:
            maturity_score += 15
        elif rating > 0:
            maturity_score += 10

        # 趋势维度
        if trend in ('↑', '↗', '↑↑'):
            maturity_score += 15
        elif trend in ('↓', '↓↓'):
            maturity_score -= 10

        # 判断阶段
        if maturity_score >= 75:
            stage = '成熟期'
            recommendation = '可测试,但需差异化竞争'
        elif maturity_score >= 50:
            stage = '成长期'
            recommendation = '最佳入场窗口'
        elif maturity_score >= 25:
            stage = '新品期'
            recommendation = '高风险高回报'
        else:
            stage = '未确定'
            recommendation = '需更多数据验证'

        return {
            'maturity_score': maturity_score,
            'product_stage': stage,
            'recommendation': recommendation,
        }

    @staticmethod
    def calculate_lifecycle_value(p: dict) -> float:
        """
        计算生命周期价值
        预测产品能在市场存活多久
        """
        reviews = _safe_int(p.get('reviews_count'))
        rev_vel = _safe_float(p.get('review_velocity'))
        offers = _safe_int(p.get('amazon_offer_count'))
        trend = _safe_str(p.get('trend_direction'))

        # 基础生命周期 (月)
        lifecycle = 12

        # 趋势向下,缩短生命周期
        if trend in ('↓', '↓↓'):
            lifecycle -= 6
        elif trend in ('↘',):
            lifecycle -= 3

        # 竞争激烈,缩短生命周期
        if offers > 50:
            lifecycle -= 4
        elif offers > 30:
            lifecycle -= 2

        # 增长中,延长生命周期
        if rev_vel > 20:
            lifecycle += 6
        elif rev_vel > 10:
            lifecycle += 3

        # 成熟产品,生命周期更长
        if reviews > 500:
            lifecycle += 3

        return max(3, min(36, lifecycle))


class AutoReportingSystem:
    """
    v33.0: 自动化报告系统
    生成专业选品报告
    """

    @staticmethod
    def generate_selection_report(products: list[dict]) -> dict:
        """
        生成选品报告
        """
        if not products:
            return {}

        # 统计概览
        total = len(products)
        scored_products = [p for p in products if p.get('expert_selection_score')]

        # 按优先级分组
        priority_groups = {'S': [], 'A': [], 'B': [], 'C': []}
        for p in scored_products:
            pri = p.get('expert_priority', 'C')
            priority_groups[pri].append(p)

        # 计算平均分
        avg_expert = sum(p.get('expert_selection_score', 0) for p in scored_products) / max(1, len(scored_products))
        avg_risk = sum(p.get('expert_risk_score', 0) for p in scored_products) / max(1, len(scored_products))

        # 趋势统计
        trend_counts = {'上升': 0, '稳定': 0, '下降': 0}
        for p in products:
            trend = _safe_str(p.get('trend_direction'))
            if trend in ('↑', '↗', '↑↑'):
                trend_counts['上升'] += 1
            elif trend in ('↓', '↓↓', '↘'):
                trend_counts['下降'] += 1
            else:
                trend_counts['稳定'] += 1

        return {
            'report_date': datetime.now().strftime('%Y-%m-%d %H:%M'),
            'total_products': total,
            'scored_count': len(scored_products),
            'priority_s': len(priority_groups['S']),
            'priority_a': len(priority_groups['A']),
            'priority_b': len(priority_groups['B']),
            'priority_c': len(priority_groups['C']),
            'avg_expert_score': round(avg_expert, 1),
            'avg_risk_score': round(avg_risk, 1),
            'trend_breakdown': trend_counts,
            'top_recommendations': priority_groups['S'][:5],
        }

    @staticmethod
    def print_report_summary(report: dict):
        """打印报告摘要"""
        if not report:
            return

        print("\n" + "="*50)
        print("📊 v33.0 选品报告摘要")
        print("="*50)
        print(f"📅 生成时间: {report.get('report_date', '')}")
        print(f"📦 总产品数: {report.get('total_products', 0)}")
        print(f"✅ 已评分: {report.get('scored_count', 0)}")
        print(f"\n🎯 优先级分布:")
        print(f"   S级(立即测试): {report.get('priority_s', 0)} 个")
        print(f"   A级(值得验证): {report.get('priority_a', 0)} 个")
        print(f"   B级(观察等待): {report.get('priority_b', 0)} 个")
        print(f"   C级(建议放弃): {report.get('priority_c', 0)} 个")
        print(f"\n📈 平均分数:")
        print(f"   专家评分: {report.get('avg_expert_score', 0)}")
        print(f"   风险评分: {report.get('avg_risk_score', 0)}")
        print(f"\n📉 趋势分布:")
        tr = report.get('trend_breakdown', {})
        print(f"   上升: {tr.get('上升', 0)} | 稳定: {tr.get('稳定', 0)} | 下降: {tr.get('下降', 0)}")
        print("="*50)


def apply_v27_enhancements(products: list[dict]) -> list[dict]:
    """
    v33.0: 应用所有增强功能
    趋势预测 + 竞品分析 + 历史分析 + 报告生成
    """
    enhanced = []

    for p in products:
        try:
            # 趋势预测
            trend_pred = TrendPredictionEngine.predict_momentum(p)
            p.update(trend_pred)
            p['trend_confidence'] = TrendPredictionEngine.calculate_trend_confidence(p)

            # 竞品分析
            comp_analysis = CompetitorAnalysisEngine.analyze_market_position(p)
            p['competitor_strengths'] = comp_analysis['strengths']
            p['competitor_weaknesses'] = comp_analysis['weaknesses']
            p['competitor_opportunities'] = comp_analysis['opportunities']
            p['win_probability'] = CompetitorAnalysisEngine.calculate_win_probability(p)

            # 历史分析
            maturity = HistoricalDataAnalyzer.analyze_product_maturity(p)
            p['product_stage'] = maturity['product_stage']
            p['maturity_score'] = maturity['maturity_score']
            p['lifecycle_months'] = HistoricalDataAnalyzer.calculate_lifecycle_value(p)

            enhanced.append(p)
        except Exception as e:
            log.warning(f"  ⚠️ v27增强失败: {e}")
            enhanced.append(p)

    # 生成报告
    report = AutoReportingSystem.generate_selection_report(enhanced)
    AutoReportingSystem.print_report_summary(report)

    return enhanced


