class WebhookNotifier:
    """
    v33.0: Webhook通知器
    支持: Slack/Discord/Telegram/Email
    """

    def __init__(self):
        self.webhooks = {
            'slack': None,
            'discord': None,
            'telegram': None,
            'email': None,
        }

    def configure(self, platform: str, url: str):
        """配置webhook"""
        if platform in self.webhooks:
            self.webhooks[platform] = url
            log.info(f"  ✅ Webhook配置: {platform}")

    def send_notification(self, platform: str, message: str) -> bool:
        """
        发送通知
        """
        url = self.webhooks.get(platform)
        if not url:
            log.warning(f"  ⚠️ {platform} webhook未配置")
            return False

        try:
            # TODO: 实现实际发送
            log.info(f"  📤 通知已发送 [{platform}]: {message[:50]}...")
            return True
        except Exception as e:
            log.error(f"  ❌ 通知发送失败: {e}")
            return False

    def notify_selection_result(self, products: list[dict], top_n: int = 5):
        """通知选品结果"""
        top = products[:top_n]
        msg = f"🎯 新选品结果 ({len(products)}个候选, Top{top_n}):\n"

        for i, p in enumerate(top, 1):
            name = p.get('name', 'N/A')[:30]
            score = p.get('expert_selection_score', 0)
            price = p.get('price', 0)
            msg += f"{i}. {name} - ${price:.0f} (评分:{score:.0f})\n"

        # 发送到所有配置的webhook
        for platform in self.webhooks:
            if self.webhooks[platform]:
                self.send_notification(platform, msg)

        return msg


class DataLakeManager:
    """
    v33.0: 数据湖管理器
    本地存储历史选品数据
    """

    def __init__(self, data_dir: str = None):
        self.data_dir = data_dir or os.path.join(SCRIPT_DIR, 'data_lake')
        os.makedirs(self.data_dir, exist_ok=True)

    def save_product_snapshot(self, product: dict, round_name: str = None):
        """
        保存产品快照
        """
        if not round_name:
            round_name = datetime.now().strftime('%Y%m%d_%H%M%S')

        asin = product.get('asin', 'unknown')
        filepath = os.path.join(self.data_dir, f'{asin}_{round_name}.json')

        try:
            with open(filepath, 'w', encoding='utf-8') as f:
                json.dump(product, f, ensure_ascii=False, indent=2)
            return filepath
        except Exception as e:
            log.error(f"  ❌ 快照保存失败: {e}")
            return None

    def load_product_history(self, asin: str) -> list[dict]:
        """
        加载产品历史快照
        """
        history = []
        pattern = os.path.join(self.data_dir, f'{asin}_*.json')

        for filepath in glob.glob(pattern):
            try:
                with open(filepath, 'r', encoding='utf-8') as f:
                    history.append(json.load(f))
            except Exception:
                continue

        return sorted(history, key=lambda x: x.get('timestamp', ''), reverse=True)

    def analyze_trends(self, asin: str) -> dict:
        """
        分析产品趋势变化
        """
        history = self.load_product_history(asin)

        if not history:
            return {}

        # 计算变化趋势
        prices = [p.get('price', 0) for p in history if p.get('price')]
        bsr_ranks = [p.get('bsr_rank', 0) for p in history if p.get('bsr_rank')]
        ratings = [p.get('rating', 0) for p in history if p.get('rating')]

        return {
            'price_trend': 'up' if prices[-1] > prices[0] else 'down' if prices[-1] < prices[0] else 'stable',
            'bsr_trend': 'up' if bsr_ranks[-1] < bsr_ranks[0] else 'down' if bsr_ranks[-1] > bsr_ranks[0] else 'stable',
            'rating_trend': 'up' if ratings[-1] > ratings[0] else 'down' if ratings[-1] < ratings[0] else 'stable',
            'snapshot_count': len(history),
        }


class WorkflowEngine:
    """
    v33.0: 工作流引擎
    自动化选品→验证→测试流程
    """

    def __init__(self):
        self.stages = [
            'scrape',      # 采集
            'validate',   # 验证
            'enrich',     # 补充数据
            'score',      # 评分
            'shortlist',   # 短名单
            'test',       # 测试
        ]
        self.current_stage = 0

    def run_pipeline(self, products: list[dict], max_items: int = 10) -> list[dict]:
        """
        运行完整工作流
        """
        log.info(f"  🚀 启动工作流 ({len(self.stages)}个阶段)")

        result = products

        # Stage 1: 采集 (已有)

        # Stage 2: 验证
        result = select_validation_pool(result, max_items)

        # Stage 3: 补充数据
        # 调用 Google Trends, Shopify 等

        # Stage 4: 评分
        result = apply_expert_scoring(result)

        # Stage 5: 短名单
        result = apply_v27_enhancements(result)

        # Stage 6: 生成测试建议

        log.info(f"  ✅ 工作流完成,产出 {len(result)} 个候选")

        return result

    def get_next_action(self, product: dict) -> str:
        """
        获取下一步建议
        """
        stage = product.get('workflow_stage', 'scrape')

        action_map = {
            'scrape': '采集产品数据',
            'validate': '验证BSR和价格',
            'enrich': '补充趋势数据',
            'score': '执行专家评分',
            'shortlist': '生成短名单',
            'test': '准备广告测试',
        }

        return action_map.get(stage, '未知阶段')


def apply_v28_integration(products: list[dict]) -> list[dict]:
    """
    v33.0: 应用多数据源整合
    """
    integrated = []

    for p in products:
        try:
            # 合并多数据源信号
            p = DataSourceIntegrator.merge_signals(p)

            integrated.append(p)
        except Exception as e:
            log.warning(f"  ⚠️ v28整合失败: {e}")
            integrated.append(p)

    # 统计
    sources_stats = {}
    for p in integrated:
        for src in p.get('data_sources', []):
            sources_stats[src] = sources_stats.get(src, 0) + 1

    log.info(f"  📊 [v28] 数据源信号: {sources_stats}")

    return integrated


