class CacheManager:
    """
    v33.0: 缓存管理器
    减少重复请求,提升性能
    """

    def __init__(self, max_size: int = 1000, ttl: int = 3600):
        self._cache = {}
        self._timestamps = {}
        self.max_size = max_size
        self.ttl = ttl
        self._hits = 0
        self._misses = 0

    def get(self, key: str) -> tuple:
        """获取缓存,返回 (值, 是否命中)"""
        if key in self._cache:
            # 检查过期
            if time.time() - self._timestamps.get(key, 0) < self.ttl:
                self._hits += 1
                return self._cache[key], True
            else:
                # 过期删除
                del self._cache[key]
                del self._timestamps[key]

        self._misses += 1
        return None, False

    def set(self, key: str, value):
        """设置缓存"""
        # 清理过期或超出容量时清理
        if len(self._cache) >= self.max_size:
            # LRU: 删除最老的
            oldest_key = min(self._timestamps, key=self._timestamps.get)
            del self._cache[oldest_key]
            del self._timestamps[oldest_key]

        self._cache[key] = value
        self._timestamps[key] = time.time()

    def clear(self):
        """清空缓存"""
        self._cache.clear()
        self._timestamps.clear()
        self._hits = 0
        self._misses = 0

    def get_stats(self) -> dict:
        """获取缓存统计"""
        total = self._hits + self._misses
        hit_rate = self._hits / total if total > 0 else 0
        return {
            'size': len(self._cache),
            'hits': self._hits,
            'misses': self._misses,
            'hit_rate': round(hit_rate * 100, 1),
        }


# 全局缓存实例
_global_cache = CacheManager()


class RequestRetryHandler:
    """
    v33.0: 请求重试处理器
    优雅处理失败请求
    """

    @staticmethod
    def retry_with_backoff(
        func,
        max_retries: int = 3,
        base_delay: float = 1.0,
        backoff_factor: float = 2.0,
        max_delay: float = 30.0,
    ):
        """
        指数退避重试装饰器
        """
        def wrapper(*args, **kwargs):
            last_exception = None

            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    last_exception = e
                    if attempt < max_retries:
                        delay = min(base_delay * (backoff_factor ** attempt), max_delay)
                        log.warning(f"  ⚠️ 请求失败, {attempt + 1}/{max_retries}重试, 等待{delay}s: {e}")
                        time.sleep(delay)

            raise last_exception

        return wrapper


class ErrorHandler:
    """
    v33.0: 统一错误处理
    生产环境必需的错误管理
    """

    ERROR_CODES = {
        'NETWORK_ERROR': {'code': 1001, 'severity': 'warning'},
        'RATE_LIMIT': {'code': 1002, 'severity': 'info'},
        'PARSE_ERROR': {'code': 1003, 'severity': 'warning'},
        'VALIDATION_ERROR': {'code': 1004, 'severity': 'error'},
        'TIMEOUT': {'code': 1005, 'severity': 'warning'},
    }

    @staticmethod
    def handle_error(error: Exception, context: str = '') -> dict:
        """
        统一错误处理
        返回错误响应
        """
        error_type = type(error).__name__
        error_info = ErrorHandler.ERROR_CODES.get(error_type, {})

        error_response = {
            'success': False,
            'error': error_type,
            'message': str(error),
            'context': context,
            'code': error_info.get('code', 9999),
            'severity': error_info.get('severity', 'error'),
            'timestamp': datetime.now().isoformat(),
        }

        # 记录日志
        if error_info.get('severity') == 'error':
            log.error(f"  ❌ 错误 [{context}]: {error}")
        else:
            log.warning(f"  ⚠️ 警告 [{context}]: {error}")

        return error_response

    @staticmethod
    def is_retryable(error: Exception) -> bool:
        """判断错误是否可重试"""
        retryable_types = (
            'TimeoutError',
            'ConnectionError',
            'HTTPError',
            'SSLError',
        )
        return type(error).__name__ in retryable_types


class PerformanceMonitor:
    """
    v33.0: 性能监控
    追踪关键指标
    """

    def __init__(self):
        self._metrics = {
            'requests': 0,
            'errors': 0,
            'cache_hits': 0,
            'total_time': 0.0,
            'by_stage': {},
        }

    def record_request(self, duration: float, stage: str = 'unknown'):
        """记录请求"""
        self._metrics['requests'] += 1
        self._metrics['total_time'] += duration

        if stage not in self._metrics['by_stage']:
            self._metrics['by_stage'][stage] = {'count': 0, 'time': 0.0}

        self._metrics['by_stage'][stage]['count'] += 1
        self._metrics['by_stage'][stage]['time'] += duration

    def record_error(self):
        """记录错误"""
        self._metrics['errors'] += 1

    def get_stats(self) -> dict:
        """获取统计"""
        requests = self._metrics['requests']
        avg_time = self._metrics['total_time'] / requests if requests > 0 else 0
        error_rate = self._metrics['errors'] / requests if requests > 0 else 0

        return {
            'total_requests': requests,
            'total_errors': self._metrics['errors'],
            'error_rate': round(error_rate * 100, 2),
            'avg_duration': round(avg_time, 2),
            'by_stage': {
                stage: {
                    'count': data['count'],
                    'avg_time': round(data['time'] / data['count'], 2) if data['count'] > 0 else 0
                }
                for stage, data in self._metrics['by_stage'].items()
            },
        }


# 全局性能监控
_perf_monitor = PerformanceMonitor()


class APIRouter:
    """
    v33.0: API路由
    简单的HTTP��务封装
    """

    def __init__(self):
        self.routes = {}

    def route(self, path: str, methods: list = None):
        """装饰器注册路由"""
        if methods is None:
            methods = ['GET']

        def decorator(func):
            self.routes[path] = {'func': func, 'methods': methods}
            return func

        return decorator

    def handle_request(self, path: str, method: str = 'GET', params: dict = None):
        """处理请求"""
        route = self.routes.get(path)

        if not route:
            return {'error': 'Not Found', 'code': 404}

        if method not in route['methods']:
            return {'error': 'Method Not Allowed', 'code': 405}

        try:
            return route['func'](params or {})
        except Exception as e:
            return ErrorHandler.handle_error(e, f'API:{path}')


