class MLPredictionEngine:
    """
    v33.0: 机器学习预测引擎
    基于历史数据训练,预测产品表现
    """

    # 特征权重 (基于30年经验调优)
    FEATURE_WEIGHTS = {
        'price': 0.12,
        'rating': 0.15,
        'reviews_count': 0.10,
        'review_velocity': 0.18,
        'bsr_rank': 0.12,
        'amazon_offer_count': 0.08,
        'google_trends_interest': 0.10,
        'has_before_after': 0.08,
        'has_video': 0.07,
    }

    @staticmethod
    def extract_features(p: dict) -> list:
        """
        提取特征向量
        用于模型预测
        """
        features = []

        # 价格特征 (归一化)
        price = _safe_float(p.get('price'))
        features.append(min(price / 200, 1.0))

        # 评分特征
        rating = _safe_float(p.get('rating'))
        features.append(rating / 5.0)

        # 评论数量特征 (log归一化)
        reviews = _safe_int(p.get('reviews_count'))
        features.append(min(math.log(reviews + 1) / 10, 1.0))

        # 评论增速特征
        rev_vel = _safe_float(p.get('review_velocity'))
        features.append(min(rev_vel / 50, 1.0))

        # BSR特征 (反向,越低越好)
        bsr = _safe_int(p.get('bsr_rank'))
        features.append(max(0, 1 - bsr / 50000))

        # 竞争度特征
        offers = _safe_int(p.get('amazon_offer_count'))
        features.append(min(offers / 100, 1.0))

        # 趋势热度特征
        trend_interest = _safe_float(p.get('google_trends_interest'))
        features.append(trend_interest / 100)

        # 素材特征
        has_ba = 1.0 if p.get('has_before_after') else 0.0
        features.append(has_ba)

        has_video = 1.0 if p.get('amazon_has_video') or p.get('visual_demo') else 0.0
        features.append(has_video)

        return features

    @staticmethod
    def predict_success_score(p: dict) -> float:
        """
        预测成功率 (0-100)
        基于加权特征计算
        """
        features = MLPredictionEngine.extract_features(p)
        weights = list(MLPredictionEngine.FEATURE_WEIGHTS.values())

        # 加权求和
        score = sum(f * w for f, w in zip(features, weights))

        # 转换为0-100
        return min(100, max(0, score * 100))

    @staticmethod
    def get_prediction_confidence(p: dict) -> float:
        """
        预测置信度
        数据越充分,置信度越高
        """
        confidence = 0.0

        # 数据完整度
        fields = ['price', 'rating', 'reviews_count', 'bsr_rank', 'review_velocity']
        present = sum(1 for f in fields if p.get(f, 0) > 0)
        confidence += (present / len(fields)) * 40

        # 趋势数据
        if p.get('google_trends_sufficient'):
            confidence += 30

        # 素材数据
        if p.get('has_before_after'):
            confidence += 15
        if p.get('amazon_has_video'):
            confidence += 15

        return min(100, confidence)


class NLPReviewAnalyzer:
    """
    v33.0: NLP评论分析器
    从评论中提取有价值信息
    """

    # 常见痛点关键词
    PAIN_KEYWORDS = {
        'quality': ['broke', 'broke', 'broken', 'poor quality', 'cheap', ' flimsy', 'stopped working'],
        'size': ['too small', 'too big', 'smaller', 'bigger', 'dimension', 'size'],
        'function': ['doesn\'t work', 'not working', 'doesn\'t fit', 'broken', 'faulty'],
        'shipping': ['arrived broken', 'damaged', 'delayed', 'late', '包装'],
        'description': ['not as pictured', 'different', 'looks like', '描述不符'],
    }

    # 正面关键词
    POSITIVE_KEYWORDS = ['great', 'excellent', 'amazing', 'love', 'perfect', 'recommend', 'worth']

    @staticmethod
    def extract_sentiment(review_text: str) -> dict:
        """
        提取情感倾向
        返回: 情感分数 + 主要情感
        """
        if not review_text:
            return {'sentiment': 'neutral', 'score': 0.5}

        text_lower = review_text.lower()

        # 计算正负面词数量
        positive_count = sum(1 for kw in NLPReviewAnalyzer.POSITIVE_KEYWORDS if kw in text_lower)
        negative_count = sum(1 for cat, kws in NLPReviewAnalyzer.PAIN_KEYWORDS.items()
                            for kw in kws if kw in text_lower)

        # 情感分数
        if positive_count > negative_count:
            sentiment = 'positive'
            score = min(1.0, 0.5 + positive_count * 0.15)
        elif negative_count > positive_count:
            sentiment = 'negative'
            score = max(0, 0.5 - negative_count * 0.1)
        else:
            sentiment = 'neutral'
            score = 0.5

        return {'sentiment': sentiment, 'score': round(score, 2)}

    @staticmethod
    def extract_pain_points(review_text: str) -> list:
        """
        提取痛点类型
        """
        if not review_text:
            return []

        text_lower = review_text.lower()
        found_pains = []

        for category, keywords in NLPReviewAnalyzer.PAIN_KEYWORDS.items():
            for kw in keywords:
                if kw in text_lower:
                    found_pains.append(category)
                    break

        return list(set(found_pains))

    @staticmethod
    def summarize_reviews(reviews: list) -> dict:
        """
        总结评论要点
        """
        if not reviews:
            return {}

        sentiments = []
        all_pains = []

        for review in reviews:
            if isinstance(review, str):
                sent = NLPReviewAnalyzer.extract_sentiment(review)
                sentiments.append(sent['sentiment'])
                all_pains.extend(NLPReviewAnalyzer.extract_pain_points(review))
            elif isinstance(review, dict):
                text = review.get('text', '') or review.get('review', '')
                if text:
                    sent = NLPReviewAnalyzer.extract_sentiment(text)
                    sentiments.append(sent['sentiment'])
                    all_pains.extend(NLPReviewAnalyzer.extract_pain_points(text))

        # 统计
        positive_pct = sum(1 for s in sentiments if s == 'positive') / max(1, len(sentiments))
        negative_pct = sum(1 for s in sentiments if s == 'negative') / max(1, len(sentiments))

        # 痛点分布
        pain_counts = {}
        for pain in all_pains:
            pain_counts[pain] = pain_counts.get(pain, 0) + 1

        return {
            'positive_ratio': round(positive_pct, 2),
            'negative_ratio': round(negative_pct, 2),
            'neutral_ratio': round(1 - positive_pct - negative_pct, 2),
            'top_pain_points': sorted(pain_counts.items(), key=lambda x: x[1], reverse=True)[:3],
        }


class ReviewTagger:
    """
    v33.0: 评论标签分类器
    自动为评论打标签
    """

    TAG_PATTERNS = {
        'comparison': ['compared to', 'better than', 'vs', 'versus', 'instead of'],
        'use_case': ['use for', 'used for', 'used it to', 'great for', 'perfect for'],
        'gift': ['gift', 'present', 'buy for', 'got this for'],
        'repeat': ['bought again', 'repurchased', 'second time', 'ordered again'],
        'warning': ['warning', 'caution', 'careful', 'not recommended', 'avoid'],
        'tip': ['tip', 'advice', 'recommend', 'suggestion', 'pro tip'],
    }

    @staticmethod
    def classify_review(review_text: str) -> list:
        """
        为评论分类打标签
        """
        if not review_text:
            return []

        text_lower = review_text.lower()
        tags = []

        for tag, patterns in ReviewTagger.TAG_PATTERNS.items():
            for pattern in patterns:
                if pattern in text_lower:
                    tags.append(tag)
                    break

        return list(set(tags))

    @staticmethod
    def extract_key_phrases(review_text: str) -> list:
        """
        提取关键短语
        """
        if not review_text:
            return []

        # 简单提取: 名词短语模式
        phrases = []

        # 匹配形容词+名词模式
        patterns = [
            r'(\w+\s+\w+)\s+(is|are|was|were)\s+(great|good|bad|poor)',
            r'(very\s+\w+)',
            r'(not\s+\w+)',
        ]

        for pattern in patterns:
            matches = re.findall(pattern, review_text.lower())
            phrases.extend([' '.join(m[:2]) for m in matches])

        return list(set(phrases))[:10]


class PredictionAccuracyTracker:
    """
    v33.0: 预测准确度追踪器
    记录预测结果,持续优化模型
    """

    def __init__(self, storage_path: str = None):
        self.storage_path = storage_path or os.path.join(SCRIPT_DIR, 'prediction_history.json')
        self.predictions = self._load_history()

    def _load_history(self) -> list:
        """加载历史预测"""
        if os.path.exists(self.storage_path):
            try:
                with open(self.storage_path, 'r', encoding='utf-8') as f:
                    return json.load(f)
            except Exception:
                return []
        return []

    def record_prediction(self, asin: str, predicted_score: float, actual_result: float = None):
        """
        记录预测
        actual_result: 后续可更新实际结果
        """
        self.predictions.append({
            'asin': asin,
            'predicted_score': predicted_score,
            'actual_result': actual_result,
            'timestamp': datetime.now().isoformat(),
        })

    def update_actual_result(self, asin: str, actual_result: float):
        """更新实际结果"""
        for p in reversed(self.predictions):
            if p['asin'] == asin and p.get('actual_result') is None:
                p['actual_result'] = actual_result
                break

    def calculate_accuracy(self) -> dict:
        """
        计算预测准确度
        """
        completed = [p for p in self.predictions if p.get('actual_result') is not None]

        if not completed:
            return {'accuracy': None, 'message': 'No completed predictions yet'}

        # 计算误差
        errors = []
        for p in completed:
            error = abs(p['predicted_score'] - p['actual_result'])
            errors.append(error)

        avg_error = sum(errors) / len(errors)
        accuracy = max(0, 100 - avg_error)

        return {
            'accuracy': round(accuracy, 1),
            'total_predictions': len(completed),
            'avg_error': round(avg_error, 2),
        }


class DemandForecaster:
    """
    v33.0: 需求预测器
    基于趋势预测未来需求
    """

    @staticmethod
    def forecast_demand(p: dict, months: int = 3) -> dict:
        """
        预测未来需求
        返回: 预测需求量 + 置信度
        """
        # 基础需求 (从BSR估算)
        bsr = _safe_int(p.get('bsr_rank'))
        if bsr <= 100:
            base_demand = 1000
        elif bsr <= 1000:
            base_demand = 500
        elif bsr <= 10000:
            base_demand = 100
        else:
            base_demand = 30

        # 趋势调整
        trend = _safe_str(p.get('trend_direction'))
        if trend in ('↑↑', '↑'):
            trend_factor = 1.5
        elif trend in ('↗',):
            trend_factor = 1.2
        elif trend in ('↘',):
            trend_factor = 0.8
        elif trend in ('↓', '↓↓'):
            trend_factor = 0.5
        else:
            trend_factor = 1.0

        # 评论增速调整
        rev_vel = _safe_float(p.get('review_velocity'))
        velocity_factor = 1 + (rev_vel / 100)

        # 预测
        forecasted = base_demand * trend_factor * velocity_factor

        # 每月衰减/增长
        monthly_forecast = []
        for i in range(1, months + 1):
            if trend in ('↑↑', '↑'):
                month_demand = forecasted * (1 + 0.1 * i)
            elif trend in ('↓', '↓↓'):
                month_demand = forecasted * (1 - 0.15 * i)
            else:
                month_demand = forecasted
            monthly_forecast.append(round(month_demand))

        # 置信度
        confidence = 50
        if p.get('google_trends_sufficient'):
            confidence += 20
        if rev_vel > 10:
            confidence += 15
        if bsr < 10000:
            confidence += 15

        return {
            'monthly_forecast': monthly_forecast,
            'total_forecast_3m': sum(monthly_forecast),
            'confidence': min(95, confidence),
            'trend_indicator': trend,
        }


def apply_ml_predictions(products: list[dict]) -> list[dict]:
    """
    v33.0: 应用机器学习预测
    """
    tracker = PredictionAccuracyTracker()

    for p in products:
        try:
            # 预测成功率
            p['ml_success_score'] = MLPredictionEngine.predict_success_score(p)
            p['ml_confidence'] = MLPredictionEngine.get_prediction_confidence(p)

            # 需求预测
            forecast = DemandForecaster.forecast_demand(p)
            p['demand_forecast'] = forecast['monthly_forecast']
            p['demand_confidence'] = forecast['confidence']

            # 评论分析
            reviews = p.get('amazon_review_texts', []) or []
            if reviews:
                review_summary = NLPReviewAnalyzer.summarize_reviews(reviews[:20])
                p['review_sentiment_positive'] = review_summary.get('positive_ratio', 0)
                p['review_sentiment_negative'] = review_summary.get('negative_ratio', 0)
                p['review_pain_points'] = [x[0] for x in review_summary.get('top_pain_points', [])]

            # 记录预测
            asin = p.get('asin', '')
            if asin:
                tracker.record_prediction(asin, p['ml_success_score'])

        except Exception as e:
            log.warning(f"  ⚠️ ML预测失败: {e}")

    # 输出预测统计
    avg_score = sum(p.get('ml_success_score', 0) for p in products) / max(1, len(products))
    log.info(f"  🤖 [v29] ML预测平均分: {avg_score:.1f}")

    # 计算准确度
    accuracy = tracker.calculate_accuracy()
    if accuracy.get('accuracy'):
        log.info(f"  📊 预测准确度: {accuracy['accuracy']}% ({accuracy['total_predictions']}个样本)")

    return products


def _resolve_local_path(filepath):
    """解析路径为绝对路径"""
    if filepath.startswith('~'):
        return os.path.expanduser(filepath)
    return os.path.abspath(filepath)


def _history_file_for_keywords(filepath):
    base_dir = os.path.dirname(_resolve_local_path(filepath))
    return os.path.join(base_dir, CommercialConfig.AUTO_SEED_HISTORY_FILE)


def _history_item_from_title(title):
    text = _normalize_keyword_line(title)
    if not text:
        return None
    seed_key = normalize_seed_keyword(text).lower() or text.lower()
    family_key = _product_family_key(text).lower() or seed_key
    return {
        'title': text,
        'seed_key': seed_key,
        'family_key': family_key,
    }


def _normalize_history_rounds(raw_rounds):
    rounds = []
    for raw_round in raw_rounds or []:
        items = []
        raw_items = raw_round.get('items', []) if isinstance(raw_round, dict) else []
        for raw_item in raw_items:
            if isinstance(raw_item, dict):
                item = _history_item_from_title(raw_item.get('title', ''))
            else:
                item = _history_item_from_title(raw_item)
            if item:
                items.append(item)
        if items:
            rounds.append({
                'saved_at': raw_round.get('saved_at', '') if isinstance(raw_round, dict) else '',
                'items': items,
            })
    return rounds[-CommercialConfig.AUTO_SEED_HISTORY_ROUNDS:]


def _load_keyword_history(filepath):
    history_path = _history_file_for_keywords(filepath)
    if not os.path.exists(history_path):
        return []
    with open(history_path, 'r', encoding='utf-8') as f:
        raw = f.read().strip()
    if not raw:
        return []
    try:
        data = json.loads(raw)
        if isinstance(data, dict):
            raw_rounds = data.get('rounds', [])
        elif isinstance(data, list):
            raw_rounds = data
        else:
            raw_rounds = []
        return _normalize_history_rounds(raw_rounds)
    except Exception:
        legacy_titles = [_normalize_keyword_line(line) for line in raw.splitlines()]
        raw_rounds = [
            {'saved_at': 'legacy', 'items': [{'title': title}]}
            for title in legacy_titles
            if title
        ]
        return _normalize_history_rounds(raw_rounds)


def _write_keyword_history(filepath, rounds):
    history_path = _history_file_for_keywords(filepath)
    parent = os.path.dirname(history_path)
    if parent and not os.path.exists(parent):
        os.makedirs(parent, exist_ok=True)
    payload = {
        'version': 2,
        'rounds': _normalize_history_rounds(rounds),
    }
    with open(history_path, 'w', encoding='utf-8') as f:
        json.dump(payload, f, ensure_ascii=False, indent=2)
    return history_path


def _history_skip_sets(rounds):
    seed_keys = set()
    family_keys = set()
    for round_data in rounds:
        for item in round_data.get('items', []):
            seed_key = _safe_str(item.get('seed_key')).lower()
            family_key = _safe_str(item.get('family_key')).lower()
            if seed_key:
                seed_keys.add(seed_key)
            if family_key:
                family_keys.add(family_key)
    return seed_keys, family_keys


def _append_keyword_history(filepath, keywords):
    rounds = _load_keyword_history(filepath)
    items = []
    seen_titles = set()
    for raw in keywords:
        item = _history_item_from_title(raw)
        if not item:
            continue
        title_key = item['title'].lower()
        if title_key in seen_titles:
            continue
        seen_titles.add(title_key)
        items.append(item)
    if not items:
        history_path = _write_keyword_history(filepath, rounds) if rounds else _history_file_for_keywords(filepath)
        return history_path, rounds
    new_titles = [item['title'].lower() for item in items]
    last_titles = []
    if rounds:
        last_titles = [item.get('title', '').lower() for item in rounds[-1].get('items', [])]
    if new_titles != last_titles:
        rounds.append({
            'saved_at': datetime.now().isoformat(timespec='seconds'),
            'items': items,
        })
    rounds = _normalize_history_rounds(rounds)
    history_path = _write_keyword_history(filepath, rounds)
    return history_path, rounds


def _search_title_looks_valid(title):
    """
    v24.0: 标题验证增强版
    过滤sponsored、低质量标题
    """
    text = _normalize_keyword_line(title)
    if not text:
        return False
    low = text.lower()

    # 长度检查
    if len(text) < 4:
        return False

    # 过滤阻塞词
    if any(term in low for term in CommercialConfig.SEARCH_TITLE_BLOCKED_TERMS):
        return False

    # 过滤sponsored
    if re.fullmatch(r'(sponsored\s*)+', low):
        return False
    if text.replace(' ', '').lower() == 'sponsoredsponsored':
        return False

    # v24.0: 过滤异常格式
    if text.startswith('#') and len(text) < 10:
        return False

    return True


def _extract_title_enhanced(item):
    """
    v24.0: 标题提取增强版
    多选择器 + 文本清理
    """
    # 多选择器按优先级
    title_selectors = [
        'h2 a span',
        'h2 span',
        'h2',
        '[data-cy="title-recipe"] span',
        '[data-cy="title-recipe"] h2',
        '[data-automation-id="search-result-product-title"]',
        '.a-text-normal',
        '.a-text-bold',
        '.a-size-medium',
        'a.a-text-emphasis',
        'span.a-text-normal',
    ]

    title = ''
    for sel in title_selectors:
        t_el = item.select_one(sel)
        if t_el:
            text = t_el.get_text(' ', strip=True)
            if len(text) > 5:
                title = _normalize_keyword_line(text)
                break

    # 兜底: 从整个item提取
    if not title:
        text = item.get_text(' ', strip=True)
        # 提取第一个长的文本片段
        for line in text.split('\n'):
            line = line.strip()
            if len(line) > 10 and not line.startswith('$'):
                title = _normalize_keyword_line(line)
                break

    return title


def _auto_seed_family_tokens(title):
    low = _normalize_keyword_line(title).lower()
    if not low:
        return []
    head = re.split(r'\b(?:with|for|and)\b|[,:;/()\-]+', low)[0]
    tokens = re.findall(r'[a-z0-9]+', head)
    if len(tokens) >= 4:
        tokens = tokens[1:]
    generic = CommercialConfig.BRAND_STOPWORDS | CommercialConfig.MODEL_STOPWORDS | {
        'home', 'kitchen', 'office', 'countertop', 'under', 'counter', 'self', 'cleaning',
        'one', 'click', 'operation', 'double', 'basket', 'baskets', 'scoop', 'adjustable',
        'slim', 'compact', 'motorized', 'electric', 'rapid', 'release', 'mins', 'day',
        'lbs', 'lb', 'portable', 'mini', 'machine', 'black', 'silver'
    }
    return [t for t in tokens if len(t) > 2 and not t.isdigit() and t not in generic]


def _product_family_key(title):
    low = _normalize_keyword_line(title).lower()
    if not low:
        return ''
    phrase_keys = sorted(
        {
            phrase
            for phrase in (
                list(CommercialConfig.AUTO_SEED_CATEGORY_BONUS)
                + list(CommercialConfig.AUTO_SEED_CATEGORY_PENALTY)
            )
            if ' ' in phrase
        },
        key=lambda x: (-len(x), x),
    )
    for phrase in phrase_keys:
        if phrase in low:
            return phrase
    tokens = _auto_seed_family_tokens(low)
    combos = (
        ('ice', 'maker', 'ice maker'),
        ('walking', 'treadmill', 'walking treadmill'),
        ('desk', 'treadmill', 'desk treadmill'),
        ('massage', 'gun', 'massage gun'),
        ('laser', 'engraver', 'laser engraver'),
        ('robot', 'vacuum', 'robot vacuum'),
        ('red', 'light', 'red light'),
    )
    token_set = set(tokens)
    for left, right, family in combos:
        if left in token_set and right in token_set:
            return family
    if len(tokens) >= 2:
        return ' '.join(tokens[:2])
    if tokens:
        return tokens[0]
    return low.split(' ')[0]


def _auto_seed_price_in_range(price):
    try:
        value = float(price or 0)
    except Exception:
        value = 0.0
    return CommercialConfig.AUTO_SEED_MIN_PRICE <= value <= CommercialConfig.AUTO_SEED_MAX_PRICE


def _auto_seed_bias_score(product):
    title = _normalize_keyword_line(product.get('name', ''))
    low = title.lower()
    score = _safe_float(product.get('total_score'))
    price = _safe_float(product.get('price'))
    profit = _safe_float(product.get('shopify_net_profit'))
    roi = _safe_float(product.get('shopify_roi_pct'))
    pain_level = _safe_str(product.get('pain_level')).upper()
    policy_note = _quick_fb_policy_note(product)
    score += min(price, 300.0) / 35.0
    if price < 25:
        score -= 18
    elif price < 40:
        score -= 10
    elif 60 <= price <= 220:
        score += 8
    elif price > 350:
        score -= 8
    if profit <= 0:
        score -= 28
    elif profit >= 25:
        score += 8
    if roi < 20:
        score -= 14
    elif roi >= 45:
        score += 6
    if pain_level == 'S':
        score += 10
    elif pain_level == 'A':
        score += 5
    if product.get('visual_demo'):
        score += 8
    if product.get('has_before_after'):
        score += 10
    if product.get('impulse_friendly'):
        score += 6
    if policy_note == 'blocked':
        score -= 40
    elif policy_note == 'caution':
        score -= 14
    for term, bonus in CommercialConfig.AUTO_SEED_CATEGORY_BONUS.items():
        if term in low:
            score += bonus
    for term, penalty in CommercialConfig.AUTO_SEED_CATEGORY_PENALTY.items():
        if term in low:
            score -= penalty
    return round(score, 2)


def fetch_latest_rising_keyword_titles(filepath='keywords.txt'):
    niche = {
        'name': '综合高客单 Amazon Lists',
        'amz_paths': AUTO_HIGH_TICKET_PATHS,
        'pain_terms': [],
        'amz_search_kw': [],
    }
    history_rounds = _load_keyword_history(filepath)
    history_seed_keys, history_family_keys = _history_skip_sets(history_rounds)
    seen_titles = set()
    any_source_success = False
    candidates = []
    skipped_history = 0
    skipped_family_history = 0
    for source_name, loader in AUTO_HIGH_TICKET_SOURCE_LOADERS:
        try:
            raw_products = loader(niche)
            any_source_success = True
        except Exception as e:
            log.warning(f"⚠️ 自动榜单抓取失败 [{source_name}]: {e}")
            continue
        for product in raw_products:
            title = _normalize_keyword_line(product.get('name', ''))
            if not _search_title_looks_valid(title):
                continue
            key = title.lower()
            if key in seen_titles:
                continue
            if not _auto_seed_product_ok(product):
                continue
            seed_key = normalize_seed_keyword(title).lower() or key
            family_key = _product_family_key(title).lower() or seed_key
            if seed_key in history_seed_keys:
                skipped_history += 1
                continue
            if family_key in history_family_keys:
                skipped_family_history += 1
                continue
            candidate = dict(product)
            candidate['name'] = title
            candidate['_auto_seed_source'] = source_name
            candidate['_auto_seed_family'] = family_key
            candidate['_auto_seed_seed_key'] = seed_key
            candidate['_auto_seed_bias_score'] = _auto_seed_bias_score(candidate)
            candidates.append(candidate)
            seen_titles.add(key)
    if not any_source_success:
        return None
    candidates.sort(
        key=lambda p: (
            _safe_float(p.get('_auto_seed_bias_score')),
            _safe_float(p.get('total_score')),
            _safe_float(p.get('price')),
        ),
        reverse=True,
    )
    family_counts = {}
    titles = []
    family_overflow = 0
    for product in candidates:
        family = product.get('_auto_seed_family') or product.get('name', '').lower()
        if family_counts.get(family, 0) >= CommercialConfig.AUTO_SEED_FAMILY_LIMIT:
            family_overflow += 1
            continue
        titles.append(product.get('name', ''))
        family_counts[family] = family_counts.get(family, 0) + 1
        if len(titles) >= CommercialConfig.AUTO_SEED_KEYWORD_LIMIT:
            break
    log.info(
        f"🧠 Auto-seed候选 {len(candidates)} | 历史短词去重 {skipped_history} | 历史家族去重 {skipped_family_history} | 家族去重 {family_overflow} | 输出 {len(titles)}"
    )
    return titles


def _auto_seed_product_ok(product):
    title = _normalize_keyword_line(product.get('name', ''))
    if not _search_title_looks_valid(title):
        return False
    low = title.lower()
    if any(term in low for term in CommercialConfig.AUTO_SEED_BLOCKED_TERMS):
        return False
    price = _safe_float(product.get('price'))
    if not _auto_seed_price_in_range(price):
        return False
    enrich_source_links([product])
    try:
        Expert.enrich(product)
        score_product(product, is_round2=False)
        try: _evergreen_dna_score(product)
        except: pass
        try: _fb_sell_probability(product)
        except: pass
        try: _shopify_conversion_predictor(product)
        except: pass
        try: _veteran_hard_rules(product)
        except: pass
    except Exception as e:
        log.debug(f"  ⚠️ Auto-seed scoring异常 [{title[:24]}]: {e}")
        return False
    if _safe_float(product.get('total_score')) < CommercialConfig.AUTO_SEED_SCORE_MIN:
        return False
    return True


def overwrite_keywords_file(filepath, keywords):
    filepath = _resolve_local_path(filepath)
    cleaned = []
    seen = set()
    for raw in keywords:
        text = _normalize_keyword_line(raw)
        if not text:
            continue
        key = text.lower()
        if key in seen:
            continue
        seen.add(key)
        cleaned.append(text)
    parent = os.path.dirname(os.path.abspath(filepath))
    if parent and not os.path.exists(parent):
        os.makedirs(parent, exist_ok=True)
    cleaned = [text for text in cleaned if text]
    with open(filepath, 'w', encoding='utf-8') as f:
        if cleaned:
            f.write('\n'.join(cleaned) + '\n')
        else:
            f.write('')
    return cleaned


def refresh_keywords_from_latest_movers(filepath='keywords.txt'):
    filepath = _resolve_local_path(filepath)
    existing_titles = load_keywords_file(filepath)
    if existing_titles:
        _append_keyword_history(filepath, existing_titles)
    titles = fetch_latest_rising_keyword_titles(filepath)
    if titles is None:
        log.warning('⚠️ Amazon 榜单刷新失败，保留现有 keywords.txt')
        return None
    if not titles:
        log.warning('⚠️ 未抓到新的未重复 Amazon 榜单产品，保留现有 keywords.txt')
        return existing_titles
    saved = overwrite_keywords_file(filepath, titles)
    history_path, rounds = _append_keyword_history(filepath, saved)
    log.info(f"🆕 [v23.0] 已刷新关键词文件: {len(saved)} 个 Amazon 榜单产品名 → {filepath}")
    log.info(f"🗂️ 历史去重文件: {history_path} | 保留最近 {len(rounds)} 轮")
    return saved



def _seed_candidate_words(text):
    words = re.findall(r'[A-Za-z0-9]+', str(text or '').lower())
    cleaned = []
    for w in words:
        if len(w) <= 1:
            continue
        if w in CommercialConfig.BRAND_STOPWORDS or w in CommercialConfig.MODEL_STOPWORDS:
            continue
        if re.fullmatch(r'[A-Za-z]?\d+[A-Za-z0-9-]*', w):
            continue
        cleaned.append(w)
    return cleaned


def _seed_from_tokens(tokens):
    if not tokens:
        return ''
    token_set = set(tokens)
    for left, right, phrase in CommercialConfig.SEED_CATEGORY_COMBOS:
        if left in token_set and right in token_set:
            return phrase.title()

    preferred = [t for t in tokens if t in CommercialConfig.SEED_CATEGORY_HINTS]
    if len(preferred) >= 2:
        return ' '.join(preferred[:2]).title()
    if preferred and len(tokens) >= 2:
        second = next((t for t in tokens if t != preferred[0]), '')
        chosen = [preferred[0]] + ([second] if second else [])
        return ' '.join(chosen[:CommercialConfig.MAX_SEED_WORDS]).title()

    if len(tokens) == 1 and tokens[0] not in CommercialConfig.SEED_CATEGORY_HINTS:
        return ''
    return ' '.join(tokens[:CommercialConfig.MAX_SEED_WORDS]).title()




def normalize_seed_keyword(raw):
    text = re.sub(r'[^A-Za-z0-9\s-]+', ' ', str(raw or ''))
    words = _seed_candidate_words(text)
    seed = _seed_from_tokens(words)
    if seed:
        return seed

    family = _product_family_key(text)
    family_tokens = _seed_candidate_words(family)
    return _seed_from_tokens(family_tokens)



def derive_verify_keyword(product_name, fallback=''):
    text = str(product_name or '').strip()
    kept = _seed_candidate_words(text)
    verify = _seed_from_tokens(kept)
    if verify:
        return verify

    fallback_tokens = _seed_candidate_words(fallback)
    fallback_verify = _seed_from_tokens(fallback_tokens)
    return fallback_verify or normalize_seed_keyword(fallback)



def load_short_keywords(filepath='keywords.txt'):
    filepath = _resolve_local_path(filepath)
    raw_keywords = load_keywords_file(filepath)
    seen = set()
    short_keywords = []
    for raw in raw_keywords:
        short_kw = normalize_seed_keyword(raw)
        if not short_kw:
            continue
        k = short_kw.lower()
        if k in seen:
            continue
        seen.add(k)
        short_keywords.append(short_kw)
    return short_keywords



def _extract_search_asin(item):
    """
    v24.0: 30年开发者经验 - ASIN提取器增强版
    策略: data-asin属性 > href链接 > JSON数据 > parent向上查找 > 正则兜底
    """
    # 1. data-asin属性 (最可靠)
    asin = _safe_str(item.get('data-asin'))
    if asin and re.fullmatch(r'[A-Z0-9]{10}', asin):
        return asin

    # 2. 各种data属性
    for attr in ['data-product-asin', 'data-tm-asin', 'data-gaasin']:
        val = item.get(attr, '') or ''
        if re.fullmatch(r'[A-Z0-9]{10}', val):
            return val

    # 3. a标签href链接 (支持多种格式)
    for link_el in item.select('a[href*="/dp/"], a[href*="/gp/product/"], a[href*="/gp-awesome/"], a[href*="/gp/"]'):
        href = link_el.get('href', '') or ''
        m = re.search(r'/(?:dp|gp/awesome/|gp/product/)([A-Z0-9]{10})', href)
        if m:
            return m.group(1)

    # 4. 从parent元素向上查找 (关键!)
    try:
        parent = item.parent
        for _ in range(5):  # 向上最多5层
            if not parent:
                break
            asin = parent.get('data-asin', '') or ''
            if re.fullmatch(r'[A-Z0-9]{10}', asin):
                return asin
            parent = parent.parent
    except Exception:
        pass

    # 5. 从整个HTML文本正则提取
    html = item.decode() if hasattr(item, 'decode') else str(item)
    m = re.search(r'data-asin=["\']?([A-Z0-9]{10})["\']?', html, re.I)
    if m:
        return m.group(1)

    # 6. 从任何link元素提取
    for link_el in item.select('a[href]'):
        href = link_el.get('href', '') or ''
        if '/dp/' in href or '/gp/product/' in href:
            parts = href.rstrip('/').split('/')
            for part in reversed(parts):
                if re.fullmatch(r'[A-Z0-9]{10}', part):
                    return part

    return ''



def _extract_search_price(item):
    """
    v24.0: 30年开发者经验 - 价格提取器增强版
    策略: CSS选择器 > JSON数据 > 文本正则 > 结构化数据解析 > 多级fallback
    """
    # ===== 阶段1: CSS选择器 (按优先级排列, 20+选择器) =====
    selectors_phase1 = [
        # 2024-2025新版价格格式
        '.a-price .a-offscreen',
        '.a-price-whole',
        '[data-a-color="price"] .a-offscreen',
        'span.a-price span[aria-hidden="true"]',
        '.a-color-price .a-offscreen',
        '.s-price-instructions-style .a-offscreen',
        '.a-price-range .a-offscreen',
        # data-cy属性
        '[data-cy="price-recipe"] .a-offscreen',
        '[data-cy="secondary-offer-recipe"] .a-offscreen',
        '[data-cy="main-price"] .a-offscreen',
        '[data-cy="price-block"] .a-offscreen',
        # 2024新版div结构
        '.reinventPricePriceToPayMargin .a-offscreen',
        '.reinventPricePriceToPay .a-offscreen',
        '#priceblock_ourprice .a-offscreen',
        '#priceblock_dealprice .a-offscreen',
        '#corePrice_feature_div .a-offscreen',
        '#corePriceDisplay_desktop_feature_div .a-offscreen',
        # 经典选择器
        '.a-price-whole',
        '.a-price-fraction',
        '#priceblock_listprice',
        '#priceblock_ourprice_lbl',
        # SP-PC新结构
        '.spc-price .a-offscreen',
        '.product槹价格 .a-offscreen',
    ]

    for pr_sel in selectors_phase1:
        try:
            pr_el = item.select_one(pr_sel)
            if not pr_el:
                continue
            text = pr_el.get_text(' ', strip=True)
            price = extract_num(text)
            if price > 0 and price < 100000:  # 合理价格范围
                return price
        except Exception:
            continue

    # ===== 阶段2: whole + fraction组合 =====
    try:
        whole_el = item.select_one('.a-price-whole')
        frac_el = item.select_one('.a-price-fraction, .a-price-fraction+span')
        if whole_el:
            combo = whole_el.get_text('', strip=True)
            if frac_el:
                combo = f'{combo}.{frac_el.get_text("", strip=True)}'
            price = extract_num(combo)
            if price > 0:
                return price
    except Exception:
        pass

    # ===== 阶段3: 从JSON数据提取 (Amazon新版) =====
    try:
        html = item.decode() if hasattr(item, 'decode') else str(item)
        # 提取 price
        json_patterns = [
            r'"priceAmount"\s*:\s*([0-9.]+)',
            r'"price"\s*:\s*([0-9.]+)',
            r'"amount"\s*:\s*([0-9.]+)',
            r'"formattedPrice"\s*:\s*"[^"]*(\d[\d,]+\.?\d*)"',
        ]
        for pattern in json_patterns:
            m = re.search(pattern, html, re.I)
            if m:
                price = extract_num(m.group(1))
                if price > 0 and price < 100000:
                    return price
    except Exception:
        pass

    # ===== 阶段4: 从整个item文本提取 =====
    try:
        text = item.get_text(' ', strip=True)
        # 多种价格格式
        price_patterns = [
            r'\$\s*(\d[\d,]+\.?\d*)',           # $19.99
            r'USD\s*(\d[\d,]+\.?\d*)',          # USD19.99
            r'price["\']?\s*:\s*(\d[\d,]+\.?\d*)',  # price:19.99
            r'(\d+,?\d*)\s*(?:dollars?|USD)',   # 19 dollars
        ]
        for pattern in price_patterns:
            matches = re.findall(pattern, text, re.I)
            for match in matches:
                price = extract_num(match)
                if price > 0 and price < 100000:
                    return price
    except Exception:
        pass

    # ===== 阶段5: 从data attributes提取 =====
    try:
        for attr in ['data-price', 'data-price', 'data-a-price', 'data-ga-strike-price']:
            val = item.get(attr, '')
            if val:
                price = extract_num(val)
                if price > 0:
                    return price
    except Exception:
        pass

    # ===== 阶段6: 特殊结构处理 =====
    try:
        # 处理 priceToaster (新版)
        pt = item.select_one('[id*="priceToaster"], [data-cy="priceToaster"]')
        if pt:
            text = pt.get_text(' ', strip=True)
            price = extract_num(text)
            if price > 0:
                return price

        # 处理 deal badge价格
        deal = item.select_one('.a-badge-text, [data-a-color="deal"]')
        if deal:
            text = deal.get_text(' ', strip=True)
            m = re.search(r'\$[\s]*(\d[\d,]+\.?\d*)', text)
            if m:
                price = extract_num(m.group(1))
                if price > 0:
                    return price
    except Exception:
        pass

    return 0.0



def _extract_search_rating(item):
    """
    v24.0: 30年开发者经验 - 评分提取器增强版
    策略: aria-label > title属性 > CSS class解析 > JSON数据 > 文本提取 > 多级fallback
    """
    # ===== 阶段1: aria-label和title属性 (最可靠) =====
    rating_attr_selectors = [
        '[aria-label*="out of"]',
        '[aria-label*="stars"]',
        '[aria-label*="rating"]',
        '[title*="out of"]',
        '[title*="stars"]',
        '[data-hook*="rating"]',
    ]
    for sel in rating_attr_selectors:
        try:
            el = item.select_one(sel)
            if not el:
                continue
            # 优先从aria-label提取
            text = el.get('aria-label', '') or el.get('title', '') or el.get_text(' ', strip=True)
            # 匹配各种格式: "4.5 out of 5", "4.5 out of 5 stars", "4.5/5", "4.5 stars"
            patterns = [
                r'(\d+\.?\d*)\s*(?:out of|/)\s*5',
                r'^(\d+\.?\d*)\s*(?:out of|/)\s*5',
                r'(\d+\.?\d*)\s*stars?',
            ]
            for pattern in patterns:
                m = re.search(pattern, text, re.I)
                if m:
                    rating = float(m.group(1))
                    if 0 < rating <= 5:
                        return rating
        except Exception:
            continue

    # ===== 阶段2: star元素选择器 =====
    star_selectors = [
        'i[class*="a-icon-star"] span.a-icon-alt',
        'span[class*="a-icon-alt"]',
        '.a-icon-star-small .a-icon-alt',
        '.a-star-medium .a-icon-alt',
        '.a-star-large .a-icon-alt',
        '.a-star-small .a-icon-alt',
        '.a-star-4-5 .a-icon-alt',
        '.a-star-3-5 .a-icon-alt',
        'span.a-icon-alt',
        'i.a-icon-star',
        '#acrPopover .a-icon-alt',
    ]
    for sel in star_selectors:
        try:
            el = item.select_one(sel)
            if not el:
                continue
            text = el.get('aria-label', '') or el.get('title', '') or el.get_text(' ', strip=True)
            m = re.search(r'(\d+\.?\d*)', text)
            if m:
                rating = float(m.group(1))
                if 0 < rating <= 5:
                    return rating
        except Exception:
            continue

    # ===== 阶段3: 从CSS class解析评分 (关键!) =====
    try:
        # 查找所有带star的class元素
        star_candidates = item.select('[class*="star"]')
        for star_el in star_candidates:
            classes = star_el.get('class', []) or []
            cls_str = ' '.join(classes)
            # 匹配模式: a-star-4-5, a-star-4-5, star-4-5
            patterns = [
                r'a-star-(\d)[-\s]*(\d)',
                r'star-(\d)[-\s]*(\d)',
                r'stars-(\d)[-\s]*(\d)',
            ]
            for pattern in patterns:
                m = re.search(pattern, cls_str, re.I)
                if m:
                    rating = float(f"{m.group(1)}.{m.group(2)}")
                    if 0 < rating <= 5:
                        return rating
    except Exception:
        pass

    # ===== 阶段4: JSON数据提取 =====
    try:
        html = item.decode() if hasattr(item, 'decode') else str(item)
        json_patterns = [
            r'"rating"\s*:\s*([0-9.]+)',
            r'"averageRating"\s*:\s*([0-9.]+)',
            r'"stars"\s*:\s*([0-9.]+)',
            r'"ratingValue"\s*:\s*([0-9.]+)',
        ]
        for pattern in json_patterns:
            m = re.search(pattern, html, re.I)
            if m:
                rating = float(m.group(1))
                if 0 < rating <= 5:
                    return rating
    except Exception:
        pass

    # ===== 阶段5: 从整个文本提取 =====
    try:
        text = item.get_text(' ', strip=True)
        patterns = [
            r'(\d+\.?\d*)\s*(?:out of|/)\s*5',
            r'(\d+\.?\d*)\s*/\s*5',
            r'rating\s*:?\s*(\d+\.?\d*)',
        ]
        for pattern in patterns:
            m = re.search(pattern, text, re.I)
            if m:
                rating = float(m.group(1))
                if 0 < rating <= 5:
                    return rating
    except Exception:
        pass

    # ===== 阶段6: 数字结构解析 =====
    try:
        # 查找span中的数字,通常是第一个
        num_spans = item.select('span.a-text-bubble')
        if num_spans:
            for span in num_spans:
                text = span.get_text(' ', strip=True)
                if text.isdigit() or '.' in text:
                    rating = extract_num(text)
                    if 0 < rating <= 5:
                        return rating
    except Exception:
        pass

    return 0.0



def _extract_search_reviews(item):
    """
    v24.0: 30年开发者经验 - 评论数提取器增强版
    策略: aria-label > href链接 > data属性 > CSS选择器 > JSON数据 > 文本正则
    """
    # ===== 阶段1: aria-label (最可靠) =====
    attr_selectors = [
        '[aria-label*="rating"]',
        '[aria-label*="review"]',
        '[aria-label*="customer"]',
        '[data-hook="total-review"]',
        '[data-hook="rating"]',
        '[data-a-hook="rating"]',
    ]
    for sel in attr_selectors:
        try:
            el = item.select_one(sel)
            if not el:
                continue
            text = el.get('aria-label', '') or el.get_text(' ', strip=True)
            text = text.replace(',', '').replace('.', '')
            # 匹配: "4,567 ratings", "45,678 reviews", "1234 ratings"
            m = re.search(r'(\d[\d,]*)', text)
            if m:
                count = int(m.group(1).replace(',', ''))
                if count > 0:
                    return count
        except Exception:
            continue

    # ===== 阶段2: a link元素 (常见结构) =====
    link_selectors = [
        'a[href*="customerReviews"]',
        'a[href*="#customerReviews"]',
        'a[href*="reviews"]',
        'a.s-underline-text',
        'a[aria-label*="review"]',
    ]
    for sel in link_selectors:
        try:
            el = item.select_one(sel)
            if not el:
                continue
            text = el.get('aria-label', '') or el.get_text(' ', strip=True)
            text = text.replace(',', '')
            m = re.search(r'(\d+)', text)
            if m:
                count = int(m.group(1))
                if count > 0:
                    return count
        except Exception:
            continue

    # ===== 阶段3: span元素选择器 =====
    span_selectors = [
        'span.s-underline-text',
        'span.a-size-base',
        'span.a-size-small',
        'span.a-color-secondary',
        'span[data-a-text-value]',
    ]
    for sel in span_selectors:
        try:
            el = item.select_one(sel)
            if not el:
                continue
            text = el.get('aria-label', '') or el.get_text(' ', strip=True)
            # 跳过太短的text
            text_clean = text.replace(',', '').replace('.', '')
            if len(text_clean) < 2:
                continue
            m = re.search(r'^(\d[\d,]*)', text_clean)
            if m:
                count = int(m.group(1).replace(',', ''))
                if 0 < count < 1000000:  # 合理范围
                    return count
        except Exception:
            continue

    # ===== 阶段4: data属性 =====
    try:
        for attr in ['data-total-reviews', 'data-reviews', 'data-review-count', 'data-a-dp-review']:
            val = item.get(attr, '')
            if val:
                count = int(extract_num(val))
                if count > 0:
                    return count
    except Exception:
        pass

    # ===== 阶段5: JSON数据提取 =====
    try:
        html = item.decode() if hasattr(item, 'decode') else str(item)
        json_patterns = [
            r'"reviewCount"\s*:\s*(\d+)',
            r'"totalReviews"\s*:\s*(\d+)',
            r'"reviews"\s*:\s*(\d+)',
            r'"ratingCount"\s*:\s*(\d+)',
        ]
        for pattern in json_patterns:
            m = re.search(pattern, html, re.I)
            if m:
                count = int(m.group(1))
                if count > 0:
                    return count
    except Exception:
        pass

    # ===== 阶段6: 文本正则提取 =====
    try:
        text = item.get_text(' ', strip=True)
        # 更精确的模式
        patterns = [
            r'(\d[\d,]*(?:,\d{3})*(?:\.\d+)?)\s*(?:ratings?|reviews?)',
            r'(\d{1,3}(?:,\d{3})*)\s*(?:ratings?|reviews?)',
            r'(?:ratings?|reviews?)[:\s]+(\d[\d,]*)',
        ]
        for pattern in patterns:
            m = re.search(pattern, text, re.I)
            if m:
                count = int(m.group(1).replace(',', ''))
                if count > 0 and count < 1000000:
                    return count
    except Exception:
        pass

    # ===== 阶段7: 数字bubble元素 =====
    try:
        bubbles = item.select('span.a-text-bubble, span[data-a-text-value]')
        for bubble in bubbles:
            text = bubble.get_text(' ', strip=True).replace(',', '')
            if text.isdigit():
                count = int(text)
                if 0 < count < 1000000:
                    return count
    except Exception:
        pass

    return 0



def _extract_search_image(item):
    """
    v24.0: 30年开发者经验 - 图片URL提取器增强版
    策略: data-image-latency > src > data-src > data-old-hires > source set > 任何img
    """
    # ===== 阶段1: data属性 (2024新版Amazon) =====
    img_attrs = [
        'data-image-latency',
        'data-old-hires',
        'data-a-dynamic-image',
        'data-ez-img-src',
        'data-tm-img-url',
        'data-zoom-image',
    ]
    for attr in img_attrs:
        for img_el in item.select(f'img[{attr}]'):
            url = img_el.get(attr, '') or ''
            if url and url.startswith('http'):
                normalized = _normalize_amazon_asset_url(url, 1600)
                if normalized:
                    return normalized

    # ===== 阶段2: src属性优先级 =====
    src_priority = [
        'data-image-latency="s-product-image"',
        'class="s-image"',
        'class*="product-image"',
        'class*="a-dynamic-image"',
    ]
    for sel in src_priority:
        for img_el in item.select(f'img[{sel}]'):
            url = img_el.get('src', '') or ''
            if url and 'images-amazon' in url or 'media-amazon' in url:
                normalized = _normalize_amazon_asset_url(url, 1600)
                if normalized:
                    return normalized

    # ===== 阶段3: 标准img选择器 =====
    img_selectors = [
        'img.s-image',
        'img[data-image-latency]',
        'img.a-dynamic-image',
        'img[src*="images-amazon"]',
        'img[src*="media-amazon"]',
        'img[src*="product-image"]',
        'img[alt]',
        'img',
    ]
    for sel in img_selectors:
        for img_el in item.select(sel):
            url = img_el.get('src', '') or img_el.get('data-src', '') or ''
            if url and 'blank' in url.lower():
                continue
            if url and (url.startswith('http') or 'amazon' in url):
                normalized = _normalize_amazon_asset_url(url, 1600)
                if normalized:
                    return normalized

    # ===== 阶段4: source元素 =====
    try:
        for src_el in item.select('source[type="image/*"], source[srcset]'):
            url = src_el.get('srcset', '') or src_el.get('src', '')
            if url:
                # 解析srcset获取第一个URL
                url = url.split(',')[0].strip().split(' ')[0]
                if url.startswith('http'):
                    normalized = _normalize_amazon_asset_url(url, 1600)
                    if normalized:
                        return normalized
    except Exception:
        pass

    # ===== 阶段5: picture元素 =====
    try:
        for picture in item.select('picture'):
            for img_el in picture.select('img'):
                url = img_el.get('src', '') or ''
                if url and 'amazon' in url.lower():
                    normalized = _normalize_amazon_asset_url(url, 1600)
                    if normalized:
                        return normalized
    except Exception:
        pass

    # ===== 阶段6: 任何可能的URL =====
    try:
        html = item.decode() if hasattr(item, 'decode') else str(item)
        # 从HTML提��任何图片URL
        patterns = [
            r'(https?://images[-_]?amazon[^"\'>\s]+\.(?:jpg|jpeg|png|webp))',
            r'(https?://media[-_]?amazon[^"\'>\s]+\.(?:jpg|jpeg|png|webp))',
        ]
        for pattern in patterns:
            m = re.search(pattern, html, re.I)
            if m:
                url = m.group(1)
                normalized = _normalize_amazon_asset_url(url, 1600)
                if normalized:
                    return normalized
    except Exception:
        pass

    return ''



def _normalize_keyword_line(raw):
    """
    v24.0: 关键词行标准化
    移除特殊字符,统一空格
    """
    text = re.sub(r'\s+', ' ', str(raw or '').replace('\u00a0', ' ')).strip(' |,-')
    return text.strip()


def _validate_product_minimal(p):
    """
    v24.0: 产品最小验证
    确保产品有最基本的字段
    """
    if not p:
        return False
    # 必须有ASIN或有效名称
    asin = p.get('asin', '') or ''
    name = p.get('name', '') or ''
    if not asin and not name:
        return False
    # 必须有价格
    price = _safe_float(p.get('price'))
    if price <= 0:
        return False
    return True


def _diagnose_product_health(p):
    """
    v24.0: 产品健康度诊断
    返回缺失的关键字段列表
    """
    missing = []

    if not p.get('asin'):
        missing.append('asin')
    if _safe_float(p.get('price')) <= 0:
        missing.append('price')
    if _safe_float(p.get('rating')) <= 0:
        missing.append('rating')
    if _safe_int(p.get('reviews_count')) <= 0:
        missing.append('reviews')
    if not p.get('image_url'):
        missing.append('image')
    if not p.get('name'):
        missing.append('name')
    if not p.get('category'):
        missing.append('category')

    return missing


def _enrich_product_fields(p):
    """
    v24.0: 产品字段补充
    填充计算字段和默认值
    """
    # 确保必填字段有值
    if not p.get('source'):
        p['source'] = 'amazon_search'

    # 计算成本估算
    price = _safe_float(p.get('price'))
    if price > 0 and not p.get('cost'):
        p['cost'] = round(price * 0.35, 2)  # 35%成本估算

    # BSR bucket
    bsr = _safe_int(p.get('bsr_rank'))
    if bsr > 0 and not p.get('amazon_bsr_bucket'):
        if bsr <= 1000:
            p['amazon_bsr_bucket'] = 'Top 1000'
        elif bsr <= 5000:
            p['amazon_bsr_bucket'] = 'Top 5000'
        elif bsr <= 20000:
            p['amazon_bsr_bucket'] = 'Top 20000'
        elif bsr <= 50000:
            p['amazon_bsr_bucket'] = 'Top 50000'
        else:
            p['amazon_bsr_bucket'] = '50000+'

    # 月销估算
    bsr = _safe_int(p.get('bsr_rank'))
    est = _safe_int(p.get('amazon_sales_est_monthly'))
    if bsr > 0 and est <= 0:
        # 基于BSR的简单估算
        if bsr <= 100:
            p['amazon_sales_est_monthly'] = random.randint(500, 2000)
        elif bsr <= 1000:
            p['amazon_sales_est_monthly'] = random.randint(200, 800)
        elif bsr <= 5000:
            p['amazon_sales_est_monthly'] = random.randint(80, 300)
        elif bsr <= 20000:
            p['amazon_sales_est_monthly'] = random.randint(30, 100)
        else:
            p['amazon_sales_est_monthly'] = random.randint(5, 30)
        p['amazon_sales_source'] = 'bsr_estimate'

    return p


def _extract_search_variant_count(item):
    """
    v24.0: 30年开发者经验 - 变体数量提取器增强版
    策略: 文本匹配 > data属性 > JSON数据 > 结构探测 > 链接检测
    """
    # ===== 阶段1: 文本匹配 (最强) =====
    text_selectors = [
        'span.a-size-base',
        'span.a-color-secondary',
        'span.s-variation-text',
        'span.a-text-selected-bundle',
        'span[aria-live]',
        'div[data-variant]',
    ]
    for sel in text_selectors:
        try:
            elements = item.select(sel)
            for span in elements:
                text = span.get_text(' ', strip=True)
                # 匹配: "4+ colors", "12 options", "5 sizes"
                patterns = [
                    r'(\d+)\+?\s*(?:colors?|styles?|sizes?|options?|patterns?|flavors?|variants?)',
                    r'(\d+)\s*(?:colors?|styles?|sizes?|options?|patterns?|flavors?|variants?)',
                ]
                for pattern in patterns:
                    m = re.search(pattern, text, re.I)
                    if m:
                        count = int(m.group(1))
                        if count > 0:
                            return count
        except Exception:
            continue

    # ===== 阶段2: data属性 =====
    try:
        for attr in ['data-variant-count', 'data-options', 'data-colors', 'data-sizes']:
            val = item.get(attr, '')
            if val:
                count = int(extract_num(val))
                if count > 0:
                    return count
    except Exception:
        pass

    # ===== 阶段3: JSON数据 =====
    try:
        html = item.decode() if hasattr(item, 'decode') else str(item)
        json_patterns = [
            r'"variantCount"\s*:\s*(\d+)',
            r'"optionCount"\s*:\s*(\d+)',
            r'"totalVariants"\s*:\s*(\d+)',
        ]
        for pattern in json_patterns:
            m = re.search(pattern, html, re.I)
            if m:
                count = int(m.group(1))
                if count > 0:
                    return count
    except Exception:
        pass

    # ===== 阶段4: 结构探测 =====
    try:
        # 检查是否有变体链接
        var_links = item.select('a[href*="variation"], a[data-variation]')
        if len(var_links) >= 2:
            return len(var_links)

        # 检查是否有颜色/尺寸swatch
        swatches = item.select('.swatch, .a-button-text, [class*="swatch"]')
        if len(swatches) >= 2:
            return len(swatches)

        # 检查变体按钮数量
        btns = item.select('button[name], input[type="radio"], input[type="checkbox"]')
        if len(btns) >= 2:
            return min(len(btns), 50)  # 合理上限
    except Exception:
        pass

    # ===== 阶段5: 图片数量估算 =====
    try:
        imgs = item.select('img')
        if len(imgs) >= 3:
            # 多图通常意味着有变体
            return min(len(imgs), 20)
    except Exception:
        pass

    # ===== 阶段6: 变体相关��键词检测 =====
    try:
        text = item.get_text(' ', strip=True).lower()
        keyword_patterns = [
            r'(\d+)\s*(?:colors?|styles?|sizes?|options)',
            r'(\d+)\+?\s*(?:options?|variants?)',
        ]
        for pattern in keyword_patterns:
            m = re.search(pattern, text)
            if m:
                count = int(m.group(1))
                if count > 0:
                    return count
    except Exception:
        pass

    # ===== 阶段7: 基础检测 =====
    if item.select_one('a[href*="variation"], [class*="variation"], [id*="variation"]'):
        return 2

    return 0



def _estimate_search_proxy_bsr(search_rank, badge=''):
    """
    v24.0: BSR估算增强版
    根据搜索排名和badge估算BSR,支持更多场景
    """
    # 基础估算
    if search_rank <= 1:
        est_bsr = random.randint(100, 1000)
    elif search_rank <= 3:
        est_bsr = random.randint(500, 3000)
    elif search_rank <= 5:
        est_bsr = random.randint(2000, 8000)
    elif search_rank <= 8:
        est_bsr = random.randint(5000, 15000)
    elif search_rank <= 12:
        est_bsr = random.randint(12000, 35000)
    elif search_rank <= 16:
        est_bsr = random.randint(30000, 60000)
    elif search_rank <= 20:
        est_bsr = random.randint(50000, 100000)
    else:
        est_bsr = random.randint(80000, 200000)

    # Badge调整
    badge_lower = (badge or '').lower()
    if 'best seller' in badge_lower or '#1' in badge_lower:
        est_bsr = min(est_bsr, 500)
    elif 'best' in badge_lower:
        est_bsr = min(est_bsr, 2000)
    elif 'new' in badge_lower:
        est_bsr = min(est_bsr, 10000)
    elif 'deal' in badge_lower:
        est_bsr = min(est_bsr, 8000)

    return est_bsr



def _build_search_product(item, seed_kw, search_rank):
    """
    v24.0: 30年开发者经验 - 搜索结果构建器增强版
    策略: 多重验证 + 增强字段提取 + 严格验证
    """
    # ===== ASIN提取 =====
    asin = _extract_search_asin(item)
    if not asin:
        return None

    # ===== 标题提取 (多选择器) =====
    title_selectors = [
        'h2 a span',
        'h2 span',
        'h2',
        '[data-cy="title-recipe"] span',
        '[data-cy="title-recipe"] h2',
        '[data-automation-id]',
        '.a-text-normal',
        '.a-text-bold',
    ]
    title = ''
    for sel in title_selectors:
        t_el = item.select_one(sel)
        if t_el:
            title = _normalize_keyword_line(t_el.get_text(' ', strip=True))
            if len(title) > 5:
                break

    if not title or not _search_title_looks_valid(title):
        return None

    # ===== 价格提取 =====
    price = _extract_search_price(item)

    # ===== 评分提取 =====
    rating = _extract_search_rating(item)

    # ===== 评论数提取 =====
    rev_count = _extract_search_reviews(item)

    # ===== Badge提取 =====
    badge_selectors = [
        '.a-badge-text',
        '.a-badge-label-inner',
        'span.a-badge',
        'span[class*="badge"]',
        '[data-badge]',
    ]
    badge = ''
    for sel in badge_selectors:
        badge_el = item.select_one(sel)
        if badge_el:
            badge = badge_el.get_text(' ', strip=True)
            if badge:
                break

    # ===== 图片URL提取 =====
    img_url = _extract_search_image(item)

    # ===== 变体数量 =====
    variant_count = _extract_search_variant_count(item)

    # ===== 构建产品 =====
    p = _make_product(
        title,
        'keywords_txt_short',
        price,
        seed_kw,
        asin=asin,
        url=build_amazon_url(asin),
        image_url=img_url,
        rating=rating,
        reviews_count=rev_count,
        badge=badge,
    )

    # ===== 补充字段 =====
    p['seed_keyword'] = seed_kw
    p['verify_keyword'] = derive_verify_keyword(title, fallback=seed_kw)
    p['amazon_search_rank'] = search_rank
    p['amazon_result_page'] = 1
    p['amazon_badge_text'] = badge
    p['bsr_rank'] = _estimate_search_proxy_bsr(search_rank, badge)
    p['amazon_bsr_source'] = 'search_proxy'

    if variant_count > 0:
        p['variant_count'] = variant_count
        p['has_variants'] = True
        p['variant_types'] = '多选项'
        p['amazon_sku_count'] = variant_count
        p['amazon_variant_source'] = 'search_snippet'

    # ===== 应用Amazon事实增强 =====
    _apply_amazon_fact_enrichment(p, source='search_snippet')
    return p



def _search_page_low_signal(html, batch):
    """
    v24.0: 低信号检测
    判断搜索结果页是否为低质量页(CAPTCHA等)
    """
    text = str(html or '')[:12000].lower()
    if not text:
        return True
    if len(batch) >= CommercialConfig.SEARCH_LOW_SIGNAL_MIN_ITEMS:
        return False
    low_signal_terms = [
        'captcha', 'robot', 'automated', 'unusual traffic', 'enter the characters',
        'sorry, we just need to make sure', 'sign in', 'check your browser', 'access denied',
    ]
    return any(term in text for term in low_signal_terms) or 'data-asin' not in text


def _filter_valid_products(products):
    """
    v24.0: 过滤有效产品
    确保每个产品有最基本的字段
    """
    valid = []
    for p in products:
        if _validate_product_minimal(p):
            valid.append(p)
    return valid


def _print_field_coverage(products, prefix="  "):
    """
    v24.0: 打印字段覆盖率
    用于诊断
    """
    if not products:
        return

    fields = ['asin', 'name', 'price', 'rating', 'reviews_count', 'image_url', 'category', 'bsr_rank']
    covered = {f: 0 for f in fields}

    for p in products:
        for f in fields:
            val = p.get(f)
            if f in ['price', 'rating', 'reviews_count', 'bsr_rank']:
                if val and float(val) > 0:
                    covered[f] += 1
            elif val:
                covered[f] += 1

    log.info(f"{prefix}字段覆盖率:")
    for f, count in covered.items():
        pct = (count / len(products) * 100) if products else 0
        log.info(f"  {f}: {count}/{len(products)} ({pct:.0f}%)")



def _rescue_product_from_pdp(product):
    """
    v24.0: 30年开发者经验 - PDP救援函数增强版
    策略: 重试多次 + 多选择器 + JSON数据 + 文本正则兜底
    """
    asin = _safe_str(product.get('asin'))
    if not re.fullmatch(r'[A-Z0-9]{10}', asin):
        return False

    # 多次重试抓取
    html = None
    for attempt in range(3):
        html = _smart_amz_fetch(build_amazon_url(asin), retries=1)
        if html and len(html) > 5000:
            break
        import time
        time.sleep(1)

    if not html or len(html) < 5000:
        return False

    soup = BeautifulSoup(html, 'html.parser')
    page_text = soup.get_text(' ', strip=True)
    rescued = False

    # ===== 价格提取 (多选择器) =====
    if product.get('price', 0) <= 0:
        # 先用搜索页的函数
        price = _extract_search_price(soup)
        if price <= 0:
            # 兜底选择器
            price_selectors = [
                '.a-price .a-offscreen',
                '.reinventPricePriceToPayMargin .a-offscreen',
                '#corePriceDisplay_desktop_feature_div .a-offscreen',
                '#corePrice_feature_div .a-offscreen',
                '#priceblock_ourprice',
                '#priceblock_dealprice',
                '.a-price-whole',
                '[data-a-color="price"] .a-offscreen',
            ]
            for sel in price_selectors:
                el = soup.select_one(sel)
                if el:
                    price = extract_num(el.get_text(' ', strip=True))
                    if price > 0:
                        break
        if price <= 0:
            # 正则兜底
            m = re.search(r'\$\s*(\d[\d,]+\.?\d*)', page_text)
            if m:
                price = extract_num(m.group(1))
        if price > 0:
            product['price'] = price
            rescued = True

    # ===== 评分提取 =====
    if product.get('rating', 0) <= 0:
        rating_selectors = [
            '#acrPopover',
            '[data-hook="rating-out-of-text"]',
            'i[data-hook="average-star-rating"] span',
            '.a-popover-inner',
            '#avgRating .a-icon-alt',
        ]
        for sel in rating_selectors:
            el = soup.select_one(sel)
            if el:
                text = el.get('title', '') or el.get('aria-label', '') or el.get_text(' ', strip=True)
                m = re.search(r'(\d+\.?\d*)', text)
                if m:
                    rating = float(m.group(1))
                    if 0 < rating <= 5:
                        product['rating'] = rating
                        rescued = True
                        break

    # ===== 评论数提取 =====
    if product.get('reviews_count', 0) <= 0:
        reviews_selectors = [
            '#acrCustomerReviewText',
            '[data-hook="total-review-count"]',
            'a[href*="#customerReviews"]',
            '#reviewsSummary .a-link-emphasis',
        ]
        for sel in reviews_selectors:
            el = soup.select_one(sel)
            if el:
                text = el.get_text(' ', strip=True)
                text = text.replace(',', '').replace('.', '')
                m = re.search(r'(\d+)', text)
                if m:
                    reviews = int(m.group(1))
                    if reviews > 0:
                        product['reviews_count'] = reviews
                        rescued = True
                        break

    # ===== 品牌提取 =====
    brand_el = soup.select_one('#bylineInfo, a#bylineInfo, a#brand, #brand, [data-feature-name="brand"]')
    brand = brand_el.get_text(' ', strip=True) if brand_el else ''
    # 处理 "Visit the X Brand" 格式
    brand = re.sub(r'^(Visit the|Brand:|Brand)\s+', '', brand, flags=re.I).strip()
    if brand and not product.get('amazon_brand'):
        product['amazon_brand'] = brand
        rescued = True

    # ===== Sold By / Ships From =====
    sold_by_selectors = [
        '#merchantInfo', '#tabular-buybox .tabular-buybox-text', '#shipsFromSoldBy_feature_div',
        '#sellerProfileTriggerId', '#newAccordionRow_1 .a-color-base', '#fulfillerInfoFeature_feature_div',
        '#newAccordionRow .a-color-base',
    ]
    sold_by = _safe_str(product.get('amazon_sold_by'))
    ships_from = _safe_str(product.get('amazon_ships_from'))
    for sel in sold_by_selectors:
        el = soup.select_one(sel)
        if not el:
            continue
        txt = el.get_text(' ', strip=True)
        if 'Sold by' in txt and not sold_by:
            m = re.search(r'Sold by\s+([^.;|]+)', txt, re.I)
            if m:
                sold_by = m.group(1).strip()
        if 'Ships from' in txt and not ships_from:
            m = re.search(r'Ships from\s+([^.;|]+)', txt, re.I)
            if m:
                ships_from = m.group(1).strip()
    # 文本正则兜底
    if not sold_by:
        m = re.search(r'Sold by\s+([^.;|]+)', page_text, re.I)
        if m:
            sold_by = m.group(1).strip()
    if not ships_from:
        m = re.search(r'Ships from\s+([^.;|]+)', page_text, re.I)
        if m:
            ships_from = m.group(1).strip()
    if sold_by and sold_by != product.get('amazon_sold_by'):
        product['amazon_sold_by'] = sold_by
        rescued = True
    if ships_from and ships_from != product.get('amazon_ships_from'):
        product['amazon_ships_from'] = ships_from
        rescued = True

    # ===== Offer数量 =====
    offer_el = soup.select_one('#olp-upd-new, #aod-offer-count, [href*="all-offers-display"], #aod-pagination')
    if offer_el:
        offer_count = int(extract_num(offer_el.get_text(' ', strip=True)))
        if offer_count > 0 and offer_count != _safe_int(product.get('amazon_offer_count')):
            product['amazon_offer_count'] = offer_count
            product['amz_seller_count'] = offer_count
            rescued = True

    # ===== A+ Content =====
    if not product.get('amazon_has_aplus') and soup.select_one('#aplus, #aplusProductDescription, [class*="aplus"]'):
        product['amazon_has_aplus'] = True
        rescued = True

    # ===== 图片数量 =====
    if _safe_int(product.get('amazon_main_image_count')) <= 0:
        img_selectors = [
            '#altImages img',
            '#imageBlock img',
            '#main-image-container img',
            'img[data-old-hires]',
            '.a-dynamic-image',
        ]
        total_imgs = 0
        for sel in img_selectors:
            total_imgs = len(soup.select(sel))
            if total_imgs > 0:
                break
        if total_imgs > 0:
            product['amazon_main_image_count'] = total_imgs
            rescued = True

    # ===== Bullet数量 =====
    if _safe_int(product.get('amazon_bullet_count')) <= 0:
        bullet_lis = soup.select('#feature-bullets li, #productDescription li, .feature li')
        bullet_count = len([li for li in bullet_lis if li.get_text(' ', strip=True)])
        if bullet_count > 0:
            product['amazon_bullet_count'] = bullet_count
            rescued = True

    # ===== 变体数量 =====
    sku_count = int(product.get('amazon_sku_count', 0) or product.get('variant_count', 0) or 0)
    variant_labels = set()
    variantSelectors = [
        '#variation_style_name .a-row',
        '#variation_color_name .a-row',
        '#variation_size_name .a-row',
        '.a-dropdown-container label',
        '[data-variation-type]',
    ]
    for label_el in soup.select(', '.join(variantSelectors)):
        label_text = label_el.get_text(strip=True).lower()
        if any(k in label_text for k in ['color', 'size', 'style', 'pattern', 'flavor']):
            variant_labels.add(label_text.split(':')[0].strip())

    var_btns = soup.select('#variation_style_name li, #variation_color_name li, .swatchSelect, [id*="variation"] li')
    sku_count = max(sku_count, len(var_btns) if var_btns else 0)

    # JSON数据提取变体数量
    twister_match = re.search(r'"dimensionValuesDisplayData"\s*:\s*\{([^}]+)\}', html)
    if twister_match:
        dims = twister_match.group(1)
        asin_count = len(re.findall(r'"B[A-Z0-9]{9}"', dims))
        sku_count = max(sku_count, asin_count)
    if sku_count > 1:
        product['variant_count'] = sku_count
        product['has_variants'] = True
        product['amazon_sku_count'] = sku_count
        product['variant_types'] = ', '.join(sorted(variant_labels)) if variant_labels else (product.get('variant_types') or f'{sku_count} variants')
        product['amazon_variant_source'] = 'amazon_pdp_rescue'
        rescued = True

    if _safe_str(product.get('amazon_bsr_source')) != 'amazon_pdp':
        bsr_patterns = [
            r'Best Sellers Rank\s*#?([\d,]+)',
            r'#([\d,]+)\s+in\s+[A-Za-z& ,\-]+'
        ]
        for pattern in bsr_patterns:
            m = re.search(pattern, page_text, re.I)
            if not m:
                continue
            cand = int(m.group(1).replace(',', ''))
            if cand > 0:
                product['bsr_rank'] = cand
                product['amazon_bsr_source'] = 'amazon_pdp'
                rescued = True
                break

    if rescued:
        _apply_amazon_fact_enrichment(product, source='amazon_pdp_rescue')
    return rescued



def _rescue_search_batch(products):
    rescued = 0
    attempted = 0
    for p in products:
        if attempted >= CommercialConfig.SEARCH_PDP_RESCUE_LIMIT:
            break
        rank = _safe_int(p.get('amazon_search_rank'))
        needs_rescue = (
            p.get('price', 0) <= 0
            or p.get('reviews_count', 0) <= 0
            or p.get('rating', 0) <= 0
            or _safe_str(p.get('amazon_bsr_source')) == 'search_proxy'
        )
        if not needs_rescue or rank <= 0 or rank > CommercialConfig.SEARCH_PDP_RESCUE_RANK_MAX:
            continue
        attempted += 1
        if _rescue_product_from_pdp(p):
            rescued += 1
    return attempted, rescued



def scrape_from_short_keywords(filepath='keywords.txt'):
    keywords = load_short_keywords(filepath)
    if not keywords:
        log.warning(f"  ⚠️ 无有效短关键词 ({filepath})")
        return []
    log.info(f"📋 [v25.0] 短关键词加载: {len(keywords)} 个")
    all_products = []

    # v24.0: 诊断统计
    total_extracted = {'asin': 0, 'price': 0, 'rating': 0, 'reviews': 0, 'image': 0, 'variant': 0}
    total_rescued = {'price': 0, 'rating': 0, 'reviews': 0}

    for i, seed_kw in enumerate(keywords, 1):
        log.info(f"  🔍 [{i}/{len(keywords)}] 短词搜索: '{seed_kw}'")
        try:
            url = "https://www.amazon.com/s?k=" + urllib.parse.quote_plus(seed_kw) + "&s=exact-aware-popularity-rank"
            html = SmartFetcher.fetch(url, allow_pw=False)
            if not html:
                log.warning(f"    ❌ 无结果: {seed_kw}")
                continue
            soup = BeautifulSoup(html, 'html.parser')
            batch = []
            nodes = soup.select('div[data-asin], div.s-result-item[data-component-type="s-search-result"]')[:24]

            # v24.0: 诊断 - 提取前先统计
            for item in nodes:
                # 预检查各字段提取成功率
                if _extract_search_asin(item):
                    total_extracted['asin'] += 1
                if _extract_search_price(item) > 0:
                    total_extracted['price'] += 1
                if _extract_search_rating(item) > 0:
                    total_extracted['rating'] += 1
                if _extract_search_reviews(item) > 0:
                    total_extracted['reviews'] += 1
                if _extract_search_image(item):
                    total_extracted['image'] += 1
                if _extract_search_variant_count(item) > 0:
                    total_extracted['variant'] += 1

                p = _build_search_product(item, seed_kw, len(batch) + 1)
                if p:
                    batch.append(p)

            if _search_page_low_signal(html, batch):
                fallback_html = _smart_amz_fetch(url, retries=2)
                if fallback_html:
                    fallback_soup = BeautifulSoup(fallback_html, 'html.parser')
                    fallback_batch = []
                    seen_asins = set()
                    fallback_nodes = fallback_soup.select('div[data-asin], div.s-result-item[data-component-type="s-search-result"]')[:24]
                    for item in fallback_nodes:
                        p = _build_search_product(item, seed_kw, len(fallback_batch) + 1)
                        if not p:
                            continue
                        asin = p.get('asin', '')
                        if asin in seen_asins:
                            continue
                        seen_asins.add(asin)
                        fallback_batch.append(p)
                    if len(fallback_batch) > len(batch):
                        batch = fallback_batch

            # 记录rescue前状态
            for p in batch:
                if p.get('price', 0) <= 0:
                    total_rescued['price'] += 1
                if p.get('rating', 0) <= 0:
                    total_rescued['rating'] += 1
                if p.get('reviews_count', 0) <= 0:
                    total_rescued['reviews'] += 1

            price_missing = sum(1 for p in batch if p.get('price', 0) <= 0)
            review_missing = sum(1 for p in batch if p.get('reviews_count', 0) <= 0)
            rating_missing = sum(1 for p in batch if p.get('rating', 0) <= 0)
            rescue_attempted, rescue_hit = _rescue_search_batch(batch)

            log.info(
                f"    ✅ 抓到 {len(batch)} 个真实产品 | 缺价 {price_missing} | 缺评 {review_missing} | 缺星 {rating_missing} | PDP补全 {rescue_hit}/{rescue_attempted}"
            )
            all_products.extend(batch)
            Config.delay(0.3)
        except Exception as e:
            log.error(f"    ❌ 短词采集异常 [{seed_kw}]: {e}")

    # v24.0: 打印诊断报告
    log.info(f"📊 [v25.0] 提取诊断报告:")
    log.info(f"   ASIN: {total_extracted['asin']} | 价格: {total_extracted['price']} | 评分: {total_extracted['rating']} | 评论: {total_extracted['reviews']} | 图片: {total_extracted['image']} | 变体: {total_extracted['variant']}")
    log.info(f"   待救援: 价格 {total_rescued['price']} | 评分 {total_rescued['rating']} | 评论 {total_rescued['reviews']}")

    return all_products


def round1_rank(products):
    for p in products:
        try:
            Expert.enrich(p)
            score_product(p, is_round2=False)
            synthesize_commercial_fields(p)
            p.update(compute_selection_core_scores(p))
            p.update(derive_selection_route(p))
            p.update(build_professional_decision_card(p))
            p['selection_bucket_tag'] = compute_selection_bucket_tag(p)
        except Exception as e:
            log.debug(f"  ⚠️ Round1异常 [{p.get('name','')[:24]}]: {e}")
    products.sort(key=compute_selection_priority_key, reverse=True)
    return products



def _quick_fb_policy_note(p):
    text = (str(p.get('name', '')) + ' ' + str(p.get('category', ''))).lower()
    for kw in ProfessionalScorer.FB_POLICY_RISK['blocked']:
        if kw in text:
            return 'blocked'
    for kw in ProfessionalScorer.FB_POLICY_RISK['caution']:
        if kw in text:
            return 'caution'
    return 'safe'



def _normalize_signal_part(text):
    text = re.sub(r'\s+', ' ', str(text or '')).strip(' |')
    if not text:
        return ''
    alias_map = {
        'Amazon需求不足': 'Amazon需求证明不足',
        'PDP素材/卖点不足': 'PDP卖点/异议层还不够',
        'FB盈利未证实': 'FB经济模型未证实',
        '缺FB验证': 'FB经济模型未证实',
        'FB回本未证实': 'FB经济模型未证实',
        '证据质量不足': '证据覆盖还不够完整',
        '素材冲击偏弱': '素材冲击不够',
        '预算门槛高': '冷启动预算偏高',
        '测试预算略高': '冷启动预算偏高',
        '转化链偏长': '转化链路偏长',
        '转化链路长': '转化链路偏长',
        '客单不足': '客单偏低',
        '外部市场承接弱': '市场承接仍薄',
        '物流摩擦大': '物流受限',
        'FB政策不友好': 'FB政策高风险',
        '缺Google Trends': '趋势证据不够硬',
    }
    return alias_map.get(text, text)



def _dedupe_signal_parts(parts):
    out = []
    seen = set()
    for raw in parts:
        text = _normalize_signal_part(raw)
        if not text:
            continue
        key = text.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(text)
    return out



def _dedupe_text_parts(parts):
    out = []
    seen = set()
    for raw in parts:
        text = re.sub(r'\s+', ' ', str(raw or '')).strip(' |；')
        if not text:
            continue
        key = text.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(text)
    return out



def _join_reason_parts(parts, limit=5):
    return '；'.join(_dedupe_text_parts(parts)[:limit])



def _decision_gap_parts(frame, blockers, limit=2, product=None, persist=False):
    if isinstance(product, dict) and not persist:
        locked = []
        primary_locked = _normalize_signal_part(product.get('decision_primary_gap', ''))
        secondary_locked = _normalize_signal_part(product.get('decision_secondary_gap', ''))
        if primary_locked:
            locked.append(primary_locked)
        if secondary_locked and secondary_locked != primary_locked:
            locked.append(secondary_locked)
        if locked:
            return locked[:limit]

    ordered = []
    primary = _normalize_signal_part(frame.get('primary_gap', '')) if isinstance(frame, dict) else ''
    if primary:
        ordered.append(primary)
    blocker_items = blockers if isinstance(blockers, (list, tuple)) else re.split(r'\s*\|\s*', str(blockers or ''))
    for item in _dedupe_signal_parts(blocker_items):
        if not item or item == primary:
            continue
        ordered.append(item)
        if len(ordered) >= limit:
            break
    ordered = ordered[:limit]
    if isinstance(product, dict) and persist:
        product['decision_primary_gap'] = ordered[0] if ordered else ''
        product['decision_secondary_gap'] = ordered[1] if len(ordered) > 1 else ''
    return ordered



def _decision_reason(mode, frame, blockers, product=None):
    gaps = _decision_gap_parts(frame, blockers, limit=2, product=product)
    win_path = str((frame or {}).get('win_path', '') or '').strip()
    test_focus = str((frame or {}).get('test_focus', '') or '').strip()
    parts = []
    if mode == '可直接开测 / 可放大':
        parts.append('Launch-ready: demand, PDP, and media path are in place')
        if win_path:
            parts.append('Win path: ' + win_path)
        if test_focus:
            parts.append('First test/首测: ' + test_focus)
    elif mode == '可小预算测试':
        parts.append('Real product; start with a controlled small-budget test')
        if gaps:
            parts.append('Primary gap/主缺口: ' + gaps[0])
        if len(gaps) > 1:
            parts.append('Secondary gap/次缺口: ' + gaps[1])
        if test_focus:
            parts.append('First test/首测: ' + test_focus)
    elif mode == '真实产品但先补一个关键证据':
        parts.append('Real product, but fill one key proof gap first: ' + (gaps[0] if gaps else '关键证据'))
        if len(gaps) > 1:
            parts.append('Next gap/其次补: ' + gaps[1])
        if test_focus:
            parts.append('After proof, test this first/补完后先测: ' + test_focus)
    else:
        parts.append('Structurally not a priority right now')
        if gaps:
            parts.append('Primary blocker/主阻碍: ' + gaps[0])
        if len(gaps) > 1:
            parts.append('Secondary blocker/次阻碍: ' + gaps[1])
    return _join_reason_parts(parts, limit=4)



def _decision_basis(mode, frame, blockers, product=None):
    gaps = _decision_gap_parts(frame, blockers, limit=2, product=product)
    win_path = str((frame or {}).get('win_path', '') or '').strip()
    parts = []
    if mode == '可直接开测 / 可放大':
        parts.append('Launch now / 可直接开测')
        if win_path:
            parts.append('Win path: ' + win_path)
    elif mode == '可小预算测试':
        parts.append('Run a small-budget test first / 先小预算测试')
        if gaps:
            parts.append('Close: ' + gaps[0])
        if len(gaps) > 1:
            parts.append('Then: ' + gaps[1])
    elif mode == '真实产品但先补一个关键证据':
        parts.append('Fill one key proof gap first / 先补关键证据')
        if gaps:
            parts.append('Close: ' + gaps[0])
        if len(gaps) > 1:
            parts.append('Then: ' + gaps[1])
    else:
        parts.append('Not a priority now / 结构性不优先')
        if gaps:
            parts.append('Blocker: ' + gaps[0])
        if len(gaps) > 1:
            parts.append('Then: ' + gaps[1])
    return _join_parts(parts, limit=3)



def _is_high_risk_fallback(p):
    policy = _safe_str(p.get('fb_policy_risk'))
    shipping = _safe_str(p.get('shipping_feasibility'))
    return policy.startswith('🔴') or shipping.startswith('🔴')



def _fallback_priority_tuple(p):
    frame = _commercial_decision_frame(p)
    policy = _safe_str(p.get('fb_policy_risk'))
    shipping = _safe_str(p.get('shipping_feasibility'))
    trend_quality = _safe_str(p.get('google_trends_quality'))
    trend_direction = _safe_str(p.get('trend_direction'))
    fb_days = _safe_int(p.get('fb_oldest_ad_days'))
    profit_cold = _safe_float(p.get('profit_cold'))
    roas_cold = _safe_float(p.get('est_roas_cold'))
    creative = _safe_str(p.get('fb_creative_feasibility'))
    main_gap = _normalize_signal_part(p.get('decision_primary_gap', '') or frame.get('primary_gap', ''))
    price = _safe_float(p.get('price'))
    pain_level = _safe_str(p.get('pain_level')).upper()
    scene_detail = _safe_str(p.get('scene_detail'))
    has_video = bool(p.get('amazon_has_video'))
    impulse_friendly = bool(p.get('impulse_friendly'))
    review_creative_angle_score = _safe_float(p.get('review_creative_angle_score'))

    paid_ready = bool(
        fb_days >= 14
        or (profit_cold > 0 and roas_cold >= 1.2)
        or _safe_float(p.get('paid_media_score')) >= 52
    )
    trend_ready = bool(
        p.get('google_trends_sufficient')
        or trend_quality == 'strong'
        or (trend_quality == 'medium' and trend_direction in ('↑↑', '↑', '→'))
    )
    demo_ready = bool(
        p.get('has_before_after')
        or p.get('visual_demo')
        or has_video
        or creative.startswith('强')
        or frame.get('offer_edge_score', 0) >= 55
        or frame.get('media_fit_score', 0) >= 48
        or review_creative_angle_score >= 55
    )
    impulse_ready = bool(
        impulse_friendly
        or (pain_level in ('S', 'A') and price >= 80)
        or review_creative_angle_score >= 55
    )
    asset_ready = bool(
        scene_detail
        or review_creative_angle_score >= 50
        or frame.get('offer_edge_score', 0) >= 58
    )
    market_ready = bool(
        frame.get('market_support_score', 0) >= 24
        or p.get('shopify_competitors', 0)
        or p.get('google_shop_sellers', 0)
        or p.get('us_search_volume', 0)
    )
    gap_rank = {
        '证据覆盖还不够完整': 4,
        '趋势证据不够硬': 3,
        '市场承接仍薄': 2,
        'FB经济模型未证实': 2,
        'PDP卖点/异议层还不够': 1,
        'Amazon需求证明不足': 0,
        '趋势下行，当前不宜优先': -1,
    }.get(main_gap, 1)

    return (
        0 if policy.startswith('🔴') else 1,
        0 if shipping.startswith('🔴') else 1,
        0 if policy.startswith('🟡') else 1,
        1 if paid_ready else 0,
        1 if trend_ready else 0,
        1 if demo_ready else 0,
        1 if impulse_ready else 0,
        1 if asset_ready else 0,
        1 if market_ready else 0,
        gap_rank,
        -(frame.get('execution_friction_score', 0) or 0),
        frame.get('asymmetry_score', 0) or 0,
        frame.get('media_fit_score', 0) or 0,
        frame.get('offer_edge_score', 0) or 0,
        p.get('paid_media_score', 0),
        p.get('amazon_fact_score', 0),
        p.get('evidence_quality_score', 0),
        p.get('validation_priority_score', 0),
    )



def _append_unique_part(parts, text):
    text = _normalize_signal_part(text)
    if text and text not in _dedupe_signal_parts(parts):
        parts.append(text)



