def _review_media_summary(media):
    items = [x for x in (media or []) if isinstance(x, dict)]
    if not items:
        return ''
    image_count = sum(1 for x in items if str(x.get('type') or '').lower() != 'video')
    video_count = sum(1 for x in items if str(x.get('type') or '').lower() == 'video')
    parts = []
    if image_count:
        parts.append(f'{image_count} buyer photo{"s" if image_count != 1 else ""}')
    if video_count:
        parts.append(f'{video_count} buyer video{"s" if video_count != 1 else ""}')
    first_caption = ''
    for item in items:
        caption = _short_phrase(item.get('caption', ''), 34)
        if caption:
            first_caption = caption
            break
    if first_caption:
        parts.append(f'best proof: {first_caption}')
    return _join_parts(parts, limit=3)



def _safe_copy_anchor(product=None):
    p = product if isinstance(product, dict) else {}
    anchor = str(p.get('verify_keyword') or p.get('seed_keyword') or p.get('name') or '').strip()
    anchor = re.sub(r'\s+', ' ', anchor)
    return _short_phrase(anchor, 48)



def _direct_response_copy_mode(product=None, frame=None, tier='weak'):
    p = product if isinstance(product, dict) else {}
    commercial_frame = frame if isinstance(frame, dict) else _commercial_decision_frame(p)
    verification_passed = bool(p.get('verification_passed'))
    roas_cold = _safe_float(p.get('est_roas_cold'))
    profit_cold = _safe_float(p.get('profit_cold'))
    budget_min = _safe_float(p.get('daily_budget_min'))
    touchpoints = _safe_int(p.get('fb_touchpoints_needed'))
    fb_days = _safe_int(p.get('fb_oldest_ad_days'))
    creative = _safe_str(p.get('fb_creative_feasibility'))
    policy = _safe_str(p.get('fb_policy_risk'))
    shipping = _safe_str(p.get('shipping_feasibility'))
    evidence_quality = _safe_float(p.get('evidence_quality_score'))
    paid_media_score = _safe_float(p.get('paid_media_score'))
    primary_gap = _safe_str(commercial_frame.get('primary_gap'))
    friction = _safe_float(commercial_frame.get('execution_friction_score'))
    asymmetry = _safe_float(commercial_frame.get('asymmetry_score'))
    offer_edge = _safe_float(commercial_frame.get('offer_edge_score'))
    media_fit = _safe_float(commercial_frame.get('media_fit_score'))
    market_support = _safe_float(commercial_frame.get('market_support_score'))

    if policy.startswith('🔴') or shipping.startswith('🔴') or primary_gap in ('趋势下行，当前不宜优先', 'Amazon需求证明不足'):
        return 'hold / not ad-ready'

    scale_ready = bool(
        verification_passed
        and tier in ('strong', 'medium')
        and roas_cold >= 5.0
        and profit_cold >= 20
        and budget_min <= 80
        and 0 < touchpoints <= 2
        and not policy.startswith('🟡')
        and friction <= 24
        and asymmetry >= 62
        and media_fit >= 58
        and offer_edge >= 48
        and market_support >= 24
        and evidence_quality >= 52
        and (creative.startswith('强') or paid_media_score >= 62 or fb_days >= 14)
    )
    if scale_ready:
        return 'scale-grade direct response'

    test_ready = bool(
        verification_passed
        and tier in ('strong', 'medium')
        and friction <= 42
        and offer_edge >= 38
        and media_fit >= 40
        and (roas_cold >= 1.5 or profit_cold > 0 or paid_media_score >= 50 or fb_days >= 14)
    )
    if test_ready:
        return 'test-grade direct response'

    if verification_passed or primary_gap:
        return 'proof-first / conservative'
    return 'hold / not ad-ready'



def _direct_response_cta(mode, channel='fb'):
    if channel == 'shopify':
        if mode == 'scale-grade direct response':
            return 'Lead the page to the buy decision fast.'
        if mode == 'test-grade direct response':
            return 'Make the first click-to-cart path easy to judge.'
        return 'Keep the page proof-first and easy to scan.'
    if mode == 'scale-grade direct response':
        return 'Shop the full product details now.'
    if mode == 'test-grade direct response':
        return 'Check the product details before you buy.'
    if mode == 'proof-first / conservative':
        return 'See whether it fits the way you would use it.'
    return 'Review the product details before testing.'



def _direct_response_promise(text, product=None):
    raw = _review_headline_line(text, 64) or _review_copy_line(text, 72, sentence=False)
    bucket = _review_proof_bucket(raw or text)
    if bucket == 'quiet':
        return 'Quieter everyday use'
    if bucket == 'cleanliness':
        return 'A cleaner routine with less mess'
    if bucket == 'ease':
        return 'An easier start from the first use'
    if bucket == 'performance':
        return 'A result buyers notice in real use'
    if bucket == 'battery':
        return 'Longer runtime with less charging friction'
    if bucket == 'usage':
        return 'A use case buyers understand right away'
    if raw:
        return raw[:1].upper() + raw[1:]
    anchor = _safe_copy_anchor(product)
    return f'The clearest use case for {anchor}' if anchor else ''



def _direct_response_mechanism(text, product=None):
    raw = _review_copy_line(text, 88) or _review_copy_line(text, 72, sentence=False)
    bucket = _review_proof_bucket(raw or text)
    if raw and bucket in ('cleanliness', 'ease', 'performance', 'battery', 'usage'):
        return raw
    if bucket == 'quiet':
        return 'Use the quieter day-to-day routine as the mechanism buyers can picture fastest.'
    if bucket == 'cleanliness':
        return 'Show how the lower-mess routine is different in real use.'
    if bucket == 'ease':
        return 'Make the low-friction setup or first-use flow the proof of value.'
    if bucket == 'performance':
        return 'Show the practical payoff in a way buyers can see quickly.'
    if bucket == 'battery':
        return 'Make runtime and lower charging friction part of the reason to believe.'
    if bucket == 'usage':
        return 'Tie the product to the exact routine where the payoff is easiest to picture.'
    anchor = _safe_copy_anchor(product)
    return f'Keep {anchor} explained through the first real use case buyers care about.' if anchor else ''



def _direct_response_hook(product=None, promise='', mode='proof-first / conservative'):
    anchor = _safe_copy_anchor(product)
    promise = re.sub(r'\s+', ' ', str(promise or '')).strip(' .')
    if mode == 'scale-grade direct response':
        if promise:
            return promise
        if anchor:
            return f'Why {anchor} wins the click fast'
    if mode == 'test-grade direct response':
        if promise:
            return promise
        if anchor:
            return f'The clearest use case for {anchor}'
    if anchor:
        return f'Why buyers consider {anchor} first'
    return 'The clearest use case to test first'



def _direct_response_frame(product=None, pos_points=None, neg_points=None, frame=None, tier='weak'):
    p = product if isinstance(product, dict) else {}
    commercial_frame = frame if isinstance(frame, dict) else _commercial_decision_frame(p, pos_points=pos_points, neg_points=neg_points)
    proofs = _review_proof_lines(pos_points, limit=6 if tier == 'strong' else 4, max_chars=88, min_chars=24)
    main = _pick_bucket_line(proofs, 'performance', 'cleanliness', 'ease', 'quiet', 'battery', 'usage', 'general')
    support = ''
    for candidate in proofs:
        if candidate != main:
            support = candidate
            break
    objection = ''
    answer = ''
    for point in list(neg_points or [])[:4]:
        objection = _review_question(point)
        if objection:
            answer = _review_objection_answer(point)
            break
    promise = _direct_response_promise(main, p)
    mechanism = _direct_response_mechanism(support or main, p)
    mode = _direct_response_copy_mode(p, commercial_frame, tier=tier)
    proof = _review_copy_line(main, 88) if main else ''
    support_proof = _review_copy_line(support, 88) if support else ''
    hero = promise or _safe_copy_anchor(p)
    hook = _direct_response_hook(p, promise=promise, mode=mode)
    angle = _review_angle_label(support or main or objection)
    cta = _direct_response_cta(mode, 'fb')
    section_cta = _direct_response_cta(mode, 'shopify')
    summary = _join_parts([mode, promise, mechanism, proof or support_proof, objection], limit=4)
    return {
        'mode': mode,
        'promise': promise,
        'mechanism': mechanism,
        'proof': proof,
        'support_proof': support_proof,
        'objection': objection,
        'answer': answer,
        'hero': hero,
        'hook': hook,
        'angle': angle,
        'cta': cta,
        'section_cta': section_cta,
        'summary': summary,
    }



def _copy_clean_text(text, max_chars=0, allow_cjk=False):
    raw = re.sub(r'\s+', ' ', str(text or '')).strip(' "\'“”.,;:-!?')
    if not raw:
        return ''
    if not allow_cjk and re.search(r'[\u4e00-\u9fff]', raw):
        return ''
    return _short_phrase(raw, max_chars) if max_chars else raw



def _copy_sentence(text, max_chars=0, allow_cjk=False):
    raw = _copy_clean_text(text, max_chars=max_chars, allow_cjk=allow_cjk)
    if not raw:
        return ''
    return raw[:1].upper() + raw[1:]



def _copy_first_text(*values, max_chars=0, allow_cjk=False):
    for value in values:
        raw = _copy_sentence(value, max_chars=max_chars, allow_cjk=allow_cjk)
        if raw:
            return raw
    return ''



def _copy_is_generic(text):
    low = re.sub(r'\s+', ' ', str(text or '')).strip().lower()
    if not low:
        return False
    generic_phrases = (
        'clearest use case',
        'buyers need a clearer',
        'buyers still need',
        'practical payoff',
        'first-use payoff',
        'buyers understand right away',
        'simpler, more practical reason',
        'problem behind',
        'use case buyers care about',
        'use case buyers understand',
        'lead with the buyer',
        'audience-led demo',
        'problem-solution demo',
    )
    return any(phrase in low for phrase in generic_phrases)



