def _review_shopify_headline(pos_points, neg_points, product=None, tier='medium', drf=None):
    direct = drf if isinstance(drf, dict) else _direct_response_frame(product, pos_points=pos_points, neg_points=neg_points, tier=tier)
    copy_frame = _v251_copy_frame(product, direct)
    headline = _review_headline_line(copy_frame.get('shopify_value_prop', ''), 68)
    if headline and not _is_fragile_english_copy(headline):
        return headline
    hero = _review_headline_line(direct.get('hero', ''), 68)
    if hero and not _is_fragile_english_copy(hero):
        return hero
    promise = _review_headline_line(direct.get('promise', ''), 68)
    if promise and not _is_fragile_english_copy(promise):
        return promise
    proof_lines = _review_proof_lines(pos_points, limit=5, max_chars=92, min_chars=24)
    if proof_lines:
        for bucket_group in (('performance', 'cleanliness'), ('ease', 'quiet', 'battery'), ('usage', 'general')):
            line = _pick_bucket_line(proof_lines, *bucket_group)
            headline = _review_headline_line(line, 68) if line else ''
            if headline:
                return headline
        headline = _review_headline_line(proof_lines[0], 68)
        if headline:
            return headline
    if tier != 'weak' and neg_points:
        q = _review_question(neg_points[0])
        if q:
            return q.rstrip(' ?')
    if isinstance(product, dict):
        fallback = str(product.get('name') or product.get('category') or product.get('verify_keyword') or product.get('seed_keyword') or '').strip()
        fallback = _short_phrase(fallback, 68)
        if fallback and not re.search(r'[\u4e00-\u9fff]', fallback):
            return fallback
    return ''



