def _review_intel_label(bucket, positive=True):
    positive_map = {
        'cleanliness': 'Cleaner outcome',
        'ease': 'Easy routine',
        'performance': 'Visible payoff',
        'battery': 'Battery confidence',
        'fit_space': 'Fits the real use case',
        'durability': 'Holds up over time',
        'comfort': 'Feels better to use',
        'maintenance': 'Low upkeep',
        'accessories': 'Comes ready to use',
        'value': 'Feels worth the price',
        'noise': 'Quiet enough for daily use',
        'general': 'Repeat buyer praise',
    }
    negative_map = {
        'cleanliness': 'Mess / odor complaints',
        'ease': 'Setup friction',
        'performance': 'Performance misses',
        'battery': 'Battery complaints',
        'fit_space': 'Size / fit complaints',
        'durability': 'Durability complaints',
        'comfort': 'Comfort complaints',
        'maintenance': 'Upkeep complaints',
        'accessories': 'Missing accessory complaints',
        'value': 'Value-for-money objections',
        'noise': 'Noise complaints',
        'general': 'Repeat buyer objections',
    }
    return (positive_map if positive else negative_map).get(bucket, positive_map['general'] if positive else negative_map['general'])



def _review_theme_bucket(text):
    low = str(text or '').lower()
    if re.search(r'\b(?:quiet|sleep mode|silent|barely hear|loud|louder|noise|noisy)\b', low):
        return 'noise'
    if re.search(r'\b(?:clean|cleaner|mess|odor|smell|fresh|scoop|waste compartment|easy to empty)\b', low):
        return 'cleanliness'
    if re.search(r'\b(?:easy|simple|straightforward|setup|set up|app|automatic|auto|convenient|pair|connect|wifi)\b', low):
        return 'ease'
    if re.search(r'\b(?:accurate|accuracy|clear|bright|difference|noticeable|powerful|strong|effective|results?|locks? on|precision|works?)\b', low):
        return 'performance'
    if re.search(r'\b(?:battery|runtime|charge|charging|lasts?)\b', low):
        return 'battery'
    if re.search(r'\b(?:fit|fitting|size|sizing|small|large|space|footprint|bedroom|kitchen|multi-cat|daily use|everyday use|routine)\b', low):
        return 'fit_space'
    if re.search(r'\b(?:broke|broken|failed|stopped working|quit working|durable|durability|holds up|sturdy|solid build|fragile|flimsy|cheap|plastic|rust|scratch)\b', low):
        return 'durability'
    if re.search(r'\b(?:comfort|comfortable|grip|handle|weight|heavy|awkward|slippery)\b', low):
        return 'comfort'
    if re.search(r'\b(?:replacement|filter|parts|maintenance|upkeep|clean the|washable|sharpening|lost its edge)\b', low):
        return 'maintenance'
    if re.search(r'\b(?:case|accessories|manual|instructions?|included|came with)\b', low):
        return 'accessories'
    if re.search(r'\b(?:worth it|expensive|pricey|costly|value)\b', low):
        return 'value'
    return 'general'



def _review_segment_points(seg_map, preferred_order=None, limit=24):
    out = []
    ordered_keys = []
    for key in list(preferred_order or []) + list((seg_map or {}).keys()):
        if key not in ordered_keys:
            ordered_keys.append(key)
    for key in ordered_keys:
        for line in (seg_map or {}).get(key, []) or []:
            text = str(line or '').strip()
            if text:
                out.append(text)
    return _dedupe_copy_lines(out, limit=limit)



def _review_cluster_records(lines, positive=True, limit=5):
    buckets = {}
    for line in list(lines or []):
        text = re.sub(r'\s+', ' ', str(line or '')).strip()
        if not text:
            continue
        bucket = _review_theme_bucket(text)
        rec = buckets.setdefault(bucket, {'bucket': bucket, 'count': 0, 'lines': []})
        rec['count'] += 1
        if len(rec['lines']) < 3:
            rec['lines'].append(text)
    ranked = sorted(buckets.values(), key=lambda item: (item['count'], len(item['lines'][0]) if item['lines'] else 0), reverse=True)
    out = []
    for item in ranked[:limit]:
        evidence = item['lines'][0] if item['lines'] else ''
        label = _review_intel_label(item['bucket'], positive=positive)
        out.append({
            'bucket': item['bucket'],
            'count': item['count'],
            'label': label,
            'evidence': evidence,
            'lines': item['lines'][:],
        })
    return out



def filter_low_signal_reviews(reviews: list[str]) -> list[str]:
    """Filter generic low-signal review lines while preserving fallback coverage."""
    patterns = [
        re.compile(r'^(great|good|excellent|perfect|awesome|amazing|love|nice|fantastic)\b.{0,50}$', re.IGNORECASE),
        re.compile(r'^five\s+stars?\.?$', re.IGNORECASE),
        re.compile(r'^(does what it says|as described|as expected|as advertised)', re.IGNORECASE),
        re.compile(r'^(happy|satisfied|pleased|delighted)\s+with', re.IGNORECASE),
        re.compile(r'^\w+\s+(product|item|purchase|buy|value)[\s\-–—]+with\s+', re.IGNORECASE),
        re.compile(r'^(highly recommend|would recommend|will recommend)', re.IGNORECASE),
    ]
    original: list[str] = []
    seen_original = set()
    for review in list(reviews or []):
        text = re.sub(r'\s+', ' ', str(review or '')).strip()
        key = text.lower()
        if not text or key in seen_original:
            continue
        seen_original.add(key)
        original.append(text)

    filtered: list[str] = []
    seen_filtered = set()
    for text in original:
        if len(text) < 25:
            continue
        if any(pattern.search(text) for pattern in patterns):
            continue
        key = text.lower()
        if key in seen_filtered:
            continue
        seen_filtered.add(key)
        filtered.append(text)

    if len(filtered) < 3:
        return original[:3]
    return filtered



def refine_cluster_line(line: str) -> str:
    """Trim generic cluster lines and keep short meaningful statements intact."""
    raw = re.sub(r'\s+', ' ', str(line or '')).strip()
    if not raw:
        return ''

    words = raw.split()
    if len(words) > 18:
        truncated = ' '.join(words[:14]).strip()
        if len(truncated.split()) < 6:
            return raw
        raw = truncated + '...'

    blacklist = {
        'great quality', 'good quality', 'nice product', 'works well',
        'does the job', 'love it', 'highly recommend', 'excellent',
    }
    lowered = raw.lower()
    if any(term in lowered for term in blacklist):
        rewritten = f'Specific buyer proof needed — {raw}'
        if len(rewritten.split()) < 6:
            return str(line or '').strip()
        return rewritten
    return raw



def _review_cluster_lines(records, limit=4):
    out = []
    for rec in list(records or [])[:limit]:
        label = str(rec.get('label') or '').strip()
        evidence = str(rec.get('evidence') or '').strip()
        count = _safe_int(rec.get('count'))
        if label and evidence:
            line = refine_cluster_line(f'{label} ({count}) — {evidence}')
            if line:
                out.append(line)
        elif label:
            line = refine_cluster_line(f'{label} ({count})')
            if line:
                out.append(line)
    return out[:limit]



