def map_emotional_triggers(neg_clusters: list, pos_clusters: list) -> list[dict]:
    """Detect top emotional triggers from clustered review evidence."""
    trigger_specs = [
        ('fear_of_missing_out', ('finally', 'wish i found sooner', 'game changer'), 'Open on the payoff buyers wish they had sooner.'),
        ('frustration_relief', ('used to', 'now', 'switched from'), 'Show the old frustration first, then the relief moment.'),
        ('social_validation', ('husband loves', 'kids use it', 'office', 'gift'), 'Lead with who else approved it in real life.'),
        ('identity_signal', ('professional', 'serious', 'real', 'not a toy'), 'Position it as the serious-choice upgrade.'),
        ('urgency_trigger', ('limited', 'while it lasts', 'selling fast', 'back in stock'), 'Use scarcity proof without sounding generic.'),
    ]
    evidence_pool = []
    for rec in list(pos_clusters or []) + list(neg_clusters or []):
        for line in rec.get('lines', [])[:2] or []:
            text = re.sub(r'\s+', ' ', str(line or '')).strip()
            if text:
                evidence_pool.append(text)
        evidence = re.sub(r'\s+', ' ', str(rec.get('evidence') or '')).strip()
        if evidence:
            evidence_pool.append(evidence)

    out = []
    seen = set()
    for trigger, keywords, hook in trigger_specs:
        for snippet in evidence_pool:
            low = snippet.lower()
            if any(keyword in low for keyword in keywords) and trigger not in seen:
                seen.add(trigger)
                out.append({
                    'trigger': trigger,
                    'evidence': snippet,
                    'copy_hook': hook,
                })
                break
        if len(out) >= 3:
            break
    return out[:3]



def generate_objection_handler(neg_points: list, price: float, product: dict | None = None) -> list[str]:
    """Generate Shopify objection handlers from review negatives and pricing context."""
    product = product or {}
    rating = _safe_float(product.get('rating'))
    reviews_count = _safe_int(product.get('reviews_count'))
    shipping_feasibility = _safe_str(product.get('shipping_feasibility')).lower()
    lines = []
    low_points = ' | '.join(str(x or '').lower() for x in list(neg_points or [])[:8])

    if any(token in low_points for token in ('durable', 'durability', 'broke', 'break', 'last')):
        lines.append('Built to last: designed for repeat use — backed by our 90-day guarantee')
    if price > 80:
        monthly = max(1, round(price / 12.0))
        lines.append(f'Costs less than ${monthly}/month when spread across a year of use')
    if any(token in low_points for token in ('ship', 'delivery', 'arrive')) or shipping_feasibility.startswith('✅'):
        lines.append('Ships from US warehouse — arrives in 3-5 days')
    if any(token in low_points for token in ('size', 'fit', 'small', 'large')):
        lines.append("See the size guide before ordering — free exchanges if it doesn't fit")
    if any(token in low_points for token in ('quality', 'cheap', 'defect', 'broken')) or rating >= 4.2:
        lines.append(f'Every unit QC tested — {rating:.1f} average from {reviews_count} verified buyers')
    # --- v54 fix: guarantee at least one handler so column is never empty ---
    if not lines:
        name_short = _safe_str(product.get('name'))[:60]
        if rating > 0 and reviews_count > 0:
            lines.append(f'Every unit QC tested — {rating:.1f} average from {reviews_count} verified buyers')
        elif name_short:
            lines.append(f'Designed and tested for everyday reliability — {name_short}')
        else:
            lines.append('Tested for everyday reliability — backed by our quality guarantee')
    return _dedupe_copy_lines(lines, limit=4)



def _pareto_rank_value(product: dict) -> tuple:
    """Return a stable sorting tuple for Pareto-based ranking."""
    tier_order = {'S': 4, 'A': 3, 'B': 2, 'C': 1}
    return (
        tier_order.get(_safe_str(product.get('paretoTier')).upper(), 0),
        _safe_float(product.get('closed_loop_score')),
        _safe_float(product.get('v57_opportunity_score')),
        _safe_float(product.get('fbAdsScore')),
        _safe_float(product.get('shopifyReadinessScore')),
    )



def generate_master_summary(products: list[dict]) -> dict:
    """Generate a master portfolio summary across professional selection routes and launch readiness."""
    items = list(products or [])
    tier_counts = {tier: 0 for tier in ('S', 'A', 'B', 'C')}
    route_counts = {
        '可立即测试': 0,
        '值得进入验证池二轮': 0,
        '只适合 Amazon 研究': 0,
        '只适合 D2C 创意测试': 0,
        '建议放弃': 0,
    }
    for product in items:
        tier = _safe_str(product.get('paretoTier')).upper()
        if tier in tier_counts:
            tier_counts[tier] += 1
        stage = _safe_str(product.get('selection_stage_label'))
        if stage in route_counts:
            route_counts[stage] += 1

    ranked = sorted(items, key=compute_selection_priority_key, reverse=True)
    top_3_products = [
        {
            'name': _safe_str(p.get('name')),
            'paretoTier': _safe_str(p.get('paretoTier')),
            'closedLoopScore': _safe_float(p.get('closed_loop_score')),
            'finalSelectionScore': _safe_float(p.get('final_selection_score')),
            'v57OpportunityScore': _safe_float(p.get('v57_opportunity_score')),
            'selectionRoute': _safe_str(p.get('selection_route_label')),
            'selectionStage': _safe_str(p.get('selection_stage_label')),
        }
        for p in ranked[:3]
    ]
    best_fb_product = ranked[0].get('name', '') if ranked else ''
    if items:
        best_fb_product = max(items, key=lambda p: _safe_float(p.get('fbAdsScore'))).get('name', '')
        best_shopify_product = max(items, key=lambda p: _safe_float(p.get('shopifyReadinessScore'))).get('name', '')
        avg_closed_loop_score = round(sum(_safe_float(p.get('closed_loop_score')) for p in items) / len(items), 1)
        avg_final_selection_score = round(sum(_safe_float(p.get('final_selection_score')) for p in items) / len(items), 1)
        avg_v57_opportunity_score = round(sum(_safe_float(p.get('v57_opportunity_score')) for p in items) / len(items), 1)
    else:
        best_shopify_product = ''
        avg_closed_loop_score = 0.0
        avg_final_selection_score = 0.0
        avg_v57_opportunity_score = 0.0

    launch_ready = route_counts['可立即测试']
    launch_ready_pct = round((launch_ready / max(1, len(items))) * 100, 1)
    top_names = ', '.join([item['name'] for item in top_3_products if item.get('name')])
    return {
        'total_analyzed': len(items),
        'tier_s_count': tier_counts['S'],
        'tier_a_count': tier_counts['A'],
        'tier_b_count': tier_counts['B'],
        'tier_c_count': tier_counts['C'],
        'ready_to_launch_count': route_counts['可立即测试'],
        'reround_count': route_counts['值得进入验证池二轮'],
        'amazon_only_count': route_counts['只适合 Amazon 研究'],
        'd2c_only_count': route_counts['只适合 D2C 创意测试'],
        'drop_count': route_counts['建议放弃'],
        'top_3_products': top_3_products,
        'best_fb_product': best_fb_product,
        'best_shopify_product': best_shopify_product,
        'avg_closed_loop_score': avg_closed_loop_score,
        'avg_final_selection_score': avg_final_selection_score,
        'avg_v57_opportunity_score': avg_v57_opportunity_score,
        'pareto_insight': f'{launch_ready_pct}% 的产品达到可立即测试标准，预算优先集中到: {top_names}'.strip(),
    }



def _write_master_summary(summary: dict, output_dir: str) -> str:
    """Write the master summary to disk as a timestamped text file."""
    os.makedirs(output_dir, exist_ok=True)
    stamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    path = Path(output_dir) / f'summary_{stamp}.txt'
    top_lines = []
    for idx, item in enumerate(summary.get('top_3_products', []) or [], 1):
        top_lines.append(
            f"{idx}. {item.get('name', '')} | Tier {item.get('paretoTier', '')} | Closed loop {_safe_float(item.get('closedLoopScore')):.1f} | v57 {_safe_float(item.get('v57OpportunityScore')):.1f}"
        )
    body = '\n'.join([
        'MASTER SUMMARY',
        f"Total analyzed: {summary.get('total_analyzed', 0)}",
        f"Tier S: {summary.get('tier_s_count', 0)}",
        f"Tier A: {summary.get('tier_a_count', 0)}",
        f"Tier B: {summary.get('tier_b_count', 0)}",
        f"Tier C: {summary.get('tier_c_count', 0)}",
        f"Best FB product: {summary.get('best_fb_product', '')}",
        f"Best Shopify product: {summary.get('best_shopify_product', '')}",
        f"Average closed loop score: {summary.get('avg_closed_loop_score', 0)}",
        f"Average v57 opportunity score: {summary.get('avg_v57_opportunity_score', 0)}",
        f"Pareto insight: {summary.get('pareto_insight', '')}",
        '',
        'Top 3 products:',
        *top_lines,
    ])
    with open(path, 'w', encoding='utf-8') as f:
        f.write(body)
    return str(path)



def _review_intelligence_frame(p, pos_points=None, neg_points=None, media=None):
    """Build structured review intelligence plus emotional trigger outputs."""
    pos_segments = _normalize_review_segment_map(p.get('amazon_review_positive_segments') or {}, limit=14)
    neg_segments = _normalize_review_segment_map(p.get('amazon_review_negative_segments') or {}, limit=14)
    pos_pool = _dedupe_copy_lines(
        _review_segment_points(pos_segments, preferred_order=['five_star_helpful', 'positive_helpful', 'positive_recent', 'pdp_positive'], limit=24),
        limit=18,
        fallbacks=pos_points or [],
    )
    neg_pool = _dedupe_copy_lines(
        _review_segment_points(neg_segments, preferred_order=['one_star_helpful', 'two_star_helpful', 'critical_helpful', 'critical_recent', 'three_star_helpful', 'pdp_negative', 'fallback_negative'], limit=24),
        limit=18,
        fallbacks=neg_points or [],
    )
    pos_pool = filter_low_signal_reviews(pos_pool)
    neg_pool = filter_low_signal_reviews(neg_pool)
    pos_clusters = _review_cluster_records(pos_pool, positive=True, limit=5)
    neg_clusters = _review_cluster_records(neg_pool, positive=False, limit=5)

    top_demands = _review_cluster_lines(pos_clusters, limit=4)
    top_hates = _review_cluster_lines(neg_clusters, limit=4)
    most_feature = ''
    if pos_clusters:
        lead = pos_clusters[0]
        most_feature = f"{lead['label']} — {lead['evidence']}"

    feature_value_map = _review_cluster_lines(pos_clusters, limit=5)
    buying_motives = []
    for rec in pos_clusters[:4]:
        buying_motives.append(f"Buyers want {rec['label'].lower()} — {rec['evidence']}")
    unmet_needs = _dedupe_copy_lines([_review_unmet_need(rec.get('bucket'), rec.get('evidence')) for rec in neg_clusters[:4]], limit=4)
    objection_clusters = _dedupe_copy_lines([
        f"{_review_question(rec.get('evidence'))} — {rec.get('evidence')}"
        for rec in neg_clusters[:4] if rec.get('evidence')
    ], limit=4)

    real_pain_story = ''
    if neg_clusters:
        lead_neg = neg_clusters[0]
        real_pain_story = f"Lead with the real complaint: {_lower_first(lead_neg['evidence'])}"
    real_proof_story = ''
    proof_line = _review_proof_lines(pos_pool, limit=3, max_chars=88, min_chars=20)
    if proof_line:
        real_proof_story = f"Use buyer proof: {_lower_first(proof_line[0])}"

    hook_seed = _compress_to_hook((pos_clusters[0]['evidence'] if pos_clusters else '') or (neg_clusters[0]['evidence'] if neg_clusters else ''), product=p)
    best_angle = ''
    if neg_clusters and pos_clusters:
        best_angle = f"Open on {neg_clusters[0]['label'].lower()}, then show {pos_clusters[0]['label'].lower()} as the payoff"
    elif pos_clusters:
        best_angle = f"Show {pos_clusters[0]['label'].lower()} with a concrete demo payoff"

    competitor_weaknesses = _review_cluster_lines(neg_clusters, limit=4)
    severe_buckets = {'durability', 'performance', 'battery'}
    red_flags = _dedupe_copy_lines([
        f"{rec['label']} — {rec['evidence']}" for rec in neg_clusters if rec.get('bucket') in severe_buckets
    ], limit=3)
    fixable_complaints = _dedupe_copy_lines([
        f"{rec['label']} — {rec['evidence']}" for rec in neg_clusters if rec.get('bucket') not in severe_buckets
    ], limit=4)
    competitor_opportunity = ''
    source_rec = neg_clusters[0] if neg_clusters else None
    if source_rec:
        competitor_opportunity = f"Win by solving {source_rec['label'].lower()} more clearly than incumbent Amazon listings"

    bundle_extensions, bundle_logic = _review_bundle_options(neg_clusters)

    top_pos_count = pos_clusters[0]['count'] if pos_clusters else 0
    top_neg_count = neg_clusters[0]['count'] if neg_clusters else 0
    feature_focus = 0.0
    if pos_clusters:
        pos_total = max(1, sum(rec['count'] for rec in pos_clusters))
        feature_focus = min(100.0, round((top_pos_count / pos_total) * 100 + 18, 1))
    demand_clarity = min(100.0, round(top_pos_count * 18 + len(pos_clusters) * 8 + (10 if most_feature else 0), 1)) if pos_clusters else 0.0
    pain_intensity = min(100.0, round(top_neg_count * 18 + len(neg_clusters) * 8 + (10 if red_flags else 0), 1)) if neg_clusters else 0.0
    objection_severity = min(100.0, round(len(red_flags) * 18 + top_neg_count * 12 + len(objection_clusters) * 6, 1)) if neg_clusters else 0.0
    creative_angle = min(100.0, round((20 if real_pain_story else 0) + (20 if real_proof_story else 0) + (14 if hook_seed else 0) + (14 if best_angle else 0) + min(18, len(media or []) * 4), 1))
    bundle_score = min(100.0, round(len(bundle_extensions) * 18 + (10 if bundle_logic else 0) + (8 if fixable_complaints else 0), 1))
    emotional_triggers = map_emotional_triggers(neg_clusters, pos_clusters)
    top_emotional_hook = str((emotional_triggers[0] or {}).get('copy_hook', '') if emotional_triggers else '').strip()

    summary = _join_parts([
        most_feature,
        top_hates[0] if top_hates else '',
        best_angle,
        competitor_opportunity,
        bundle_logic,
    ], limit=5)
    return {
        'review_top_demands': top_demands,
        'review_top_hates': top_hates,
        'review_most_valuable_feature': most_feature,
        'review_feature_value_map': feature_value_map,
        'review_unmet_needs': unmet_needs,
        'review_buying_motives': _dedupe_copy_lines(buying_motives, limit=4),
        'review_objection_clusters': objection_clusters,
        'review_real_pain_story': real_pain_story,
        'review_real_proof_story': real_proof_story,
        'review_best_fb_angle': best_angle,
        'review_best_hook_seed': hook_seed,
        'review_competitor_weaknesses': competitor_weaknesses,
        'review_competitor_opportunity': competitor_opportunity,
        'review_red_flag_complaints': red_flags,
        'review_fixable_complaints': fixable_complaints,
        'review_bundle_extensions': bundle_extensions,
        'review_bundle_logic': bundle_logic,
        'review_bundle_score': bundle_score,
        'review_demand_clarity_score': demand_clarity,
        'review_pain_intensity_score': pain_intensity,
        'review_feature_focus_score': feature_focus,
        'review_objection_severity_score': objection_severity,
        'review_creative_angle_score': creative_angle,
        'review_intelligence_summary': summary,
        'emotionalTriggers': emotional_triggers,
        'topEmotionalHook': top_emotional_hook,
    }



def synthesize_commercial_fields(p):
    if not p.get('hook_suggestions'):
        try:
            p['hook_suggestions'] = gen_hooks(p)
        except Exception:
            p['hook_suggestions'] = []

    trends_interest = _safe_int(p.get('google_trends_interest'))
    trends_related = [str(x).strip() for x in (p.get('google_trends_related') or []) if str(x).strip()][:3]
    trends_keyword = _safe_str(p.get('google_trends_keyword'))
    trends_quality = _safe_str(p.get('google_trends_quality'))
    trends_source = _safe_str(p.get('google_trends_source'))
    trends_sufficient = bool(p.get('google_trends_sufficient'))
    review_velocity = _safe_int(p.get('review_velocity'))
    google_rating = _safe_float(p.get('google_shop_rating'))
    google_avg = _safe_float(p.get('google_shop_avg_price'))
    shopify_avg = _safe_float(p.get('shopify_price_avg'))
    profit_cold = _safe_float(p.get('profit_cold'))
    roas_cold = _safe_float(p.get('est_roas_cold'))

    amazon_price = _safe_float(p.get('price'))
    amazon_rating = _safe_float(p.get('rating'))
    amazon_reviews = _safe_int(p.get('reviews_count'))
    amazon_bsr = int(_safe_float(p.get('bsr_rank')))
    amazon_bsr_bucket = _safe_str(p.get('amazon_bsr_bucket'))
    amazon_bsr_source = _safe_str(p.get('amazon_bsr_source'))
    amazon_sales_est = int(_safe_float(p.get('amazon_sales_est_monthly')))
    amazon_sales_source = _safe_str(p.get('amazon_sales_source'))
    amazon_sales_conf = _safe_str(p.get('amazon_sales_confidence'))
    amazon_fact_conf = _safe_str(p.get('amazon_fact_confidence'))
    amazon_brand = _safe_str(p.get('amazon_brand'))
    amazon_sold_by = _safe_str(p.get('amazon_sold_by'))
    amazon_ships_from = _safe_str(p.get('amazon_ships_from'))
    amazon_offer_count = _safe_int(p.get('amazon_offer_count'))
    amazon_has_aplus = bool(p.get('amazon_has_aplus'))
    amazon_has_video = bool(p.get('amazon_has_video'))
    amazon_image_count = _safe_int(p.get('amazon_main_image_count'))
    amazon_bullet_count = _safe_int(p.get('amazon_bullet_count'))
    amazon_sku_count = _safe_int(p.get('amazon_sku_count'))
    amazon_search_rank = _safe_int(p.get('amazon_search_rank'))
    amazon_badge = str(p.get('amazon_badge_text') or p.get('badge') or '').strip()
    amazon_listing_quality = _safe_str(p.get('amz_listing_quality'))
    amazon_competition = _safe_str(p.get('amz_competition_level'))
    amazon_brand_moat = _safe_str(p.get('amz_brand_moat'))
    amazon_demand = _safe_str(p.get('amz_demand_signal'))
    amazon_review_grade = _safe_str(p.get('amz_review_velocity_grade'))
    variant_types = _safe_str(p.get('variant_types'))

    pos_points, neg_points = _review_points(p)
    p['amazon_review_positive_points'] = pos_points
    p['amazon_review_negative_points'] = neg_points
    media = [x for x in (p.get('amazon_review_media') or []) if isinstance(x, dict)][:8]
    copy_evidence_tier = _review_copy_tier(pos_points, neg_points, media)
    p['copy_evidence_tier'] = copy_evidence_tier
    p['amazon_review_media'] = media
    p['amazon_review_media_summary'] = _review_media_summary(media)
    p['amazon_review_summary'] = _review_summary(pos_points, neg_points)
    p['amazon_review_positive_segments'] = _normalize_review_segment_map(p.get('amazon_review_positive_segments') or {}, limit=14)
    p['amazon_review_negative_segments'] = _normalize_review_segment_map(p.get('amazon_review_negative_segments') or {}, limit=14)
    if not p.get('amazon_review_segment_summary'):
        p['amazon_review_segment_summary'] = _review_segment_summary(
            p.get('amazon_review_positive_segments') or {},
            p.get('amazon_review_negative_segments') or {},
        )
    review_intel = _review_intelligence_frame(p, pos_points=pos_points, neg_points=neg_points, media=media)
    p.update(review_intel)

    amazon_fact_score = 0.0
    if amazon_price >= 50:
        amazon_fact_score += 16
        if amazon_price >= 80:
            amazon_fact_score += 5
    elif amazon_price >= 35:
        amazon_fact_score += 7
    if amazon_rating >= 4.5:
        amazon_fact_score += 12
    elif amazon_rating >= 4.2:
        amazon_fact_score += 8
    elif amazon_rating >= 3.8:
        amazon_fact_score += 4
    if amazon_reviews >= 1000:
        amazon_fact_score += 14
    elif amazon_reviews >= 300:
        amazon_fact_score += 11
    elif amazon_reviews >= 80:
        amazon_fact_score += 8
    elif amazon_reviews >= 20:
        amazon_fact_score += 4
    if amazon_bsr > 0:
        if amazon_bsr <= 1000:
            amazon_fact_score += 14
        elif amazon_bsr <= 5000:
            amazon_fact_score += 11
        elif amazon_bsr <= 10000:
            amazon_fact_score += 8
        elif amazon_bsr <= 50000:
            amazon_fact_score += 5
        else:
            amazon_fact_score += 2
    if review_velocity >= 30:
        amazon_fact_score += 10
    elif review_velocity >= 10:
        amazon_fact_score += 7
    elif review_velocity >= 1:
        amazon_fact_score += 3
    if amazon_offer_count <= 2 and amazon_offer_count > 0:
        amazon_fact_score += 6
    elif amazon_offer_count <= 5 and amazon_offer_count > 0:
        amazon_fact_score += 3
    if amazon_sku_count >= 2:
        amazon_fact_score += 5
    if amazon_has_aplus:
        amazon_fact_score += 4
    if amazon_has_video:
        amazon_fact_score += 4
    if amazon_image_count >= 6:
        amazon_fact_score += 3
    if amazon_bullet_count >= 5:
        amazon_fact_score += 3
    if amazon_listing_quality.startswith('⭐'):
        amazon_fact_score += 4
    elif amazon_listing_quality.startswith('🟢'):
        amazon_fact_score += 2
    if amazon_brand_moat in ('无', '低'):
        amazon_fact_score += 4
    elif amazon_brand_moat == '中':
        amazon_fact_score += 1
    else:
        amazon_fact_score -= 4
    p['amazon_fact_score'] = max(0.0, min(100.0, round(amazon_fact_score, 1)))

    pdp_build_score = 0.0
    if p.get('pain_level') == 'S':
        pdp_build_score += 22
    elif p.get('pain_level') == 'A':
        pdp_build_score += 16
    elif p.get('pain_level') == 'B':
        pdp_build_score += 10
    if p.get('scene_detail'):
        pdp_build_score += 10
    if pos_points:
        pdp_build_score += min(16, len(pos_points) * 2)
    if neg_points:
        pdp_build_score += min(12, len(neg_points) * 2)
    if media:
        pdp_build_score += min(16, len(media) * 2)
    if amazon_has_video:
        pdp_build_score += 8
    if amazon_image_count >= 6:
        pdp_build_score += 8
    if amazon_bullet_count >= 5:
        pdp_build_score += 8
    if p.get('has_before_after'):
        pdp_build_score += 8
    elif p.get('visual_demo'):
        pdp_build_score += 5
    p['pdp_build_score'] = max(0.0, min(100.0, round(pdp_build_score, 1)))

    paid_media_score = 0.0
    est_cpm = _safe_float(p.get('est_cpm'))
    fb_days = _safe_int(p.get('fb_oldest_ad_days'))
    daily_budget_min = _safe_float(p.get('daily_budget_min'))
    touchpoints = _safe_int(p.get('fb_touchpoints_needed'))
    creative_feasibility = _safe_str(p.get('fb_creative_feasibility'))
    shipping_feasibility = _safe_str(p.get('shipping_feasibility'))
    fb_policy_risk = _safe_str(p.get('fb_policy_risk'))
    if profit_cold > 15:
        paid_media_score += 18
    elif profit_cold > 0:
        paid_media_score += 12
    elif roas_cold >= 1.2:
        paid_media_score += 6
    if roas_cold >= 1.5:
        paid_media_score += 16
    elif roas_cold >= 1.2:
        paid_media_score += 10
    elif roas_cold >= 1.0:
        paid_media_score += 5
    if fb_days >= 30:
        paid_media_score += 14
    elif fb_days >= 14:
        paid_media_score += 10
    elif p.get('ad_library_count', 0) > 0:
        paid_media_score += 5
    if est_cpm > 0:
        if est_cpm <= 18:
            paid_media_score += 12
        elif est_cpm <= 24:
            paid_media_score += 8
        elif est_cpm <= 30:
            paid_media_score += 4
        else:
            paid_media_score -= 6
    if creative_feasibility.startswith('强'):
        paid_media_score += 14
    elif creative_feasibility.startswith('中'):
        paid_media_score += 8
    if shipping_feasibility.startswith('✅') or shipping_feasibility.startswith('🟢'):
        paid_media_score += 10
    elif shipping_feasibility.startswith('🟡'):
        paid_media_score += 2
    elif shipping_feasibility.startswith('🔴'):
        paid_media_score -= 10
    if not fb_policy_risk.startswith('🔴'):
        paid_media_score += 10
    elif fb_policy_risk.startswith('🟡'):
        paid_media_score += 2
    else:
        paid_media_score -= 12
    if daily_budget_min > 0:
        if daily_budget_min <= 50:
            paid_media_score += 8
        elif daily_budget_min <= 80:
            paid_media_score += 5
        elif daily_budget_min >= 120:
            paid_media_score -= 6
    if touchpoints > 0:
        if touchpoints <= 2:
            paid_media_score += 8
        elif touchpoints <= 4:
            paid_media_score += 4
        else:
            paid_media_score -= 6
    p['paid_media_score'] = max(0.0, min(100.0, round(paid_media_score, 1)))

    evidence_quality_score = 0.0
    if trends_sufficient:
        evidence_quality_score += 22
    elif trends_quality == 'strong':
        evidence_quality_score += 16
    elif trends_quality == 'medium':
        evidence_quality_score += 10
    elif trends_quality == 'weak':
        evidence_quality_score += 4
    if trends_source in ('pytrends', 'google_trends_page', 'google_trends_widgets'):
        evidence_quality_score += 10
    elif trends_source:
        evidence_quality_score += 5
    if amazon_fact_conf == '高':
        evidence_quality_score += 20
    elif amazon_fact_conf == '中':
        evidence_quality_score += 12
    elif amazon_fact_conf == '低':
        evidence_quality_score += 5
    if amazon_sales_conf == '高':
        evidence_quality_score += 10
    elif amazon_sales_conf == '中':
        evidence_quality_score += 6
    elif amazon_sales_conf:
        evidence_quality_score += 3
    if amazon_bsr_source == 'amazon_pdp':
        evidence_quality_score += 10
    elif amazon_bsr_source:
        evidence_quality_score += 4
    if media:
        evidence_quality_score += 8
    if p.get('google_shop_sellers', 0) > 0 or p.get('shopify_competitors', 0) > 0:
        evidence_quality_score += 10
    if p.get('ad_library_count', 0) > 0 or fb_days > 0:
        evidence_quality_score += 10
    p['evidence_quality_score'] = max(0.0, min(100.0, round(evidence_quality_score, 1)))

    frame = _commercial_decision_frame(p, pos_points=pos_points, neg_points=neg_points)
    p['demand_proof_score'] = frame['demand_proof_score']
    p['offer_edge_score'] = frame['offer_edge_score']
    p['media_fit_score'] = frame['media_fit_score']
    p['market_support_score'] = frame['market_support_score']
    p['execution_friction_score'] = frame['execution_friction_score']
    p['evidence_depth_score'] = frame['evidence_depth_score']
    p['asymmetry_score'] = frame['asymmetry_score']
    p['win_path'] = frame['win_path']
    p['gap_path'] = frame['gap_path']
    p['risk_path'] = frame['risk_path']
    p['test_focus'] = frame['test_focus']

    loop_frame = _closed_loop_frame(p, frame)
    p.update(loop_frame)
    _apply_v25_shortlist_labels(p, loop_frame)

    direct_response = _direct_response_frame(p, pos_points=pos_points, neg_points=neg_points, frame=frame, tier=copy_evidence_tier)
    copy_frame = _v251_copy_frame(p, direct_response, loop_frame)
    p.update(copy_frame)
    if p.get('fb_demo_angle'):
        p['first_fb_test'] = p.get('fb_demo_angle')
    if p.get('shopify_value_prop'):
        p['shopify_close_angle'] = p.get('shopify_value_prop')
    p['closed_loop_summary'] = _join_parts([
        p.get('product_identity', '') or p.get('hero_pain_statement', ''),
        p.get('first_fb_test', ''),
        p.get('shopify_close_angle', ''),
        p.get('main_blocker', ''),
    ], limit=4)
    p['copy_mode'] = direct_response.get('mode', '')
    p['direct_response_summary'] = direct_response.get('summary', '')
    p['direct_response_promise'] = direct_response.get('promise', '')
    p['direct_response_mechanism'] = direct_response.get('mechanism', '')
    p['direct_response_hero'] = direct_response.get('hero', '')
    p['direct_response_hook'] = direct_response.get('hook', '')
    p['direct_response_angle'] = direct_response.get('angle', '')
    p['amazon_review_shopify_use'] = _review_shopify_use(pos_points, neg_points, p, direct_response)
    p['amazon_review_fb_use'] = _review_fb_use(pos_points, neg_points, p, direct_response)
    p['shopify_review_headline'] = _review_shopify_headline(pos_points, neg_points, p, copy_evidence_tier, direct_response)
    p['shopify_review_bullets_en'] = _review_shopify_bullets_en(pos_points, copy_evidence_tier, p, direct_response)
    p['shopify_review_faq_en'] = _review_shopify_faq_en(neg_points, p, direct_response)
    p['fb_review_hooks_en'] = _review_fb_hooks_en(pos_points, neg_points, copy_evidence_tier, p, direct_response)
    p['fb_review_primary_texts_en'] = _review_fb_primary_texts_en(pos_points, neg_points, copy_evidence_tier, p, direct_response)
    p['fb_review_angles_en'] = _review_fb_angles_en(pos_points, neg_points, p, direct_response)
