    p['reviewEvidenceCoverage'] = _review_evidence_coverage(pos_points, neg_points)
    p['reviewEvidencePackEn'] = _join_copy_sections([
        _copy_pack_text('Review evidence coverage', p.get('reviewEvidenceCoverage', '')),
        _copy_pack_block('Top positive review proof', pos_points, limit=10, numbered=True),
        _copy_pack_block('Top buyer objections from reviews', neg_points, limit=10, numbered=True),
        _copy_pack_block('Segment summary', p.get('amazon_review_segment_summary') or [], limit=8),
    ])
    p['shopifyCopyPackEn'] = _join_copy_sections([
        _copy_pack_text('Headline', p.get('shopify_review_headline', '')),
        _copy_pack_text('Subheadline', p.get('shopify_subheadline', '')),
        _copy_pack_block('Bullets', p.get('shopify_review_bullets_en') or [], limit=6),
        _copy_pack_block('FAQ', p.get('shopify_review_faq_en') or [], limit=10),
        _copy_pack_block('Objection handlers', p.get('shopifyObjectionHandlers') or [], limit=4),
        _copy_pack_text('CTA', p.get('shopify_cta_line', ''), p.get('next_action', ''), max_chars=120),
    ])
