def _is_shortlist_yes(product: dict) -> bool:
    """Return whether a product is currently marked as an affirmative shortlist pick."""
    decision = _safe_str(product.get('shortlist_decision')).lower()
    return 'yes' in decision



def _snapshot_record(product: dict) -> dict:
    """Build the persisted snapshot payload for a single product."""
    return {
        'asin': _safe_str(product.get('asin')),
        'name': _safe_str(product.get('name')),
        'price': _safe_float(product.get('price')),
        'rating': _safe_float(product.get('rating')),
        'reviewsCount': _safe_int(product.get('reviews_count')),
        'shortlist_score': _safe_float(product.get('shortlist_score')),
        'closedLoopScore': _safe_float(product.get('closed_loop_score')),
        'v57OpportunityScore': _safe_float(product.get('v57_opportunity_score')),
        'easySellScore': _safe_float(product.get('easy_sell_score')),
        'earlySignalScore': _safe_float(product.get('early_signal_score')),
        'shortlistDecision': _safe_str(product.get('shortlist_decision')),
        'sellVerdict': _safe_str(product.get('sell_verdict')),
    }



def _snapshot_record_key(record: dict) -> str:
    """Build a stable snapshot lookup key from stored product fields."""
    asin = _safe_str(record.get('asin'))
    if asin:
        return asin
    return dedup_key(record.get('name', ''), record.get('price', 0))



def save_snapshot(products: list[dict], output_dir: str) -> str:
    """Persist the current affirmative shortlist products to a timestamped JSON snapshot."""
    os.makedirs(output_dir, exist_ok=True)
    stamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    path = Path(output_dir) / f'snapshot_{stamp}.json'
    shortlist_records = [_snapshot_record(p) for p in list(products or []) if _is_shortlist_yes(p)]
    payload = {
        'generated_at': stamp,
        'products': shortlist_records,
    }
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(payload, f, ensure_ascii=False, indent=2)
    return str(path)



def load_latest_snapshot(output_dir: str) -> dict[str, dict]:
    """Load the newest saved shortlist snapshot keyed by ASIN or fallback product key."""
    base = Path(output_dir)
    if not base.exists():
        return {}
    snapshot_files = sorted(base.glob('snapshot_*.json'))
    if not snapshot_files:
        return {}
    latest_path = snapshot_files[-1]
    with open(latest_path, 'r', encoding='utf-8') as f:
        data = json.load(f) or {}
    products = data.get('products') if isinstance(data, dict) else []
    out: dict[str, dict] = {}
    for record in list(products or []):
        if not isinstance(record, dict):
            continue
        out[_snapshot_record_key(record)] = record
    return out



def generate_delta_report(current: list[dict], prev_snapshot: dict[str, dict]) -> str:
    """Generate a markdown delta report against the previous shortlist snapshot."""
    current_map = {}
    for product in list(current or []):
        record = _snapshot_record(product)
        current_map[_snapshot_record_key(record)] = record

    lines = ['## Delta Report']

    for key, record in current_map.items():
        current_yes = 'yes' in _safe_str(record.get('shortlistDecision')).lower()
        previous = prev_snapshot.get(key)
        previous_yes = 'yes' in str((previous or {}).get('shortlistDecision', '') or '').lower()
        name = record.get('name') or (previous or {}).get('name') or key

        if current_yes and not previous_yes:
            lines.append(f"- 🆕 {name} entered the shortlist")
        if previous:
            closed_loop_delta = _safe_float(record.get('closedLoopScore')) - _safe_float(previous.get('closedLoopScore'))
            if closed_loop_delta >= 8:
                lines.append(f"- 📈 {name} closedLoopScore +{closed_loop_delta:.1f}")
            elif closed_loop_delta <= -8:
                lines.append(f"- 📉 {name} closedLoopScore {closed_loop_delta:.1f}")

            rating_delta = _safe_float(record.get('rating')) - _safe_float(previous.get('rating'))
            if rating_delta <= -0.2:
                lines.append(f"- ⚠️ {name} rating dropped {abs(rating_delta):.1f}")

    for key, previous in prev_snapshot.items():
        current = current_map.get(key)
        previous_yes = 'yes' in _safe_str(previous.get('shortlistDecision')).lower()
        current_yes = 'yes' in str((current or {}).get('shortlistDecision', '') or '').lower()
        if previous_yes and not current_yes:
            name = (current or {}).get('name') or previous.get('name') or key
            lines.append(f"- ⬇️ {name} dropped from the shortlist")

    if len(lines) == 1:
        lines.append('- No material shortlist changes detected')
    return '\n'.join(lines)



def _sorted_export_products(products: list[dict]) -> list[dict]:
    """Sort products using the same ordering as the inherited v20 Excel export."""
    return sorted(products, key=lambda x: (
        1 if str(x.get('sell_verdict', '')).startswith('🟢') else 0,
        1 if x.get('verification_passed') else 0,
        x.get('instant_sell_score', 0),
        x.get('chain_score', 0),
        x.get('v57_opportunity_score', 0),
        x.get('easy_sell_score', 0),
        x.get('early_signal_score', 0),
        x.get('validation_priority_score', 0),
        x.get('total_score', 0),
        x.get('price', 0),
    ), reverse=True)



