def export_excel(products: list[dict], stats: dict) -> str:
    """Export Excel via v20 and then apply v23 shortlist and launch-intel enhancements."""
    path = _export_excel_base(products, stats)
    if not path or not load_workbook or not os.path.exists(path):
        return path

    wb = load_workbook(path)
    ws = wb[wb.sheetnames[0]]
    shortlist_insert_at = ws.max_column + 1
    for col_idx in range(1, ws.max_column + 1):
        if ws.cell(row=1, column=col_idx).value == 'Closed-loop score':
            shortlist_insert_at = col_idx + 1
            break
    ws.insert_cols(shortlist_insert_at)
    ws.cell(row=1, column=shortlist_insert_at, value='Shortlist score')

    # v54fix: filter LAUNCH_INTEL_COLUMNS to only keep columns with data
    _launch_cols = [(f, h) for f, h in LAUNCH_INTEL_COLUMNS
                    if any(_column_has_meaningful_raw_value(f, p.get(f)) for p in products)]
    launch_insert_at = ws.max_column + 1
    ws.insert_cols(launch_insert_at, amount=len(_launch_cols))
    for idx, (_, header) in enumerate(_launch_cols):
        ws.cell(row=1, column=launch_insert_at + idx, value=header)

    sorted_products = _sorted_export_products(products)
    for row_idx, product in enumerate(sorted_products, 2):
        score_cell = ws.cell(row=row_idx, column=shortlist_insert_at, value=_safe_float(product.get('shortlist_score')))
        score_cell.number_format = '0.0'
        for idx, (field, _) in enumerate(_launch_cols):
            value = product.get(field, '')
            if field == 'shopifyObjectionHandlers' and isinstance(value, list):
                value = ' | '.join(str(x).strip() for x in value if str(x).strip())
            elif field in ('shopifyReadinessScore', 'fbAdsScore', 'competitiveOpportunityScore', 'v57_opportunity_score', 'easy_sell_score', 'early_signal_score'):
                value = float(value or 0)
            elif isinstance(value, list):
                value = ' | '.join(str(x).strip() for x in value if str(x).strip())
            ws.cell(row=row_idx, column=launch_insert_at + idx, value=value)

    fill_header = PatternFill('solid', fgColor='DBEAFE')
    fill_grey = PatternFill('solid', fgColor='F0F0F0')
    fill_green = PatternFill('solid', fgColor='C6EFCE')
    fill_yellow = PatternFill('solid', fgColor='FFEB9C')
    fill_blue = PatternFill('solid', fgColor='DBEAFE')
    fill_red = PatternFill('solid', fgColor='FECACA')
    fill_shortlist_row = PatternFill('solid', fgColor='E8F5E9')
    font_header = Font(name='Calibri', size=11, bold=True, color='FFFFFF')
    align_right = Alignment(horizontal='right', vertical='center', wrap_text=True)
    align_wrap = Alignment(horizontal='left', vertical='top', wrap_text=True)

    max_row = ws.max_row
    max_col = ws.max_column
    headers = [str(ws.cell(row=1, column=col_idx).value or '') for col_idx in range(1, max_col + 1)]
    review_cols = [idx for idx, header in enumerate(headers, 1) if 'review' in header.lower()]
    launch_header_to_col = {header: launch_insert_at + idx for idx, (_, header) in enumerate(_launch_cols)}

    for row_idx in range(2, max_row + 1):
        for col_idx in review_cols:
            ws.cell(row=row_idx, column=col_idx).fill = fill_grey

    for row_idx, product in enumerate(sorted_products, 2):
        if _is_shortlist_yes(product):
            for col_idx in range(1, max_col + 1):
                ws.cell(row=row_idx, column=col_idx).fill = fill_shortlist_row

    numeric_cols = set()
    sample_end = min(max_row, 20)
    for col_idx in range(1, max_col + 1):
        numeric_count = 0
        sample_count = 0
        for row_idx in range(2, sample_end + 1):
            value = ws.cell(row=row_idx, column=col_idx).value
            if value in ('', None):
                continue
            sample_count += 1
            if isinstance(value, (int, float)) and not isinstance(value, bool):
                numeric_count += 1
        if sample_count and numeric_count >= max(1, sample_count // 2):
            numeric_cols.add(col_idx)

    for col_idx in numeric_cols:
        for row_idx in range(2, max_row + 1):
            cell = ws.cell(row=row_idx, column=col_idx)
            if isinstance(cell.value, (int, float)) and not isinstance(cell.value, bool):
                cell.alignment = align_right
                if col_idx in {
                    shortlist_insert_at,
                    launch_header_to_col.get('shopifyReadinessScore', -1),
                    launch_header_to_col.get('fbAdsScore', -1),
                    launch_header_to_col.get('competitiveOpportunityScore', -1),
                    launch_header_to_col.get('v57OpportunityScore', -1),
                    launch_header_to_col.get('easySellScore', -1),
                    launch_header_to_col.get('earlySignalScore', -1),
                }:
                    cell.number_format = '0.0'
                elif float(cell.value).is_integer() and abs(float(cell.value)) >= 1000:
                    cell.number_format = '#,##0'

    for row_idx in range(2, max_row + 1):
        cell = ws.cell(row=row_idx, column=shortlist_insert_at)
        value = float(cell.value or 0)
        if value >= 75:
            cell.fill = fill_green
        elif value >= 50:
            cell.fill = fill_yellow

        if 'paretoTier' in launch_header_to_col:
            tier_cell = ws.cell(row=row_idx, column=launch_header_to_col['paretoTier'])
            tier = str(tier_cell.value or '').strip().upper()
            if tier == 'S':
                tier_cell.fill = fill_green
            elif tier == 'A':
                tier_cell.fill = fill_blue
            elif tier == 'B':
                tier_cell.fill = fill_yellow
            elif tier == 'C':
                tier_cell.fill = fill_red

        brief_col = launch_header_to_col.get('fbLaunchBrief')
        brief_cell = ws.cell(row=row_idx, column=brief_col) if brief_col else None
        if brief_cell:
            brief_cell.alignment = align_wrap
            brief_lines = max(1, str(brief_cell.value or '').count('\n') + 1)
            ws.row_dimensions[row_idx].height = max(ws.row_dimensions[row_idx].height or 15, min(brief_lines * 16, 96))
        if 'competitiveGapAnalysis' in launch_header_to_col:
            ws.cell(row=row_idx, column=launch_header_to_col['competitiveGapAnalysis']).alignment = align_wrap
        if 'shopifyObjectionHandlers' in launch_header_to_col:
            ws.cell(row=row_idx, column=launch_header_to_col['shopifyObjectionHandlers']).alignment = align_wrap
        for header in ('v57PrioritySignal', 'easySellInsights', 'earlySignals', 'timeToSaturation'):
            if header in launch_header_to_col:
                ws.cell(row=row_idx, column=launch_header_to_col[header]).alignment = align_wrap

    if DataBarRule and max_row >= 2:
        for header in ('shopifyReadinessScore', 'fbAdsScore', 'v57OpportunityScore', 'easySellScore', 'earlySignalScore'):
            if header not in launch_header_to_col:
                continue
            col_letter = get_column_letter(launch_header_to_col[header])
            ws.conditional_formatting.add(
                f'{col_letter}2:{col_letter}{max_row}',
                DataBarRule(start_type='num', start_value=0, end_type='num', end_value=100, color='63C384', showValue=True),
            )

    for col_idx in range(1, max_col + 1):
        header_cell = ws.cell(row=1, column=col_idx)
        header_cell.fill = fill_header
        header_cell.font = font_header
        header_cell.alignment = align_wrap

    ws.freeze_panes = 'B2'
    last_col = get_column_letter(max_col)
    ws.auto_filter.ref = f'A1:{last_col}{max_row}'

    for col_idx in range(1, max_col + 1):
        column_cells = [ws.cell(row=row_idx, column=col_idx) for row_idx in range(1, max_row + 1)]
        max_len = max(len(str(cell.value or '')) for cell in column_cells)
        ws.column_dimensions[get_column_letter(col_idx)].width = min(max_len + 2, 58)

    wb.save(path)
    return path



# === TEST ===
def _test_filter_low_signal_reviews() -> None:
    """Validate low-signal review filtering with five dropped and five kept examples."""
    filtered_examples = [
        'Five Stars',
        'Great value',
        'Does what it says',
        'Happy with the purchase so far',
        'Excellent Product - With One Shortcoming',
    ]
    kept_examples = [
        'The blade stays sharp after a month of daily prep and cleanup stays quick.',
        'Battery lasts through two full-room sessions before needing another charge.',
        'The low-noise mode makes it usable at night without waking the baby.',
        'Setup took under ten minutes and the app kept the routine easy to repeat.',
        'The bin seals odor better than our last model and cuts litter mess noticeably.',
    ]
    results = filter_low_signal_reviews(filtered_examples + kept_examples)
    for text in filtered_examples:
        assert text not in results
    for text in kept_examples:
        assert text in results



def export_csv_v25(products: list[dict], filename: str = None) -> str:
    """
    v33.0: 增强CSV导出格式
    新增 v25 质量分数和筛选原因
    """
    if not products:
        return ""

    # v25 关键字段 - 包含新增的质量评估
    key_fields = [
        'name', 'asin', 'price', 'rating', 'reviews_count',
        'category', 'bsr_rank', 'total_score', 'validation_priority_score',
        'sell_verdict', 'paretoTier', 'pain_level',
        # v25 新增字段
        'v25_quality_score', 'amazon_offer_count', 'review_velocity',
        'closed_loop_score', 'shortlist_score', 'closed_loop_bucket',
        'watchlist_reason', 'verification_stage',
    ]

    # 生成文件名
    if not filename:
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        filename = f"amazon_products_v25_{timestamp}.csv"

    filepath = Path(Config.OUT_DIR) / filename

    try:
        with open(filepath, 'w', encoding='utf-8-sig', newline='') as f:
            writer = csv.writer(f)

            # 动态收集所有存在过的header
            all_headers = set(key_fields)
            for p in products:
                all_headers.update(p.keys())

            # 过滤只保留存在的字段
            headers = [h for h in key_fields if h in all_headers]
            # 添加其他可能存在的字段
            for h in all_headers:
                if h not in headers:
                    headers.append(h)

            writer.writerow(headers)

            # 写入数据
            for p in products:
                row = []
                for h in headers:
                    val = p.get(h, '')
                    if isinstance(val, list):
                        val = ' | '.join(str(x) for x in val)
                    row.append(val)
                writer.writerow(row)

        log.info(f"  📊 [v25] CSV导出: {filepath}")
        return str(filepath)
    except Exception as e:
        log.error(f"  ❌ [v25] CSV导出失败: {e}")
        return ""


def export_csv(products: list[dict], filename: str = None) -> str:
    """保持原接口兼容，调用 v25 版本"""
    return export_csv_v25(products, filename)



