def _call_opus_api(prompt, api_key, model='claude-opus-4-5'):
    """调用 Anthropic Claude API 并返回原始文本 + 解析后的 JSON"""
    try:
        import anthropic
    except ImportError:
        log.warning('  ⚠️ anthropic SDK 未安装 (pip install anthropic)，回退到 requests')
        return _call_opus_api_fallback(prompt, api_key, model)

    try:
        client = anthropic.Anthropic(api_key=api_key)
        msg = client.messages.create(
            model=model,
            max_tokens=2500,
            messages=[{'role': 'user', 'content': prompt}],
        )
        raw_text = msg.content[0].text if msg.content else ''
        # 尝试解析 JSON
        text = raw_text.strip()
        if text.startswith('```'):
            text = re.sub(r'^```json?\s*', '', text)
        if text.endswith('```'):
            text = text[:-3]
        try:
            parsed = json.loads(text.strip())
        except json.JSONDecodeError:
            parsed = None
        return raw_text, parsed
    except Exception as e:
        log.debug(f'  Opus API 调用异常: {e}')
        return None, None




def _call_opus_api_fallback(prompt, api_key, model='claude-opus-4-5'):
    """fallback: 使用 requests 直接调用 Anthropic API"""
    try:
        headers = {
            'Content-Type': 'application/json',
            'x-api-key': api_key,
            'anthropic-version': '2023-06-01',
        }
        body = {
            'model': model,
            'max_tokens': 2500,
            'temperature': 0.3,
            'messages': [{'role': 'user', 'content': prompt}],
        }
        r = requests.post(
            'https://api.anthropic.com/v1/messages',
            headers=headers, json=body, timeout=60,
        )
        if r.status_code == 200:
            data = r.json()
            raw_text = ''
            for block in data.get('content', []):
                if block.get('type') == 'text':
                    raw_text += block['text']
            text = raw_text.strip()
            if text.startswith('```'):
                text = re.sub(r'^```json?\s*', '', text)
            if text.endswith('```'):
                text = text[:-3]
            try:
                parsed = json.loads(text.strip())
            except json.JSONDecodeError:
                parsed = None
            return raw_text, parsed
        elif r.status_code == 429:
            log.warning('  ⚠️ Opus API rate limited, 等待10秒...')
            time.sleep(10)
            return None, None
        else:
            log.debug(f'  Opus API: HTTP {r.status_code}')
            return None, None
    except Exception as e:
        log.debug(f'  Opus API fallback 异常: {e}')
        return None, None




def _apply_opus_result_to_product(p, ai):
    """将 Opus AI 分析结果映射回产品字典"""
    if not ai or not isinstance(ai, dict):
        return

    # 裁决
    p['opus_verdict'] = ai.get('verdict', '')
    p['opus_verdict_reasons'] = ai.get('verdict_reasons', [])

    # 竞争+差异化
    p['opus_competitor_weakness'] = ai.get('competitor_weakness', '')
    p['opus_differentiation_angle'] = ai.get('differentiation_angle', '')

    # 风险
    p['opus_biggest_risk'] = ai.get('biggest_risk', '')
    p['opus_risk_mitigation'] = ai.get('risk_mitigation', '')

    # FB广告方案
    p['opus_ad_format'] = ai.get('ad_format', '')
    p['opus_hook_line'] = ai.get('hook_line', '')
    p['opus_ad_copy'] = ai.get('ad_copy', '')
    p['opus_audience_tags'] = ai.get('audience_tags', [])
    p['opus_daily_budget'] = float(ai.get('daily_budget', 0) or 0)
    p['opus_budget_reason'] = ai.get('budget_reason', '')

    # 落地页
    p['opus_landing_first_screen'] = ai.get('landing_first_screen', '')
    p['opus_landing_problem'] = ai.get('landing_problem', '')
    p['opus_landing_solution'] = ai.get('landing_solution', '')
    p['opus_landing_proof'] = ai.get('landing_proof', '')
    p['opus_landing_cta'] = ai.get('landing_cta', '')

    # 卖点
    p['opus_selling_points'] = [
        ai.get('selling_point_1', ''),
        ai.get('selling_point_2', ''),
        ai.get('selling_point_3', ''),
    ]

    # 定价
    try:
        p['opus_suggested_price'] = float(ai.get('suggested_price', 0) or 0)
    except (TypeError, ValueError):
        p['opus_suggested_price'] = 0
    p['opus_pricing_reason'] = ai.get('pricing_reason', '')

    # 供应链
    p['opus_supply_chain_risk'] = ai.get('supply_chain_risk', '')
    p['opus_supply_chain_advice'] = ai.get('supply_chain_advice', '')

    # 路线图
    p['opus_week1_plan'] = ai.get('week1_plan', '')
    p['opus_week2_plan'] = ai.get('week2_plan', '')
    p['opus_week34_plan'] = ai.get('week34_plan', '')

    # 信心
    try:
        p['opus_confidence_score'] = int(float(ai.get('confidence_score', 0) or 0))
    except (TypeError, ValueError):
        p['opus_confidence_score'] = 0
    p['opus_confidence_diff_reason'] = ai.get('confidence_diff_reason', '')
    p['opus_most_notable'] = ai.get('most_notable', '')

    p['opus_ai_analyzed'] = True
    log.info(f'    ✅ Opus AI: {p.get("opus_verdict", "")} | 信心={p.get("opus_confidence_score", 0)} | {p.get("opus_most_notable", "")[:40]}')




def apply_opus_to_top_products(products, api_key='', grades=('S+', 'S', 'A'), max_calls=5):
    """
    v34.0: 对评级最高的产品调用 Anthropic Claude API 做深度分析
    仅对 commercial_grade 或 expert_priority 在 grades 中的产品调用。
    """
    if not api_key:
        api_key = os.environ.get('ANTHROPIC_API_KEY', '')
    if not api_key:
        log.info('  ⏭️ [Opus AI] 未设置 ANTHROPIC_API_KEY，跳过 AI 深度分析')
        return products

    # 筛选候选品
    candidates = []
    for p in products:
        grade = str(p.get('commercial_grade', '') or p.get('expert_priority', '') or '').strip()
        passed = bool(p.get('verification_passed'))
        score = float(p.get('expert_selection_score', 0) or 0)
        already = bool(p.get('opus_ai_analyzed'))
        if already:
            continue
        if grade in grades or (passed and score >= 55):
            candidates.append(p)

    candidates = candidates[:max_calls]
    if not candidates:
        log.info('  ⏭️ [Opus AI] 无符合条件的候选品')
        return products

    log.info(f'  🤖 [Opus AI] 开始分析 {len(candidates)} 个候选品 (grades={grades}, max={max_calls}, model=claude-opus-4-5)')

    for i, p in enumerate(candidates, 1):
        name = str(p.get('name', ''))[:40]
        try:
            log.info(f'    [{i}/{len(candidates)}] {name} ...')
            prompt = _build_opus_prompt(p)
            raw_text, parsed = _call_opus_api(prompt, api_key)
            if raw_text:
                p['opus_deep_analysis'] = raw_text
            if parsed:
                _apply_opus_result_to_product(p, parsed)
            elif raw_text:
                # JSON解析失败但有原始文本，仍存储
                p['opus_deep_analysis'] = raw_text
                p['opus_ai_analyzed'] = True
                log.info(f'    ✅ Opus AI (raw): 获得原始分析文本 ({len(raw_text)}字符)')
            else:
                # 重试一次
                time.sleep(3)
                raw_text, parsed = _call_opus_api(prompt, api_key)
                if raw_text:
                    p['opus_deep_analysis'] = raw_text
                if parsed:
                    _apply_opus_result_to_product(p, parsed)
                elif raw_text:
                    p['opus_ai_analyzed'] = True
                    log.info(f'    ✅ Opus AI (raw retry): ({len(raw_text)}字符)')
                else:
                    log.warning(f'    ⚠️ Opus AI 分析失败: {name}')
        except Exception as e:
            log.error(f'    ❌ Opus AI 异常 [{name}]: {e}')

        # 请求间隔
        if i < len(candidates):
            time.sleep(2)

    analyzed = len([p for p in products if p.get('opus_ai_analyzed')])
    log.info(f'  ✅ [Opus AI] 完成: {analyzed} 个产品已获得 AI 深度分析')
    return products


