def _opus_verdict(p):
    """根据产品数据生成最终选品裁决"""
    sanitize_product_data(p)
    mode = str(p.get('commercial_mode', '') or '').strip()
    sell_verdict = str(p.get('sell_verdict', '') or '').strip()
    passed = p.get('verification_passed', False)
    score = float(p.get('expert_selection_score', 0) or 0)
    profit = float(p.get('profit_cold', 0) or 0)
    roas = float(p.get('est_roas_cold', 0) or 0)
    trend_dir = str(p.get('trend_direction', '') or '').strip()

    if passed and (profit > 0 or roas >= 1.3) and trend_dir in ('↑', '↑↑'):
        return '🟢 立即测试'
    elif passed or score >= 55:
        return '🟡 观察30天后决定'
    elif trend_dir in ('↓', '↓↓') or score < 30:
        return '🔴 直接放弃'
    else:
        return '🟡 观察30天后决定'




def _opus_verdict_reasons(p):
    """生成3条核心决策理由"""
    reasons = []
    price = float(p.get('price', 0) or 0)
    profit = float(p.get('profit_cold', 0) or 0)
    roas = float(p.get('est_roas_cold', 0) or 0)
    trend_dir = str(p.get('trend_direction', '') or '').strip()
    fb_days = int(float(p.get('fb_oldest_ad_days', 0) or 0))
    reviews = int(float(p.get('reviews_count', 0) or 0))
    pain = str(p.get('pain_level', '') or '').strip()
    moat = str(p.get('amz_brand_moat', '') or '').strip()
    creative = str(p.get('fb_creative_feasibility', '') or '').strip()

    # 正面信号
    if profit > 10:
        reasons.append(f'冷流量单件利润${profit:.0f}，ROI可控')
    elif profit > 0:
        reasons.append(f'冷利润${profit:.0f}，需优化转化率')
    if roas >= 1.5:
        reasons.append(f'ROAS {roas:.1f}x，广告模型健康')
    if trend_dir in ('↑', '↑↑'):
        reasons.append('需求趋势上行，时机窗口开')
    if fb_days >= 30:
        reasons.append(f'FB广告存活{fb_days}天，已被验证')
    if pain in ('S', 'A'):
        reasons.append(f'痛点{pain}级，素材冲击力强')
    if moat in ('无', '低', 'weak', 'low'):
        reasons.append('品牌壁垒低，白牌切入可行')
    if creative.startswith('强'):
        reasons.append('素材制作难度低，可快速出片')

    # 负面信号
    if profit <= 0 and roas < 1.0:
        reasons.append('冷流量无利润，经济模型不成立')
    if trend_dir in ('↓', '↓↓'):
        reasons.append('趋势下行，入场时机不佳')
    if price < 30:
        reasons.append(f'客单${price:.0f}偏低，广告成本难覆盖')
    if moat in ('高', 'high', 'strong'):
        reasons.append('品牌壁垒高，白牌难以撼动')

    return reasons[:3] if reasons else ['数据信号不足', '需补充市场验证', '建议先小预算探测']




def _opus_opportunity(p):
    """核心机会与差异化角度"""
    gap_analysis = str(p.get('competitiveGapAnalysis', '') or '').strip()
    entry = str(p.get('recommendedEntryAngle', '') or '').strip()
    spy_diff = str(p.get('spy_differentiation', '') or '').strip()
    neg_pts = p.get('amazon_review_negative_points') or []
    moat = str(p.get('amz_brand_moat', '') or '').strip()
    comp = str(p.get('amz_competition_level', '') or '').strip()

    weakness = ''
    if neg_pts:
        weakness = f'竞品主要差评集中在: {neg_pts[0]}'
    elif comp:
        weakness = f'竞争格局: {comp}'
    else:
        weakness = '竞品缺乏差异化页面和视频素材'

    angle = entry or spy_diff or gap_analysis or '以用户痛点+真实评论素材做差异化落地页，主打竞品忽略的使用场景'
    return weakness, angle




def _opus_risk(p):
    """最大风险与规避方案"""
    blockers = str(p.get('monetization_blockers', '') or p.get('main_blocker', '') or '').strip()
    fb_policy = str(p.get('fb_policy_risk', '') or '').strip()
    shipping = str(p.get('shipping_feasibility', '') or '').strip()
    profit = float(p.get('profit_cold', 0) or 0)
    trend_dir = str(p.get('trend_direction', '') or '').strip()

    if fb_policy.startswith('🔴'):
        return 'FB政策高风险，素材可能被拒审', '规避: 避免夸大疗效词汇，用场景化描述替代功效宣称，准备3套备用素材'
    if profit <= 0:
        return '冷流量无法盈利，CPA高于单件毛利', '规避: 先用$20/天小预算验证CPM和CTR，优化落地页转化率至3%+再放量'
    if shipping.startswith('🔴'):
        return '物流时效/尺寸不可控，退货率风险高', '规避: 选择美国仓备货或轻量包装产品线，首单走空运小批量验证'
    if trend_dir in ('↓', '↓↓'):
        return '需求趋势下行，流量成本将持续走高', '规避: 限定测试周期14天，不追加预算，同步准备替代品'
    if blockers:
        first_blocker = blockers.split('|')[0].strip()
        return first_blocker, f'规避: 在Week 1集中解决此项，设定明确Pass/Fail标准'
    return '转化率不达预期导致CPA偏高', '规避: 落地页先做A/B测试(2版)，FB广告前3天只看CTR和CPM，不看ROAS'




def _opus_fb_plan(p):
    """Facebook广告首支方案"""
    has_ba = bool(p.get('has_before_after'))
    has_demo = bool(p.get('visual_demo'))
    pain = str(p.get('pain_level', '') or '').strip()
    hero = str(p.get('hero_pain_statement', '') or p.get('direct_response_hero', '') or '').strip()
    hook_list = p.get('fb_review_hooks_en') or p.get('hook_suggestions') or []
    primary_texts = p.get('fb_review_primary_texts_en') or []
    audience_desc = str(p.get('target_audience', '') or p.get('scene_detail', '') or '').strip()
    budget = float(p.get('daily_budget_min', 0) or 0)
    roas = float(p.get('est_roas_cold', 0) or 0)
    cpm = float(p.get('est_cpm', 0) or 0)
    category = str(p.get('category', '') or p.get('seed_keyword', '') or '').strip()

    # 广告形式
    if has_ba:
        ad_format = '视频(Before/After对比)——视觉冲击最强，适合痛点型产品冷流量破冰'
    elif has_demo:
        ad_format = '视频(产品演示)——15秒内展示使用效果，降低决策门槛'
    elif pain in ('S', 'A'):
        ad_format = 'UGC视频——用真人口述痛点经历，共情>说服，冷流量CTR最高'
    else:
        ad_format = '轮播图文——多角度展示卖点，适合理性决策型品类'

    # Hook
    hook = ''
    if hook_list and isinstance(hook_list[0], str):
        hook = hook_list[0]
    if not hook and hero:
        hook = hero
    if not hook:
        hook = f'Stop wasting money on {category} that doesn\'t work — here\'s what actually does.'

    # 正文
    primary = ''
    if primary_texts and isinstance(primary_texts[0], str):
        primary = primary_texts[0]
    if not primary:
        promise = str(p.get('direct_response_promise', '') or '').strip()
        mechanism = str(p.get('direct_response_mechanism', '') or '').strip()
        primary = f'{hero or "Tired of the same old problem?"} {promise or "This changes everything."} {mechanism or "See the difference yourself."} Shop now → 50% OFF today only.'

    # 受众
    interests = []
    if audience_desc:
        interests.append(f'{audience_desc} — 核心使用人群')
    if category:
        interests.append(f'{category} buyers — 品类兴趣精准匹配')
    interests.append('Online shopping + Product reviews — 高购买意向泛人群')

    if budget <= 0:
        budget = 30 if cpm <= 20 else 50
    budget_reason = f'CPM约${cpm:.0f}，需覆盖50+触达才能验证素材' if cpm > 0 else '首阶段验证素材CTR和CPM基准值'

    return ad_format, hook, primary[:200], interests[:3], budget, budget_reason




def _opus_landing_page(p):
    """Shopify落地页5段结构"""
    hero = str(p.get('hero_pain_statement', '') or p.get('direct_response_hero', '') or '').strip()
    headline = str(p.get('shopify_review_headline', '') or p.get('shopify_value_prop', '') or '').strip()
    problem = str(p.get('core_problem', '') or p.get('fb_visual_problem', '') or '').strip()
    solution = str(p.get('direct_response_mechanism', '') or p.get('direct_response_promise', '') or '').strip()
    name = str(p.get('name', '') or '').strip()[:60]
    price = float(p.get('shopify_sell_price', 0) or p.get('price', 0) or 0)
    pos_pts = p.get('amazon_review_positive_points') or []
    neg_pts = p.get('amazon_review_negative_points') or []
    reviews = int(float(p.get('reviews_count', 0) or 0))
    rating = float(p.get('rating', 0) or 0)

    first_screen = headline or hero or f'{name} — The solution thousands of buyers trust'
    problem_section = problem or (f'Buyers report: "{neg_pts[0]}"' if neg_pts else 'The old way doesn\'t work — here\'s why')
    solution_section = solution or (f'Top review: "{pos_pts[0]}"' if pos_pts else f'{name} solves this with a completely new approach')
    proof = f'{reviews:,}+ reviews, {rating:.1f}★ average' if reviews > 0 else 'Thousands of happy customers'
    if pos_pts:
        proof += f' — "{pos_pts[0][:60]}"'
    cta = f'Get yours for ${price:.0f} — Free shipping + 30-day guarantee' if price > 0 else 'Order now — Limited stock available'

    return first_screen, problem_section, solution_section, proof, cta




def _opus_selling_points(p):
    """3条直接可用广告卖点"""
    pos_pts = p.get('amazon_review_positive_points') or []
    neg_pts = p.get('amazon_review_negative_points') or []
    scene = str(p.get('scene_detail', '') or '').strip()
    points = []

    for pt in pos_pts[:2]:
        points.append(f'{pt} — 来自真实买家评论')
    if neg_pts:
        points.append(f'解决了竞品痛点「{neg_pts[0][:30]}」— 差异化核心卖点')
    if scene and len(points) < 3:
        points.append(f'适用场景: {scene} — 精准匹配目标用户日常')

    while len(points) < 3:
        points.append('高性价比替代方案 — 独立站直供省去中间溢价')
    return points[:3]




def _opus_pricing(p):
    """定价策略分析"""
    amz_price = float(p.get('price', 0) or 0)
    shopify_price = float(p.get('shopify_sell_price', 0) or 0)
    cost_1688 = float(p.get('cost_1688_usd', 0) or 0)
    google_avg = float(p.get('google_shop_avg_price', 0) or 0)
    shopify_avg = float(p.get('shopify_price_avg', 0) or 0)

    if shopify_price <= 0:
        shopify_price = amz_price * 0.85 if amz_price > 0 else 0

    # 心理定价
    if shopify_price > 0:
        if shopify_price > 100:
            suggested = int(shopify_price / 10) * 10 - 1  # $99, $89...
        elif shopify_price > 30:
            suggested = int(shopify_price) - (int(shopify_price) % 10) - 1  # $49, $59...
            if suggested <= 0:
                suggested = int(shopify_price) - 1
        else:
            suggested = round(shopify_price, 99) if shopify_price > 20 else shopify_price
            suggested = int(shopify_price)
    else:
        suggested = 0

    if suggested > 0 and suggested % 10 != 9 and suggested > 20:
        suggested = (suggested // 10) * 10 + 9

    reason_parts = []
    if amz_price > 0:
        reason_parts.append(f'Amazon售价${amz_price:.0f}')
    if google_avg > 0:
        reason_parts.append(f'Google Shopping均价${google_avg:.0f}')
    if cost_1688 > 0 and suggested > 0:
        margin_pct = ((suggested - cost_1688) / suggested) * 100
        reason_parts.append(f'毛利率{margin_pct:.0f}%')
    reason_parts.append('尾数.99心理定价')

    return amz_price, suggested, '，'.join(reason_parts)




def _opus_supply_chain(p):
    """供应链风险评级"""
    shipping = str(p.get('shipping_feasibility', '') or '').strip()
    price = float(p.get('price', 0) or 0)
    cost = float(p.get('cost_1688_usd', 0) or 0)

    if shipping.startswith('🔴'):
        level = '高'
        advice = '首单50件空运验证退货率 | 优先1688找有海外仓的供应商 | 备货周期拉长至30天'
    elif shipping.startswith('🟡') or price > 100:
        level = '中'
        advice = '首单100件混合发货 | 1688+AliExpress比价 | 保持15天安全库存'
    else:
        level = '低'
        advice = '首单200件海运 | 1688直采成本最优 | 按周销量×2备货'

    return level, advice




def _opus_confidence(p):
    """Opus信心评分"""
    system_score = float(p.get('expert_selection_score', 0) or 0)
    profit = float(p.get('profit_cold', 0) or 0)
    roas = float(p.get('est_roas_cold', 0) or 0)
    trend = str(p.get('trend_direction', '') or '').strip()
    fb_days = int(float(p.get('fb_oldest_ad_days', 0) or 0))
    pain = str(p.get('pain_level', '') or '').strip()
    passed = bool(p.get('verification_passed'))

    confidence = 35  # 基线
    if profit > 10: confidence += 15
    elif profit > 0: confidence += 8
    if roas >= 1.5: confidence += 12
    elif roas >= 1.2: confidence += 6
    if trend in ('↑', '↑↑'): confidence += 10
    elif trend in ('↓', '↓↓'): confidence -= 15
    if fb_days >= 30: confidence += 12
    elif fb_days >= 14: confidence += 6
    if pain in ('S', 'A'): confidence += 8
    if passed: confidence += 10
    confidence = max(10, min(95, confidence))

    diff_reasons = []
    if abs(confidence - system_score) > 15:
        if confidence > system_score:
            diff_reasons.append('实操经验中痛点型+BA素材的转化率比系统预期更高')
        else:
            diff_reasons.append('系统未充分考虑冷流量获客的实际CPM波动和季节性因素')
    elif abs(confidence - system_score) > 5:
        diff_reasons.append('微调了FB广告竞争强度和创意制作难度的权重')
    else:
        diff_reasons.append('系统评分与实操判断基本一致')

    # 最值得注意的事
    notable = str(p.get('win_path', '') or p.get('review_most_valuable_feature', '') or p.get('hero_pain_statement', '') or '').strip()
    if not notable:
        if profit > 15:
            notable = f'冷流量单件利润${profit:.0f}，这是最稀缺的信号'
        elif fb_days >= 30:
            notable = f'广告已存活{fb_days}天，有人在赚钱'
        elif pain in ('S',):
            notable = '痛点S级，素材冲击力就是最大的护城河'
        else:
            notable = '需要更多数据才能做出高置信判断'

    return confidence, diff_reasons[0], notable




def generate_opus_analysis_report(p):
    """
    v33.1: 生成完整的 Opus 产品深度分析报告
    包含10个板块的全量化分析，直接可执行。
    """
    sanitize_product_data(p)
    name = str(p.get('name', '') or '')[:60]
    asin = str(p.get('asin', '') or '')
    price = float(p.get('price', 0) or 0)
    shopify_price = float(p.get('shopify_sell_price', 0) or 0)
    system_score = float(p.get('expert_selection_score', 0) or 0)

    # ① 最终裁决
    verdict = _opus_verdict(p)
    reasons = _opus_verdict_reasons(p)

    # ② 机会与差异化
    weakness, angle = _opus_opportunity(p)

    # ③ 最大风险
    risk, mitigation = _opus_risk(p)

    # ④ FB广告方案
    ad_format, hook, primary, interests, budget, budget_reason = _opus_fb_plan(p)

    # ⑤ 落地页
    fs, prob, sol, proof, cta = _opus_landing_page(p)

    # ⑥ 卖点
    selling_points = _opus_selling_points(p)

    # ⑦ 定价
    amz_p, suggested_p, pricing_reason = _opus_pricing(p)

    # ⑧ 供应链
    sc_level, sc_advice = _opus_supply_chain(p)

    # ⑨ 30天路线图
    budget_display = f'${budget:.0f}' if budget > 0 else '$30'

    # ⑩ 信心评分
    confidence, diff_reason, notable = _opus_confidence(p)

    report = f"""━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📦 Opus 产品深度分析: {name}
ASIN: {asin} | Amazon ${price:.0f} | Shopify ${shopify_price:.0f}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

【① 最终选品裁决】
**{verdict}**
1. {reasons[0]}
2. {reasons[1] if len(reasons) > 1 else '—'}
3. {reasons[2] if len(reasons) > 2 else '—'}

【② 核心机会与差异化角度】
竞品弱点: {weakness}
切入方向: {angle}

【③ 最大风险与规避方案】
根本风险: {risk}
{mitigation}

【④ Facebook广告首支方案】
- 广告形式: {ad_format}
- Hook钩子: {hook}
- 广告正文: {primary[:200]}
- 受众定向:
  1. {interests[0] if interests else '—'}
  2. {interests[1] if len(interests) > 1 else '—'}
  3. {interests[2] if len(interests) > 2 else '—'}
- 冷启动日预算: {budget_display}，原因: {budget_reason}

【⑤ Shopify落地页5段结构】
First Screen: {fs}
Problem: {prob}
Solution: {sol}
Proof: {proof}
CTA: {cta}

【⑥ 3条直接可用广告卖点】
1. {selling_points[0]}
2. {selling_points[1]}
3. {selling_points[2]}

【⑦ 定价策略】
Amazon ${amz_p:.0f} → 独立站建议 **${suggested_p}**
理由: {pricing_reason}

【⑧ 供应链风险评级】
风险等级: **{sc_level}**
{sc_advice}

【⑨ 30天测试路线图】
Week 1 验证期: 上3组素材+2版落地页，日预算{budget_display} → 看CTR≥1.2%、CPM≤$25，否则换素材
Week 2 优化期: 砍掉CPA最高的素材，放量CTR最高的 → 看ROAS≥1.0、加购率≥5%
Week 3-4 放量/砍掉: ROAS≥1.3且日出单≥3则加预算50% → 否则暂停，复盘素材角度后决定是否换品

【⑩ Opus信心评分】
我的综合信心分: **{confidence}/100**
与系统评分({system_score:.0f}分)的差异原因: {diff_reason}
如果只能说一件事: **{notable}**
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"""

    p['opus_analysis_report'] = report
    return report




def export_opus_reports(products, cap=None):
    """
    v33.1: 批量导出 Opus 分析报告到文本文件
    只导出验证通过或Top候选品。
    """
    if not products:
        return
    cap = cap or 10
    targets = [p for p in products if p.get('verification_passed') or p.get('fallback_validated')][:cap]
    if not targets:
        targets = products[:min(cap, 5)]

    stamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    fn = f'{Config.OUT_DIR}/opus_analysis_{stamp}.txt'
    reports = []
    for i, p in enumerate(targets, 1):
        try:
            report = generate_opus_analysis_report(p)
            reports.append(f'\n{"=" * 60}\n产品 #{i}\n{"=" * 60}\n{report}')
            log.info(f'  📋 Opus报告 #{i}: {str(p.get("name", ""))[:40]}')
        except Exception as e:
            log.debug(f'  ⚠️ Opus报告异常 [{p.get("name", "")[:24]}]: {e}')

    if reports:
        Path(fn).write_text('\n'.join(reports), encoding='utf-8')
        log.info(f'  📄 Opus分析报告: {fn} ({len(reports)}个产品)')
    return fn






# ================================================================
#  v40.0 ULTIMATE: 从 v52 合并的可行性评分集成
# ================================================================

def apply_viability_scoring(products: list) -> list:
    """集成 viability_scorer 的6维度评分到产品数据中"""
    try:
        from viability_scorer import calculate_viability_score, calculate_shopify_fit, score_normalized_product
        for p in products:
            try:
                score_normalized_product(p)
            except Exception:
                pass
            try:
                price = float(p.get('price', 0) or 0)
                reviews = int(p.get('reviews_count', 0) or p.get('review_count', 0) or 0)
                rating = float(p.get('rating', 0) or 0)
                badge = str(p.get('amazon_badge', '') or '')
                fulfilled = str(p.get('amazon_fulfilled_by', '') or '')
                bsr = p.get('bsr_rank')
                if bsr:
                    bsr = int(bsr)
                score, label, detail = calculate_viability_score(price, reviews, rating, badge, fulfilled, bsr)
                p['viability_score'] = score
                p['viability_label'] = label
                p['viability_detail'] = detail
            except Exception:
                pass
            try:
                shopify_fit = calculate_shopify_fit(
                    price=float(p.get('price', 0) or 0),
                    review_count=int(p.get('reviews_count', 0) or p.get('review_count', 0) or 0),
                    rating=float(p.get('rating', 0) or 0),
                    has_visual_demo=bool(p.get('visual_demo') or p.get('has_before_after')),
                )
                p['shopify_fit_score'] = shopify_fit.get('score', 0)
                p['shopify_fit_label'] = shopify_fit.get('label', '')
            except Exception:
                pass
        log.info(f'  ✅ [v40] 可行性评分完成: {len(products)}品')
    except ImportError:
        log.debug('  ℹ️ viability_scorer.py 不可用, 跳过可行性评分')
    return products


def apply_ultimate_enhancements(products: list, ai_top: int = 0) -> list:
    """
    v40.0 ULTIMATE: 集成所有增强管线
    1. v27 商用增强 (ExpertSelection, TrendPrediction, CompetitorAnalysis)
    2. v28 集成 (DataSource, RealtimeMonitor, Webhook, DataLake)
    3. v34 操盘级增强 (竞争空白, FB投放摘要, 异议处理, 创意评级)
    4. v52 可行性评分 (6维度加权)
    5. Opus AI 深度分析 (Claude API)
    """
    log.info('  🔧 [v40] ULTIMATE 全功能增强管线启动...')

    # Stage 1: v27 商用增强
    try:
        products = apply_v27_enhancements(products)
    except Exception as e:
        log.debug(f'  ⚠️ v27增强异常: {e}')

    # Stage 2: v28 集成
    try:
        products = apply_v28_integration(products)
    except Exception as e:
        log.debug(f'  ⚠️ v28集成异常: {e}')

    # Stage 3: v34 操盘级增强
    try:
        products = apply_v34_enhancements(products)
    except Exception as e:
        log.debug(f'  ⚠️ v34增强异常: {e}')

    # Stage 4: v57 易出单 + 早期信号评分
    try:
        products = apply_v57_scoring(products)
    except Exception as e:
        log.debug(f'  ⚠️ v57评分异常: {e}')

    # Stage 5: v52 可行性评分
    try:
        products = apply_viability_scoring(products)
    except Exception as e:
        log.debug(f'  ⚠️ 可行性评分异常: {e}')

    # Stage 6: Opus AI 深度分析 (可选)
    if ai_top > 0:
        try:
            api_key = os.environ.get('ANTHROPIC_API_KEY', '')
            if api_key:
                products = apply_opus_to_top_products(products, api_key=api_key, max_calls=ai_top)
                export_opus_reports(products, cap=ai_top)
            else:
                log.info('  ℹ️ 未设置 ANTHROPIC_API_KEY, 跳过 Opus AI 分析')
                log.info('  💡 启用: export ANTHROPIC_API_KEY=sk-ant-xxx')
        except Exception as e:
            log.debug(f'  ⚠️ Opus AI异常: {e}')

    log.info(f'  ✅ [v40] ULTIMATE 增强完成: {len(products)}品')
    return products


def run():
    parser = argparse.ArgumentParser(description='Amazon 终极选品系统 v40.0 ULTIMATE')
    parser.add_argument('--niche', type=str, default='', help='兼容旧入口参数；v57主流程以关键词文件为输入')
    parser.add_argument('--silent', action='store_true', help='兼容旧入口参数；v57默认非交互')
    parser.add_argument('--kw-file', type=str, default='keywords.txt', help='指定关键词文件')
    parser.add_argument('--kw-only', action='store_true', help='仅从关键词采集')
    parser.add_argument('--no-validate', action='store_true', help='跳过真实验证，仅做本地评分与导出')
    parser.add_argument('--verify-top', type=int, default=CommercialConfig.VERIFY_TOP_DEFAULT, help='仅验证前N个候选品')
    parser.add_argument('--final-top', type=int, default=CommercialConfig.FINAL_TOP_DEFAULT, help='输出前N个已验证品')
    parser.add_argument('--watchlist-top', type=int, default=CommercialConfig.WATCHLIST_TOP_DEFAULT, help='输出前N个观察品')
    parser.add_argument('--excel-only', action='store_true', help='仅导出Excel')
    parser.add_argument('--ai-top', type=int, default=0, help='AI分析前N个已验证产品')
    parser.add_argument('--test', action='store_true', help='运行内置测试')
    parser.add_argument('--benchmark', action='store_true', help='运行性能基准测试')
    parser.add_argument('--demo', action='store_true', help='运行演示模式')
    parser.add_argument('--quick', nargs='?', const='massage gun', metavar='KEYWORD', help='快速分析单个关键词')
    args = parser.parse_args()

    if args.test:
        run_tests()
        return
    if args.benchmark:
        run_benchmark()
        return
    if args.demo:
        run_demo()
        return
    if args.quick is not None:
        result = run_quick_analysis(args.quick)
        print(f"\n结果: {result}")
        return

    # ===== v33.0 生产级配置 =====
    generate_default_keywords_file(args.kw_file)

    start = time.time()

    # v3: 初始化轨迹
    traj = reset_logger("amazon_selector") if HAS_GUARD else None

    # v30: 初始化日志配置
    logging.basicConfig(
        level=logging.INFO,
        format='%(asctime)s | %(levelname)s | %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )

    log.info('='*50)
    log.info('🏆 Amazon 终极选品系统 v54.0 PRO')
    log.info('='*50)

    print('\n' + '#' * 60)
    print('#  v40.0 ULTIMATE 终极版')
    print('#  短关键词采集 + 真实验证 + 专家决策 + 生产级架构')
    print('#' * 60 + '\n')
    log.info('=' * 60)
    log.info('v54.0 ULTIMATE | 30年经验+FB出单优化+长青品识别 | 专家+AI+ML')
    log.info(f'  verify_top={args.verify_top} | final_top={args.final_top} | watchlist_top={args.watchlist_top}')
    if args.niche:
        log.info(f'  ℹ️ --niche={args.niche} 已兼容接收；v57使用 --kw-file 控制关键词输入')
    log.info('=' * 60)

    if args.kw_only:
        log.info('ℹ️ --kw-only 模式，跳过 Amazon 榜单刷新，保留用户 keywords.txt')
        refreshed_titles = None
    else:
        refreshed_titles = refresh_keywords_from_latest_movers(args.kw_file)
        if refreshed_titles is None:
            log.info('ℹ️ Amazon 榜单刷新失败，继续使用现有关键词文件内容')
        elif not refreshed_titles:
            log.warning('⚠️ 当前筛选条件下没有新的可用 seed，keywords.txt 已清空')

    products = scrape_from_short_keywords(args.kw_file)
    if not products:
        log.error('❌ 未采集到有效产品')
        return

    seen = set()
    deduped = []
    for p in products:
        key = p.get('asin') or dedup_key(p.get('name', ''), p.get('price', 0))
        if key in seen:
            continue
        seen.add(key)
        deduped.append(p)
    log.info(f'📊 采集:{len(products)} → 去重:{len(deduped)}')

    enrich_source_links(deduped)
    apply_v57_scoring(deduped)
    round1_rank(deduped)

    validation_pool = select_validation_pool(deduped, max(1, args.verify_top))
    if args.no_validate:
        log.info('⏩ --no-validate: 跳过真实验证，使用本地评分继续生成候选池')
        for p in validation_pool:
            p['verification_passed'] = False
            p['fallback_validated'] = True
            p['verification_stage'] = p.get('verification_stage') or '跳过真实验证'
            p['verification_reason'] = p.get('verification_reason') or 'Skipped live validation by --no-validate / 已按参数跳过真实验证'
    else:
        validate_small_pool(validation_pool)
    score_validated_pool(validation_pool)

    validated_ids = {p.get('asin') or dedup_key(p.get('name', ''), p.get('price', 0)) for p in validation_pool}
    watchlist = build_watchlist(deduped, validated_ids, args.watchlist_top)

    enrich_final_market_context(validation_pool, args.final_top)
    decorate_output_products(validation_pool)
    decorate_output_products(watchlist)

    winners = print_validated_results(validation_pool, args.final_top, watchlist)
    watchlist_ids = {p.get('asin') or dedup_key(p.get('name', ''), p.get('price', 0)) for p in winners}
    watchlist = [p for p in watchlist if (p.get('asin') or dedup_key(p.get('name', ''), p.get('price', 0))) not in watchlist_ids]

    enrich_validated_review_insights(winners, cap=args.final_top)

    # v40.0 ULTIMATE: 全功能增强管线
    try:
        winners = apply_ultimate_enhancements(winners, ai_top=args.ai_top)
        watchlist = apply_ultimate_enhancements(watchlist, ai_top=0)
    except Exception as e:
        log.debug(f'  ⚠️ ULTIMATE增强异常: {e}')

    passed_count = len([p for p in validation_pool if p.get('verification_passed') and not p.get('fallback_validated')])
    verdict_counts = {
        'launch_now': len([p for p in winners if 'Launch now' in str(p.get('sell_verdict', '')) or '立即投放' in str(p.get('sell_verdict', ''))]),
        'test_watch': len([p for p in winners if 'Test first' in str(p.get('sell_verdict', '')) or '测试观察' in str(p.get('sell_verdict', ''))]),
        'watchlist': len(watchlist),
    }
    export_set = winners + watchlist
    html_export_set = export_set
    excel_export_set = deduped
    trend_export_set = winners + watchlist[:min(len(watchlist), 3)]
    enrich_export_trends(trend_export_set, cap=len(trend_export_set))
    decorate_output_products(html_export_set)
    decorate_output_products(excel_export_set)
    master_summary = generate_master_summary(html_export_set)
    summary_path = _write_master_summary(master_summary, Config.OUT_DIR)
    print('\n📊 总览摘要')
    print(f"总分析数: {master_summary.get('total_analyzed', 0)}")
    print(f"🚀 S级: {master_summary.get('tier_s_count', 0)} | ✅ A级: {master_summary.get('tier_a_count', 0)} | 👀 B级: {master_summary.get('tier_b_count', 0)} | ❌ C级: {master_summary.get('tier_c_count', 0)}")
    print(f"🎯 可立即测试: {master_summary.get('ready_to_launch_count', 0)} | 🧪 二轮验证: {master_summary.get('reround_count', 0)} | 🛒 Amazon向: {master_summary.get('amazon_only_count', 0)} | 📣 D2C向: {master_summary.get('d2c_only_count', 0)} | ⛔ 放弃: {master_summary.get('drop_count', 0)}")
    print(f"🎯 最佳 Facebook 产品: {master_summary.get('best_fb_product', '')}")
    print(f"🛍️ 最佳 Shopify 产品: {master_summary.get('best_shopify_product', '')}")
    print(f"📈 平均闭环分数: {_safe_float(master_summary.get('avg_closed_loop_score')):.1f}")
    print(f"🧠 平均选品总分: {_safe_float(master_summary.get('avg_final_selection_score')):.1f}")
    print(f"⚡ 平均v57机会分: {_safe_float(master_summary.get('avg_v57_opportunity_score')):.1f}")
    print(f"💡 {master_summary.get('pareto_insight', '')}")
    for idx, item in enumerate(master_summary.get('top_3_products', []) or [], 1):
        print(f"{idx}. {item.get('name', '')} | 分层 {item.get('paretoTier', '')} | 阶段 {item.get('selectionStage', '')} | 选品总分 {_safe_float(item.get('finalSelectionScore')):.1f} | v57 {_safe_float(item.get('v57OpportunityScore')):.1f} | 闭环分 {_safe_float(item.get('closedLoopScore')):.1f}")
    log.info(f'  🧠 Master summary: {summary_path}')
    stats = {
        'total': len(products),
        'dedup': len(deduped),
        'elapsed': round(time.time() - start),
        'validation_pool': len(validation_pool),
        'passed_count': passed_count,
        'winner_count': len(winners),
        'best_product': winners[0].get('name', '') if winners else '',
        'verdict_counts': verdict_counts,
        'master_summary': master_summary,
    }
    try:
        export_excel(excel_export_set, stats)
    except Exception as e:
        log.error(f'  ❌ Excel导出失败: {e}')

    # v24.0: CSV已禁用 — 只输出Excel格式
    # try:
    #     csv_path = export_csv(deduped)
    #     log.info(f'  📊 CSV: {csv_path}')
    # except Exception as e:
    #     log.error(f'  ❌ CSV导出失败: {e}')

    if not args.excel_only:
        try:
            export_html(html_export_set, stats)
        except Exception as e:
            log.error(f'  ❌ HTML导出失败: {e}')

    output_dir = Config.OUT_DIR
    previous_snapshot = load_latest_snapshot(output_dir)
    snapshot_path = save_snapshot(winners, output_dir)
    if previous_snapshot:
        delta = generate_delta_report(winners + watchlist, previous_snapshot)
        log.info(delta)
        delta_stamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        delta_path = Path(output_dir) / f'delta_report_{delta_stamp}.txt'
        with open(delta_path, 'w', encoding='utf-8') as f:
            f.write(delta)
        log.info(f'  🧾 Delta report: {delta_path}')
    log.info(f'  📸 Snapshot: {snapshot_path}')

    ai_count = min(args.ai_top, len(winners)) if args.ai_top > 0 else 0
    if ai_count > 0 and Config.ANTHROPIC_KEY:
        try:
            AIAnalyzer.analyze_batch(winners, max_count=ai_count)
        except Exception as e:
            log.error(f'  ❌ AI分析异常: {e}')

    log.info('\n' + '━' * 60)
    log.info(f"✅ v34.0 完成! {stats['elapsed']}s")
    log.info(f"   采集:{len(products)} → 去重:{len(deduped)} → 验证池:{len(validation_pool)} → 已验证通过:{len([p for p in validation_pool if p.get('verification_passed') and not p.get('fallback_validated')])}")
    if winners:
        log.info(f"   📌 最佳品: {winners[0].get('name','')[:40]}")
    log.info('━' * 60)
    
    # v56.0: 输出验证报告
    report = ValidationStats.get_report()
    log.info('📊 v56.0 产品验证报告')
    log.info(f"   总验证: {report['total']} | 通过: {report['passed']} | 失败: {report['failed']}")
    log.info(f"   通过率: {report['pass_rate']:.1f}%")
    if report['failed'] > 0:
        log.info('   失败原因:')
        for reason, count in report['failure_reasons'].items():
            log.info(f"     • {reason}: {count}")
    log.info('━' * 60)
    
    # v56.0: 写入 rejected.json
    if ValidationStats.rejected_products:
        rejected_path = Path(Config.OUT_DIR) / 'rejected.json'
        with open(rejected_path, 'w', encoding='utf-8') as f:
            json.dump(ValidationStats.rejected_products, f, ensure_ascii=False, indent=2)
        log.info(f'  🚫 Rejected products: {rejected_path}')
    
    # v3: 保存轨迹
    if traj:
        traj.set_meta(
            total=len(products), dedup=len(deduped),
            winners=len(winners), elapsed=round(time.time() - start)
        )
        traj.emit_span("success", {
            "products": len(products), "winners": len(winners),
            "duration": round(time.time() - start)
        })
        ev = traj.evaluate()
        traj.save()
        log.info(f'📊 Trajectory: score={ev["score"]}/100 spans={ev["spans"]} wall={ev["wall_time"]}s')

    SmartFetcher.cleanup()


# ===== v33.0 测试与演示 =====


def run_tests():
    """
    v33.0: 运行内置测试
    验证各模块功能
    """
    print("\n" + "="*60)
    print("🧪 v33.0 内置测试")
    print("="*60)

    passed = 0
    failed = 0

    # Test 1: SmartFilterRules
    print("\n📋 测试1: SmartFilterRules")
    try:
        test_product = {
            'asin': 'B08N5WRWNW',
            'name': 'Test Product',
            'price': 59.99,
            'rating': 4.5,
            'bsr_rank': 500,
            'review_velocity': 35,
            'reviews_count': 500,
            'amazon_offer_count': 15,
        }
        should_verify, reason = SmartFilterRules.should_verify_product(test_product)
        assert should_verify == True, "应该通过验证"
        quality_score = SmartFilterRules.get_product_quality_score(test_product)
        assert quality_score > 50, f"质量分应该>50, 得到{quality_score}"
        print(f"  ✅ 通过: 质量分={quality_score:.1f}")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 2: ExpertSelectionEngine
    print("\n📋 测试2: ExpertSelectionEngine")
    try:
        decision = ExpertSelectionEngine.make_selection_decision(test_product)
        assert 'expert_selection_score' in decision, "应该有专家评分"
        assert 'expert_priority' in decision, "应该有优先级"
        print(f"  ✅ 通过: 专家评分={decision['expert_selection_score']}, 优先级={decision['expert_priority']}")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 3: RiskAssessmentModel
    print("\n📋 测试3: RiskAssessmentModel")
    try:
        risk = RiskAssessmentModel.assess_all_risks(test_product)
        assert 'total_risk_score' in risk, "应该有风险总分"
        assert 'risk_level' in risk, "应该有风险级别"
        print(f"  ✅ 通过: 风险分={risk['total_risk_score']}, 级别={risk['risk_level']}")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 4: TrendPredictionEngine
    print("\n📋 测试4: TrendPredictionEngine")
    try:
        trend = TrendPredictionEngine.predict_momentum(test_product)
        assert 'momentum_score' in trend, "应该有动量评分"
        assert 'trend_prediction' in trend, "应该有趋势预测"
        confidence = TrendPredictionEngine.calculate_trend_confidence(test_product)
        print(f"  ✅ 通过: 动量={trend['momentum_score']}, 预测={trend['trend_prediction']}, 置信度={confidence}%")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 5: MLPredictionEngine
    print("\n📋 测试5: MLPredictionEngine")
    try:
        ml_score = MLPredictionEngine.predict_success_score(test_product)
        ml_conf = MLPredictionEngine.get_prediction_confidence(test_product)
        assert 0 <= ml_score <= 100, "ML分数应在0-100"
        print(f"  ✅ 通过: ML预测={ml_score:.1f}, 置信度={ml_conf}%")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 6: NLPReviewAnalyzer
    print("\n📋 测试6: NLPReviewAnalyzer")
    try:
        review = "This product is amazing! Great quality and fast shipping. Highly recommend!"
        sentiment = NLPReviewAnalyzer.extract_sentiment(review)
        assert sentiment['sentiment'] == 'positive', "应该是正面情感"
        pain_points = NLPReviewAnalyzer.extract_pain_points("The product broke after one week. Poor quality!")
        assert len(pain_points) > 0, "应该检测到痛点"
        print(f"  ✅ 通过: 情感={sentiment['sentiment']}, 痛点={pain_points}")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 7: CacheManager
    print("\n📋 测试7: CacheManager")
    try:
        cache = CacheManager(max_size=10, ttl=60)
        cache.set('test_key', 'test_value')
        val, hit = cache.get('test_key')
        assert hit == True, "应该命中"
        assert val == 'test_value', "值应该匹配"
        stats = cache.get_stats()
        assert stats['hit_rate'] >= 0, "应该有命中率"
        print(f"  ✅ 通过: 缓存命中率={stats['hit_rate']}%")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 8: PerformanceMonitor
    print("\n📋 测试8: PerformanceMonitor")
    try:
        perf = PerformanceMonitor()
        perf.record_request(1.5, 'scrape')
        perf.record_request(2.0, 'validate')
        perf.record_error()
        stats = perf.get_stats()
        assert stats['total_requests'] == 2, "应该2个请求"
        assert stats['total_errors'] == 1, "应该1个错误"
        print(f"  ✅ 通过: 请求={stats['total_requests']}, 错误={stats['total_errors']}, 错误率={stats['error_rate']}%")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 9: AutoReportingSystem
    print("\n📋 测试9: AutoReportingSystem")
    try:
        test_products = [
            {'name': 'Product A', 'expert_selection_score': 80, 'expert_priority': 'S', 'trend_direction': '↑', 'price': 50},
            {'name': 'Product B', 'expert_selection_score': 60, 'expert_priority': 'A', 'trend_direction': '→', 'price': 80},
            {'name': 'Product C', 'expert_selection_score': 40, 'expert_priority': 'C', 'trend_direction': '↓', 'price': 30},
        ]
        report = AutoReportingSystem.generate_selection_report(test_products)
        assert report['total_products'] == 3, "应该有3个产品"
        assert report['priority_s'] == 1, "应该有1个S级"
        print(f"  ✅ 通过: 报告生成成功")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 10: CompetitorAnalysisEngine
    print("\n📋 测试10: CompetitorAnalysisEngine")
    try:
        analysis = CompetitorAnalysisEngine.analyze_market_position(test_product)
        assert 'strengths' in analysis, "应该有优势"
        win_prob = CompetitorAnalysisEngine.calculate_win_probability(test_product)
        assert 0 <= win_prob <= 100, "胜出概率应在0-100"
        print(f"  ✅ 通过: 分析={len(analysis['strengths'])}优势, 胜出概率={win_prob:.1f}%")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # Test 11: v57 full integration scoring
    print("\n📋 测试11: v57 易出单 + 早期信号集成")
    try:
        v57_product = test_product.copy()
        v57_product['seed_keyword'] = 'massage gun'
        _apply_v57_product_scoring(v57_product)
        core_scores = compute_selection_core_scores(v57_product)
        assert 0 <= v57_product['v57_opportunity_score'] <= 100, "v57机会分应在0-100"
        assert 'v57_opportunity_score' in core_scores, "选品核心分应包含v57机会分"
        print(f"  ✅ 通过: v57={v57_product['v57_opportunity_score']:.1f}, 易出单={v57_product['easy_sell_score']:.1f}, 早期={v57_product['early_signal_score']:.1f}")
        passed += 1
    except Exception as e:
        print(f"  ❌ 失败: {e}")
        failed += 1

    # 总结
    print("\n" + "="*60)
    print(f"📊 测试结果: {passed} 通过, {failed} 失败")
    print("="*60)

    return passed, failed


