# ═══ v55 PRO: 独立的商用Excel导出工具 ═══
def export_v55_professional(products, output_dir='/Users/doi/Desktop/output', filename_prefix='选品报告'):
    """可独立调用的商用Excel导出"""
    class FakeLogger:
        def info(self, msg): print(msg)
        def warning(self, msg): print(f'WARN: {msg}')
    class FakeExporter:
        def __init__(self):
            self.logger = FakeLogger()
            self.output_dir = output_dir

    def _export_excel_base(self, products, filename_prefix="\u9009\u54c1\u62a5\u544a"):
        """v55 PRO: 30\u5e74\u9009\u54c1\u5e08\u5546\u7528\u7ea7Excel\u8f93\u51fa"""
        try:
            from openpyxl import Workbook
            from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
            from openpyxl.utils import get_column_letter
        except ImportError:
            self.logger.warning("openpyxl\u672a\u5b89\u88c5, \u8df3\u8fc7Excel\u8f93\u51fa")
            return None

        from datetime import datetime
        stamp = datetime.now().strftime("%Y%m%d_%H%M")
        output_dir = getattr(self, 'output_dir', '/Users/doi/Desktop/output')
        os.makedirs(output_dir, exist_ok=True)
        fpath = os.path.join(output_dir, f"{filename_prefix}_{stamp}.xlsx")

        wb = Workbook()

        # \u2500\u2500 \u6837\u5f0f\u5b9a\u4e49 \u2500\u2500
        NAVY = PatternFill('solid', fgColor='1B2A4A')
        DARK = PatternFill('solid', fgColor='2C3E6B')
        GOLD = PatternFill('solid', fgColor='F4A900')
        GREEN_H = PatternFill('solid', fgColor='2E7D32')
        GREEN_BG = PatternFill('solid', fgColor='E8F5E9')
        RED_BG = PatternFill('solid', fgColor='FFEBEE')
        YELLOW_BG = PatternFill('solid', fgColor='FFF8E1')
        GRAY_BG = PatternFill('solid', fgColor='F5F5F5')
        S_FILL = PatternFill('solid', fgColor='FFD700')
        A_FILL = PatternFill('solid', fgColor='C8E6C9')
        B_FILL = PatternFill('solid', fgColor='FFF9C4')
        WH = Font(name='Microsoft YaHei', size=11, bold=True, color='FFFFFF')
        BF = Font(name='Microsoft YaHei', size=10)
        SF = Font(name='Consolas', size=11, bold=True)
        TH = Border(
            left=Side('thin',color='D0D0D0'), right=Side('thin',color='D0D0D0'),
            top=Side('thin',color='D0D0D0'), bottom=Side('thin',color='D0D0D0')
        )
        CT = Alignment(horizontal='center', vertical='center', wrap_text=True)
        LT = Alignment(horizontal='left', vertical='top', wrap_text=True)

        def write_hdr(ws, headers, fill=NAVY):
            for col, (h, w) in enumerate(headers, 1):
                c = ws.cell(row=1, column=col, value=h)
                c.fill = fill; c.font = WH; c.alignment = CT; c.border = TH
                ws.column_dimensions[get_column_letter(col)].width = w

        def safe_get(p, key, default=''):
            try:
                v = p.get(key, default) if isinstance(p, dict) else getattr(p, key, default)
                return v if v is not None else default
            except: return default

        def expert_priority(total_score):
            if total_score >= 85: return 'S'
            if total_score >= 70: return 'A'
            if total_score >= 50: return 'B'
            return 'C'

        def expert_verdict(p, total_score, priority):
            verdicts = {
                'S': '\u2b50 S\u7ea7\u2014\u7acb\u5373\u91c7\u8d2d\u6d4b\u8bd5: \u591a\u7ef4\u5ea6\u8bc4\u5206\u4f18\u79c0',
                'A': '\ud83d\udfe2 A\u7ea7\u2014\u91cd\u70b9\u8ddf\u8fdb: \u6f5c\u529b\u4ea7\u54c1',
                'B': '\ud83d\udfe1 B\u7ea7\u2014\u89c2\u5bdf\u5907\u9009: \u9700\u66f4\u591a\u9a8c\u8bc1',
                'C': '\u26aa C\u7ea7\u2014\u6682\u4e0d\u63a8\u8350',
            }
            return verdicts.get(priority, '')

        def expert_insight(p):
            insights = []
            margin = safe_get(p, 'margin_score', 0) or safe_get(p, 'estimated_margin', 0)
            fb = safe_get(p, 'fb_score', 0)
            comp = safe_get(p, 'competition_score', 0) or safe_get(p, 'market_score', 0)
            pain = safe_get(p, 'pain_score', 0)
            impulse = safe_get(p, 'impulse_score', 0)
            price = safe_get(p, 'price', 0)

            if isinstance(margin, (int, float)) and margin >= 15:
                insights.append('\ud83d\udcb0 \u9ad8\u5229\u6da6\u7a7a\u95f4')
            if isinstance(fb, (int, float)) and fb >= 15:
                insights.append('\ud83d\udcf1 FB\u6295\u653e\u9002\u914d\u5ea6\u9ad8')
            if isinstance(comp, (int, float)) and comp >= 15:
                insights.append('\ud83d\udfe2 \u7ade\u4e89\u7a97\u53e3\u597d')
            if isinstance(pain, (int, float)) and pain >= 15:
                insights.append('\ud83d\udd25 \u75db\u70b9\u660e\u786e')
            if isinstance(impulse, (int, float)) and impulse >= 15:
                insights.append('\u26a1 \u51b2\u52a8\u8d2d\u4e70\u5f3a')
            if isinstance(price, (int, float)):
                if 25 <= price <= 80:
                    insights.append('\ud83c\udfaf \u4ef7\u683c\u751c\u533a($25-80)')
                elif price > 80:
                    insights.append('\ud83d\udc8e \u9ad8\u5ba2\u5355(>$80)')
            return ' | '.join(insights[:4]) if insights else '\u9700\u8fdb\u4e00\u6b65\u8bc4\u4f30'

        # \u2550\u2550\u2550\u2550\u2550\u2550 Sheet 1: \u9009\u54c1Dashboard \u2550\u2550\u2550\u2550\u2550\u2550
        ws1 = wb.active
        ws1.title = '\u9009\u54c1Dashboard'
        ws1.sheet_properties.tabColor = '1B2A4A'

        dash_cols = [
            ('\u6392\u540d', 5), ('\u4f18\u5148\u7ea7', 7), ('\u4ea7\u54c1\u540d\u79f0', 44), ('\u4ef7\u683c($)', 9), ('\u8bc4\u5206(Rating)', 10),
            ('\u8bc4\u8bba\u6570', 8), ('BSR', 12), ('\u7efc\u5408\u5206', 8),
            ('FB\u5206', 7), ('\u75db\u70b9\u5206', 7), ('\u5229\u6da6\u5206', 7), ('\u51b2\u52a8\u5206', 7),
            ('\u573a\u666f\u5206', 7), ('\u5e02\u573a\u5206', 7), ('\u7ade\u4e89\u5206', 7), ('\u89c6\u89c9\u5206', 7),
            ('\u9009\u54c1\u5e08\u5224\u5b9a', 36), ('30\u5e74\u6d1e\u89c1', 50),
        ]
        write_hdr(ws1, dash_cols)

        for idx, p in enumerate(products[:200], 1):
            scores_map = {
                'fb': safe_get(p, 'fb_score', 0),
                'pain': safe_get(p, 'pain_score', 0),
                'margin': safe_get(p, 'margin_score', 0),
                'impulse': safe_get(p, 'impulse_score', 0),
                'scene': safe_get(p, 'scene_score', 0),
                'market': safe_get(p, 'market_score', 0),
                'competition': safe_get(p, 'competition_score', 0),
                'visual': safe_get(p, 'visual_score', 0),
            }
            total = safe_get(p, 'total_score', 0)
            if not isinstance(total, (int, float)) or total == 0:
                total = sum(v for v in scores_map.values() if isinstance(v, (int, float)))
            priority = expert_priority(total)
            verdict = expert_verdict(p, total, priority)
            insight = expert_insight(p)

            row_data = [
                idx, priority,
                safe_get(p, 'title', safe_get(p, 'name', '')),
                safe_get(p, 'price', ''),
                safe_get(p, 'rating', ''),
                safe_get(p, 'review_count', safe_get(p, 'reviews', '')),
                safe_get(p, 'bsr', safe_get(p, 'best_seller_rank', '')),
                total,
                scores_map['fb'], scores_map['pain'], scores_map['margin'],
                scores_map['impulse'], scores_map['scene'], scores_map['market'],
                scores_map['competition'], scores_map['visual'],
                verdict, insight,
            ]

            r = idx + 1
            for col, val in enumerate(row_data, 1):
                c = ws1.cell(row=r, column=col, value=val)
                c.font = BF; c.alignment = LT; c.border = TH
                if idx % 2 == 0: c.fill = GRAY_BG

            # \u4f18\u5148\u7ea7\u7740\u8272
            pc = ws1.cell(row=r, column=2)
            if priority == 'S': pc.fill = S_FILL; pc.font = Font(name='Consolas', bold=True, size=12, color='8B6914')
            elif priority == 'A': pc.fill = A_FILL; pc.font = Font(name='Consolas', bold=True, size=12, color='2E7D32')
            elif priority == 'B': pc.fill = B_FILL; pc.font = Font(name='Consolas', bold=True, size=12, color='F57F17')

            # \u7efc\u5408\u5206\u7740\u8272
            sc = ws1.cell(row=r, column=8)
            if isinstance(total, (int, float)):
                if total >= 85: sc.fill = GREEN_BG; sc.font = Font(name='Consolas', bold=True, color='1B5E20')
                elif total >= 50: sc.fill = YELLOW_BG; sc.font = SF
                else: sc.fill = RED_BG; sc.font = Font(name='Consolas', bold=True, color='B71C1C')

        # \u2550\u2550\u2550\u2550\u2550\u2550 Sheet 2: \u4ea7\u54c1\u660e\u7ec6 \u2550\u2550\u2550\u2550\u2550\u2550
        ws2 = wb.create_sheet('\u4ea7\u54c1\u660e\u7ec6')
        ws2.sheet_properties.tabColor = '2C3E6B'

        # \u52a8\u6001\u6784\u5efa\u5217 \u2014 \u9002\u914d dict \u6216 object
        all_keys = set()
        for p in products[:5]:
            if isinstance(p, dict):
                all_keys.update(p.keys())
            else:
                all_keys.update(k for k in dir(p) if not k.startswith('_'))

        # \u4f18\u5148\u5c55\u793a\u7684\u5217
        priority_keys = [
            'title', 'name', 'asin', 'price', 'rating', 'review_count', 'reviews',
            'bsr', 'best_seller_rank', 'category', 'brand',
            'total_score', 'fb_score', 'pain_score', 'margin_score', 'impulse_score',
            'scene_score', 'market_score', 'competition_score', 'visual_score',
            'estimated_margin', 'estimated_profit', 'url', 'image_url',
        ]
        ordered_keys = [k for k in priority_keys if k in all_keys]
        ordered_keys += sorted(k for k in all_keys if k not in ordered_keys and not k.startswith('_'))
        ordered_keys = ordered_keys[:50]  # cap

        detail_headers = [(k, max(12, min(len(str(k))*1.5+4, 40))) for k in ordered_keys]
        write_hdr(ws2, detail_headers, fill=DARK)

        for idx, p in enumerate(products[:500], 1):
            r = idx + 1
            for col, key in enumerate(ordered_keys, 1):
                val = safe_get(p, key, '')
                if isinstance(val, (list, dict, set)):
                    val = str(val)[:200]
                c = ws2.cell(row=r, column=col, value=val)
                c.font = BF; c.alignment = LT; c.border = TH
                if idx % 2 == 0: c.fill = GRAY_BG

        # \u2550\u2550\u2550\u2550\u2550\u2550 Sheet 3: \u8bc4\u5206\u96f7\u8fbe\u56fe\u6570\u636e \u2550\u2550\u2550\u2550\u2550\u2550
        ws3 = wb.create_sheet('\u8bc4\u5206\u96f7\u8fbe\u56fe')
        ws3.sheet_properties.tabColor = 'FF5722'

        radar_cols = [
            ('\u4ea7\u54c1', 36), ('FB\u5206', 8), ('\u75db\u70b9\u5206', 8), ('\u5229\u6da6\u5206', 8),
            ('\u51b2\u52a8\u5206', 8), ('\u573a\u666f\u5206', 8), ('\u5e02\u573a\u5206', 8),
            ('\u7ade\u4e89\u5206', 8), ('\u89c6\u89c9\u5206', 8), ('\u603b\u5206', 8), ('\u4f18\u5148\u7ea7', 7),
        ]
        write_hdr(ws3, radar_cols, fill=PatternFill('solid', fgColor='FF5722'))

        for idx, p in enumerate(products[:100], 1):
            total = safe_get(p, 'total_score', 0)
            if not isinstance(total, (int,float)): total = 0
            row_data = [
                safe_get(p, 'title', safe_get(p, 'name', '')),
                safe_get(p, 'fb_score', 0), safe_get(p, 'pain_score', 0),
                safe_get(p, 'margin_score', 0), safe_get(p, 'impulse_score', 0),
                safe_get(p, 'scene_score', 0), safe_get(p, 'market_score', 0),
                safe_get(p, 'competition_score', 0), safe_get(p, 'visual_score', 0),
                total, expert_priority(total),
            ]
            for col, val in enumerate(row_data, 1):
                c = ws3.cell(row=idx+1, column=col, value=val)
                c.font = BF; c.alignment = LT; c.border = TH

        # \u2550\u2550\u2550\u2550\u2550\u2550 Sheet 4: 30\u5e74\u9009\u54c1\u5e08\u64cd\u76d8\u624b\u518c \u2550\u2550\u2550\u2550\u2550\u2550
