            ['\u6cd5\u52194: \u8d8b\u52bf\u4fe1\u53f7', 'Google Trends\u4e0a\u5347+FB\u5e7f\u544a\u589e\u52a0 = \u53cc\u91cd\u786e\u8ba4', '\u53ea\u770bAmazon\u6570\u636e\u4f1a\u9519\u8fc7\u65b0\u5174\u54c1\u7c7b'],
            ['\u6cd5\u52195: \u590d\u8d2d\u6f5c\u529b', '\u6d88\u8017\u54c1/\u914d\u4ef6\u7c7b=\u9ad8LTV, \u4e00\u6b21\u6027\u4ea7\u54c1=\u9700\u66f4\u4f4e\u83b7\u5ba2\u6210\u672c', '\u8ba2\u9605\u6a21\u5f0f\u662f\u6700\u4f73\u5546\u4e1a\u6a21\u578b'],
