            ['\u75db\u70b9\u5206(0-20)', '\u7528\u6237\u771f\u5b9e\u75db\u70b9\u7a0b\u5ea6: \u5dee\u8bc4\u5206\u6790+\u529f\u80fd\u7f3a\u9677+\u672a\u6ee1\u8db3\u9700\u6c42', '\u226515=\u5f3a\u75db\u70b9\u53ef\u5229\u7528'],
            ['\u5229\u6da6\u5206(0-20)', '\u9884\u4f30\u5229\u6da6\u7a7a\u95f4: \u552e\u4ef7-\u6210\u672c-\u7269\u6d41-\u5e7f\u544a\u8d39', '\u226515=\u5229\u6da6\u7a7a\u95f4\u5145\u8db3'],
            ['\u51b2\u52a8\u5206(0-20)', '\u51b2\u52a8\u8d2d\u4e70\u6f5c\u529b: \u4ef7\u683c\u611f\u77e5+\u60c5\u7eea\u4ef7\u503c+\u5373\u65f6\u6ee1\u8db3\u611f', '\u226515=\u5f3a\u51b2\u52a8\u4ea7\u54c1'],
