            ['\u7ade\u4e89\u5206(0-20)', '\u7ade\u4e89\u53ef\u8fdb\u5165\u5ea6: \u54c1\u724c\u96c6\u4e2d\u5ea6+\u65b0\u54c1\u673a\u4f1a+\u58c1\u5792\u9ad8\u5ea6', '\u226515=\u7ade\u4e89\u53ef\u5165'],
