            ['B\u7ea7(50-69\u5206)', '\u52a0\u5165\u89c2\u5bdf\u5217\u8868, \u5b9a\u671f\u590d\u67e5BSR\u8d8b\u52bf', '\u76ee\u6807: \u6301\u7eed\u8ddf\u8e2a30\u5929'],
